  var activeCount: Int {
    orders.filter { $0.status != .delivered }.count
  }

  var deliveredCount: Int {
    orders.filter { $0.status == .delivered }.count
  }

  var exceptionCount: Int {
    orders.filter { $0.status == .exception || $0.reviewState == .needsReview }.count
  }

  var reviewOrders: [TrackedOrder] {
    orders.filter { $0.status == .exception || $0.reviewState != .accepted }
  }

  var reviewMailEvents: [MailEvent] {
    mailEvents.filter { $0.severity != .info || $0.reviewState != .accepted }
  }

  var reviewIntakeEmails: [ForwardedEmailIntake] {
    intakeEmails.filter { $0.reviewState == .needsReview }
  }

  var intakeParserDiagnostics: [IntakeParserDiagnostic] {
    intakeEmails.compactMap(intakeParserDiagnostic(for:))
      .sorted { lhs, rhs in
        if lhs.severity != rhs.severity {
          return lhs.severity.sortRank > rhs.severity.sortRank
        }
        return lhs.title < rhs.title
      }
  }

  var spaceMailIntakeHealthSummaries: [SpaceMailIntakeHealthSummary] {
    spaceMailIMAPConnections.map(spaceMailIntakeHealthSummary(for:))
  }

  var gmailIntakeHealthSummaries: [GmailIntakeHealthSummary] {
    gmailMailboxConnections.map(gmailIntakeHealthSummary(for:))
  }

  var microsoft365IntakeHealthSummaries: [Microsoft365IntakeHealthSummary] {
    microsoft365MailboxConnections.map(microsoft365IntakeHealthSummary(for:))
  }

  var mailboxProviderComparisonSummary: MailboxProviderComparisonSummary {
    let spaceMailSummaries = spaceMailIntakeHealthSummaries
    let gmailSummaries = gmailIntakeHealthSummaries

    let spaceMailFetched = spaceMailSummaries.reduce(0) { $0 + $1.fetchedCount }
    let spaceMailImported = spaceMailSummaries.reduce(0) { $0 + $1.importedCount }
    let spaceMailFiltered = spaceMailSummaries.reduce(0) { $0 + $1.filteredCount }
    let spaceMailUncertain = spaceMailSummaries.reduce(0) { $0 + $1.totalUncertainCount }
    let spaceMailParserIssues = spaceMailSummaries.reduce(0) { $0 + $1.parserIssueCount }
    let spaceMailCredentialBlockers = spaceMailIMAPConnections.filter { connection in
      !connection.credentialStorageStatus.localizedCaseInsensitiveContains("available")
        && !connection.credentialStorageStatus.localizedCaseInsensitiveContains("ready")
        && !connection.credentialStorageStatus.localizedCaseInsensitiveContains("Keychain")
    }.count
    let spaceMailSetupBlockers = spaceMailIMAPConnections.isEmpty ? 1 : 0
    let spaceMailBlocked = spaceMailSetupBlockers + spaceMailCredentialBlockers

    let gmailFetched = gmailSummaries.reduce(0) { $0 + $1.fetchedCount }
    let gmailImported = gmailSummaries.reduce(0) { $0 + $1.importedCount }
    let gmailFiltered = gmailSummaries.reduce(0) { $0 + $1.filteredCount }
    let gmailUncertain = gmailSummaries.reduce(0) { $0 + $1.totalUncertainCount }
    let gmailReadinessBlockers = gmailMailboxConnections.filter { !gmailOAuthReadinessSummary(for: $0).isReady }.count
    let gmailSignedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let gmailSetupBlockers = gmailMailboxConnections.isEmpty ? 0 : gmailReadinessBlockers + (gmailSignedInCount == 0 ? 1 : 0)
    let microsoftSummaries = microsoft365IntakeHealthSummaries
    let microsoftReadyCount = microsoft365MailboxConnections.filter { microsoft365OAuthReadinessSummary(for: $0).isReady }.count
    let microsoftSignedInCount = microsoft365MailboxConnections.filter { microsoft365AuthSessionState(for: $0).status == .connected }.count
    let microsoftFetched = microsoftSummaries.reduce(0) { $0 + $1.fetchedCount }
    let microsoftImported = microsoftSummaries.reduce(0) { $0 + $1.importedCount }
    let microsoftFiltered = microsoftSummaries.reduce(0) { $0 + $1.totalFilteredCount }
    let microsoftUncertain = microsoftSummaries.reduce(0) { $0 + $1.totalUncertainCount }
    let microsoftDuplicate = microsoftSummaries.reduce(0) { $0 + $1.duplicateCount }
    let microsoftProblemCount = microsoftSummaries.reduce(0) { $0 + $1.blockedCount }

    let spaceMailStatusTitle: String
    let spaceMailDetail: String
    let spaceMailNextAction: String
    let spaceMailTone: String
    if spaceMailIMAPConnections.isEmpty {
      spaceMailStatusTitle = "SpaceMail not configured"
      spaceMailDetail = "Add SpaceMail when the mailbox is hosted by SpaceMail or another IMAP provider."
      spaceMailNextAction = "Add SpaceMail setup and store the password reference in Keychain."
      spaceMailTone = "warning"
    } else if spaceMailCredentialBlockers > 0 {
      spaceMailStatusTitle = "SpaceMail credential needed"
      spaceMailDetail = "\(spaceMailCredentialBlockers) SpaceMail setup\(spaceMailCredentialBlockers == 1 ? "" : "s") still need a usable Keychain credential reference."
      spaceMailNextAction = "Set/check the SpaceMail credential, then run manual read-only refresh."
      spaceMailTone = "attention"
    } else if spaceMailImported > 0 || spaceMailUncertain > 0 || spaceMailParserIssues > 0 {
      spaceMailStatusTitle = "SpaceMail has operator work"
      spaceMailDetail = "\(spaceMailImported) imported, \(spaceMailUncertain) uncertain, and \(spaceMailParserIssues) parser issue\(spaceMailParserIssues == 1 ? "" : "s") across configured SpaceMail mailboxes."
      spaceMailNextAction = "Review Inbox intake, uncertain previews, and parser diagnostics."
      spaceMailTone = "attention"
    } else if spaceMailFiltered > 0 || spaceMailFetched > 0 {
      spaceMailStatusTitle = "SpaceMail filtering is active"
      spaceMailDetail = "\(spaceMailFetched) fetched with \(spaceMailFiltered) filtered non-order message\(spaceMailFiltered == 1 ? "" : "s") kept out of Inbox."
      spaceMailNextAction = "Run manual refresh when new order mail is expected."
      spaceMailTone = "success"
    } else {
      spaceMailStatusTitle = "SpaceMail ready"
      spaceMailDetail = "SpaceMail is configured, but no refresh evidence is active yet."
      spaceMailNextAction = "Run manual read-only SpaceMail refresh from Mailbox Monitor."
      spaceMailTone = "neutral"
    }

    let gmailStatusTitle: String
    let gmailDetail: String
    let gmailNextAction: String
    let gmailTone: String
    if gmailMailboxConnections.isEmpty {
      gmailStatusTitle = "Gmail optional"
      gmailDetail = "Add Gmail only for mailboxes hosted by Gmail or Google Workspace."
      gmailNextAction = "Leave Gmail alone unless an operator needs a Google-hosted mailbox."
      gmailTone = "neutral"
    } else if gmailSetupBlockers > 0 {
      gmailStatusTitle = "Gmail setup or sign-in blocked"
      gmailDetail = "\(gmailSetupBlockers) Gmail blocker\(gmailSetupBlockers == 1 ? "" : "s") need setup, callback, OAuth, or sign-in attention."
      gmailNextAction = "Open Gmail setup, run readiness checks, then test Google sign-in."
      gmailTone = "warning"
    } else if gmailImported > 0 || gmailUncertain > 0 {
      gmailStatusTitle = "Gmail has operator work"
      gmailDetail = "\(gmailImported) imported and \(gmailUncertain) uncertain Gmail message\(gmailUncertain == 1 ? "" : "s") need local review."
      gmailNextAction = "Review Gmail-origin Inbox rows and uncertain Gmail previews."
      gmailTone = "attention"
    } else if gmailFiltered > 0 || gmailFetched > 0 {
      gmailStatusTitle = "Gmail filtering is active"
      gmailDetail = "\(gmailFetched) fetched with \(gmailFiltered) filtered non-order message\(gmailFiltered == 1 ? "" : "s") kept out of Inbox."
      gmailNextAction = "Run manual Gmail refresh only when checking a Google-hosted mailbox."
      gmailTone = "success"
    } else {
      gmailStatusTitle = "Gmail ready for first refresh"
      gmailDetail = "Gmail setup is connected with no current intake evidence."
      gmailNextAction = "Run manual read-only Gmail refresh when needed."
      gmailTone = "neutral"
    }

    let microsoftStatusTitle: String
    let microsoftDetail: String
    let microsoftNextAction: String
    let microsoftTone: String
    if microsoft365MailboxConnections.isEmpty {
      microsoftStatusTitle = "Microsoft 365 optional"
      microsoftDetail = "Use Outlook / Microsoft 365 only when the mailbox is Microsoft-hosted."
      microsoftNextAction = "Leave Outlook / Microsoft 365 alone unless a Microsoft-hosted mailbox is being tested."
      microsoftTone = "neutral"
    } else if microsoftProblemCount > 0 {
      microsoftStatusTitle = "Microsoft 365 needs review"
      microsoftDetail = "\(microsoftProblemCount) Outlook / Microsoft 365 setup\(microsoftProblemCount == 1 ? "" : "s") have auth, consent, or Graph-read diagnostics to review."
      microsoftNextAction = "Open Outlook / Microsoft 365 setup or Audit before relying on Graph refresh."
      microsoftTone = "warning"
    } else if microsoftImported > 0 || microsoftUncertain > 0 {
      microsoftStatusTitle = "Outlook / Microsoft 365 has operator work"
      microsoftDetail = "\(microsoftImported) Outlook-origin imported message\(microsoftImported == 1 ? "" : "s") and \(microsoftUncertain) uncertain preview\(microsoftUncertain == 1 ? "" : "s") need local review."
      microsoftNextAction = "Review Outlook-origin Inbox rows and uncertain Microsoft 365 previews before creating or linking orders."
      microsoftTone = "attention"
    } else if microsoftFiltered > 0 || (microsoftSignedInCount > 0 && microsoftFetched > 0) {
      microsoftStatusTitle = "Outlook / Microsoft 365 has refresh evidence"
      microsoftDetail = "\(microsoftFetched) Outlook fetch signal\(microsoftFetched == 1 ? "" : "s"), \(microsoftFiltered) filtered example\(microsoftFiltered == 1 ? "" : "s"), and \(microsoftDuplicate) duplicate-safe result\(microsoftDuplicate == 1 ? "" : "s") are available for review."
      microsoftNextAction = "Review Mailbox Monitor or Audit before using Outlook as the active provider path."
      microsoftTone = "attention"
    } else if microsoftSignedInCount > 0 {
      microsoftStatusTitle = "Microsoft 365 signed in"
      microsoftDetail = "\(microsoftSignedInCount) Outlook setup\(microsoftSignedInCount == 1 ? "" : "s") are signed in, but Graph refresh has not produced Inbox evidence."
      microsoftNextAction = "Run explicit read-only Graph refresh only when this is the active Outlook mailbox."
      microsoftTone = "attention"
    } else if microsoftReadyCount > 0 {
      microsoftStatusTitle = "Microsoft 365 ready for sign-in"
      microsoftDetail = "\(microsoftReadyCount) Outlook setup\(microsoftReadyCount == 1 ? "" : "s") have OAuth readiness values."
      microsoftNextAction = "Test Microsoft sign-in only for a Microsoft-hosted mailbox."
      microsoftTone = "neutral"
    } else {
      microsoftStatusTitle = "Outlook / Microsoft 365 setup incomplete"
      microsoftDetail = "Outlook / Microsoft 365 needs tenant, client, redirect, scope, and sign-in readiness before it can be used for a Microsoft-hosted mailbox."
      microsoftNextAction = "Finish Microsoft 365 readiness, or use the provider that actually hosts the active mailbox."
      microsoftTone = "neutral"
    }

    let anyProviderConfigured = !spaceMailIMAPConnections.isEmpty || !gmailMailboxConnections.isEmpty || !microsoft365MailboxConnections.isEmpty
    let anyProviderBlocked = spaceMailBlocked > 0 || gmailSetupBlockers > 0 || microsoftProblemCount > 0
    let anyOperatorWork = spaceMailImported + gmailImported + microsoftImported + spaceMailUncertain + gmailUncertain + microsoftUncertain + spaceMailParserIssues > 0
    let anyRefreshEvidence = spaceMailFetched + gmailFetched + microsoftFetched + spaceMailFiltered + gmailFiltered + microsoftFiltered > 0

    let recommendedProvider: String
    let configuredProviderNames = [
      spaceMailIMAPConnections.isEmpty ? nil : "SpaceMail",
      gmailMailboxConnections.isEmpty ? nil : "Gmail",
      microsoft365MailboxConnections.isEmpty ? nil : "Outlook"
    ].compactMap { $0 }
    if configuredProviderNames.count > 1 {
      recommendedProvider = configuredProviderNames.joined(separator: " + ")
    } else if !spaceMailIMAPConnections.isEmpty {
      recommendedProvider = "SpaceMail"
    } else if !gmailMailboxConnections.isEmpty {
      recommendedProvider = "Gmail"
    } else if !microsoft365MailboxConnections.isEmpty {
      recommendedProvider = "Outlook"
    } else {
      recommendedProvider = "Add provider"
    }

    let title: String
    let detail: String
    let tone: String
    var actionItems: [MailboxProviderActionItem] = []
    var decisionRules: [MailboxProviderDecisionRule] = [
      MailboxProviderDecisionRule(
        title: "Use the provider that hosts the mailbox",
        detail: "SpaceMail is for IMAP-hosted mailboxes, Gmail is for Gmail or Google Workspace, and Outlook / Microsoft 365 is for Microsoft-hosted mailboxes. All providers feed the same local Inbox triage flow.",
        tone: "neutral",
        symbol: "mail.stack.fill"
      ),
      MailboxProviderDecisionRule(
        title: "Keep mixed mailboxes filtered",
        detail: "Mixed mailbox mode should filter ordinary personal, newsletter, security, and marketing mail before it reaches Inbox. Import or task only genuine order messages.",
        tone: (spaceMailFiltered + gmailFiltered + microsoftFiltered) > 0 ? "success" : "neutral",
        symbol: "line.3.horizontal.decrease.circle"
      ),
      MailboxProviderDecisionRule(
        title: "Use manual refresh as the control point",
        detail: "Mailbox refreshes stay explicit, read-only, and limited to recent previews. There is no background sync, notification flow, outbound email, or mailbox mutation.",
        tone: "success",
        symbol: "hand.tap.fill"
      )
    ]

    if configuredProviderNames.count > 1 {
      decisionRules.insert(
        MailboxProviderDecisionRule(
          title: "Provider paths can run side by side",
          detail: "Keep each mailbox setup separate, then compare refresh results here before deciding which provider needs operator attention.",
          tone: "attention",
          symbol: "arrow.left.arrow.right.circle.fill"
        ),
        at: 1
      )
    } else if !gmailMailboxConnections.isEmpty {
      decisionRules.insert(
        MailboxProviderDecisionRule(
          title: "Gmail is the active mailbox path",
          detail: "Complete Google iOS OAuth client, callback scheme, sign-in, and read-only Gmail consent before relying on real Gmail refresh.",
          tone: gmailSetupBlockers > 0 ? "warning" : "attention",
          symbol: "envelope.badge.shield.half.filled"
        ),
        at: 1
      )
    } else if !spaceMailIMAPConnections.isEmpty {
      decisionRules.insert(
        MailboxProviderDecisionRule(
          title: "SpaceMail is the active mailbox path",
          detail: "Confirm IMAP host, folder, SSL/TLS, and Keychain credential before relying on real SpaceMail refresh.",
          tone: spaceMailBlocked > 0 ? "warning" : "attention",
          symbol: "server.rack"
        ),
        at: 1
      )
    } else if !microsoft365MailboxConnections.isEmpty {
      decisionRules.insert(
        MailboxProviderDecisionRule(
          title: "Microsoft 365 is an advanced mailbox path",
          detail: "Use Outlook / Microsoft Graph only for Microsoft-hosted mailboxes, and keep read-only refresh explicit.",
          tone: microsoftProblemCount > 0 ? "warning" : "attention",
          symbol: "mail.stack.fill"
        ),
        at: 1
      )
    }

    if !anyProviderConfigured {
      title = "Choose a mailbox provider"
      detail = "Active mailbox providers feed the same local Inbox intake path, but no provider setup exists yet."
      tone = "warning"
    } else if anyOperatorWork {
      title = "Mailbox intake needs operator review"
      detail = "Provider setup is working enough to surface imported, uncertain, or parser review work."
      tone = "attention"
    } else if anyProviderBlocked {
      title = "Mailbox setup has blockers"
      detail = "At least one configured provider needs credentials, readiness, or sign-in attention before it can be relied on."
      tone = "warning"
    } else if anyRefreshEvidence {
      title = "Mailbox intake is quiet"
      detail = "Manual refresh evidence exists, and current provider filters are keeping non-order mail out of Inbox."
      tone = "success"
    } else {
      title = "Mailbox providers are ready for testing"
      detail = "Provider setup exists, but the next proof point is a manual read-only refresh."
      tone = "neutral"
    }

    if spaceMailIMAPConnections.isEmpty && gmailMailboxConnections.isEmpty && microsoft365MailboxConnections.isEmpty {
      actionItems.append(
        MailboxProviderActionItem(
          providerName: "Mailbox",
          title: "Choose a mailbox provider",
          detail: "Add the provider that hosts the mailbox you want ParcelOps to read manually.",
          priority: "1",
          tone: "warning",
          symbol: "envelope.badge.fill"
        )
      )
    }

    if !spaceMailIMAPConnections.isEmpty {
      if spaceMailCredentialBlockers > 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "SpaceMail",
            title: "Set SpaceMail credential",
            detail: "A Keychain password reference is needed before real IMAP refresh can be relied on.",
            priority: "1",
            tone: "warning",
            symbol: "key.fill"
          )
        )
      } else if spaceMailImported > 0 || spaceMailUncertain > 0 || spaceMailParserIssues > 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "SpaceMail",
            title: "Review SpaceMail intake",
            detail: "Confirm imported rows, uncertain previews, and parser diagnostics before creating orders.",
            priority: "1",
            tone: "attention",
            symbol: "tray.full.fill"
          )
        )
      } else if spaceMailFetched == 0 && spaceMailFiltered == 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "SpaceMail",
            title: "Run first SpaceMail refresh",
            detail: "Use the explicit manual read-only refresh after confirming host, folder, and credential.",
            priority: "2",
            tone: "attention",
            symbol: "arrow.clockwise.circle.fill"
          )
        )
      } else {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "SpaceMail",
            title: "Monitor SpaceMail refreshes",
            detail: "Current evidence is quiet; refresh manually when new order mail is expected.",
            priority: "3",
            tone: "success",
            symbol: "checkmark.seal.fill"
          )
        )
      }
    }

    if !gmailMailboxConnections.isEmpty {
      if gmailSetupBlockers > 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Gmail",
            title: "Finish Gmail setup",
            detail: "Resolve readiness, callback, OAuth, or sign-in blockers before using real Gmail refresh.",
            priority: "1",
            tone: "warning",
            symbol: "person.crop.circle.badge.exclamationmark.fill"
          )
        )
      } else if gmailImported > 0 || gmailUncertain > 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Gmail",
            title: "Review Gmail intake",
            detail: "Confirm Gmail-origin Inbox rows and uncertain previews before creating orders.",
            priority: "1",
            tone: "attention",
            symbol: "tray.full.fill"
          )
        )
      } else if gmailFetched == 0 && gmailFiltered == 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Gmail",
            title: "Run first Gmail refresh",
            detail: "Use the explicit manual read-only Gmail refresh only for Google-hosted mailboxes.",
            priority: "2",
            tone: "attention",
            symbol: "arrow.clockwise.circle.fill"
          )
        )
      } else {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Gmail",
            title: "Monitor Gmail refreshes",
            detail: "Current evidence is quiet; refresh manually when checking the Google-hosted mailbox.",
            priority: "3",
            tone: "success",
            symbol: "checkmark.seal.fill"
          )
        )
      }
    }

    if !microsoft365MailboxConnections.isEmpty {
      if microsoftProblemCount > 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Outlook",
            title: "Review Microsoft 365 diagnostics",
            detail: "Auth, consent, or Graph refresh diagnostics need review before this provider can be trusted.",
            priority: "1",
            tone: "warning",
            symbol: "exclamationmark.triangle.fill"
          )
        )
      } else if microsoftImported > 0 || microsoftUncertain > 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Outlook",
            title: "Review Outlook intake",
            detail: "Confirm Outlook-origin Inbox rows and uncertain Microsoft 365 previews before creating orders.",
            priority: "1",
            tone: "attention",
            symbol: "tray.full.fill"
          )
        )
      } else if microsoftSignedInCount == 0 && microsoftReadyCount == 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Outlook",
            title: "Finish Microsoft 365 readiness",
            detail: "Complete tenant/client/redirect/scope placeholders before sign-in or Graph refresh.",
            priority: "2",
            tone: "neutral",
            symbol: "checklist"
          )
        )
      } else if microsoftSignedInCount == 0 {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Outlook",
            title: "Test Microsoft sign-in",
            detail: "Run sign-in only when this mailbox is Microsoft-hosted and Graph refresh is needed.",
            priority: "2",
            tone: "attention",
            symbol: "person.badge.key.fill"
          )
        )
      } else {
        actionItems.append(
          MailboxProviderActionItem(
            providerName: "Outlook",
            title: "Keep Outlook as explicit refresh",
            detail: "Run Graph refresh manually only when the Outlook mailbox is the active intake source.",
            priority: "3",
            tone: "neutral",
            symbol: "mail.stack.fill"
          )
        )
      }
    }

    return MailboxProviderComparisonSummary(
      title: title,
      detail: detail,
      tone: tone,
      recommendedProvider: recommendedProvider,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Providers", value: "\(mailboxProviderSetupCount)", tone: anyProviderConfigured ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(spaceMailFetched + gmailFetched + microsoftFetched)", tone: anyRefreshEvidence ? "neutral" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(spaceMailImported + gmailImported + microsoftImported)", tone: (spaceMailImported + gmailImported + microsoftImported) > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(spaceMailFiltered + gmailFiltered + microsoftFiltered)", tone: (spaceMailFiltered + gmailFiltered + microsoftFiltered) > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(spaceMailUncertain + gmailUncertain + microsoftUncertain)", tone: (spaceMailUncertain + gmailUncertain + microsoftUncertain) > 0 ? "attention" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(spaceMailBlocked + gmailSetupBlockers + microsoftProblemCount)", tone: (spaceMailBlocked + gmailSetupBlockers + microsoftProblemCount) > 0 ? "warning" : "success")
      ],
      decisionRules: Array(decisionRules.prefix(4)),
      providers: [
        MailboxProviderComparisonItem(
          providerName: "SpaceMail",
          statusTitle: spaceMailStatusTitle,
          detail: spaceMailDetail,
          nextAction: spaceMailNextAction,
          tone: spaceMailTone,
          symbol: "server.rack",
          fetchedCount: spaceMailFetched,
          importedCount: spaceMailImported,
          filteredCount: spaceMailFiltered,
          blockedCount: spaceMailBlocked,
          uncertainCount: spaceMailUncertain
        ),
        MailboxProviderComparisonItem(
          providerName: "Gmail",
          statusTitle: gmailStatusTitle,
          detail: gmailDetail,
          nextAction: gmailNextAction,
          tone: gmailTone,
          symbol: "envelope.badge.shield.half.filled",
          fetchedCount: gmailFetched,
          importedCount: gmailImported,
          filteredCount: gmailFiltered,
          blockedCount: gmailSetupBlockers,
          uncertainCount: gmailUncertain
        ),
        MailboxProviderComparisonItem(
          providerName: "Outlook",
          statusTitle: microsoftStatusTitle,
          detail: microsoftDetail,
          nextAction: microsoftNextAction,
          tone: microsoftTone,
          symbol: "mail.stack.fill",
          fetchedCount: microsoftFetched,
          importedCount: microsoftImported,
          filteredCount: microsoftFiltered,
          blockedCount: microsoftProblemCount,
          uncertainCount: microsoftUncertain
        )
      ],
      actionItems: actionItems.sorted { lhs, rhs in
        if lhs.priority != rhs.priority {
          return lhs.priority < rhs.priority
        }
        return lhs.providerName < rhs.providerName
      }
    )
  }

  var mailboxOperationsHandoffSummary: MailboxOperationsHandoffSummary {
    let comparison = mailboxProviderComparisonSummary
    let spaceMailSummaries = spaceMailIntakeHealthSummaries
    let gmailSummaries = gmailIntakeHealthSummaries
    let microsoftSummaries = microsoft365IntakeHealthSummaries

    let importedCount = spaceMailSummaries.reduce(0) { $0 + $1.importedCount }
      + gmailSummaries.reduce(0) { $0 + $1.importedCount }
      + microsoftSummaries.reduce(0) { $0 + $1.importedCount }
    let filteredCount = spaceMailSummaries.reduce(0) { $0 + $1.filteredCount }
      + gmailSummaries.reduce(0) { $0 + $1.filteredCount }
      + microsoftSummaries.reduce(0) { $0 + $1.totalFilteredCount }
    let duplicateCount = spaceMailSummaries.reduce(0) { $0 + $1.duplicateCount }
      + gmailSummaries.reduce(0) { $0 + $1.duplicateCount }
      + microsoftSummaries.reduce(0) { $0 + $1.duplicateCount }
    let uncertainCount = spaceMailSummaries.reduce(0) { $0 + $1.totalUncertainCount }
      + gmailSummaries.reduce(0) { $0 + $1.totalUncertainCount }
      + microsoftSummaries.reduce(0) { $0 + $1.totalUncertainCount }
    let parserIssueCount = intakeParserDiagnostics.count
    let linkedOrderCount = intakeEmails.filter { $0.linkedOrderID != nil }.count
    var unresolvedIntakeCount = 0
    for email in intakeEmails where email.reviewState != .reviewed && email.reviewState != .ignored {
      unresolvedIntakeCount += 1
    }
    let providerBlockers = comparison.providers.reduce(0) { $0 + $1.blockedCount }
    let latestDates = (spaceMailSummaries.map(\.lastRefreshDate) + gmailSummaries.map(\.lastRefreshDate) + microsoftSummaries.map(\.lastRefreshDate))
      .filter { !$0.isEmpty && $0 != "Never" }
    let lastEvidenceText = latestDates.first ?? "No real mailbox refresh evidence yet"

    var lines: [MailboxOperationsHandoffLine] = []
    if providerBlockers > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Provider setup blockers",
          detail: "\(providerBlockers) setup, credential, readiness, or sign-in blocker\(providerBlockers == 1 ? "" : "s") should be resolved before relying on live mailbox intake.",
          tone: "warning",
          symbol: "exclamationmark.triangle.fill"
        )
      )
    }
    if importedCount > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Imported intake ready",
          detail: "\(importedCount) imported message\(importedCount == 1 ? "" : "s") should be reviewed in Inbox and linked or converted to orders.",
          tone: "attention",
          symbol: "tray.full.fill"
        )
      )
    }
    if uncertainCount > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Uncertain mailbox previews",
          detail: "\(uncertainCount) uncertain mixed-mailbox preview\(uncertainCount == 1 ? "" : "s") remain out of Inbox until an operator imports or dismisses them.",
          tone: "attention",
          symbol: "questionmark.folder.fill"
        )
      )
    }
    if parserIssueCount > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Parser review needed",
          detail: "\(parserIssueCount) local parser diagnostic\(parserIssueCount == 1 ? "" : "s") should be checked before trusting detected order, tracking, or destination fields.",
          tone: "attention",
          symbol: "doc.text.magnifyingglass"
        )
      )
    }
    if unresolvedIntakeCount > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Inbox triage still open",
          detail: "\(unresolvedIntakeCount) intake row\(unresolvedIntakeCount == 1 ? "" : "s") remain open or need review in primary Inbox triage.",
          tone: "attention",
          symbol: "envelope.open.fill"
        )
      )
    }
    if linkedOrderCount > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Inbox-to-order trail exists",
          detail: "\(linkedOrderCount) intake row\(linkedOrderCount == 1 ? "" : "s") already link to local order context.",
          tone: "success",
          symbol: "shippingbox.fill"
        )
      )
    }
    if filteredCount > 0 || duplicateCount > 0 {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "Mailbox noise controlled",
          detail: "\(filteredCount) filtered and \(duplicateCount) duplicate message\(filteredCount + duplicateCount == 1 ? "" : "s") were kept from creating duplicate Inbox work.",
          tone: "success",
          symbol: "line.3.horizontal.decrease.circle.fill"
        )
      )
    }
    if lines.isEmpty {
      lines.append(
        MailboxOperationsHandoffLine(
          title: "No mailbox handoff work",
          detail: "No imported, uncertain, parser, provider, or duplicate mailbox work is currently promoted for operator handoff.",
          tone: "neutral",
          symbol: "checkmark.circle.fill"
        )
      )
    }

    let title: String
    let detail: String
    let tone: String
    if providerBlockers > 0 {
      title = "Mailbox handoff has setup blockers"
      detail = "Resolve provider setup before depending on live intake results."
      tone = "warning"
    } else if importedCount + uncertainCount + parserIssueCount + unresolvedIntakeCount > 0 {
      title = "Mailbox handoff has operator work"
      detail = "Inbox, uncertain review, or parser follow-up should be handled before the next refresh cycle."
      tone = "attention"
    } else if filteredCount + duplicateCount > 0 {
      title = "Mailbox handoff is stable"
      detail = "Recent mailbox activity is mostly filtered or duplicate-safe, with no promoted order work."
      tone = "success"
    } else {
      title = "Mailbox handoff is quiet"
      detail = "Provider setup is ready or optional, and there is no current mailbox work to hand over."
      tone = "neutral"
    }

    return MailboxOperationsHandoffSummary(
      title: title,
      detail: detail,
      tone: tone,
      lastEvidenceText: lastEvidenceText,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Open intake", value: "\(unresolvedIntakeCount)", tone: unresolvedIntakeCount > 0 ? "attention" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount > 0 ? "attention" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Parser", value: "\(parserIssueCount)", tone: parserIssueCount > 0 ? "attention" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(providerBlockers)", tone: providerBlockers > 0 ? "warning" : "success")
      ],
      lines: Array(lines.prefix(6))
    )
  }

  var mailboxProviderTestQueueSummary: MailboxProviderTestQueueSummary {
    let comparison = mailboxProviderComparisonSummary
    let setup = mailboxProviderSetupChecklistSummary
    let handoff = mailboxOperationsHandoffSummary
    let releasePlan = mailboxReleaseTestPlanSummary
    let decision = mailboxOperatorDecisionSummary
    let spaceMailHealth = spaceMailIntakeHealthSummaries
    let gmailHealth = gmailIntakeHealthSummaries
    let microsoftHealth = microsoft365IntakeHealthSummaries
    let spaceMailFetched = spaceMailHealth.reduce(0) { $0 + $1.fetchedCount }
    let spaceMailImported = spaceMailHealth.reduce(0) { $0 + $1.importedCount }
    let spaceMailUncertain = spaceMailHealth.reduce(0) { $0 + $1.totalUncertainCount }
    let gmailFetched = gmailHealth.reduce(0) { $0 + $1.fetchedCount }
    let gmailImported = gmailHealth.reduce(0) { $0 + $1.importedCount }
    let gmailUncertain = gmailHealth.reduce(0) { $0 + $1.totalUncertainCount }
    let microsoftFetched = microsoftHealth.reduce(0) { $0 + $1.fetchedCount }
    let microsoftImported = microsoftHealth.reduce(0) { $0 + $1.importedCount }
    let microsoftUncertain = microsoftHealth.reduce(0) { $0 + $1.totalUncertainCount }
    let microsoftFiltered = microsoftHealth.reduce(0) { $0 + $1.totalFilteredCount }
    let parserIssueCount = intakeParserDiagnostics.count
    let openInboxCount = reviewIntakeEmails.count
    let linkedOrderCount = intakeEmails.filter { $0.linkedOrderID != nil }.count
    let inboxCreatedOrderCount = inboxCreatedOrders.count
    var items: [MailboxProviderTestQueueItem] = []

    for provider in setup.providers {
      let incompleteChecks = provider.checks.filter { !$0.isComplete && $0.tone != "neutral" }
      if provider.tone == "neutral" && incompleteChecks.isEmpty {
        continue
      }
      if incompleteChecks.isEmpty {
        items.append(
          MailboxProviderTestQueueItem(
            providerName: provider.providerName,
            phase: "Setup",
            title: "\(provider.providerName) setup verified",
            detail: provider.detail,
            nextAction: provider.nextAction,
            evidence: "\(provider.checks.count) setup check\(provider.checks.count == 1 ? "" : "s") complete.",
            isComplete: true,
            tone: "success",
            symbol: provider.symbol
          )
        )
      } else {
        for check in incompleteChecks.prefix(3) {
          items.append(
            MailboxProviderTestQueueItem(
              providerName: provider.providerName,
              phase: "Setup",
              title: check.title,
              detail: check.detail,
              nextAction: provider.nextAction,
              evidence: "Setup checklist item is not complete.",
              isComplete: false,
              tone: check.tone,
              symbol: check.symbol
            )
          )
        }
      }
    }

    for provider in comparison.providers {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: provider.providerName,
          phase: "Provider status",
          title: provider.statusTitle,
          detail: provider.detail,
          nextAction: provider.nextAction,
          evidence: "\(provider.fetchedCount) fetched, \(provider.importedCount) imported, \(provider.filteredCount) filtered, \(provider.uncertainCount) uncertain, \(provider.blockedCount) blocker\(provider.blockedCount == 1 ? "" : "s").",
          isComplete: provider.tone == "success" || provider.tone == "neutral",
          tone: provider.tone,
          symbol: provider.symbol
        )
      )
    }

    if !spaceMailIMAPConnections.isEmpty {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "SpaceMail",
          phase: "Refresh",
          title: spaceMailFetched > 0 ? "SpaceMail refresh evidence exists" : "Run SpaceMail manual refresh",
          detail: spaceMailFetched > 0 ? "SpaceMail has real or mock refresh evidence available for operator review." : "SpaceMail is configured but needs a manual read-only refresh proof point.",
          nextAction: spaceMailFetched > 0 ? "Review imported, uncertain, filtered, and duplicate results." : "Run real SpaceMail refresh from Mailbox Monitor when new order mail is expected.",
          evidence: "\(spaceMailFetched) fetched, \(spaceMailImported) imported, \(spaceMailUncertain) uncertain.",
          isComplete: spaceMailFetched > 0,
          tone: spaceMailFetched > 0 ? (spaceMailImported + spaceMailUncertain > 0 ? "attention" : "success") : "attention",
          symbol: "server.rack"
        )
      )
    }

    if !gmailMailboxConnections.isEmpty {
      let signedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
      let compiledConfigBlockers = gmailMailboxConnections.filter { connection in
        let readiness = gmailOAuthReadinessSummary(for: connection)
        return readiness.missingFields.contains { field in
          field.localizedCaseInsensitiveContains("Compiled App Info.plist")
            || field.localizedCaseInsensitiveContains("compiled")
        }
      }
      if !compiledConfigBlockers.isEmpty {
        let blockerDetails = compiledConfigBlockers.prefix(3).map { connection in
          let readiness = gmailOAuthReadinessSummary(for: connection)
          return "\(connection.displayName): \(readiness.compiledClientIDStatus); \(readiness.compiledCallbackSchemeStatus)"
        }
        items.append(
          MailboxProviderTestQueueItem(
            providerName: "Gmail",
            phase: "Compile config",
            title: "Rebuild app with Gmail OAuth values",
            detail: "Saved Gmail setup values do not yet match the compiled app configuration required by GoogleSignIn callback handling.",
            nextAction: "Update Project.json and App/Info.plist with the Google iOS OAuth client ID and reversed callback scheme, regenerate/rebuild, then rerun readiness.",
            evidence: blockerDetails.joined(separator: " | "),
            isComplete: false,
            tone: "warning",
            symbol: "app.badge.checkmark"
          )
        )
      }
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Gmail",
          phase: "Refresh",
          title: gmailFetched > 0 ? "Gmail refresh evidence exists" : signedInCount > 0 ? "Run Gmail manual refresh" : "Test Google sign-in",
          detail: gmailFetched > 0 ? "Gmail has refresh evidence available for operator review." : signedInCount > 0 ? "A Google account is connected, but no Gmail fetch evidence is recorded yet." : "Gmail setup exists but needs a connected Google sign-in before real refresh.",
          nextAction: gmailFetched > 0 ? "Review Gmail imported, uncertain, filtered, and duplicate results." : signedInCount > 0 ? "Run real Gmail refresh when checking a Google-hosted mailbox." : "Run Test real Google sign-in before refresh.",
          evidence: "\(signedInCount) signed in, \(gmailFetched) fetched, \(gmailImported) imported, \(gmailUncertain) uncertain.",
          isComplete: gmailFetched > 0,
          tone: gmailFetched > 0 ? (gmailImported + gmailUncertain > 0 ? "attention" : "success") : "attention",
          symbol: "envelope.badge.shield.half.filled"
        )
      )
    }

    if !microsoft365MailboxConnections.isEmpty {
      let signedInCount = microsoft365MailboxConnections.filter { microsoft365AuthSessionState(for: $0).status == .connected }.count
      let readyCount = microsoft365MailboxConnections.filter { microsoft365OAuthReadinessSummary(for: $0).isReady }.count
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Outlook",
          phase: "Refresh",
          title: microsoftFetched > 0 ? "Outlook refresh evidence exists" : signedInCount > 0 ? "Run Outlook manual refresh" : "Test Microsoft sign-in",
          detail: microsoftFetched > 0 ? "Outlook has Microsoft Graph refresh evidence available for operator review." : signedInCount > 0 ? "A Microsoft account is connected, but no Graph fetch evidence is recorded yet." : "Outlook / Microsoft 365 setup exists but needs a connected sign-in before real Graph refresh.",
          nextAction: (microsoftImported + microsoftUncertain) > 0 ? "Review Outlook imported and uncertain rows in Mailbox Monitor or Inbox." : microsoftFetched > 0 ? "Review Outlook filtered, duplicate, and auth diagnostics." : signedInCount > 0 ? "Run real Graph refresh when checking a Microsoft-hosted mailbox." : "Run Test real Microsoft sign-in before refresh.",
          evidence: "\(readyCount) ready setup, \(signedInCount) signed in, \(microsoftFetched) fetched, \(microsoftImported) imported, \(microsoftFiltered) filtered, \(microsoftUncertain) uncertain.",
          isComplete: microsoftFetched > 0,
          tone: (microsoftImported + microsoftUncertain) > 0 ? "attention" : microsoftFetched > 0 ? "success" : "attention",
          symbol: "mail.stack.fill"
        )
      )
    }

    if openInboxCount > 0 {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Inbox",
          phase: "Triage",
          title: "Review mailbox-created intake",
          detail: "\(openInboxCount) intake row\(openInboxCount == 1 ? "" : "s") still need operator review.",
          nextAction: "Open Inbox, then review, ignore, link, or create orders from confirmed rows.",
          evidence: "\(linkedOrderCount) linked intake row\(linkedOrderCount == 1 ? "" : "s"), \(inboxCreatedOrderCount) Inbox-created order\(inboxCreatedOrderCount == 1 ? "" : "s").",
          isComplete: false,
          tone: "attention",
          symbol: "tray.full.fill"
        )
      )
    } else {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Inbox",
          phase: "Triage",
          title: "Inbox triage is clear",
          detail: "No forwarded intake rows currently need review.",
          nextAction: "Run a manual provider refresh when new mailbox activity is expected.",
          evidence: "\(linkedOrderCount) linked intake row\(linkedOrderCount == 1 ? "" : "s"), \(inboxCreatedOrderCount) Inbox-created order\(inboxCreatedOrderCount == 1 ? "" : "s").",
          isComplete: true,
          tone: "success",
          symbol: "tray.fill"
        )
      )
    }

    if parserIssueCount > 0 {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Parser",
          phase: "Quality",
          title: "Review parser diagnostics",
          detail: "\(parserIssueCount) parser diagnostic\(parserIssueCount == 1 ? "" : "s") may affect order, tracking, merchant, or destination detection.",
          nextAction: "Open Mailbox Monitor parser diagnostics and reprocess rows after parser fixes.",
          evidence: "Diagnostics are local and based on stored previews only.",
          isComplete: false,
          tone: "attention",
          symbol: "doc.text.magnifyingglass"
        )
      )
    }

    for step in releasePlan.steps where !step.isComplete {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Release",
          phase: "QA",
          title: step.title,
          detail: step.detail,
          nextAction: step.nextAction,
          evidence: step.evidence,
          isComplete: false,
          tone: step.tone,
          symbol: step.symbol
        )
      )
    }

    for item in decision.decisions where item.isActive {
      items.append(
        MailboxProviderTestQueueItem(
          providerName: "Decision",
          phase: "Next action",
          title: item.title,
          detail: item.detail,
          nextAction: item.action,
          evidence: "Pulled from the active mailbox operator decision summary.",
          isComplete: false,
          tone: item.tone,
          symbol: item.symbol
        )
      )
    }

    let sortedItems = items.sorted { lhs, rhs in
      func rank(_ item: MailboxProviderTestQueueItem) -> Int {
        if item.tone == "warning" { return 0 }
        if item.tone == "attention" && !item.isComplete { return 1 }
        if !item.isComplete { return 2 }
        if item.tone == "neutral" { return 3 }
        return 4
      }
      if rank(lhs) != rank(rhs) { return rank(lhs) < rank(rhs) }
      if lhs.providerName != rhs.providerName { return lhs.providerName < rhs.providerName }
      return lhs.title < rhs.title
    }
    let openCount = sortedItems.filter { !$0.isComplete }.count
    let warningCount = sortedItems.filter { $0.tone == "warning" && !$0.isComplete }.count
    let attentionCount = sortedItems.filter { $0.tone == "attention" && !$0.isComplete }.count
    let evidenceCount = spaceMailFetched + gmailFetched + microsoftFetched + linkedOrderCount + inboxCreatedOrderCount

    let title: String
    let detail: String
    let tone: String
    if warningCount > 0 {
      title = "Mailbox provider test queue has blockers"
      detail = "\(warningCount) blocking provider test item\(warningCount == 1 ? "" : "s") should be resolved before treating mailbox intake as release-ready."
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Mailbox provider test queue needs review"
      detail = "\(attentionCount) provider test item\(attentionCount == 1 ? "" : "s") still need operator action or review."
      tone = "attention"
    } else if evidenceCount > 0 {
      title = "Mailbox provider test queue is mostly clear"
      detail = "Provider setup, refresh evidence, Inbox triage, and order handoff are available for release-candidate review."
      tone = "success"
    } else {
      title = "Mailbox provider test queue is waiting for first evidence"
      detail = "Run the next provider setup or manual refresh step to build local test evidence."
      tone = "neutral"
    }

    return MailboxProviderTestQueueSummary(
      title: title,
      detail: detail,
      tone: tone,
      currentProvider: comparison.recommendedProvider,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Open", value: "\(openCount)", tone: openCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Inbox", value: "\(openInboxCount)", tone: openInboxCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Evidence", value: "\(evidenceCount)", tone: evidenceCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Handoff", value: handoff.tone == "success" || handoff.tone == "neutral" ? "Clear" : "Review", tone: handoff.tone),
        SpaceMailReleaseSnapshotMetric(title: "Release", value: "\(releasePlan.steps.filter(\.isComplete).count)/\(releasePlan.steps.count)", tone: releasePlan.tone)
      ],
      items: sortedItems
    )
  }

  var mailboxProviderHandoffPacketSummary: MailboxProviderHandoffPacketSummary {
    let comparison = mailboxProviderComparisonSummary
    let setup = mailboxProviderSetupChecklistSummary
    let queue = mailboxProviderTestQueueSummary
    let handoff = mailboxOperationsHandoffSummary
    let decision = mailboxOperatorDecisionSummary
    let blockers = mailboxReleaseBlockerSummary
    let timeline = mailboxRunTimelineSummary
    let releasePlan = mailboxReleaseTestPlanSummary
    let generatedDate = Self.auditTimestamp()
    let openQueueItems = queue.items.filter { !$0.isComplete }
    let warningCount = openQueueItems.filter { $0.tone == "warning" }.count
    let attentionCount = openQueueItems.filter { $0.tone == "attention" }.count
    let openInboxCount = reviewIntakeEmails.count
    let linkedOrderCount = Set(intakeEmails.compactMap(\.linkedOrderID)).count
    let inboxOrderCount = inboxCreatedOrders.count
    let openTaskCount = reviewTasksNeedingAttention.count + handoffNotesNeedingAttention.count
    let releaseQATaskIDs = [
      "spacemail-release-snapshot",
      "gmail-release-readiness",
      "mailbox-release-readiness",
      "mailbox-provider-release-gate"
    ]
    let microsoft365ReleaseConnectionIDs = Set(microsoft365MailboxConnections.map { $0.id.uuidString })
    let releaseQATasks = reviewTasks.filter {
      $0.linkedEntityType == .integration && releaseQATaskIDs.contains($0.linkedEntityID)
    }
    let microsoft365ReleaseQATasks = reviewTasks.filter {
      $0.linkedEntityType == .integration
        && microsoft365ReleaseConnectionIDs.contains($0.linkedEntityID)
        && $0.title.localizedCaseInsensitiveContains("Outlook release self-check")
    }
    let allReleaseQATasks = releaseQATasks + microsoft365ReleaseQATasks
    let openReleaseQATaskCount = allReleaseQATasks.filter { $0.status != .completed }.count
    let completedReleaseQATaskCount = allReleaseQATasks.filter { $0.status == .completed }.count

    let providerLines = comparison.providers.map { provider in
      "\(provider.providerName): \(provider.statusTitle). \(provider.fetchedCount) fetched, \(provider.importedCount) imported, \(provider.uncertainCount) uncertain, \(provider.blockedCount) blockers. Next: \(provider.nextAction)"
    }
    let setupLines = setup.providers.map { provider in
      let incomplete = provider.checks.filter { !$0.isComplete }.map(\.title)
      return "\(provider.providerName): \(provider.status). \(incomplete.isEmpty ? "All setup checks complete." : "Missing: \(incomplete.joined(separator: ", ")).")"
    }
    let queueLines = openQueueItems.prefix(8).map { item in
      "\(item.providerName) / \(item.phase): \(item.title). Next: \(item.nextAction)"
    }
    let blockerLines = blockers.blockers.prefix(6).map { blocker in
      "\(blocker.source): \(blocker.title). Next: \(blocker.nextAction)"
    }
    let handoffLines = handoff.lines.map { line in
      "\(line.title): \(line.detail)"
    }
    let releaseLines = releasePlan.steps.filter { !$0.isComplete }.prefix(6).map { step in
      "\(step.title): \(step.nextAction)"
    }
    let fixedReleaseQALines = releaseQATaskIDs.map { taskID in
      let tasks = releaseQATasks.filter { $0.linkedEntityID == taskID }
      let open = tasks.filter { $0.status != .completed }.count
      let completed = tasks.filter { $0.status == .completed }.count
      let label: String
      switch taskID {
      case "spacemail-release-snapshot":
        label = "SpaceMail release snapshot"
      case "gmail-release-readiness":
        label = "Gmail release readiness"
      case "mailbox-release-readiness":
        label = "Combined mailbox release readiness"
      default:
        label = "Mailbox provider release gate"
      }
      return "\(label): \(tasks.count) task\(tasks.count == 1 ? "" : "s"), \(open) open, \(completed) completed."
    }
    let outlookOpen = microsoft365ReleaseQATasks.filter { $0.status != .completed }.count
    let outlookCompleted = microsoft365ReleaseQATasks.filter { $0.status == .completed }.count
    let releaseQALines = fixedReleaseQALines + [
      "Outlook release self-check: \(microsoft365ReleaseQATasks.count) task\(microsoft365ReleaseQATasks.count == 1 ? "" : "s"), \(outlookOpen) open, \(outlookCompleted) completed."
    ]

    let sections = [
      MailboxProviderHandoffPacketSection(
        title: "Provider state",
        detail: comparison.detail,
        tone: comparison.tone,
        symbol: "envelope.badge.fill",
        lines: providerLines.isEmpty ? ["No mailbox provider setup is configured."] : providerLines
      ),
      MailboxProviderHandoffPacketSection(
        title: "Setup readiness",
        detail: setup.detail,
        tone: setup.tone,
        symbol: "checklist.checked",
        lines: setupLines.isEmpty ? ["No setup checklist evidence is available."] : setupLines
      ),
      MailboxProviderHandoffPacketSection(
        title: "Next test queue",
        detail: queue.detail,
        tone: queue.tone,
        symbol: "list.bullet.clipboard.fill",
        lines: queueLines.isEmpty ? ["No open provider test queue items."] : queueLines
      ),
      MailboxProviderHandoffPacketSection(
        title: "Release blockers",
        detail: blockers.detail,
        tone: blockers.tone,
        symbol: "exclamationmark.triangle.fill",
        lines: blockerLines.isEmpty ? ["No mailbox release blockers are currently promoted."] : blockerLines
      ),
      MailboxProviderHandoffPacketSection(
        title: "Operator handoff",
        detail: handoff.detail,
        tone: handoff.tone,
        symbol: "arrow.left.arrow.right.square.fill",
        lines: handoffLines.isEmpty ? ["No handoff lines are currently promoted."] : handoffLines
      ),
      MailboxProviderHandoffPacketSection(
        title: "Release test plan",
        detail: releasePlan.detail,
        tone: releasePlan.tone,
        symbol: "checkmark.seal.fill",
        lines: releaseLines.isEmpty ? ["Release test plan has no incomplete local steps."] : releaseLines
      ),
      MailboxProviderHandoffPacketSection(
        title: "Release QA tasks",
        detail: "\(openReleaseQATaskCount) open provider release QA task\(openReleaseQATaskCount == 1 ? "" : "s"), \(completedReleaseQATaskCount) completed.",
        tone: openReleaseQATaskCount > 0 ? "success" : "attention",
        symbol: "checklist.checked",
        lines: releaseQALines
      )
    ]

    let title: String
    let detail: String
    let tone: String
    if warningCount > 0 || blockers.tone == "warning" {
      title = "Mailbox provider handoff has blockers"
      detail = "Resolve warning items before treating mailbox provider intake as release-ready."
      tone = "warning"
    } else if attentionCount > 0 || openInboxCount > 0 || openTaskCount > 0 {
      title = "Mailbox provider handoff needs operator review"
      detail = "There is open Inbox, queue, task, or handoff work for the next operator."
      tone = "attention"
    } else if timeline.entries.isEmpty {
      title = "Mailbox provider handoff needs run evidence"
      detail = "Provider setup exists, but the next packet should include a manual refresh run."
      tone = "neutral"
    } else {
      title = "Mailbox provider handoff is ready"
      detail = "Provider setup, refresh evidence, release blockers, and handoff checks are clear enough for hands-on review."
      tone = "success"
    }

    let reportLines = [
      title,
      detail,
      "Generated: \(generatedDate)",
      "Recommended provider path: \(comparison.recommendedProvider)",
      "Primary decision: \(decision.title). \(decision.primaryAction)",
      "Open queue items: \(openQueueItems.count)",
      "Open Inbox rows: \(openInboxCount)",
      "Linked intake orders: \(linkedOrderCount)",
      "Inbox-created orders: \(inboxOrderCount)",
      "Open task/handoff items: \(openTaskCount)",
      "Open provider release QA tasks: \(openReleaseQATaskCount)",
      "",
      "Sections:"
    ] + sections.flatMap { section in
      ["", "\(section.title): \(section.detail)"] + section.lines.map { "- \($0)" }
    } + [
      "",
      "Boundaries:",
      "- This packet is computed from local JSON-backed records.",
      "- It does not run mailbox refreshes, read credentials, call external services, send email, create notifications, or mutate mailbox messages."
    ]

    return MailboxProviderHandoffPacketSummary(
      title: title,
      detail: detail,
      tone: tone,
      generatedDate: generatedDate,
      reportText: reportLines.joined(separator: "\n"),
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Providers", value: comparison.recommendedProvider, tone: comparison.tone),
        SpaceMailReleaseSnapshotMetric(title: "Open queue", value: "\(openQueueItems.count)", tone: openQueueItems.isEmpty ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Inbox", value: "\(openInboxCount)", tone: openInboxCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Orders", value: "\(linkedOrderCount + inboxOrderCount)", tone: linkedOrderCount + inboxOrderCount > 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Release QA", value: "\(openReleaseQATaskCount)", tone: openReleaseQATaskCount > 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Tasks", value: "\(openTaskCount)", tone: openTaskCount == 0 ? "success" : "attention")
      ],
      sections: sections
    )
  }

  var mailboxProviderTroubleshootingSummary: MailboxProviderTroubleshootingSummary {
    let comparison = mailboxProviderComparisonSummary
    let setup = mailboxProviderSetupChecklistSummary
    let blockers = mailboxReleaseBlockerSummary
    let spaceMailHealth = spaceMailIntakeHealthSummaries
    let gmailHealth = gmailIntakeHealthSummaries
    let microsoftHealth = microsoft365IntakeHealthSummaries
    let spaceMailFetched = spaceMailHealth.reduce(0) { $0 + $1.fetchedCount }
    let spaceMailImported = spaceMailHealth.reduce(0) { $0 + $1.importedCount }
    let spaceMailFiltered = spaceMailHealth.reduce(0) { $0 + $1.filteredCount }
    let spaceMailUncertain = spaceMailHealth.reduce(0) { $0 + $1.totalUncertainCount }
    let spaceMailParserIssues = spaceMailHealth.reduce(0) { $0 + $1.parserIssueCount }
    let gmailFetched = gmailHealth.reduce(0) { $0 + $1.fetchedCount }
    let gmailImported = gmailHealth.reduce(0) { $0 + $1.importedCount }
    let gmailFiltered = gmailHealth.reduce(0) { $0 + $1.filteredCount }
    let gmailUncertain = gmailHealth.reduce(0) { $0 + $1.totalUncertainCount }
    let microsoftFetched = microsoftHealth.reduce(0) { $0 + $1.fetchedCount }
    let microsoftImported = microsoftHealth.reduce(0) { $0 + $1.importedCount }
    let microsoftFiltered = microsoftHealth.reduce(0) { $0 + $1.totalFilteredCount }
    let microsoftUncertain = microsoftHealth.reduce(0) { $0 + $1.totalUncertainCount }
    let microsoftBlocked = microsoftHealth.reduce(0) { $0 + $1.blockedCount }
    let gmailReadinessBlockers = gmailMailboxConnections.filter { !gmailOAuthReadinessSummary(for: $0).isReady }.count
    let gmailSignedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let microsoftReadinessBlockers = microsoft365MailboxConnections.filter { !microsoft365OAuthReadinessSummary(for: $0).isReady }.count
    let microsoftSignedInCount = microsoft365MailboxConnections.filter { microsoft365AuthSessionState(for: $0).status == .connected }.count
    let gmailCustomDomainNeedsVerification = gmailMailboxConnections.filter {
      let providerFit = gmailProviderFit(for: $0)
      return providerFit.isCustomDomain && !providerFit.hasGoogleEvidence
    }
    let linkedOrderCount = Set(intakeEmails.compactMap(\.linkedOrderID)).count
    let inboxOrderCount = inboxCreatedOrders.count
    var issues: [MailboxProviderTroubleshootingIssue] = []

    if spaceMailIMAPConnections.isEmpty && gmailMailboxConnections.isEmpty && microsoft365MailboxConnections.isEmpty {
      issues.append(
        MailboxProviderTroubleshootingIssue(
          providerName: "Mailbox",
          title: "No provider setup exists",
          symptom: "Mailbox intake cannot fetch real messages.",
          likelyCause: "No SpaceMail, Gmail, or Outlook local provider configuration exists.",
          nextAction: "Add the provider that hosts the mailbox, then complete credential or OAuth setup.",
          evidence: "Provider comparison recommends: \(comparison.recommendedProvider).",
          tone: "warning",
          symbol: "envelope.badge.fill"
        )
      )
    }

    for provider in setup.providers {
      let incompleteChecks = provider.checks.filter { !$0.isComplete }
      if !incompleteChecks.isEmpty {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: provider.providerName,
            title: "Setup checklist incomplete",
            symptom: provider.status,
            likelyCause: incompleteChecks.prefix(3).map(\.title).joined(separator: ", "),
            nextAction: provider.nextAction,
            evidence: "\(incompleteChecks.count) incomplete setup check\(incompleteChecks.count == 1 ? "" : "s").",
            tone: provider.tone == "success" ? "attention" : provider.tone,
            symbol: provider.symbol
          )
        )
      }
    }

    if !spaceMailIMAPConnections.isEmpty {
      let credentialMissingCount = spaceMailIMAPConnections.filter { connection in
        !connection.credentialStorageStatus.localizedCaseInsensitiveContains("available")
          && !connection.credentialStorageStatus.localizedCaseInsensitiveContains("ready")
          && !connection.credentialStorageStatus.localizedCaseInsensitiveContains("Keychain")
      }.count
      if credentialMissingCount > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "SpaceMail",
            title: "Credential reference missing",
            symptom: "Real IMAP refresh cannot authenticate safely.",
            likelyCause: "SpaceMail password/app-password has not been saved or checked in Keychain.",
            nextAction: "Use Set/update password or Check credential before running real SpaceMail refresh.",
            evidence: "\(credentialMissingCount) SpaceMail setup\(credentialMissingCount == 1 ? "" : "s") need credential attention.",
            tone: "warning",
            symbol: "key.fill"
          )
        )
      }
      if credentialMissingCount == 0 && spaceMailFetched == 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "SpaceMail",
            title: "No refresh evidence",
            symptom: "SpaceMail is configured but has no fetched message evidence.",
            likelyCause: "Manual refresh has not been run, or no result has been recorded.",
            nextAction: "Run real SpaceMail refresh when safe to test the mailbox.",
            evidence: "Fetched: 0, imported: \(spaceMailImported), filtered: \(spaceMailFiltered).",
            tone: "attention",
            symbol: "arrow.clockwise.circle"
          )
        )
      }
      if spaceMailFetched > 0 && spaceMailImported == 0 && spaceMailFiltered > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "SpaceMail",
            title: "Refresh found only filtered mail",
            symptom: "Messages were fetched but none reached Inbox.",
            likelyCause: "Mixed-mailbox filtering is treating recent messages as non-order mail.",
            nextAction: "Check filtered examples and classifier inspector before relaxing rules.",
            evidence: "\(spaceMailFetched) fetched, \(spaceMailFiltered) filtered, \(spaceMailUncertain) uncertain.",
            tone: "neutral",
            symbol: "line.3.horizontal.decrease.circle"
          )
        )
      }
      if spaceMailParserIssues > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "SpaceMail",
            title: "Parser diagnostics need review",
            symptom: "Detected order, tracking, merchant, or destination fields may be incomplete.",
            likelyCause: "Stored subject/body previews do not match the current parser rules.",
            nextAction: "Review parser diagnostics and reprocess affected intake rows.",
            evidence: "\(spaceMailParserIssues) SpaceMail parser issue\(spaceMailParserIssues == 1 ? "" : "s").",
            tone: "attention",
            symbol: "doc.text.magnifyingglass"
          )
        )
      }
      if spaceMailUncertain > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "SpaceMail",
            title: "Uncertain previews pending",
            symptom: "Order-ish messages are held out of Inbox.",
            likelyCause: "Classifier found weak order evidence without a strong order or tracking identifier.",
            nextAction: "Import true order messages or dismiss non-order messages from Mailbox Monitor.",
            evidence: "\(spaceMailUncertain) uncertain SpaceMail preview\(spaceMailUncertain == 1 ? "" : "s").",
            tone: "attention",
            symbol: "questionmark.folder.fill"
          )
        )
      }
    }

    if !gmailMailboxConnections.isEmpty {
      if !gmailCustomDomainNeedsVerification.isEmpty {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "Custom-domain Gmail host not verified",
            symptom: "A custom-domain address is configured in Gmail setup, but no local Google sign-in or Gmail refresh evidence confirms it is Google-hosted.",
            likelyCause: "The mailbox may be Google Workspace, or it may be hosted by IMAP/SpaceMail and should not use the Gmail API path.",
            nextAction: "Verify Google Workspace hosting before Gmail refresh; otherwise move the mailbox to SpaceMail/IMAP setup.",
            evidence: gmailCustomDomainNeedsVerification.prefix(3).map { "\($0.displayName): \(gmailDomain(for: $0.emailAddress))" }.joined(separator: " | "),
            tone: "attention",
            symbol: "server.rack"
          )
        )
      }
      let compiledConfigBlockers = gmailMailboxConnections.compactMap { connection -> String? in
        let readiness = gmailOAuthReadinessSummary(for: connection)
        let hasCompiledBlocker = readiness.missingFields.contains { field in
          field.localizedCaseInsensitiveContains("Compiled App Info.plist")
            || field.localizedCaseInsensitiveContains("compiled")
        }
        guard hasCompiledBlocker else { return nil }
        return "\(connection.displayName): \(readiness.compiledClientIDStatus); \(readiness.compiledCallbackSchemeStatus)"
      }
      if !compiledConfigBlockers.isEmpty {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "Compiled Gmail app config mismatch",
            symptom: "GoogleSignIn callback or real Gmail sign-in may fail even when local setup fields look filled in.",
            likelyCause: "Project.json and App/Info.plist still contain placeholder or mismatched GIDClientID / URL scheme values.",
            nextAction: "Compile the app with the saved Google iOS OAuth client ID and reversed callback scheme, then rerun Gmail readiness.",
            evidence: compiledConfigBlockers.prefix(3).joined(separator: " | "),
            tone: "warning",
            symbol: "app.badge.checkmark"
          )
        )
      }
      if gmailReadinessBlockers > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "OAuth readiness incomplete",
            symptom: "Real Gmail sign-in or refresh may not run.",
            likelyCause: "Google Cloud client ID, callback scheme, redirect URI, scopes, or setup notes need review.",
            nextAction: "Open Gmail setup, fill non-secret OAuth values, and run readiness checks.",
            evidence: "\(gmailReadinessBlockers) Gmail readiness blocker\(gmailReadinessBlockers == 1 ? "" : "s").",
            tone: "warning",
            symbol: "person.badge.key.fill"
          )
        )
      } else if gmailSignedInCount == 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "Google sign-in not connected",
            symptom: "Real Gmail refresh cannot acquire a usable Gmail API token.",
            likelyCause: "No connected Google account is recorded in local auth session state.",
            nextAction: "Run Test real Google sign-in before manual Gmail refresh.",
            evidence: "\(gmailMailboxConnections.count) Gmail setup\(gmailMailboxConnections.count == 1 ? "" : "s"), 0 connected.",
            tone: "attention",
            symbol: "person.crop.circle.badge.questionmark"
          )
        )
      } else if gmailFetched == 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "No Gmail refresh evidence",
            symptom: "Gmail sign-in exists but no message fetch result is recorded.",
            likelyCause: "Manual Gmail refresh has not been run after sign-in.",
            nextAction: "Run real Gmail refresh only when checking a Google-hosted mailbox.",
            evidence: "\(gmailSignedInCount) signed in, 0 fetched.",
            tone: "attention",
            symbol: "arrow.clockwise.circle"
          )
        )
      }
      if gmailFetched > 0 && gmailImported == 0 && gmailFiltered > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "Gmail refresh found only filtered mail",
            symptom: "Gmail fetched messages but none reached Inbox.",
            likelyCause: "Mixed-mailbox filtering is treating recent Gmail messages as non-order mail.",
            nextAction: "Check Gmail filtered examples and classifier test output.",
            evidence: "\(gmailFetched) fetched, \(gmailFiltered) filtered, \(gmailUncertain) uncertain.",
            tone: "neutral",
            symbol: "line.3.horizontal.decrease.circle"
          )
        )
      }
      if gmailImported + gmailUncertain > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Gmail",
            title: "Gmail intake needs review",
            symptom: "Gmail has imported or uncertain mailbox work.",
            likelyCause: "Recent Gmail refresh produced order-related or ambiguous messages.",
            nextAction: "Review Gmail-origin Inbox rows and uncertain previews before creating orders.",
            evidence: "\(gmailImported) imported, \(gmailUncertain) uncertain.",
            tone: "attention",
            symbol: "tray.full.fill"
          )
        )
      }
    }

    if !microsoft365MailboxConnections.isEmpty {
      if microsoftReadinessBlockers > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Outlook",
            title: "Microsoft 365 readiness incomplete",
            symptom: "Real Outlook sign-in or Graph refresh may not run.",
            likelyCause: "Tenant, client ID, redirect URI, scopes, consent notes, or setup checklist items need review.",
            nextAction: "Open Outlook / Microsoft 365 setup, fill non-secret readiness values, then test Microsoft sign-in only for Microsoft-hosted mailboxes.",
            evidence: "\(microsoftReadinessBlockers) Outlook readiness blocker\(microsoftReadinessBlockers == 1 ? "" : "s").",
            tone: "warning",
            symbol: "person.badge.key.fill"
          )
        )
      } else if microsoftSignedInCount == 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Outlook",
            title: "Microsoft sign-in not connected",
            symptom: "Real Graph refresh cannot acquire a usable read-only token.",
            likelyCause: "No connected Microsoft account is recorded in local auth session state.",
            nextAction: "Run Test real Microsoft sign-in before manual Graph refresh.",
            evidence: "\(microsoft365MailboxConnections.count) Outlook setup\(microsoft365MailboxConnections.count == 1 ? "" : "s"), 0 connected.",
            tone: "attention",
            symbol: "person.crop.circle.badge.questionmark"
          )
        )
      } else if microsoftFetched == 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Outlook",
            title: "No Outlook refresh evidence",
            symptom: "Microsoft sign-in exists but no message fetch result is recorded.",
            likelyCause: "Manual Graph refresh has not been run after sign-in.",
            nextAction: "Run real Graph refresh only when checking a Microsoft-hosted mailbox.",
            evidence: "\(microsoftSignedInCount) signed in, 0 fetched.",
            tone: "attention",
            symbol: "arrow.clockwise.circle"
          )
        )
      }
      if microsoftBlocked > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Outlook",
            title: "Graph diagnostics need review",
            symptom: "Microsoft Graph refresh reported blocked/auth/consent diagnostics.",
            likelyCause: "Microsoft Graph consent, token scope, tenant, folder, or API response needs review.",
            nextAction: "Open Audit or Mailbox Monitor and review the safe Graph diagnostic detail before relying on Outlook intake.",
            evidence: "\(microsoftBlocked) Outlook blocker\(microsoftBlocked == 1 ? "" : "s"), \(microsoftFetched) fetched, \(microsoftFiltered) filtered.",
            tone: "warning",
            symbol: "exclamationmark.triangle.fill"
          )
        )
      }
      if microsoftFetched > 0 && microsoftImported == 0 && microsoftFiltered > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Outlook",
            title: "Outlook refresh found only filtered mail",
            symptom: "Outlook fetched messages but none reached Inbox.",
            likelyCause: "Mixed-mailbox filtering is treating recent Outlook messages as non-order mail.",
            nextAction: "Check Outlook filtered examples and classifier reason labels.",
            evidence: "\(microsoftFetched) fetched, \(microsoftFiltered) filtered, \(microsoftUncertain) uncertain.",
            tone: "neutral",
            symbol: "line.3.horizontal.decrease.circle"
          )
        )
      }
      if (microsoftImported + microsoftUncertain) > 0 {
        issues.append(
          MailboxProviderTroubleshootingIssue(
            providerName: "Outlook",
            title: "Outlook intake needs review",
            symptom: "Outlook has imported or uncertain mailbox work.",
            likelyCause: "Recent Microsoft Graph refresh produced order-related or ambiguous messages.",
            nextAction: "Review Outlook-origin Inbox rows and uncertain previews before creating orders.",
            evidence: "\(microsoftImported) imported, \(microsoftUncertain) uncertain.",
            tone: "attention",
            symbol: "tray.full.fill"
          )
        )
      }
    }

    if reviewIntakeEmails.isEmpty && linkedOrderCount + inboxOrderCount == 0 && spaceMailImported + gmailImported + microsoftImported > 0 {
      issues.append(
        MailboxProviderTroubleshootingIssue(
          providerName: "Orders",
          title: "Imported mail has no order handoff",
          symptom: "Imported messages have not produced linked or Inbox-created orders.",
          likelyCause: "Inbox triage has not confirmed and linked/created order records yet.",
          nextAction: "Open Inbox or Mailbox Monitor and use Create order or Link order on confirmed intake.",
          evidence: "\(spaceMailImported + gmailImported + microsoftImported) imported, \(linkedOrderCount + inboxOrderCount) order handoff records.",
          tone: "attention",
          symbol: "shippingbox.fill"
        )
      )
    }

    for blocker in blockers.blockers.prefix(4) where blocker.tone == "warning" {
      issues.append(
        MailboxProviderTroubleshootingIssue(
          providerName: blocker.source,
          title: blocker.title,
          symptom: blocker.detail,
          likelyCause: "Release blocker queue promoted this as a warning.",
          nextAction: blocker.nextAction,
          evidence: "Release blocker tone: \(blocker.tone).",
          tone: "warning",
          symbol: blocker.symbol
        )
      )
    }

    let uniqueIssues = Array(
      Dictionary(grouping: issues, by: { "\($0.providerName)-\($0.title)-\($0.symptom)" })
        .compactMap { $0.value.first }
    ).sorted { lhs, rhs in
      func rank(_ issue: MailboxProviderTroubleshootingIssue) -> Int {
        if issue.tone == "warning" { return 0 }
        if issue.tone == "attention" { return 1 }
        if issue.tone == "neutral" { return 2 }
        return 3
      }
      if rank(lhs) != rank(rhs) { return rank(lhs) < rank(rhs) }
      if lhs.providerName != rhs.providerName { return lhs.providerName < rhs.providerName }
      return lhs.title < rhs.title
    }
    let warningCount = uniqueIssues.filter { $0.tone == "warning" }.count
    let attentionCount = uniqueIssues.filter { $0.tone == "attention" }.count

    let title: String
    let detail: String
    let tone: String
    if warningCount > 0 {
      title = "Mailbox troubleshooting has setup blockers"
      detail = "\(warningCount) warning diagnostic\(warningCount == 1 ? "" : "s") should be resolved before live mailbox intake is relied on."
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Mailbox troubleshooting has review items"
      detail = "\(attentionCount) diagnostic\(attentionCount == 1 ? "" : "s") need operator review or manual follow-up."
      tone = "attention"
    } else if uniqueIssues.isEmpty {
      title = "Mailbox troubleshooting is clear"
      detail = "No provider setup, auth, refresh, parser, Inbox, or handoff diagnostics are currently promoted."
      tone = "success"
    } else {
      title = "Mailbox troubleshooting is informational"
      detail = "Only non-blocking provider notes are currently promoted."
      tone = "neutral"
    }

    let reportLines = [
      title,
      detail,
      "Recommended provider path: \(comparison.recommendedProvider)",
      "Diagnostics: \(uniqueIssues.count)",
      ""
    ] + uniqueIssues.map { issue in
      "\(issue.providerName) - \(issue.title)\nSymptom: \(issue.symptom)\nLikely cause: \(issue.likelyCause)\nNext: \(issue.nextAction)\nEvidence: \(issue.evidence)"
    } + [
      "",
      "Boundaries: local-only diagnostic summary; no mailbox refresh, credential read, external service call, outbound email, notification, or mailbox mutation occurs."
    ]

    return MailboxProviderTroubleshootingSummary(
      title: title,
      detail: detail,
      tone: tone,
      reportText: reportLines.joined(separator: "\n\n"),
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Review", value: "\(attentionCount)", tone: attentionCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "SpaceMail", value: "\(spaceMailFetched)", tone: spaceMailFetched > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Gmail", value: "\(gmailFetched)", tone: gmailFetched > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Outlook", value: "\(microsoftFetched)", tone: microsoftFetched > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Parser", value: "\(spaceMailParserIssues)", tone: spaceMailParserIssues == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Orders", value: "\(linkedOrderCount + inboxOrderCount)", tone: linkedOrderCount + inboxOrderCount > 0 ? "success" : "attention")
      ],
      issues: uniqueIssues
    )
  }

  var mailboxProviderReleaseGateSummary: MailboxProviderReleaseGateSummary {
    let comparison = mailboxProviderComparisonSummary
    let setup = mailboxProviderSetupChecklistSummary
    let queue = mailboxProviderTestQueueSummary
    let handoffPacket = mailboxProviderHandoffPacketSummary
    let troubleshooting = mailboxProviderTroubleshootingSummary
    let blockers = mailboxReleaseBlockerSummary
    let releasePlan = mailboxReleaseTestPlanSummary
    let timeline = mailboxRunTimelineSummary
    let providerCount = spaceMailIMAPConnections.count + gmailMailboxConnections.count + microsoft365MailboxConnections.count
    let optionalProviderNames = setup.providers
      .filter { provider in
        provider.tone == "neutral"
          && provider.checks.allSatisfy { $0.tone == "neutral" || $0.isComplete }
      }
      .map(\.providerName)
    let optionalProviderText = optionalProviderNames.isEmpty ? "none" : optionalProviderNames.joined(separator: ", ")
    let gmailReadinessSummaries = gmailMailboxConnections.map(gmailOAuthReadinessSummary(for:))
    let gmailReadinessBlockers = gmailReadinessSummaries.filter { !$0.isReady }
    let gmailReadinessBlockerPreview = gmailReadinessBlockers
      .flatMap(\.missingFields)
      .prefix(3)
      .joined(separator: ", ")
    let microsoft365ReadinessSummaries = microsoft365MailboxConnections.map(microsoft365OAuthReadinessSummary(for:))
    let microsoft365ReadinessBlockers = microsoft365ReadinessSummaries.filter { !$0.isReady }
    let microsoft365ReadinessBlockerPreview = microsoft365ReadinessBlockers
      .flatMap(\.missingFields)
      .prefix(3)
      .joined(separator: ", ")
    let setupIncompleteCount = setup.providers.reduce(0) { total, provider in
      total + provider.checks.filter { !$0.isComplete && provider.tone != "neutral" && $0.tone != "neutral" }.count
    }
    let setupWarningCount = setup.providers.reduce(0) { total, provider in
      total + provider.checks.filter { !$0.isComplete && provider.tone != "neutral" && $0.tone == "warning" }.count
    }
    let openQueueCount = queue.items.filter { !$0.isComplete }.count
    let warningTroubleCount = troubleshooting.issues.filter { $0.tone == "warning" }.count
    let attentionTroubleCount = troubleshooting.issues.filter { $0.tone == "attention" }.count
    let warningBlockerCount = blockers.blockers.filter { $0.tone == "warning" }.count
    let reviewBlockerCount = blockers.blockers.filter { $0.tone == "attention" }.count
    let releaseIncompleteCount = releasePlan.steps.filter { !$0.isComplete }.count
    let openInboxCount = reviewIntakeEmails.count
    let linkedOrderCount = Set(intakeEmails.compactMap(\.linkedOrderID)).count
    let inboxCreatedOrderCount = inboxCreatedOrders.count
    let openTaskHandoffCount = reviewTasksNeedingAttention.count + handoffNotesNeedingAttention.count
    let releaseGateTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration
        && $0.linkedEntityID == "mailbox-provider-release-gate"
    }
    let releaseSnapshotTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration
        && [
          "spacemail-release-snapshot",
          "gmail-release-readiness",
          "mailbox-release-readiness"
        ].contains($0.linkedEntityID)
    }
    let microsoft365ReleaseConnectionIDs = Set(microsoft365MailboxConnections.map { $0.id.uuidString })
    let microsoft365ReleaseSnapshotTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration
        && microsoft365ReleaseConnectionIDs.contains($0.linkedEntityID)
        && $0.title.localizedCaseInsensitiveContains("Outlook release self-check")
    }
    let providerReleaseSnapshotTasks = releaseSnapshotTasks + microsoft365ReleaseSnapshotTasks
    let openReleaseGateTaskCount = releaseGateTasks.filter { $0.status != .completed }.count
    let completedReleaseGateTaskCount = releaseGateTasks.filter { $0.status == .completed }.count
    let openReleaseSnapshotTaskCount = providerReleaseSnapshotTasks.filter { $0.status != .completed }.count
    let completedReleaseSnapshotTaskCount = providerReleaseSnapshotTasks.filter { $0.status == .completed }.count
    let refreshEvidenceCount = timeline.entries.count
    let fetchedCount = totalMailboxFetchedCount
    let importedCount = totalMailboxImportedCount
    let filteredCount = totalMailboxFilteredSignalCount
    let duplicateCount = totalMailboxDuplicateCount
    let uncertainCount = totalMailboxUncertainSignalCount
    let generatedDate = Self.auditTimestamp()

    let gates = [
      MailboxProviderReleaseGateItem(
        title: "Provider configured",
        requirement: "At least one mailbox provider path is configured.",
        evidence: "\(providerCount) provider setup\(providerCount == 1 ? "" : "s") saved. Recommended path: \(comparison.recommendedProvider).",
        nextAction: "Add an active mailbox provider before release testing.",
        isPassed: providerCount > 0,
        tone: providerCount > 0 ? "success" : "warning",
        symbol: "envelope.badge.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Setup checklist complete enough",
        requirement: "Provider setup checks should not have unresolved warning blockers.",
        evidence: "\(setupIncompleteCount) incomplete required setup check\(setupIncompleteCount == 1 ? "" : "s"). Optional providers not configured: \(optionalProviderText).",
        nextAction: setupIncompleteCount == 0
          ? "Keep the active provider path current; configure optional providers only when needed."
          : "Use the provider setup checklist and fix missing credential/OAuth/readiness values.",
        isPassed: setupIncompleteCount == 0,
        tone: setupIncompleteCount == 0 ? "success" : setupWarningCount == 0 ? "attention" : "warning",
        symbol: "checklist.checked"
      ),
      MailboxProviderReleaseGateItem(
        title: "Gmail compiled callback readiness",
        requirement: "Configured Gmail providers must have saved OAuth values that match the compiled app callback configuration.",
        evidence: gmailMailboxConnections.isEmpty
          ? "No Gmail setup is configured; Gmail remains optional for non-Google mailboxes."
          : "\(gmailReadinessBlockers.count) of \(gmailMailboxConnections.count) Gmail setup\(gmailMailboxConnections.count == 1 ? "" : "s") still have OAuth/client/callback blockers\(gmailReadinessBlockerPreview.isEmpty ? "." : ": \(gmailReadinessBlockerPreview).")",
        nextAction: gmailMailboxConnections.isEmpty
          ? "Leave Gmail unconfigured unless a mailbox is hosted by Gmail or Google Workspace."
          : gmailReadinessBlockers.isEmpty
            ? "Proceed with explicit Google sign-in and manual read-only Gmail refresh testing when needed."
            : "Update saved Gmail setup values and the compiled app Info.plist/project callback configuration before relying on Gmail refresh.",
        isPassed: gmailMailboxConnections.isEmpty || gmailReadinessBlockers.isEmpty,
        tone: gmailMailboxConnections.isEmpty ? "neutral" : (gmailReadinessBlockers.isEmpty ? "success" : "warning"),
        symbol: "g.circle.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Outlook OAuth readiness",
        requirement: "Configured Outlook/Microsoft 365 providers must have saved non-secret Entra/OAuth values before real sign-in and Graph refresh are relied on.",
        evidence: microsoft365MailboxConnections.isEmpty
          ? "No Outlook setup is configured; Outlook remains optional for non-Microsoft mailboxes."
          : "\(microsoft365ReadinessBlockers.count) of \(microsoft365MailboxConnections.count) Outlook setup\(microsoft365MailboxConnections.count == 1 ? "" : "s") still have OAuth/client/redirect/scope blockers\(microsoft365ReadinessBlockerPreview.isEmpty ? "." : ": \(microsoft365ReadinessBlockerPreview).")",
        nextAction: microsoft365MailboxConnections.isEmpty
          ? "Leave Outlook unconfigured unless a mailbox is hosted by Microsoft 365 or Outlook."
          : microsoft365ReadinessBlockers.isEmpty
            ? "Proceed with explicit Microsoft sign-in and manual read-only Graph refresh testing when needed."
            : "Update saved Outlook setup values before relying on Microsoft sign-in or Graph mailbox refresh.",
        isPassed: microsoft365MailboxConnections.isEmpty || microsoft365ReadinessBlockers.isEmpty,
        tone: microsoft365MailboxConnections.isEmpty ? "neutral" : (microsoft365ReadinessBlockers.isEmpty ? "success" : "warning"),
        symbol: "mail.stack.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Manual refresh evidence exists",
        requirement: "Release testing should include at least one manual read-only provider refresh result.",
        evidence: "\(refreshEvidenceCount) run timeline entr\(refreshEvidenceCount == 1 ? "y" : "ies"), \(fetchedCount) fetched message\(fetchedCount == 1 ? "" : "s").",
        nextAction: "Run the active provider's explicit manual refresh when test mailbox access is available.",
        isPassed: refreshEvidenceCount > 0 || fetchedCount > 0,
        tone: refreshEvidenceCount > 0 || fetchedCount > 0 ? "success" : "attention",
        symbol: "arrow.clockwise.circle"
      ),
      MailboxProviderReleaseGateItem(
        title: "Mailbox noise is controlled",
        requirement: "Mixed mailbox filtering and duplicate prevention should avoid flooding Inbox.",
        evidence: "\(filteredCount) filtered, \(duplicateCount) duplicate, \(uncertainCount) uncertain, \(importedCount) imported.",
        nextAction: "Review uncertain examples and filtered reason labels if Inbox is noisy.",
        isPassed: uncertainCount == 0 || importedCount > 0 || filteredCount + duplicateCount > 0,
        tone: uncertainCount == 0 ? "success" : importedCount > 0 ? "attention" : "neutral",
        symbol: "line.3.horizontal.decrease.circle"
      ),
      MailboxProviderReleaseGateItem(
        title: "Inbox triage is actionable",
        requirement: "Imported intake should be reviewable, ignorable, linkable, or convertible to an order.",
        evidence: "\(openInboxCount) open intake row\(openInboxCount == 1 ? "" : "s"), \(linkedOrderCount) linked intake order\(linkedOrderCount == 1 ? "" : "s"), \(inboxCreatedOrderCount) Inbox-created order\(inboxCreatedOrderCount == 1 ? "" : "s").",
        nextAction: "Use Inbox or Mailbox Monitor to review, ignore, link, or create orders from confirmed intake.",
        isPassed: openInboxCount == 0 || linkedOrderCount + inboxCreatedOrderCount > 0,
        tone: openInboxCount == 0 || linkedOrderCount + inboxCreatedOrderCount > 0 ? "success" : "attention",
        symbol: "tray.full.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Order handoff is visible",
        requirement: "At least one confirmed intake-to-order path should appear across Orders, Dashboard, Workbench, Tasks, and Audit.",
        evidence: "\(linkedOrderCount + inboxCreatedOrderCount) local order handoff record\(linkedOrderCount + inboxCreatedOrderCount == 1 ? "" : "s").",
        nextAction: "Create or link one confirmed order from Inbox, then verify the source trail in Orders.",
        isPassed: linkedOrderCount + inboxCreatedOrderCount > 0 || importedCount == 0,
        tone: linkedOrderCount + inboxCreatedOrderCount > 0 ? "success" : importedCount == 0 ? "neutral" : "attention",
        symbol: "shippingbox.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Diagnostics are not blocking",
        requirement: "Troubleshooting should have no warning diagnostics before release-candidate use.",
        evidence: "\(warningTroubleCount) warning diagnostic\(warningTroubleCount == 1 ? "" : "s"), \(attentionTroubleCount) review diagnostic\(attentionTroubleCount == 1 ? "" : "s").",
        nextAction: "Open the troubleshooting guide and resolve warning diagnostics.",
        isPassed: warningTroubleCount == 0,
        tone: warningTroubleCount == 0 ? (attentionTroubleCount == 0 ? "success" : "attention") : "warning",
        symbol: "stethoscope"
      ),
      MailboxProviderReleaseGateItem(
        title: "Release blockers are clear",
        requirement: "Mailbox release blocker queue should not contain warning blockers.",
        evidence: "\(warningBlockerCount) warning blocker\(warningBlockerCount == 1 ? "" : "s"), \(reviewBlockerCount) review blocker\(reviewBlockerCount == 1 ? "" : "s").",
        nextAction: "Resolve warning blockers before relying on mailbox intake.",
        isPassed: warningBlockerCount == 0,
        tone: warningBlockerCount == 0 ? (reviewBlockerCount == 0 ? "success" : "attention") : "warning",
        symbol: "exclamationmark.triangle.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Operator follow-up is assigned",
        requirement: "Open provider queue and handoff work should either be assigned as tasks or intentionally left open.",
        evidence: "\(openQueueCount) open provider queue item\(openQueueCount == 1 ? "" : "s"), \(openTaskHandoffCount) task/handoff attention item\(openTaskHandoffCount == 1 ? "" : "s").",
        nextAction: "Create a provider queue, diagnostic, or handoff task if work needs to carry over.",
        isPassed: openQueueCount == 0 || openTaskHandoffCount > 0,
        tone: openQueueCount == 0 ? "success" : openTaskHandoffCount > 0 ? "attention" : "warning",
        symbol: "checklist"
      ),
      MailboxProviderReleaseGateItem(
        title: "Release test plan is current",
        requirement: "Mailbox release test plan should not have incomplete warning steps.",
        evidence: "\(releasePlan.steps.count - releaseIncompleteCount)/\(releasePlan.steps.count) release test step\(releasePlan.steps.count == 1 ? "" : "s") complete. Handoff packet: \(handoffPacket.title).",
        nextAction: "Complete remaining release test plan steps during hands-on QA.",
        isPassed: releaseIncompleteCount == 0 || releasePlan.tone != "warning",
        tone: releaseIncompleteCount == 0 ? "success" : releasePlan.tone,
        symbol: "checkmark.seal.fill"
      ),
      MailboxProviderReleaseGateItem(
        title: "Release validation checkpoint recorded",
        requirement: "Before release-candidate use, capture the current mailbox provider gate as a local review task.",
        evidence: "\(releaseGateTasks.count) release gate task\(releaseGateTasks.count == 1 ? "" : "s") recorded, \(openReleaseGateTaskCount) open, \(completedReleaseGateTaskCount) completed. \(providerReleaseSnapshotTasks.count) provider snapshot/self-check task\(providerReleaseSnapshotTasks.count == 1 ? "" : "s") recorded, \(openReleaseSnapshotTaskCount) open, \(completedReleaseSnapshotTaskCount) completed.",
        nextAction: openReleaseGateTaskCount + openReleaseSnapshotTaskCount == 0
          ? "Create a provider release gate task or a provider snapshot task before the next hands-on test pass."
          : "Keep release gate and provider snapshot tasks current if setup or refresh evidence changes.",
        isPassed: openReleaseGateTaskCount + openReleaseSnapshotTaskCount > 0,
        tone: openReleaseGateTaskCount + openReleaseSnapshotTaskCount == 0 ? "attention" : "success",
        symbol: "checkmark.seal"
      )
    ]

    let warningCount = gates.filter { !$0.isPassed && $0.tone == "warning" }.count
    let attentionCount = gates.filter { !$0.isPassed && $0.tone == "attention" }.count
    let passedCount = gates.filter(\.isPassed).count

    let title: String
    let detail: String
    let verdict: String
    let tone: String
    if warningCount > 0 {
      title = "Mailbox provider release gate is blocked"
      detail = "\(warningCount) gate\(warningCount == 1 ? "" : "s") must be resolved before treating mailbox provider intake as release-ready."
      verdict = "Blocked"
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Mailbox provider release gate needs review"
      detail = "\(attentionCount) gate\(attentionCount == 1 ? "" : "s") need operator review or explicit acceptance."
      verdict = "Review"
      tone = "attention"
    } else if passedCount == gates.count {
      title = "Mailbox provider release gate is ready"
      detail = "All provider release gates pass from current local evidence."
      verdict = "Ready"
      tone = "success"
    } else {
      title = "Mailbox provider release gate is pending evidence"
      detail = "\(passedCount) of \(gates.count) gates pass; remaining gates need more local evidence."
      verdict = "Pending"
      tone = "neutral"
    }

    let reportLines = [
      title,
      detail,
      "Verdict: \(verdict)",
      "Generated: \(generatedDate)",
      "Provider path: \(comparison.recommendedProvider)",
      "Optional providers not configured: \(optionalProviderText)",
      ""
    ] + gates.map { gate in
      "\(gate.isPassed ? "PASS" : "OPEN") - \(gate.title)\nRequirement: \(gate.requirement)\nEvidence: \(gate.evidence)\nNext: \(gate.nextAction)"
    } + [
      "",
      "Boundaries:",
      "- Local-only release gate computed from JSON-backed app state.",
      "- No mailbox refresh, credential read, external service call, outbound email, notification, or mailbox mutation occurs."
    ]

    return MailboxProviderReleaseGateSummary(
      title: title,
      detail: detail,
      verdict: verdict,
      tone: tone,
      generatedDate: generatedDate,
      reportText: reportLines.joined(separator: "\n\n"),
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Verdict", value: verdict, tone: tone),
        SpaceMailReleaseSnapshotMetric(title: "Passed", value: "\(passedCount)/\(gates.count)", tone: passedCount == gates.count ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Review", value: "\(attentionCount)", tone: attentionCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: fetchedCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Orders", value: "\(linkedOrderCount + inboxCreatedOrderCount)", tone: linkedOrderCount + inboxCreatedOrderCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Checkpoint", value: openReleaseGateTaskCount == 0 ? "Needed" : "Open", tone: openReleaseGateTaskCount == 0 ? "attention" : "success")
      ],
      gates: gates
    )
  }

  var mailboxProviderQACheckSummary: SpaceMailQACheckSummary {
    let hasSpaceMailSetup = !spaceMailIMAPConnections.isEmpty
    let hasGmailSetup = !gmailMailboxConnections.isEmpty
    let hasMicrosoft365Setup = !microsoft365MailboxConnections.isEmpty
    let hasSpaceMailCredential = spaceMailIMAPConnections.contains { connection in
      connection.credentialStorageStatus.localizedCaseInsensitiveContains("available")
        || connection.credentialStorageStatus.localizedCaseInsensitiveContains("ready")
        || connection.credentialStorageStatus.localizedCaseInsensitiveContains("Keychain")
    }
    let hasGmailConnectedAuth = gmailMailboxConnections.contains { gmailAuthSessionState(for: $0).status == .connected }
    let hasMicrosoft365ConnectedAuth = microsoft365MailboxConnections.contains { microsoft365AuthSessionState(for: $0).status == .connected }
    let hasCredentialOrAuth = hasSpaceMailCredential || hasGmailConnectedAuth || hasMicrosoft365ConnectedAuth
    let hasManualRefreshEvidence = spaceMailIMAPConnections.contains { $0.lastManualRefreshDate != "Never" }
      || gmailMailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
      || microsoft365MailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
    let hasDuplicateEvidence = !mailboxIngestRecords.isEmpty
      || spaceMailIMAPConnections.contains { $0.lastRefreshDuplicateCount > 0 }
      || gmailMailboxConnections.contains { $0.lastRefreshDuplicateCount > 0 }
      || microsoft365MailboxConnections.contains { $0.lastRefreshDuplicateCount > 0 }
    let hasSpaceMailMixedFilteringEvidence = spaceMailIMAPConnections.contains { connection in
      connection.mailboxMode == .mixedFiltered
        && (connection.lastRefreshFilteredNonOrderCount > 0
          || !connection.filteredMessages.isEmpty
          || !connection.uncertainMessages.isEmpty
          || !connection.lastRefreshReasonBreakdown.isEmpty)
    }
    let hasGmailMixedFilteringEvidence = gmailMailboxConnections.contains { connection in
      connection.mailboxMode == .mixedFiltered
        && (connection.lastRefreshFilteredNonOrderCount > 0
          || connection.filteredMessages?.isEmpty == false
          || connection.uncertainMessages?.isEmpty == false
          || connection.lastRefreshFilteredExamples?.isEmpty == false
          || connection.lastRefreshUncertainExamples?.isEmpty == false)
    }
    let hasMicrosoft365MixedFilteringEvidence = microsoft365MailboxConnections.contains { connection in
      connection.mailboxMode == .mixedFiltered
        && (connection.lastRefreshFilteredNonOrderCount > 0
          || !connection.filteredMessages.isEmpty
          || !connection.uncertainMessages.isEmpty
          || !connection.lastRefreshFilteredExamples.isEmpty
          || !connection.lastRefreshUncertainExamples.isEmpty)
    }
    let hasMixedFilteringEvidence = hasSpaceMailMixedFilteringEvidence
      || hasGmailMixedFilteringEvidence
      || hasMicrosoft365MixedFilteringEvidence
    let hasReadOnlyAuditEvidence = auditEvents.contains { event in
      let detail = event.afterDetail ?? ""
      return detail.localizedCaseInsensitiveContains("read-only")
        || detail.localizedCaseInsensitiveContains("No mailbox item was deleted")
        || detail.localizedCaseInsensitiveContains("No mailbox items were deleted")
        || detail.localizedCaseInsensitiveContains("No mailbox mutation")
    }
    let hasSecretBoundaryEvidence = auditEvents.contains { event in
      let detail = event.afterDetail ?? ""
      return detail.localizedCaseInsensitiveContains("No password")
        || detail.localizedCaseInsensitiveContains("No token")
        || detail.localizedCaseInsensitiveContains("not stored in JSON")
        || detail.localizedCaseInsensitiveContains("not logged")
    }
    let gmailSetupBlockers = gmailMailboxConnections.filter { !gmailOAuthReadinessSummary(for: $0).isReady }.count
    let microsoft365SetupBlockers = microsoft365MailboxConnections.filter { !microsoft365OAuthReadinessSummary(for: $0).isReady }.count
    let providerSplitClear = hasSpaceMailSetup || hasGmailSetup || hasMicrosoft365Setup
    let importedCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
      + microsoft365MailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let filteredCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
      + microsoft365MailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }

    let providerEvidence: String
    let configuredProviderNames = [
      hasSpaceMailSetup ? "SpaceMail" : nil,
      hasGmailSetup ? "Gmail" : nil,
      hasMicrosoft365Setup ? "Outlook" : nil
    ].compactMap { $0 }
    if configuredProviderNames.count > 1 {
      providerEvidence = "\(configuredProviderNames.joined(separator: ", ")) setup records exist."
    } else if hasSpaceMailSetup {
      providerEvidence = "SpaceMail setup exists for an IMAP-hosted mailbox; Gmail or Outlook can be added for hosted mailbox paths."
    } else if hasGmailSetup {
      providerEvidence = "Gmail setup exists for a Google-hosted mailbox; SpaceMail or Outlook can be added for other mailbox paths."
    } else if hasMicrosoft365Setup {
      providerEvidence = "Outlook setup exists for a Microsoft 365-hosted mailbox; SpaceMail or Gmail can be added for other mailbox paths."
    } else {
      providerEvidence = "No SpaceMail, Gmail, or Outlook provider setup exists."
    }

    let checks = [
      SpaceMailQACheck(
        title: "Provider split is explicit",
        detail: "Operators can see whether SpaceMail, Gmail, Outlook, or a combination is the active mailbox path.",
        evidence: providerEvidence,
        isComplete: providerSplitClear,
        tone: providerSplitClear ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Credential or sign-in boundary",
        detail: "A provider has safe credential/sign-in evidence before real refresh is expected to work.",
        evidence: hasCredentialOrAuth ? "SpaceMail credential, Gmail auth, or Outlook auth evidence exists." : "Set SpaceMail Keychain credential, complete Gmail sign-in, or complete Microsoft sign-in before real refresh.",
        isComplete: hasCredentialOrAuth,
        tone: hasCredentialOrAuth ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Manual refresh only",
        detail: "Refresh evidence comes from explicit operator action, not background sync.",
        evidence: hasManualRefreshEvidence ? "Manual refresh evidence exists for at least one provider." : "Run one manual provider refresh to prove the boundary.",
        isComplete: hasManualRefreshEvidence,
        tone: hasManualRefreshEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Read-only mailbox boundary",
        detail: "Audit evidence should state that mailbox items are not deleted, moved, marked read, sent, or modified.",
        evidence: hasReadOnlyAuditEvidence ? "Read-only/no-mutation audit evidence exists." : "Run a refresh and confirm Audit records the no-mutation boundary.",
        isComplete: hasReadOnlyAuditEvidence,
        tone: hasReadOnlyAuditEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Secrets stay out of JSON and Audit",
        detail: "Audit evidence should state that passwords, tokens, auth strings, and secret values are not logged or persisted.",
        evidence: hasSecretBoundaryEvidence ? "Secret-boundary audit evidence exists." : "Run credential/sign-in/refresh checks and confirm safe secret-boundary copy appears.",
        isComplete: hasSecretBoundaryEvidence,
        tone: hasSecretBoundaryEvidence ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Duplicate-safe intake",
        detail: "Provider message IDs should prevent duplicate Inbox rows while preserving local refresh metadata.",
        evidence: hasDuplicateEvidence ? "\(mailboxIngestRecords.count) ingest record\(mailboxIngestRecords.count == 1 ? "" : "s") or duplicate refresh evidence exists." : "Run refresh twice against the same mailbox to prove duplicate handling.",
        isComplete: hasDuplicateEvidence,
        tone: hasDuplicateEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Mixed mailbox filtering",
        detail: "Mixed mailboxes should keep non-order messages out of Inbox and surface uncertain messages separately.",
        evidence: hasMixedFilteringEvidence ? "\(filteredCount) filtered and \(importedCount) imported message\(filteredCount + importedCount == 1 ? "" : "s") recorded across providers." : "Run refresh/classifier checks until filtered or uncertain evidence is visible.",
        isComplete: hasMixedFilteringEvidence,
        tone: hasMixedFilteringEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Hosted OAuth blockers visible",
        detail: "If Gmail or Outlook is configured, OAuth/readiness blockers should be visible before relying on hosted-provider refresh.",
        evidence: !hasGmailSetup && !hasMicrosoft365Setup ? "Gmail and Outlook are not configured, so no hosted OAuth blockers apply." : "\(gmailSetupBlockers) Gmail and \(microsoft365SetupBlockers) Outlook readiness blocker\(gmailSetupBlockers + microsoft365SetupBlockers == 1 ? "" : "s") currently visible.",
        isComplete: (!hasGmailSetup || gmailSetupBlockers == 0) && (!hasMicrosoft365Setup || microsoft365SetupBlockers == 0),
        tone: (!hasGmailSetup || gmailSetupBlockers == 0) && (!hasMicrosoft365Setup || microsoft365SetupBlockers == 0) ? "success" : "warning"
      )
    ]

    let completedCount = checks.filter(\.isComplete).count
    let verdict: String
    let tone: String
    if completedCount == checks.count {
      verdict = "Mailbox provider QA boundaries complete"
      tone = "success"
    } else if completedCount >= 6 {
      verdict = "Mailbox provider QA boundaries mostly ready"
      tone = "attention"
    } else {
      verdict = "Mailbox provider QA boundaries need review"
      tone = "warning"
    }

    return SpaceMailQACheckSummary(
      verdict: verdict,
      detail: "\(completedCount) of \(checks.count) provider boundary checks are complete for mailbox intake.",
      completedCount: completedCount,
      totalCount: checks.count,
      tone: tone,
      checks: checks
    )
  }

  var mailboxIntakeQualitySummary: SpaceMailQACheckSummary {
    let totalIntakeCount = intakeEmails.count
    let openReviewCount = intakeEmails.filter { $0.reviewState == .needsReview }.count
    let reviewedCount = intakeEmails.filter { $0.reviewState == .reviewed }.count
    let ignoredCount = intakeEmails.filter { $0.reviewState == .ignored }.count
    let linkedOrderCount = intakeEmails.filter { $0.linkedOrderID != nil }.count
    let parserIssueCount = intakeParserDiagnostics.count
    let criticalParserIssueCount = intakeParserDiagnostics.filter { $0.severity == .critical || $0.severity == .high }.count
    let regressionResults = intakeParserRegressionResults
    let regressionPassedCount = regressionResults.filter(\.passed).count
    let regressionFailureCount = regressionResults.count - regressionPassedCount
    let intakeIDsWithSourceTrace = Set(mailboxIngestRecords.compactMap(\.intakeEmailID))
    let tracedIntakeCount = intakeEmails.filter { intakeIDsWithSourceTrace.contains($0.id) }.count
    let rowsWithOrderOrTracking = intakeEmails.filter { email in
      !email.detectedOrderNumber.isPlaceholderValidationValue
        || !email.detectedTrackingNumber.isPlaceholderValidationValue
    }.count
    let rowsWithOrderAndTracking = intakeEmails.filter { email in
      !email.detectedOrderNumber.isPlaceholderValidationValue
        && !email.detectedTrackingNumber.isPlaceholderValidationValue
    }.count
    let rowsWithDestination = intakeEmails.filter { !$0.detectedDestinationAddress.isPlaceholderValidationValue }.count
    let actionableIntakeCount = intakeEmails.filter { email in
      email.reviewState == .needsReview
        && (
          !email.detectedOrderNumber.isPlaceholderValidationValue
            || !email.detectedTrackingNumber.isPlaceholderValidationValue
            || !email.detectedDestinationAddress.isPlaceholderValidationValue
        )
    }.count
    let duplicateTraceCount = mailboxIngestRecords.count
    let allOpenRowsHaveSignals = openReviewCount == 0 || actionableIntakeCount > 0
    let reviewQueueControlled = openReviewCount <= max(3, totalIntakeCount / 2)
    let parserIssuesControlled = criticalParserIssueCount == 0

    let checks = [
      SpaceMailQACheck(
        title: "Intake rows exist",
        detail: "Mailbox imports should create local ForwardedEmailIntake rows before the operator workflow can be judged.",
        evidence: totalIntakeCount > 0 ? "\(totalIntakeCount) intake row\(totalIntakeCount == 1 ? "" : "s") captured." : "No intake rows are captured yet.",
        isComplete: totalIntakeCount > 0,
        tone: totalIntakeCount > 0 ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Provider source trace",
        detail: "Imported rows should retain local ingest metadata so duplicate refreshes can update or skip safely.",
        evidence: tracedIntakeCount > 0 ? "\(tracedIntakeCount) intake row\(tracedIntakeCount == 1 ? "" : "s") linked to provider ingest metadata." : "No intake rows have provider ingest trace yet.",
        isComplete: tracedIntakeCount > 0,
        tone: tracedIntakeCount > 0 ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Order or tracking signals",
        detail: "At least some intake rows should expose detected order or tracking fields before create-order handoff.",
        evidence: rowsWithOrderOrTracking > 0 ? "\(rowsWithOrderOrTracking) row\(rowsWithOrderOrTracking == 1 ? "" : "s") include order or tracking signals; \(rowsWithOrderAndTracking) include both." : "No intake rows currently expose an order or tracking signal.",
        isComplete: rowsWithOrderOrTracking > 0,
        tone: rowsWithOrderOrTracking > 0 ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Destination signal",
        detail: "Destination extraction is not always required, but visible destination evidence makes handoff safer.",
        evidence: rowsWithDestination > 0 ? "\(rowsWithDestination) row\(rowsWithDestination == 1 ? "" : "s") include destination signal." : "No destination signal is detected in current intake rows.",
        isComplete: rowsWithDestination > 0,
        tone: rowsWithDestination > 0 ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Open rows are actionable",
        detail: "Rows needing review should contain at least one useful local signal, not only generic or empty mailbox text.",
        evidence: allOpenRowsHaveSignals ? "\(actionableIntakeCount) open row\(actionableIntakeCount == 1 ? "" : "s") contain detected order, tracking, or destination context." : "\(openReviewCount) open row\(openReviewCount == 1 ? "" : "s") need review but no actionable signal was detected.",
        isComplete: allOpenRowsHaveSignals,
        tone: allOpenRowsHaveSignals ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Review state controlled",
        detail: "The primary Inbox should not be overwhelmed by old unresolved intake rows.",
        evidence: "\(openReviewCount) needs review, \(reviewedCount) reviewed, \(ignoredCount) ignored.",
        isComplete: reviewQueueControlled,
        tone: reviewQueueControlled ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Inbox-to-order linkage",
        detail: "At least one intake row should link to a local order before calling the intake workflow ready.",
        evidence: linkedOrderCount > 0 ? "\(linkedOrderCount) intake row\(linkedOrderCount == 1 ? "" : "s") linked to local orders." : "No intake row is linked to an order yet.",
        isComplete: linkedOrderCount > 0,
        tone: linkedOrderCount > 0 ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Parser regression samples",
        detail: "Fixed local samples should prove the parser can extract order and tracking values before mailbox provider changes are trusted.",
        evidence: regressionFailureCount == 0 ? "\(regressionPassedCount) of \(regressionResults.count) parser regression samples pass." : "\(regressionFailureCount) parser regression sample\(regressionFailureCount == 1 ? "" : "s") need review.",
        isComplete: regressionFailureCount == 0,
        tone: regressionFailureCount == 0 ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Parser diagnostics controlled",
        detail: "High-severity parser diagnostics should be handled before relying on automated order/tracking extraction.",
        evidence: "\(parserIssueCount) parser diagnostic\(parserIssueCount == 1 ? "" : "s"); \(criticalParserIssueCount) high priority.",
        isComplete: parserIssuesControlled,
        tone: parserIssuesControlled ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Duplicate metadata retained",
        detail: "Provider message IDs should remain available so repeated refreshes do not create duplicate Inbox work.",
        evidence: duplicateTraceCount > 0 ? "\(duplicateTraceCount) ingest metadata record\(duplicateTraceCount == 1 ? "" : "s") retained." : "No ingest metadata is retained yet.",
        isComplete: duplicateTraceCount > 0,
        tone: duplicateTraceCount > 0 ? "success" : "attention"
      )
    ]

    let completedCount = checks.filter(\.isComplete).count
    let verdict: String
    let tone: String
    if completedCount == checks.count {
      verdict = "Mailbox intake quality is ready"
      tone = "success"
    } else if completedCount >= 6 {
      verdict = "Mailbox intake quality is usable with review"
      tone = "attention"
    } else {
      verdict = "Mailbox intake quality needs attention"
      tone = "warning"
    }

    return SpaceMailQACheckSummary(
      verdict: verdict,
      detail: "\(completedCount) of \(checks.count) intake quality checks are complete across captured mailbox rows.",
      completedCount: completedCount,
      totalCount: checks.count,
      tone: tone,
      checks: checks
    )
  }

  var spaceMailRefreshTrendSummary: SpaceMailRefreshTrendSummary {
    let historyPairs = spaceMailIMAPConnections.flatMap { connection in
      connection.refreshHistory.map { entry in
        (connection.displayName, entry)
      }
    }
    let recentPairs = Array(historyPairs.prefix(12))
    let fetchedCount = recentPairs.reduce(0) { $0 + $1.1.fetchedCount }
    let importedCount = recentPairs.reduce(0) { $0 + $1.1.importedCount }
    let duplicateCount = recentPairs.reduce(0) { $0 + $1.1.duplicateCount }
    let filteredCount = recentPairs.reduce(0) { $0 + $1.1.filteredNonOrderCount }
    let uncertainCount = recentPairs.reduce(0) { $0 + $1.1.uncertainCount }
    let successCount = recentPairs.filter { pair in
      pair.1.status.localizedCaseInsensitiveContains("success")
        || pair.1.status.localizedCaseInsensitiveContains("completed")
        || pair.1.status.localizedCaseInsensitiveContains("duplicate")
    }.count
    let actionableCount = importedCount + uncertainCount

    let title: String
    let detail: String
    let tone: String
    if spaceMailIMAPConnections.isEmpty {
      title = "No SpaceMail refresh trend yet"
      detail = "Add a SpaceMail setup before trend evidence can appear."
      tone = "warning"
    } else if recentPairs.isEmpty {
      title = "SpaceMail refresh trend pending"
      detail = "Run manual refreshes to build a local trend across imports, duplicates, filtered messages, and uncertain reviews."
      tone = "attention"
    } else if actionableCount > 0 {
      title = "SpaceMail refresh trend has actionable intake"
      detail = "\(recentPairs.count) recent refresh event\(recentPairs.count == 1 ? "" : "s") include \(importedCount) import\(importedCount == 1 ? "" : "s") and \(uncertainCount) uncertain preview\(uncertainCount == 1 ? "" : "s")."
      tone = "attention"
    } else if filteredCount > 0 && importedCount == 0 {
      title = "SpaceMail filter trend is stable"
      detail = "\(recentPairs.count) recent refresh event\(recentPairs.count == 1 ? "" : "s") mostly filtered non-order mail from the mixed mailbox."
      tone = "success"
    } else {
      title = "SpaceMail refresh trend is quiet"
      detail = "\(recentPairs.count) recent refresh event\(recentPairs.count == 1 ? "" : "s") found no current Inbox intake."
      tone = "neutral"
    }

    let entries = recentPairs.prefix(6).map { pair in
      SpaceMailRefreshTrendEntry(
        id: pair.1.id,
        timestamp: pair.1.timestamp,
        displayName: pair.0,
        status: pair.1.status,
        detail: "\(pair.1.fetchedCount) fetched, \(pair.1.importedCount) imported, \(pair.1.duplicateCount) duplicates, \(pair.1.filteredNonOrderCount) filtered, \(pair.1.uncertainCount) uncertain.",
        tone: pair.1.importedCount > 0 || pair.1.uncertainCount > 0 ? "attention" : (pair.1.filteredNonOrderCount > 0 ? "success" : "neutral")
      )
    }

    return SpaceMailRefreshTrendSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Runs", value: "\(recentPairs.count)", tone: recentPairs.isEmpty ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Successful", value: "\(successCount)", tone: successCount == recentPairs.count && !recentPairs.isEmpty ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Duplicates", value: "\(duplicateCount)", tone: duplicateCount > 0 ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount > 0 ? "attention" : "success")
      ],
      entries: entries
    )
  }

  var spaceMailShiftHandoffSummary: SpaceMailShiftHandoffSummary {
    let spaceMailMailboxIDs = Set(spaceMailIMAPConnections.map(\.id))
    let spaceMailIngestRecords = mailboxIngestRecords.filter { spaceMailMailboxIDs.contains($0.sourceMailboxID) }
    let linkedIntakeIDs = Set(spaceMailIngestRecords.compactMap(\.intakeEmailID))
    let linkedSpaceMailIntake = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }
    let reviewSpaceMailIntake = linkedSpaceMailIntake.filter { $0.reviewState == .needsReview }
    let linkedOrders = orders.filter { order in
      linkedSpaceMailIntake.contains { $0.linkedOrderID == order.id } || order.source == .forwardedMailbox || order.checkedMailbox == "manual-import"
    }
    let parserDiagnostics = intakeParserDiagnostics.filter { linkedIntakeIDs.contains($0.intakeEmailID) }
    let uncertainCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.uncertainMessages.count }
    let filteredCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.filteredMessages.count }
    let fetchedCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let importedCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let duplicateCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshDuplicateCount }
    let filteredLastRefreshCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let uncertainLastRefreshCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshUncertainCount }
    let latestRefresh = spaceMailIMAPConnections
      .filter { $0.lastManualRefreshDate != "Never" }
      .sorted { $0.lastManualRefreshDate > $1.lastManualRefreshDate }
      .first
    let lastRefreshText = latestRefresh.map {
      "\($0.displayName) refreshed \($0.lastManualRefreshDate): \($0.lastRefreshSummary.isEmpty ? $0.connectionStatus : $0.lastRefreshSummary)"
    } ?? "No real SpaceMail refresh has been recorded."

    let lines = [
      SpaceMailShiftHandoffLine(
        title: "Latest refresh",
        detail: "\(fetchedCount) fetched, \(importedCount) imported, \(duplicateCount) duplicates, \(filteredLastRefreshCount) filtered, \(uncertainLastRefreshCount) uncertain.",
        tone: fetchedCount == 0 ? "attention" : "neutral",
        symbol: "clock.arrow.circlepath"
      ),
      SpaceMailShiftHandoffLine(
        title: "Inbox review",
        detail: reviewSpaceMailIntake.isEmpty
          ? "No SpaceMail-linked intake rows currently need review."
          : "\(reviewSpaceMailIntake.count) SpaceMail-linked intake row\(reviewSpaceMailIntake.count == 1 ? "" : "s") need review.",
        tone: reviewSpaceMailIntake.isEmpty ? "success" : "attention",
        symbol: "tray.full.fill"
      ),
      SpaceMailShiftHandoffLine(
        title: "Parser checks",
        detail: parserDiagnostics.isEmpty
          ? "No SpaceMail-linked parser diagnostics are open."
          : "\(parserDiagnostics.count) parser diagnostic\(parserDiagnostics.count == 1 ? "" : "s") need field confirmation.",
        tone: parserDiagnostics.isEmpty ? "success" : "warning",
        symbol: "text.magnifyingglass"
      ),
      SpaceMailShiftHandoffLine(
        title: "Mixed mailbox review",
        detail: uncertainCount == 0 && filteredCount == 0
          ? "No uncertain or filtered preview reviews are waiting."
          : "\(uncertainCount) uncertain and \(filteredCount) filtered preview\(uncertainCount + filteredCount == 1 ? "" : "s") are available for spot review.",
        tone: uncertainCount > 0 ? "attention" : "neutral",
        symbol: "questionmark.folder.fill"
      ),
      SpaceMailShiftHandoffLine(
        title: "Order handoff",
        detail: linkedOrders.isEmpty
          ? "No SpaceMail/InBox-created orders are currently linked for follow-up."
          : "\(linkedOrders.count) Inbox-created or SpaceMail-linked order\(linkedOrders.count == 1 ? "" : "s") exist for follow-up.",
        tone: linkedOrders.isEmpty ? "neutral" : "attention",
        symbol: "shippingbox.fill"
      )
    ]

    let openLineCount = lines.filter { $0.tone == "warning" || $0.tone == "attention" }.count
    let title: String
    let detail: String
    let tone: String
    if spaceMailIMAPConnections.isEmpty {
      title = "SpaceMail handoff unavailable"
      detail = "Add a SpaceMail setup before using the handoff summary."
      tone = "warning"
    } else if openLineCount == 0 {
      title = "SpaceMail handoff is clear"
      detail = "No immediate SpaceMail intake follow-up is open."
      tone = "success"
    } else {
      title = "SpaceMail handoff needs attention"
      detail = "\(openLineCount) handoff area\(openLineCount == 1 ? "" : "s") should be checked before the next shift."
      tone = lines.contains { $0.tone == "warning" } ? "warning" : "attention"
    }

    return SpaceMailShiftHandoffSummary(
      title: title,
      detail: detail,
      tone: tone,
      lastRefreshText: lastRefreshText,
      keyCounts: [
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Inbox review", value: "\(reviewSpaceMailIntake.count)", tone: reviewSpaceMailIntake.isEmpty ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Parser", value: "\(parserDiagnostics.count)", tone: parserDiagnostics.isEmpty ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount == 0 ? "neutral" : "attention")
      ],
      handoffLines: lines
    )
  }

  var spaceMailPostRefreshActionPlan: SpaceMailPostRefreshActionPlan {
    let spaceMailMailboxIDs = Set(spaceMailIMAPConnections.map(\.id))
    let spaceMailIngestRecords = mailboxIngestRecords.filter { spaceMailMailboxIDs.contains($0.sourceMailboxID) }
    let linkedIntakeIDs = Set(spaceMailIngestRecords.compactMap(\.intakeEmailID))
    let linkedSpaceMailIntake = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }
    let reviewSpaceMailIntake = linkedSpaceMailIntake.filter { $0.reviewState == .needsReview }
    let parserDiagnostics = intakeParserDiagnostics.filter { linkedIntakeIDs.contains($0.intakeEmailID) }
    let readyForOrder = reviewSpaceMailIntake.filter { email in
      email.linkedOrderID == nil
        && (!email.detectedOrderNumber.isPlaceholderValidationValue || !email.detectedTrackingNumber.isPlaceholderValidationValue)
    }
    let uncertainCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.uncertainMessages.count }
    let filteredReviewCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.filteredMessages.count }
    let latestFetchedCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let latestImportedCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let latestFilteredCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let latestUncertainCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshUncertainCount }

    let items = [
      SpaceMailPostRefreshActionItem(
        title: "Review imported Inbox rows",
        count: reviewSpaceMailIntake.count,
        detail: reviewSpaceMailIntake.isEmpty
          ? "No SpaceMail intake rows currently need primary Inbox review."
          : "Confirm merchant, order, tracking, and destination before creating or linking orders.",
        actionLabel: reviewSpaceMailIntake.isEmpty ? "No Inbox review needed" : "Open detected order emails",
        tone: reviewSpaceMailIntake.isEmpty ? "success" : "attention",
        symbol: "tray.full.fill"
      ),
      SpaceMailPostRefreshActionItem(
        title: "Fix parser diagnostics",
        count: parserDiagnostics.count,
        detail: parserDiagnostics.isEmpty
          ? "No SpaceMail-linked parser diagnostics are currently blocking the flow."
          : "Reprocess or edit rows where order, tracking, sender, or destination is weak.",
        actionLabel: parserDiagnostics.isEmpty ? "Parser clear" : "Use parser review queue",
        tone: parserDiagnostics.isEmpty ? "success" : "warning",
        symbol: "text.magnifyingglass"
      ),
      SpaceMailPostRefreshActionItem(
        title: "Create or link orders",
        count: readyForOrder.count,
        detail: readyForOrder.isEmpty
          ? "No SpaceMail intake rows look ready for a new linked order right now."
          : "Rows with usable order or tracking details still need an order handoff.",
        actionLabel: readyForOrder.isEmpty ? "No order handoff waiting" : "Create or link orders",
        tone: readyForOrder.isEmpty ? "success" : "attention",
        symbol: "shippingbox.fill"
      ),
      SpaceMailPostRefreshActionItem(
        title: "Review uncertain messages",
        count: uncertainCount,
        detail: uncertainCount == 0
          ? "No ambiguous SpaceMail messages are waiting outside Inbox."
          : "Import true order mail or dismiss/filter messages that should stay out of Inbox.",
        actionLabel: uncertainCount == 0 ? "No uncertain review" : "Review uncertain previews",
        tone: uncertainCount == 0 ? "success" : "attention",
        symbol: "questionmark.folder.fill"
      ),
      SpaceMailPostRefreshActionItem(
        title: "Check filtered examples",
        count: filteredReviewCount,
        detail: filteredReviewCount == 0
          ? "No filtered examples are waiting for manual review."
          : "Spot-check filtered previews if a real order email appears to be missing.",
        actionLabel: filteredReviewCount == 0 ? "No filtered review queued" : "Spot-check filtered previews",
        tone: filteredReviewCount == 0 ? "success" : "neutral",
        symbol: "line.3.horizontal.decrease.circle.fill"
      )
    ]

    let blockingItems = items.filter { $0.tone == "warning" || $0.tone == "attention" }
    let title: String
    let detail: String
    let primaryAction: String
    let tone: String
    if spaceMailIMAPConnections.isEmpty {
      title = "SpaceMail post-refresh actions unavailable"
      detail = "Add a SpaceMail setup before using the refresh workflow."
      primaryAction = "Add SpaceMail placeholder"
      tone = "warning"
    } else if latestFetchedCount == 0 && !spaceMailIMAPConnections.contains(where: { $0.lastManualRefreshDate != "Never" }) {
      title = "SpaceMail ready for first manual refresh"
      detail = "No real refresh evidence is recorded yet. Set or check the credential, then run real refresh."
      primaryAction = "Run real SpaceMail refresh"
      tone = "attention"
    } else if blockingItems.isEmpty {
      title = "SpaceMail post-refresh queue is clear"
      detail = "Latest refresh: \(latestFetchedCount) fetched, \(latestImportedCount) imported, \(latestFilteredCount) filtered, \(latestUncertainCount) uncertain."
      primaryAction = "Wait for new order mail or run another manual refresh"
      tone = "success"
    } else {
      title = "SpaceMail post-refresh actions need review"
      detail = "Latest refresh: \(latestFetchedCount) fetched, \(latestImportedCount) imported, \(latestFilteredCount) filtered, \(latestUncertainCount) uncertain."
      primaryAction = blockingItems.first?.actionLabel ?? "Review Mailbox Monitor"
      tone = blockingItems.contains(where: { $0.tone == "warning" }) ? "warning" : "attention"
    }

    return SpaceMailPostRefreshActionPlan(
      title: title,
      detail: detail,
      tone: tone,
      primaryAction: primaryAction,
      items: items
    )
  }

  private func gmailDomain(for emailAddress: String) -> String {
    let parts = emailAddress
      .trimmingCharacters(in: .whitespacesAndNewlines)
      .split(separator: "@", maxSplits: 1)
    guard parts.count == 2 else { return "" }
    return String(parts[1]).lowercased()
  }

  private func gmailProviderFit(for connection: GmailMailboxConnection) -> (
    domain: String,
    isConsumer: Bool,
    isSample: Bool,
    isCustomDomain: Bool,
    hasGoogleEvidence: Bool,
    isReady: Bool,
    detail: String,
    nextAction: String,
    tone: String
  ) {
    let domain = gmailDomain(for: connection.emailAddress)
    let isConsumer = domain == "gmail.com" || domain == "googlemail.com"
    let isSample = domain.hasSuffix(".example")
    let isCustomDomain = !domain.isEmpty && !isConsumer && !isSample
    let hasManualHostVerification = connection.providerHostVerificationStatus.localizedCaseInsensitiveContains("verified")
    let hasGoogleEvidence = gmailAuthSessionState(for: connection).status == .connected ||
      connection.lastRefreshFetchedCount > 0 ||
      connection.lastRefreshImportedCount > 0 ||
      connection.lastRefreshDuplicateCount > 0 ||
      connection.lastRefreshFilteredNonOrderCount > 0 ||
      (connection.lastRefreshUncertainCount ?? 0) > 0 ||
      connection.connectionStatus.localizedCaseInsensitiveContains("No messages") ||
      connection.connectionStatus.localizedCaseInsensitiveContains("Real Gmail")
    let isReady = isConsumer || (isCustomDomain && (hasGoogleEvidence || hasManualHostVerification))
    let detail: String
    let nextAction: String
    if isCustomDomain {
      detail = isReady
        ? (hasGoogleEvidence
            ? "Saved mailbox uses custom domain \(domain), with Google sign-in or Gmail refresh evidence recorded locally."
            : "Saved mailbox uses custom domain \(domain), with local operator host verification recorded.")
        : "Saved mailbox uses custom domain \(domain). Confirm it is hosted by Google Workspace before using Gmail API refresh."
      nextAction = isReady
        ? "Continue Gmail setup checks; use SpaceMail/IMAP only if this mailbox is not Google-hosted."
        : "Verify the mailbox is Google Workspace hosted; otherwise use SpaceMail/IMAP setup."
    } else if isConsumer {
      detail = "Saved mailbox uses consumer Gmail domain \(domain)."
      nextAction = "Continue Gmail setup checks."
    } else if isSample {
      detail = "Saved mailbox is sample data and should be replaced before real Gmail testing."
      nextAction = "Replace sample mailbox address with the real Gmail/Google Workspace address."
    } else {
      detail = "No valid Gmail mailbox domain is saved yet."
      nextAction = "Replace missing mailbox address with the real Gmail/Google Workspace address."
    }
    return (
      domain,
      isConsumer,
      isSample,
      isCustomDomain,
      hasGoogleEvidence || hasManualHostVerification,
      isReady,
      detail,
      nextAction,
      isReady ? (isCustomDomain ? "attention" : "success") : "warning"
    )
  }

  var gmailPostRefreshActionPlan: GmailPostRefreshActionPlan {
    let gmailMailboxIDs = Set(gmailMailboxConnections.map(\.id))
    let gmailIngestRecords = mailboxIngestRecords.filter { gmailMailboxIDs.contains($0.sourceMailboxID) }
    let linkedIntakeIDs = Set(gmailIngestRecords.compactMap(\.intakeEmailID))
    let linkedGmailIntake = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }
    let reviewGmailIntake = linkedGmailIntake.filter { $0.reviewState == .needsReview }
    let parserDiagnostics = intakeParserDiagnostics.filter { linkedIntakeIDs.contains($0.intakeEmailID) }
    let readyForOrder = reviewGmailIntake.filter { email in
      email.linkedOrderID == nil
        && (!email.detectedOrderNumber.isPlaceholderValidationValue || !email.detectedTrackingNumber.isPlaceholderValidationValue)
    }
    let uncertainCount = gmailMailboxConnections.reduce(0) { $0 + ($1.uncertainMessages?.count ?? 0) }
    let filteredReviewCount = gmailMailboxConnections.reduce(0) { $0 + ($1.filteredMessages?.count ?? 0) }
    let latestFetchedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let latestImportedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let latestFilteredCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let latestUncertainCount = gmailMailboxConnections.reduce(0) { $0 + ($1.lastRefreshUncertainCount ?? 0) }
    let readinessSummaries = gmailMailboxConnections.map(gmailOAuthReadinessSummary(for:))
    let setupBlockers = readinessSummaries.filter { !$0.isReady }
    let connectedAuthCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let setupIssueCount = setupBlockers.count
    let firstSetupBlocker = setupBlockers.first
    let setupBlockerPreview = firstSetupBlocker?.missingFields.prefix(3).joined(separator: ", ")
    let customDomainConnectionsNeedingVerification = gmailMailboxConnections.filter {
      let providerFit = gmailProviderFit(for: $0)
      return providerFit.isCustomDomain && !providerFit.hasGoogleEvidence
    }

    let items = [
      GmailPostRefreshActionItem(
        title: "Finish setup and sign-in",
        count: setupIssueCount + max(0, gmailMailboxConnections.count - connectedAuthCount),
        detail: setupIssueCount == 0 && connectedAuthCount > 0
          ? "Gmail setup values, compiled app callback configuration, and sign-in state are ready for manual refresh."
          : "Resolve Gmail setup blockers before real refresh: \(setupBlockerPreview ?? "complete Google sign-in").",
        actionLabel: setupIssueCount == 0 && connectedAuthCount > 0 ? "Setup ready" : "Review Gmail setup",
        tone: setupIssueCount == 0 && connectedAuthCount > 0 ? "success" : "warning",
        symbol: "person.badge.key.fill"
      ),
      GmailPostRefreshActionItem(
        title: "Confirm Gmail-hosted mailbox",
        count: customDomainConnectionsNeedingVerification.count,
        detail: customDomainConnectionsNeedingVerification.isEmpty
          ? "Gmail setup records are consumer Gmail, sample data, or custom-domain records with local Google sign-in/refresh evidence."
          : "Custom-domain Gmail records need Google-hosted evidence before using Gmail API refresh. Use IMAP/SpaceMail if the mailbox is hosted elsewhere.",
        actionLabel: customDomainConnectionsNeedingVerification.isEmpty ? "Provider fit clear" : "Verify Google Workspace hosting",
        tone: customDomainConnectionsNeedingVerification.isEmpty ? "success" : "attention",
        symbol: "server.rack"
      ),
      GmailPostRefreshActionItem(
        title: "Review imported Inbox rows",
        count: reviewGmailIntake.count,
        detail: reviewGmailIntake.isEmpty
          ? "No Gmail intake rows currently need primary Inbox review."
          : "Confirm merchant, order, tracking, and destination before creating or linking orders.",
        actionLabel: reviewGmailIntake.isEmpty ? "No Inbox review needed" : "Open detected order emails",
        tone: reviewGmailIntake.isEmpty ? "success" : "attention",
        symbol: "tray.full.fill"
      ),
      GmailPostRefreshActionItem(
        title: "Fix parser diagnostics",
        count: parserDiagnostics.count,
        detail: parserDiagnostics.isEmpty
          ? "No Gmail-linked parser diagnostics are currently blocking the flow."
          : "Reprocess or edit Gmail intake rows where order, tracking, sender, or destination is weak.",
        actionLabel: parserDiagnostics.isEmpty ? "Parser clear" : "Use parser review queue",
        tone: parserDiagnostics.isEmpty ? "success" : "warning",
        symbol: "text.magnifyingglass"
      ),
      GmailPostRefreshActionItem(
        title: "Create or link orders",
        count: readyForOrder.count,
        detail: readyForOrder.isEmpty
          ? "No Gmail intake rows look ready for a new linked order right now."
          : "Rows with usable order or tracking details still need an order handoff.",
        actionLabel: readyForOrder.isEmpty ? "No order handoff waiting" : "Create or link orders",
        tone: readyForOrder.isEmpty ? "success" : "attention",
        symbol: "shippingbox.fill"
      ),
      GmailPostRefreshActionItem(
        title: "Review uncertain messages",
        count: uncertainCount,
        detail: uncertainCount == 0
          ? "No ambiguous Gmail messages are waiting outside Inbox."
          : "Import true order mail or dismiss messages that should stay out of Inbox.",
        actionLabel: uncertainCount == 0 ? "No uncertain review" : "Review uncertain previews",
        tone: uncertainCount == 0 ? "success" : "attention",
        symbol: "questionmark.folder.fill"
      ),
      GmailPostRefreshActionItem(
        title: "Check filtered examples",
        count: filteredReviewCount,
        detail: filteredReviewCount == 0
          ? "No filtered Gmail examples are waiting for manual review."
          : "Spot-check filtered previews if a real order email appears to be missing.",
        actionLabel: filteredReviewCount == 0 ? "No filtered review queued" : "Spot-check filtered previews",
        tone: filteredReviewCount == 0 ? "success" : "neutral",
        symbol: "line.3.horizontal.decrease.circle.fill"
      )
    ]

    let blockingItems = items.filter { $0.tone == "warning" || $0.tone == "attention" }
    let title: String
    let detail: String
    let primaryAction: String
    let tone: String
    if gmailMailboxConnections.isEmpty {
      title = "Gmail post-refresh actions unavailable"
      detail = "Add a Gmail setup only when a mailbox is hosted by Gmail or Google Workspace."
      primaryAction = "Add Gmail setup"
      tone = "neutral"
    } else if let firstSetupBlocker {
      title = "Gmail setup blockers need review"
      detail = "\(firstSetupBlocker.statusText). \(firstSetupBlocker.compiledClientIDStatus). \(firstSetupBlocker.compiledCallbackSchemeStatus)."
      primaryAction = "Review Gmail setup"
      tone = "warning"
    } else if latestFetchedCount == 0 && !gmailMailboxConnections.contains(where: { $0.lastManualRefreshDate != "Never" }) {
      title = "Gmail ready for setup checks"
      detail = "No real refresh evidence is recorded yet. Finish setup, test Google sign-in, then run manual read-only refresh."
      primaryAction = blockingItems.first?.actionLabel ?? "Run real Gmail refresh"
      tone = "attention"
    } else if blockingItems.isEmpty {
      title = "Gmail post-refresh queue is clear"
      detail = "Latest refresh: \(latestFetchedCount) fetched, \(latestImportedCount) imported, \(latestFilteredCount) filtered, \(latestUncertainCount) uncertain."
      primaryAction = "Wait for new order mail or run another manual refresh"
      tone = "success"
    } else {
      title = "Gmail post-refresh actions need review"
      detail = "Latest refresh: \(latestFetchedCount) fetched, \(latestImportedCount) imported, \(latestFilteredCount) filtered, \(latestUncertainCount) uncertain."
      primaryAction = blockingItems.first?.actionLabel ?? "Review Mailbox Monitor"
      tone = blockingItems.contains(where: { $0.tone == "warning" }) ? "warning" : "attention"
    }

    return GmailPostRefreshActionPlan(
      title: title,
      detail: detail,
      tone: tone,
      primaryAction: primaryAction,
      items: items
    )
  }

  var gmailShiftHandoffSummary: GmailShiftHandoffSummary {
    let gmailMailboxIDs = Set(gmailMailboxConnections.map(\.id))
    let gmailIngestRecords = mailboxIngestRecords.filter { gmailMailboxIDs.contains($0.sourceMailboxID) }
    let linkedIntakeIDs = Set(gmailIngestRecords.compactMap(\.intakeEmailID))
    let linkedGmailIntake = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }
    let reviewGmailIntake = linkedGmailIntake.filter { $0.reviewState == .needsReview }
    let parserDiagnostics = intakeParserDiagnostics.filter { linkedIntakeIDs.contains($0.intakeEmailID) }
    let uncertainCount = gmailMailboxConnections.reduce(0) { $0 + ($1.uncertainMessages?.count ?? 0) }
    let filteredCount = gmailMailboxConnections.reduce(0) { $0 + ($1.filteredMessages?.count ?? 0) }
    let fetchedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let importedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let duplicateCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshDuplicateCount }
    let filteredLastRefreshCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let uncertainLastRefreshCount = gmailMailboxConnections.reduce(0) { $0 + ($1.lastRefreshUncertainCount ?? 0) }
    let readinessBlockers = gmailMailboxConnections.filter { !gmailOAuthReadinessSummary(for: $0).isReady }.count
    let signedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let providerFits = gmailMailboxConnections.map(gmailProviderFit(for:))
    let hostVerificationNeededCount = providerFits.filter { $0.isCustomDomain && !$0.hasGoogleEvidence }.count
    let hostVerifiedCount = providerFits.filter { $0.isCustomDomain && $0.hasGoogleEvidence }.count
    let latestRefresh = gmailMailboxConnections
      .filter { $0.lastManualRefreshDate != "Never" }
      .sorted { $0.lastManualRefreshDate > $1.lastManualRefreshDate }
      .first
    let lastRefreshText = latestRefresh.map {
      "\($0.displayName) refreshed \($0.lastManualRefreshDate): \($0.lastRefreshSummary.isEmpty ? $0.connectionStatus : $0.lastRefreshSummary)"
    } ?? "No real Gmail refresh has been recorded."

    let lines = [
      GmailShiftHandoffLine(
        title: "Setup readiness",
        detail: readinessBlockers == 0
          ? "Gmail setup fields and compiled callback checks are clear."
          : "\(readinessBlockers) Gmail setup\(readinessBlockers == 1 ? "" : "s") still have OAuth, callback, scope, or compiled app blockers.",
        tone: readinessBlockers == 0 ? "success" : "warning",
        symbol: "person.badge.key.fill"
      ),
      GmailShiftHandoffLine(
        title: "Provider host fit",
        detail: hostVerificationNeededCount == 0
          ? "No custom-domain Gmail setup is waiting for host verification. \(hostVerifiedCount) custom-domain setup\(hostVerifiedCount == 1 ? "" : "s") have local Google-hosted evidence."
          : "\(hostVerificationNeededCount) custom-domain Gmail setup\(hostVerificationNeededCount == 1 ? "" : "s") need Google Workspace host verification or should move to IMAP/SpaceMail.",
        tone: hostVerificationNeededCount == 0 ? "success" : "attention",
        symbol: "server.rack"
      ),
      GmailShiftHandoffLine(
        title: "Google sign-in",
        detail: signedInCount == 0
          ? "No Gmail setup currently has a connected Google sign-in session."
          : "\(signedInCount) Gmail setup\(signedInCount == 1 ? "" : "s") have connected sign-in state for manual read-only refresh.",
        tone: signedInCount > 0 || gmailMailboxConnections.isEmpty ? "success" : "attention",
        symbol: "person.crop.circle.badge.checkmark"
      ),
      GmailShiftHandoffLine(
        title: "Latest refresh",
        detail: "\(fetchedCount) fetched, \(importedCount) imported, \(duplicateCount) duplicates, \(filteredLastRefreshCount) filtered, \(uncertainLastRefreshCount) uncertain.",
        tone: fetchedCount == 0 ? "attention" : "neutral",
        symbol: "clock.arrow.circlepath"
      ),
      GmailShiftHandoffLine(
        title: "Inbox review",
        detail: reviewGmailIntake.isEmpty
          ? "No Gmail-linked intake rows currently need primary Inbox review."
          : "\(reviewGmailIntake.count) Gmail-linked intake row\(reviewGmailIntake.count == 1 ? "" : "s") need review.",
        tone: reviewGmailIntake.isEmpty ? "success" : "attention",
        symbol: "tray.full.fill"
      ),
      GmailShiftHandoffLine(
        title: "Parser checks",
        detail: parserDiagnostics.isEmpty
          ? "No Gmail-linked parser diagnostics are open."
          : "\(parserDiagnostics.count) Gmail parser diagnostic\(parserDiagnostics.count == 1 ? "" : "s") need field confirmation.",
        tone: parserDiagnostics.isEmpty ? "success" : "warning",
        symbol: "text.magnifyingglass"
      ),
      GmailShiftHandoffLine(
        title: "Mixed mailbox review",
        detail: uncertainCount == 0 && filteredCount == 0
          ? "No uncertain or filtered Gmail preview reviews are waiting."
          : "\(uncertainCount) uncertain and \(filteredCount) filtered Gmail preview\(uncertainCount + filteredCount == 1 ? "" : "s") are available for review.",
        tone: uncertainCount > 0 ? "attention" : "neutral",
        symbol: "questionmark.folder.fill"
      )
    ]

    let openLineCount = lines.filter { $0.tone == "warning" || $0.tone == "attention" }.count
    let title: String
    let detail: String
    let tone: String
    if gmailMailboxConnections.isEmpty {
      title = "Gmail handoff unavailable"
      detail = "Add Gmail only for mailboxes hosted by Gmail or Google Workspace."
      tone = "neutral"
    } else if openLineCount == 0 {
      title = "Gmail handoff is clear"
      detail = "No immediate Gmail setup, refresh, parser, or mixed-mailbox follow-up is open."
      tone = "success"
    } else {
      title = "Gmail handoff needs attention"
      detail = "\(openLineCount) Gmail handoff area\(openLineCount == 1 ? "" : "s") should be checked before relying on Gmail intake."
      tone = lines.contains { $0.tone == "warning" } ? "warning" : "attention"
    }

    return GmailShiftHandoffSummary(
      title: title,
      detail: detail,
      tone: tone,
      lastRefreshText: lastRefreshText,
      keyCounts: [
        SpaceMailReleaseSnapshotMetric(title: "Setups", value: "\(gmailMailboxConnections.count)", tone: gmailMailboxConnections.isEmpty ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(readinessBlockers)", tone: readinessBlockers == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Host checks", value: "\(hostVerificationNeededCount)", tone: hostVerificationNeededCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Signed in", value: "\(signedInCount)", tone: signedInCount > 0 || gmailMailboxConnections.isEmpty ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: fetchedCount > 0 ? "neutral" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount > 0 ? "attention" : "success")
      ],
      handoffLines: lines
    )
  }

  var gmailReleaseReadinessSnapshot: SpaceMailReleaseSnapshot {
    let handoff = gmailShiftHandoffSummary
    let healthSummaries = gmailIntakeHealthSummaries
    let readinessSummaries = gmailMailboxConnections.map(gmailOAuthReadinessSummary(for:))
    let setupTestPlans = gmailMailboxConnections.map(gmailSetupTestChecklist(for:))
    let setupBlockers = readinessSummaries.filter { !$0.isReady }.count
    let signedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let fetchedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let importedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let duplicateCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshDuplicateCount }
    let filteredCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let uncertainCount = gmailMailboxConnections.reduce(0) { $0 + max($1.lastRefreshUncertainCount ?? 0, $1.uncertainMessages?.count ?? 0) }
    let providerFits = gmailMailboxConnections.map(gmailProviderFit(for:))
    let hostVerificationNeededCount = providerFits.filter { $0.isCustomDomain && !$0.hasGoogleEvidence }.count
    let hostVerifiedCount = providerFits.filter { $0.isCustomDomain && $0.hasGoogleEvidence }.count
    let releaseBlockers = gmailReleaseBlockerSummary.blockers.filter { $0.tone == "warning" || $0.tone == "attention" }
    let topReleaseBlocker = releaseBlockers.first
    let parserDiagnostics = gmailMailboxConnections.reduce(0) { count, connection in
      let sourceIDs = Set(mailboxIngestRecords.filter { $0.sourceMailboxID == connection.id }.compactMap(\.intakeEmailID))
      return count + intakeParserDiagnostics.filter { sourceIDs.contains($0.intakeEmailID) }.count
    }
    let latestRefresh = gmailMailboxConnections
      .filter { $0.lastManualRefreshDate != "Never" }
      .sorted { $0.lastManualRefreshDate > $1.lastManualRefreshDate }
      .first
    let generatedDate = Date.now.formatted(date: .abbreviated, time: .shortened)
    let completedSetupSteps = setupTestPlans.reduce(0) { $0 + $1.completedCount }
    let totalSetupSteps = setupTestPlans.reduce(0) { $0 + $1.totalCount }
    let openHandoffLines = handoff.handoffLines.filter { $0.tone == "attention" || $0.tone == "warning" }.count
    let gmailConnectionIDs = Set(gmailMailboxConnections.map { $0.id.uuidString })
    let releaseSelfCheckTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration &&
        gmailConnectionIDs.contains($0.linkedEntityID) &&
        $0.title.localizedCaseInsensitiveContains("Gmail release self-check")
    }
    let releaseReadinessTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration &&
        $0.linkedEntityID == "gmail-release-readiness"
    }
    let openReleaseSelfCheckTaskCount = releaseSelfCheckTasks.filter { $0.status != .completed }.count
    let completedReleaseSelfCheckTaskCount = releaseSelfCheckTasks.filter { $0.status == .completed }.count
    let openReleaseReadinessTaskCount = releaseReadinessTasks.filter { $0.status != .completed }.count
    let completedReleaseReadinessTaskCount = releaseReadinessTasks.filter { $0.status == .completed }.count
    let hasOpenReleaseTask = gmailMailboxConnections.isEmpty || openReleaseSelfCheckTaskCount + openReleaseReadinessTaskCount > 0

    let verdict: String
    let detail: String
    let tone: String
    if gmailMailboxConnections.isEmpty {
      verdict = "Gmail release snapshot: optional path not configured"
      detail = "Add Gmail only when a mailbox is hosted by Gmail or Google Workspace. Use whichever provider hosts the active mailbox."
      tone = "neutral"
    } else if setupBlockers == 0 && signedInCount > 0 && !hasOpenReleaseTask {
      verdict = "Gmail release snapshot: release task needed"
      detail = "Create and keep open a Gmail release self-check or release readiness task before treating Gmail intake as release-ready."
      tone = "attention"
    } else if setupBlockers == 0 && signedInCount > 0 && fetchedCount > 0 && openHandoffLines == 0 && hasOpenReleaseTask {
      verdict = "Gmail release snapshot: ready for supervised testing"
      detail = "Gmail setup, sign-in, read-only refresh evidence, and handoff checks are clear enough for a focused hands-on pass."
      tone = "success"
    } else if setupBlockers == 0 && signedInCount > 0 {
      verdict = "Gmail release snapshot: usable with review"
      detail = "Gmail setup and sign-in are ready. Complete manual refresh review, uncertain-message review, or parser checks before relying on it."
      tone = "attention"
    } else {
      verdict = "Gmail release snapshot: setup still needed"
      detail = "Complete Google Cloud OAuth setup, compiled callback readiness, and real Google sign-in before running live Gmail refresh."
      tone = "warning"
    }

    let latestRefreshLine = latestRefresh.map {
      "\($0.displayName): \($0.lastRefreshSummary.isEmpty ? $0.connectionStatus : $0.lastRefreshSummary)"
    } ?? "No real Gmail refresh has been recorded yet."
    let readinessLines = readinessSummaries.map { summary in
      "- \(summary.statusText). Missing/blocking: \(summary.missingFields.isEmpty ? "none" : summary.missingFields.joined(separator: ", ")). Compiled client: \(summary.compiledClientIDStatus). Callback: \(summary.compiledCallbackSchemeStatus)."
    }
    let hostVerificationLines = gmailMailboxConnections.map { connection in
      let providerFit = gmailProviderFit(for: connection)
      let hostStatus = providerFit.isCustomDomain
        ? (providerFit.hasGoogleEvidence ? "host evidence recorded" : "host verification needed")
        : providerFit.isConsumer ? "consumer Gmail" : providerFit.isSample ? "sample setup" : "missing or invalid domain"
      return "- \(connection.displayName): \(hostStatus). \(providerFit.detail)"
    }
    let healthLines = healthSummaries.map { summary in
      let effectiveUncertainCount = max(summary.uncertainCount, summary.pendingUncertainReviewCount)
      return "- \(summary.displayName): \(summary.verdict). \(summary.fetchedCount) fetched, \(summary.importedCount) imported, \(summary.filteredCount) filtered, \(effectiveUncertainCount) uncertain."
    }
    let handoffLines = handoff.handoffLines.map { "- \($0.title): \($0.detail)" }
    let topReleaseBlockerLine = topReleaseBlocker.map {
      "- \($0.source): \($0.title). \($0.detail) Next: \($0.nextAction)"
    } ?? "- No warning or attention release blockers are currently promoted."
    let reportLines = [
      "ParcelOps Gmail local release snapshot",
      "Generated: \(generatedDate)",
      "",
      "Verdict: \(verdict)",
      "Detail: \(detail)",
      "",
      "Gmail setup records: \(gmailMailboxConnections.count)",
      "Setup test steps: \(completedSetupSteps)/\(max(totalSetupSteps, 1))",
      "OAuth readiness blockers: \(setupBlockers)",
      "Custom-domain host verified/evidenced: \(hostVerifiedCount)",
      "Custom-domain host checks needed: \(hostVerificationNeededCount)",
      "Connected Google sign-ins: \(signedInCount)",
      "Latest refresh: \(latestRefreshLine)",
      "",
      "Refresh counts:",
      "Fetched: \(fetchedCount)",
      "Imported to Inbox: \(importedCount)",
      "Duplicates: \(duplicateCount)",
      "Filtered non-order: \(filteredCount)",
      "Uncertain needing review: \(uncertainCount)",
      "Parser diagnostics: \(parserDiagnostics)",
      "Open Gmail release self-check tasks: \(openReleaseSelfCheckTaskCount)",
      "Completed Gmail release self-check tasks: \(completedReleaseSelfCheckTaskCount)",
      "Open Gmail release readiness tasks: \(openReleaseReadinessTaskCount)",
      "Completed Gmail release readiness tasks: \(completedReleaseReadinessTaskCount)",
      "Release task gate: \(hasOpenReleaseTask ? "open task present" : "open task needed")",
      "Promoted release blockers: \(releaseBlockers.count)",
      "",
      "Top release blocker:",
      topReleaseBlockerLine,
      "",
      "Readiness:",
      readinessLines.isEmpty ? "- No Gmail setup records are configured." : readinessLines.joined(separator: "\n"),
      "",
      "Provider host fit:",
      hostVerificationLines.isEmpty ? "- No Gmail setup records are configured." : hostVerificationLines.joined(separator: "\n"),
      "",
      "Health:",
      healthLines.isEmpty ? "- No Gmail health summaries are available." : healthLines.joined(separator: "\n"),
      "",
      "Handoff:",
      handoffLines.joined(separator: "\n"),
      "",
      "Release boundaries:",
      "- Gmail refresh is explicit, manual, and read-only.",
      "- Gmail API requests must not delete, move, mark read, send, or modify mailbox messages.",
      "- Google access tokens, refresh tokens, auth codes, callback URLs, client secrets, passwords, raw Gmail API responses, and full message bodies must not be stored in JSON or Audit.",
      "- Mixed mailbox filtering stays local and should keep non-order mail out of primary Inbox.",
      "",
      "Recommended Gmail test:",
      "1. Confirm Google Cloud iOS OAuth client and compiled callback scheme.",
      "2. Run Test real Google sign-in.",
      "3. Run real Gmail refresh manually.",
      "4. Review imported, uncertain, and filtered examples.",
      "5. Create or link one order from confirmed Inbox intake and confirm Dashboard, Orders, Workbench, Tasks, and Audit."
    ]

    return SpaceMailReleaseSnapshot(
      verdict: verdict,
      detail: detail,
      generatedDate: generatedDate,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Setups", value: "\(gmailMailboxConnections.count)", tone: gmailMailboxConnections.isEmpty ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(setupBlockers)", tone: setupBlockers == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Host checks", value: "\(hostVerificationNeededCount)", tone: hostVerificationNeededCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Release blockers", value: "\(releaseBlockers.count)", tone: releaseBlockers.isEmpty ? "success" : releaseBlockers.contains { $0.tone == "warning" } ? "warning" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Signed in", value: "\(signedInCount)", tone: signedInCount > 0 || gmailMailboxConnections.isEmpty ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: fetchedCount > 0 ? "neutral" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Release task", value: "\(openReleaseSelfCheckTaskCount + openReleaseReadinessTaskCount)", tone: gmailMailboxConnections.isEmpty ? "neutral" : hasOpenReleaseTask ? "success" : "attention")
      ],
      reportText: reportLines.joined(separator: "\n")
    )
  }

  func recordGmailReleaseReadinessSnapshot() {
    let snapshot = gmailReleaseReadinessSnapshot
    let connection = gmailMailboxConnections.first
    logAudit(
      action: .evaluated,
      entityType: .gmailMailboxConnection,
      entityID: connection?.id.uuidString ?? "gmail-release-readiness",
      entityLabel: connection?.displayName ?? "Gmail release readiness",
      summary: snapshot.verdict,
      afterDetail: "\(snapshot.reportText)\n\nSnapshot only. No Google sign-in, Gmail API request, token access, mailbox fetch, classifier import, external service call, or mailbox mutation occurred."
    )
  }

  func createReviewTaskFromGmailReleaseReadinessSnapshot() {
    let snapshot = gmailReleaseReadinessSnapshot
    let taskPriority: TaskPriority
    switch snapshot.tone {
    case "warning":
      taskPriority = .high
    case "attention":
      taskPriority = .normal
    default:
      taskPriority = .low
    }

    let taskTitle = snapshot.tone == "success" ? "Confirm Gmail release readiness" : "Resolve Gmail release readiness gaps"
    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .integration
        && $0.linkedEntityID == "gmail-release-readiness"
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = taskTitle
      reviewTasks[existingIndex].summary = snapshot.reportText
      reviewTasks[existingIndex].priority = taskPriority
      reviewTasks[existingIndex].dueDate = taskPriority == .high ? "Today" : "Tomorrow"
      reviewTasks[existingIndex].assignee = "Mailbox team"
      reviewTasks[existingIndex].reviewState = .needsReview
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Existing Gmail release readiness review task refreshed.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nRefreshed from current local Gmail release snapshot. No duplicate task was created. No Google sign-in, token request, Gmail API call, mailbox fetch, external service call, or mailbox mutation occurred."
      )
      return
    }

    let task = ReviewTask(
      title: taskTitle,
      summary: snapshot.reportText,
      linkedEntityType: .integration,
      linkedEntityID: "gmail-release-readiness",
      priority: taskPriority,
      dueDate: taskPriority == .high ? "Today" : "Tomorrow",
      assignee: "Mailbox team",
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: .needsReview
    )
    addReviewTask(
      task,
      summary: "Review task created from Gmail release readiness snapshot."
    )
  }

  var gmailReleaseBlockerSummary: MailboxReleaseBlockerSummary {
    let readinessSummaries = gmailMailboxConnections.map(gmailOAuthReadinessSummary(for:))
    let setupPlans = gmailMailboxConnections.map(gmailSetupTestChecklist(for:))
    let healthSummaries = gmailIntakeHealthSummaries
    let handoff = gmailShiftHandoffSummary
    let actionPlan = gmailPostRefreshActionPlan
    var blockers: [MailboxReleaseBlockerItem] = []

    if gmailMailboxConnections.isEmpty {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Gmail setup",
          title: "Gmail path is optional",
          detail: "No Gmail or Google Workspace mailbox setup is configured.",
          nextAction: "Add Gmail setup only when a mailbox is hosted by Gmail or Google Workspace.",
          tone: "neutral",
          symbol: "envelope.badge.shield.half.filled"
        )
      )
    }

    for readiness in readinessSummaries where !readiness.isReady {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Gmail OAuth readiness",
          title: readiness.statusText,
          detail: readiness.missingFields.isEmpty
            ? "\(readiness.compiledClientIDStatus). \(readiness.compiledCallbackSchemeStatus)."
            : "Missing or blocked: \(readiness.missingFields.prefix(4).joined(separator: ", ")). \(readiness.compiledClientIDStatus). \(readiness.compiledCallbackSchemeStatus).",
          nextAction: "Edit the Gmail setup, save non-secret Google OAuth values, then run Check readiness.",
          tone: "warning",
          symbol: "person.badge.key.fill"
        )
      )
    }

    for connection in gmailMailboxConnections {
      let providerFit = gmailProviderFit(for: connection)
      if providerFit.isCustomDomain && !providerFit.hasGoogleEvidence {
        blockers.append(
          MailboxReleaseBlockerItem(
            source: connection.displayName,
            title: "Google Workspace host not verified",
            detail: providerFit.detail,
            nextAction: providerFit.nextAction,
            tone: providerFit.tone,
            symbol: "server.rack"
          )
        )
      }
    }

    for connection in gmailMailboxConnections {
      let authState = gmailAuthSessionState(for: connection)
      if authState.status != .connected {
        blockers.append(
          MailboxReleaseBlockerItem(
            source: connection.displayName,
            title: "Google sign-in not connected",
            detail: "Current auth status: \(authState.status.rawValue). Signed-in account: \(authState.signedInAccount).",
            nextAction: "Run Test real Google sign-in before running real Gmail refresh.",
            tone: readinessSummaries.first(where: { $0.connectionID == connection.id })?.isReady == true ? "attention" : "warning",
            symbol: "person.crop.circle.badge.questionmark"
          )
        )
      }

      if connection.lastManualRefreshDate == "Never" {
        blockers.append(
          MailboxReleaseBlockerItem(
            source: connection.displayName,
            title: "No real Gmail refresh evidence",
            detail: "This setup has not recorded a manual real Gmail refresh result.",
            nextAction: "After setup and sign-in are ready, run manual read-only Gmail refresh.",
            tone: authState.status == .connected ? "attention" : "neutral",
            symbol: "arrow.clockwise.circle"
          )
        )
      }
    }

    for plan in setupPlans {
      for item in plan.items where !item.isComplete {
        blockers.append(
          MailboxReleaseBlockerItem(
            source: "Gmail setup test",
            title: item.title,
            detail: item.detail,
            nextAction: item.nextAction,
            tone: item.title.localizedCaseInsensitiveContains("sign-in") || item.title.localizedCaseInsensitiveContains("refresh") ? "attention" : "warning",
            symbol: item.symbolName
          )
        )
      }
    }

    for summary in healthSummaries where summary.tone == "warning" || summary.tone == "attention" {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: summary.displayName,
          title: summary.verdict,
          detail: summary.detail,
          nextAction: summary.nextAction,
          tone: summary.tone,
          symbol: summary.tone == "warning" ? "exclamationmark.triangle.fill" : "tray.full.fill"
        )
      )
    }

    for line in handoff.handoffLines where (line.tone == "warning" || line.tone == "attention") && line.title != "Provider host fit" {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Gmail handoff",
          title: line.title,
          detail: line.detail,
          nextAction: "Resolve this handoff item or leave a local follow-up task before relying on Gmail intake.",
          tone: line.tone,
          symbol: line.symbol
        )
      )
    }

    for item in actionPlan.items where item.tone == "warning" || item.tone == "attention" {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Gmail action queue",
          title: item.title,
          detail: item.detail,
          nextAction: item.actionLabel,
          tone: item.tone,
          symbol: item.symbol
        )
      )
    }

    let uniqueBlockers = Array(
      Dictionary(grouping: blockers, by: { "\($0.source)-\($0.title)-\($0.detail)" })
        .compactMap { $0.value.first }
        .sorted { lhs, rhs in
          let lhsRank = lhs.tone == "warning" ? 0 : lhs.tone == "attention" ? 1 : lhs.tone == "neutral" ? 2 : 3
          let rhsRank = rhs.tone == "warning" ? 0 : rhs.tone == "attention" ? 1 : rhs.tone == "neutral" ? 2 : 3
          if lhsRank != rhsRank { return lhsRank < rhsRank }
          return lhs.source < rhs.source
        }
    )
    let warningCount = uniqueBlockers.filter { $0.tone == "warning" }.count
    let attentionCount = uniqueBlockers.filter { $0.tone == "attention" }.count
    let setupSteps = setupPlans.reduce(0) { $0 + $1.completedCount }
    let setupTotal = setupPlans.reduce(0) { $0 + $1.totalCount }

    let title: String
    let detail: String
    let tone: String
    if gmailMailboxConnections.isEmpty {
      title = "Gmail release blockers are optional"
      detail = "No Gmail mailbox is configured. This is acceptable when the active mailbox is not hosted by Gmail or Google Workspace."
      tone = "neutral"
    } else if warningCount > 0 {
      title = "Gmail release has blocking setup items"
      detail = "\(warningCount) setup blocker\(warningCount == 1 ? "" : "s") should be resolved before live Gmail testing."
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Gmail release needs operator review"
      detail = "\(attentionCount) Gmail item\(attentionCount == 1 ? "" : "s") should be reviewed before relying on the Gmail path."
      tone = "attention"
    } else {
      title = "Gmail release blockers are clear"
      detail = "Gmail setup, sign-in, refresh, and handoff checks do not currently show release blockers."
      tone = "success"
    }

    return MailboxReleaseBlockerSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Review", value: "\(attentionCount)", tone: attentionCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Setup", value: "\(setupSteps)/\(max(setupTotal, 1))", tone: setupTotal == 0 || setupSteps == setupTotal ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Signed in", value: "\(gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count)", tone: gmailMailboxConnections.isEmpty || gmailMailboxConnections.contains { gmailAuthSessionState(for: $0).status == .connected } ? "success" : "attention")
      ],
      blockers: Array(uniqueBlockers.prefix(8))
    )
  }

  var gmailOperatorDecisionSummary: MailboxOperatorDecisionSummary {
    let blockers = gmailReleaseBlockerSummary
    let actionPlan = gmailPostRefreshActionPlan
    let warningBlockers = blockers.blockers.filter { $0.tone == "warning" }.count
    let reviewBlockers = blockers.blockers.filter { $0.tone == "attention" }.count
    let setupCount = gmailMailboxConnections.count
    let readinessBlockers = gmailMailboxConnections.filter { !gmailOAuthReadinessSummary(for: $0).isReady }.count
    let signedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let fetchedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let importedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let duplicateCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshDuplicateCount }
    let filteredCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let uncertainCount = gmailMailboxConnections.reduce(0) { $0 + max($1.lastRefreshUncertainCount ?? 0, $1.uncertainMessages?.count ?? 0) }
    let openActionItems = actionPlan.items.filter { $0.tone == "warning" || $0.tone == "attention" }

    let decisions = [
      MailboxOperatorDecisionItem(
        title: "Leave Gmail optional",
        detail: "No Gmail setup is configured. Use another provider path when the active mailbox is not hosted by Gmail or Google Workspace.",
        action: "Only add Gmail when a mailbox is hosted by Gmail or Google Workspace.",
        isActive: setupCount == 0,
        tone: setupCount == 0 ? "neutral" : "success",
        symbol: "envelope.badge.shield.half.filled"
      ),
      MailboxOperatorDecisionItem(
        title: "Fix Gmail setup blockers",
        detail: "\(readinessBlockers) setup readiness item\(readinessBlockers == 1 ? "" : "s") and \(warningBlockers) warning blocker\(warningBlockers == 1 ? "" : "s") remain.",
        action: "Edit Gmail setup, confirm OAuth values, then rerun readiness before sign-in or refresh.",
        isActive: setupCount > 0 && (readinessBlockers > 0 || warningBlockers > 0),
        tone: setupCount > 0 && (readinessBlockers > 0 || warningBlockers > 0) ? "warning" : "success",
        symbol: "person.badge.key.fill"
      ),
      MailboxOperatorDecisionItem(
        title: "Test Google sign-in",
        detail: "Gmail setup exists, but no connected Google account is available.",
        action: "Run Test real Google sign-in, then confirm Audit records a connected identity without token values.",
        isActive: setupCount > 0 && readinessBlockers == 0 && signedInCount == 0,
        tone: setupCount > 0 && readinessBlockers == 0 && signedInCount == 0 ? "attention" : "neutral",
        symbol: "person.crop.circle.badge.checkmark"
      ),
      MailboxOperatorDecisionItem(
        title: "Run manual Gmail refresh",
        detail: signedInCount > 0 ? "A Google account is connected; no real Gmail fetch evidence is recorded yet." : "Manual refresh waits until sign-in is connected.",
        action: "Use Run real Gmail refresh only when you need to test a Google-hosted mailbox.",
        isActive: setupCount > 0 && signedInCount > 0 && fetchedCount == 0,
        tone: setupCount > 0 && signedInCount > 0 && fetchedCount == 0 ? "attention" : "neutral",
        symbol: "arrow.clockwise.circle"
      ),
      MailboxOperatorDecisionItem(
        title: "Review Gmail intake",
        detail: "\(importedCount) imported row\(importedCount == 1 ? "" : "s") and \(uncertainCount) uncertain preview\(uncertainCount == 1 ? "" : "s") need operator review.",
        action: "Open Inbox or Mailbox Monitor, then review, import, dismiss, link, or create orders from Gmail rows.",
        isActive: importedCount + uncertainCount > 0,
        tone: importedCount + uncertainCount > 0 ? "attention" : "success",
        symbol: "tray.full.fill"
      ),
      MailboxOperatorDecisionItem(
        title: "Check filtered Gmail examples",
        detail: "\(filteredCount) filtered non-order message\(filteredCount == 1 ? "" : "s") and \(duplicateCount) duplicate\(duplicateCount == 1 ? "" : "s") are recorded.",
        action: "Use filtered examples only for classifier tuning; keep non-order mail out of primary Inbox.",
        isActive: setupCount > 0 && importedCount == 0 && uncertainCount == 0 && filteredCount > 0,
        tone: setupCount > 0 && importedCount == 0 && uncertainCount == 0 && filteredCount > 0 ? "neutral" : "success",
        symbol: "line.3.horizontal.decrease.circle"
      ),
      MailboxOperatorDecisionItem(
        title: "Record Gmail follow-up",
        detail: "\(reviewBlockers) review blocker\(reviewBlockers == 1 ? "" : "s") and \(openActionItems.count) action-plan item\(openActionItems.count == 1 ? "" : "s") remain.",
        action: "Create a local task only for items that need a later Gmail setup or refresh pass.",
        isActive: setupCount > 0 && warningBlockers == 0 && reviewBlockers + openActionItems.count > 0,
        tone: setupCount > 0 && warningBlockers == 0 && reviewBlockers + openActionItems.count > 0 ? "attention" : "neutral",
        symbol: "checklist"
      )
    ]

    let activeDecisions = decisions.filter(\.isActive)
    let primaryAction: String
    let title: String
    let detail: String
    let tone: String
    if let warning = activeDecisions.first(where: { $0.tone == "warning" }) {
      primaryAction = warning.action
      title = "Gmail decision: fix setup blockers"
      detail = warning.detail
      tone = "warning"
    } else if let active = activeDecisions.first {
      primaryAction = active.action
      title = "Gmail decision: \(active.title.lowercased())"
      detail = active.detail
      tone = active.tone == "success" ? "attention" : active.tone
    } else {
      primaryAction = "No Gmail action is required unless a Google-hosted mailbox becomes part of the active intake path."
      title = "Gmail decision: path is quiet"
      detail = "Gmail setup, sign-in, refresh, filtering, and intake review do not currently require operator action."
      tone = "success"
    }

    return MailboxOperatorDecisionSummary(
      title: title,
      detail: detail,
      primaryAction: primaryAction,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Setups", value: "\(setupCount)", tone: setupCount == 0 ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Signed in", value: "\(signedInCount)", tone: setupCount == 0 || signedInCount > 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: fetchedCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningBlockers)", tone: warningBlockers == 0 ? "success" : "warning")
      ],
      decisions: decisions
    )
  }

  var gmailRefreshTrendSummary: GmailRefreshTrendSummary {
    let gmailEvents = auditEvents.filter { event in
      event.entityType == .gmailMailboxConnection
        && (
          event.summary.localizedCaseInsensitiveContains("Gmail refresh")
            || event.summary.localizedCaseInsensitiveContains("Gmail mailbox fetch")
            || event.summary.localizedCaseInsensitiveContains("Gmail setup")
            || event.afterDetail?.localizedCaseInsensitiveContains("Gmail refresh") == true
        )
    }
    let recentEvents = Array(gmailEvents.prefix(8))
    let fetchedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let importedCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let duplicateCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshDuplicateCount }
    let filteredCount = gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let uncertainCount = gmailMailboxConnections.reduce(0) { $0 + ($1.lastRefreshUncertainCount ?? 0) }
    let pendingUncertainCount = gmailMailboxConnections.reduce(0) { $0 + ($1.uncertainMessages?.count ?? 0) }
    let readinessBlockers = gmailMailboxConnections.filter { !gmailOAuthReadinessSummary(for: $0).isReady }.count
    let signedInCount = gmailMailboxConnections.filter { gmailAuthSessionState(for: $0).status == .connected }.count
    let actionableCount = importedCount + pendingUncertainCount

    let title: String
    let detail: String
    let tone: String
    if gmailMailboxConnections.isEmpty {
      title = "No Gmail refresh trend yet"
      detail = "Add Gmail only for mailboxes hosted by Gmail or Google Workspace."
      tone = "neutral"
    } else if readinessBlockers > 0 {
      title = "Gmail refresh trend blocked by setup"
      detail = "\(readinessBlockers) Gmail setup\(readinessBlockers == 1 ? "" : "s") need readiness fixes before real refresh should be relied on."
      tone = "warning"
    } else if signedInCount == 0 {
      title = "Gmail refresh trend waiting for sign-in"
      detail = "Gmail setup is present, but no connected Google sign-in is available for manual read-only refresh."
      tone = "attention"
    } else if recentEvents.isEmpty && fetchedCount == 0 {
      title = "Gmail refresh trend pending"
      detail = "Run a manual Gmail refresh to build local evidence across imports, duplicates, filtered messages, and uncertain reviews."
      tone = "attention"
    } else if actionableCount > 0 {
      title = "Gmail refresh trend has actionable intake"
      detail = "\(importedCount) imported and \(pendingUncertainCount) uncertain Gmail preview\(pendingUncertainCount == 1 ? "" : "s") need operator review."
      tone = "attention"
    } else if filteredCount > 0 && importedCount == 0 {
      title = "Gmail filter trend is stable"
      detail = "Latest Gmail activity mostly filtered mixed-mailbox non-order messages out of Inbox."
      tone = "success"
    } else {
      title = "Gmail refresh trend is quiet"
      detail = "Recent Gmail activity has no current Inbox intake or uncertain review work."
      tone = "neutral"
    }

    let connectionEntries = gmailMailboxConnections.map { connection in
      let health = gmailIntakeHealthSummary(for: connection)
      let entryTone: String
      if health.tone == "warning" {
        entryTone = "warning"
      } else if (connection.lastRefreshUncertainCount ?? 0) > 0 || (connection.uncertainMessages?.isEmpty == false) {
        entryTone = "attention"
      } else if connection.lastRefreshImportedCount > 0 {
        entryTone = "attention"
      } else if connection.lastRefreshFilteredNonOrderCount > 0 || connection.lastRefreshDuplicateCount > 0 {
        entryTone = "success"
      } else {
        entryTone = health.tone
      }

      return GmailRefreshTrendEntry(
        id: connection.id,
        timestamp: connection.lastManualRefreshDate,
        displayName: connection.displayName,
        status: connection.connectionStatus,
        detail: "\(connection.lastRefreshFetchedCount) fetched, \(connection.lastRefreshImportedCount) imported, \(connection.lastRefreshDuplicateCount) duplicates, \(connection.lastRefreshFilteredNonOrderCount) filtered, \(connection.lastRefreshUncertainCount ?? 0) uncertain. \(health.nextAction)",
        tone: entryTone
      )
    }

    let historyEntries = gmailMailboxConnections.flatMap { connection in
      (connection.refreshHistory ?? []).prefix(4).map { entry in
        let entryTone: String
        if entry.status.localizedCaseInsensitiveContains("auth")
          || entry.status.localizedCaseInsensitiveContains("failed")
          || entry.status.localizedCaseInsensitiveContains("rejected")
          || entry.status.localizedCaseInsensitiveContains("not configured") {
          entryTone = "warning"
        } else if entry.importedCount > 0 || entry.uncertainCount > 0 {
          entryTone = "attention"
        } else if entry.filteredNonOrderCount > 0 || entry.duplicateCount > 0 {
          entryTone = "success"
        } else {
          entryTone = "neutral"
        }
        return GmailRefreshTrendEntry(
          id: entry.id,
          timestamp: entry.timestamp,
          displayName: connection.displayName,
          status: "\(entry.eventType): \(entry.status)",
          detail: "\(entry.fetchedCount) fetched, \(entry.importedCount) imported, \(entry.duplicateCount) duplicates, \(entry.filteredNonOrderCount) filtered, \(entry.uncertainCount) uncertain. \(entry.summary)",
          tone: entryTone
        )
      }
    }

    let eventEntries = recentEvents.prefix(6).map { event in
      let afterDetail = event.afterDetail ?? ""
      let eventTone: String
      if event.summary.localizedCaseInsensitiveContains("failed")
        || event.summary.localizedCaseInsensitiveContains("blocked")
        || afterDetail.localizedCaseInsensitiveContains("Status: Auth required")
        || afterDetail.localizedCaseInsensitiveContains("Status: API rejected") {
        eventTone = "warning"
      } else if afterDetail.localizedCaseInsensitiveContains("Imported: 0")
        && afterDetail.localizedCaseInsensitiveContains("Filtered non-order:") {
        eventTone = "success"
      } else if afterDetail.localizedCaseInsensitiveContains("Imported:")
        || afterDetail.localizedCaseInsensitiveContains("Uncertain:") {
        eventTone = "attention"
      } else {
        eventTone = "neutral"
      }

      return GmailRefreshTrendEntry(
        id: event.id,
        timestamp: event.timestamp,
        displayName: event.entityLabel,
        status: event.action.rawValue,
        detail: event.summary,
        tone: eventTone
      )
    }
    let entries = Array((historyEntries + connectionEntries + eventEntries).prefix(8))

    return GmailRefreshTrendSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Events", value: "\(recentEvents.count)", tone: recentEvents.isEmpty ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Setups", value: "\(gmailMailboxConnections.count)", tone: gmailMailboxConnections.isEmpty ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(readinessBlockers)", tone: readinessBlockers == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: fetchedCount > 0 ? "neutral" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Duplicates", value: "\(duplicateCount)", tone: duplicateCount > 0 ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(max(pendingUncertainCount, uncertainCount))", tone: max(pendingUncertainCount, uncertainCount) > 0 ? "attention" : "success")
      ],
      entries: entries
    )
  }

  var microsoft365RefreshTrendSummary: Microsoft365RefreshTrendSummary {
    let outlookEvents = auditEvents.filter { event in
      event.entityType == .microsoft365MailboxConnection
        && (
          event.summary.localizedCaseInsensitiveContains("Microsoft")
            || event.summary.localizedCaseInsensitiveContains("Graph")
            || event.summary.localizedCaseInsensitiveContains("Outlook")
            || event.afterDetail?.localizedCaseInsensitiveContains("Microsoft") == true
            || event.afterDetail?.localizedCaseInsensitiveContains("Graph") == true
        )
    }
    let recentEvents = Array(outlookEvents.prefix(8))
    let summaries = microsoft365IntakeHealthSummaries
    let fetchedCount = summaries.reduce(0) { $0 + $1.fetchedCount }
    let importedCount = summaries.reduce(0) { $0 + $1.importedCount }
    let duplicateCount = summaries.reduce(0) { $0 + $1.duplicateCount }
    let duplicateRefreshedCount = summaries.reduce(0) { $0 + $1.duplicateRefreshedCount }
    let filteredCount = summaries.reduce(0) { $0 + $1.totalFilteredCount }
    let uncertainCount = summaries.reduce(0) { $0 + $1.totalUncertainCount }
    let blockedCount = summaries.reduce(0) { $0 + $1.blockedCount }
    let readinessBlockers = microsoft365MailboxConnections.filter { !microsoft365OAuthReadinessSummary(for: $0).isReady }.count
    let connectedCount = microsoft365MailboxConnections.filter { microsoft365AuthSessionState(for: $0).status == .connected }.count
    let actionableCount = importedCount + uncertainCount + blockedCount

    let title: String
    let detail: String
    let tone: String
    if microsoft365MailboxConnections.isEmpty {
      title = "No Outlook refresh trend yet"
      detail = "Add Outlook / Microsoft 365 only for mailboxes hosted by Microsoft."
      tone = "neutral"
    } else if blockedCount > 0 {
      title = "Outlook refresh trend has Graph diagnostics"
      detail = "\(blockedCount) Microsoft 365 setup\(blockedCount == 1 ? "" : "s") have auth, consent, token, or Graph-read diagnostics to review."
      tone = "warning"
    } else if readinessBlockers > 0 {
      title = "Outlook refresh trend blocked by setup"
      detail = "\(readinessBlockers) Microsoft 365 setup\(readinessBlockers == 1 ? "" : "s") need OAuth readiness values before sign-in or refresh should be relied on."
      tone = "warning"
    } else if connectedCount == 0 && fetchedCount == 0 {
      title = "Outlook refresh trend waiting for sign-in"
      detail = "Microsoft 365 setup is present, but no connected sign-in or Graph refresh evidence is available."
      tone = "attention"
    } else if actionableCount > 0 {
      title = "Outlook refresh trend has actionable evidence"
      detail = "\(importedCount) imported, \(uncertainCount) uncertain, and \(blockedCount) diagnostic item\(blockedCount == 1 ? "" : "s") need review."
      tone = blockedCount > 0 ? "warning" : "attention"
    } else if filteredCount > 0 && importedCount == 0 {
      title = "Outlook filter trend is stable"
      detail = "Latest Microsoft 365 activity mostly filtered mixed-mailbox non-order messages out of Inbox."
      tone = "success"
    } else if duplicateCount > 0 || duplicateRefreshedCount > 0 {
      title = "Outlook refresh trend found existing mail"
      detail = "\(duplicateCount) duplicate and \(duplicateRefreshedCount) refreshed duplicate result\(duplicateRefreshedCount == 1 ? "" : "s") reused existing Inbox records."
      tone = "neutral"
    } else {
      title = "Outlook refresh trend is quiet"
      detail = "Recent Microsoft 365 activity has no current Inbox intake or uncertain review work."
      tone = "neutral"
    }

    let connectionEntries = microsoft365MailboxConnections.map { connection in
      let health = microsoft365IntakeHealthSummary(for: connection)
      let entryTone: String
      if health.blockedCount > 0 || health.tone == "warning" {
        entryTone = "warning"
      } else if health.importedCount > 0 || health.totalUncertainCount > 0 {
        entryTone = "attention"
      } else if health.totalFilteredCount > 0 || health.duplicateCount > 0 || health.duplicateRefreshedCount > 0 {
        entryTone = "success"
      } else {
        entryTone = health.tone
      }

      return Microsoft365RefreshTrendEntry(
        id: connection.id,
        timestamp: connection.lastManualRefreshDate,
        displayName: connection.displayName,
        status: connection.connectionStatus,
        detail: "\(health.fetchedCount) fetched, \(health.importedCount) imported, \(health.duplicateCount) duplicates, \(health.duplicateRefreshedCount) refreshed, \(health.totalFilteredCount) filtered, \(health.totalUncertainCount) uncertain, \(health.blockedCount) blocker. \(health.nextAction)",
        tone: entryTone
      )
    }

    let eventEntries = recentEvents.prefix(6).map { event in
      let afterDetail = event.afterDetail ?? ""
      let eventTone: String
      if event.summary.localizedCaseInsensitiveContains("failed")
        || event.summary.localizedCaseInsensitiveContains("blocked")
        || afterDetail.localizedCaseInsensitiveContains("Auth required")
        || afterDetail.localizedCaseInsensitiveContains("HTTP 401")
        || afterDetail.localizedCaseInsensitiveContains("API rejected") {
        eventTone = "warning"
      } else if afterDetail.localizedCaseInsensitiveContains("Imported: 0")
        && afterDetail.localizedCaseInsensitiveContains("Filtered") {
        eventTone = "success"
      } else if afterDetail.localizedCaseInsensitiveContains("Imported:")
        || afterDetail.localizedCaseInsensitiveContains("Uncertain:") {
        eventTone = "attention"
      } else {
        eventTone = "neutral"
      }

      return Microsoft365RefreshTrendEntry(
        id: event.id,
        timestamp: event.timestamp,
        displayName: event.entityLabel,
        status: event.action.rawValue,
        detail: event.summary,
        tone: eventTone
      )
    }
    let entries = Array((connectionEntries + eventEntries).prefix(8))

    return Microsoft365RefreshTrendSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Events", value: "\(recentEvents.count)", tone: recentEvents.isEmpty ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Setups", value: "\(microsoft365MailboxConnections.count)", tone: microsoft365MailboxConnections.isEmpty ? "neutral" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Connected", value: "\(connectedCount)", tone: connectedCount > 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(blockedCount + readinessBlockers)", tone: blockedCount + readinessBlockers == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: fetchedCount > 0 ? "neutral" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount > 0 ? "attention" : "success")
      ],
      entries: entries
    )
  }

  var spaceMailReleaseSnapshot: SpaceMailReleaseSnapshot {
    let readiness = spaceMailMVPReadinessSummary
    let qa = spaceMailQACheckSummary
    let healthSummaries = spaceMailIntakeHealthSummaries
    let fetchedCount = healthSummaries.reduce(0) { $0 + $1.fetchedCount }
    let importedCount = healthSummaries.reduce(0) { $0 + $1.importedCount }
    let duplicateCount = healthSummaries.reduce(0) { $0 + $1.duplicateCount }
    let filteredCount = healthSummaries.reduce(0) { $0 + $1.filteredCount }
    let uncertainCount = healthSummaries.reduce(0) { $0 + $1.totalUncertainCount }
    let parserIssueCount = intakeParserDiagnostics.count
    let reviewIntakeCount = reviewIntakeEmails.count
    let generatedDate = Date.now.formatted(date: .abbreviated, time: .shortened)
    let completedChecks = readiness.completedCount + qa.completedCount
    let totalChecks = readiness.totalCount + qa.totalCount
    let releaseSnapshotTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration &&
        $0.linkedEntityID == "spacemail-release-snapshot"
    }
    let openReleaseSnapshotTaskCount = releaseSnapshotTasks.filter { $0.status != .completed }.count
    let completedReleaseSnapshotTaskCount = releaseSnapshotTasks.filter { $0.status == .completed }.count
    let hasOpenReleaseSnapshotTask = spaceMailIMAPConnections.isEmpty || openReleaseSnapshotTaskCount > 0

    let verdict: String
    let detail: String
    let tone: String
    if readiness.tone == "success" && qa.tone == "success" && !hasOpenReleaseSnapshotTask {
      verdict = "SpaceMail local MVP release snapshot: release task needed"
      detail = "Create and keep open a SpaceMail release snapshot review task before treating SpaceMail intake as release-ready."
      tone = "attention"
    } else if readiness.tone == "success" && qa.tone == "success" {
      verdict = "SpaceMail local MVP release snapshot: ready for supervised testing"
      detail = "Readiness and QA evidence are complete. Continue using manual refresh and human review before operational reliance."
      tone = "success"
    } else if completedChecks >= max(totalChecks - 2, 1) {
      verdict = "SpaceMail local MVP release snapshot: nearly ready"
      detail = "\(completedChecks) of \(totalChecks) readiness and QA checks are complete. Clear the remaining checks before tagging a release."
      tone = "attention"
    } else {
      verdict = "SpaceMail local MVP release snapshot: setup still needed"
      detail = "\(completedChecks) of \(totalChecks) readiness and QA checks are complete. Follow the next action in the readiness card."
      tone = "warning"
    }

    let latestRefresh = spaceMailIMAPConnections
      .filter { $0.lastManualRefreshDate != "Never" }
      .sorted { $0.lastManualRefreshDate > $1.lastManualRefreshDate }
      .first
    let latestRefreshLine = latestRefresh.map {
      "\($0.displayName): \($0.lastRefreshSummary.isEmpty ? $0.connectionStatus : $0.lastRefreshSummary)"
    } ?? "No real SpaceMail refresh has been recorded yet."

    let reportLines = [
      "ParcelOps SpaceMail local MVP release snapshot",
      "Generated: \(generatedDate)",
      "",
      "Verdict: \(verdict)",
      "Detail: \(detail)",
      "",
      "Readiness: \(readiness.completedCount)/\(readiness.totalCount) - \(readiness.verdict)",
      "QA evidence: \(qa.completedCount)/\(qa.totalCount) - \(qa.verdict)",
      "",
      "Latest refresh: \(latestRefreshLine)",
      "Fetched: \(fetchedCount)",
      "Imported to Inbox: \(importedCount)",
      "Duplicates: \(duplicateCount)",
      "Filtered non-order: \(filteredCount)",
      "Uncertain needing review: \(uncertainCount)",
      "Parser diagnostics: \(parserIssueCount)",
      "Inbox rows needing review: \(reviewIntakeCount)",
      "Inbox-created orders: \(orders.filter { $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import" }.count)",
      "Open SpaceMail release snapshot tasks: \(openReleaseSnapshotTaskCount)",
      "Completed SpaceMail release snapshot tasks: \(completedReleaseSnapshotTaskCount)",
      "Release task gate: \(hasOpenReleaseSnapshotTask ? "open task present" : "open task needed")",
      "",
      "Release boundaries:",
      "- SpaceMail refresh is manual and read-only.",
      "- IMAP uses EXAMINE and BODY.PEEK; mailbox items are not deleted, moved, marked read, flagged, sent, or modified.",
      "- SpaceMail password/app-password is handled through Keychain status paths and is not stored in JSON or audit logs.",
      "- Mixed mailbox filtering runs locally from sender, subject, and preview only.",
      "- Shopify, carrier APIs, background sync, notifications, OCR, scanners, calendars, file pickers, and outbound email sending remain disconnected.",
      "",
      "Recommended hands-on test:",
      "1. Run real SpaceMail refresh.",
      "2. Review imported and uncertain messages in Mailbox Monitor.",
      "3. Create or link one order from Inbox.",
      "4. Confirm Orders, Dashboard, Workbench, Tasks, and Audit show the handoff.",
      "5. Quit and reopen to verify local persistence."
    ]

    return SpaceMailReleaseSnapshot(
      verdict: verdict,
      detail: detail,
      generatedDate: generatedDate,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Checks", value: "\(completedChecks)/\(totalChecks)", tone: tone),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(fetchedCount)", tone: "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Inbox imports", value: "\(importedCount)", tone: importedCount > 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Parser checks", value: "\(parserIssueCount)", tone: parserIssueCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Release task", value: "\(openReleaseSnapshotTaskCount)", tone: spaceMailIMAPConnections.isEmpty ? "neutral" : hasOpenReleaseSnapshotTask ? "success" : "attention")
      ],
      reportText: reportLines.joined(separator: "\n")
    )
  }

  var mailboxReleaseReadinessSnapshot: SpaceMailReleaseSnapshot {
    let providerQA = mailboxProviderQACheckSummary
    let intakeQuality = mailboxIntakeQualitySummary
    let handoff = mailboxOperationsHandoffSummary
    let comparison = mailboxProviderComparisonSummary
    let generatedDate = Date.now.formatted(date: .abbreviated, time: .shortened)
    let completedChecks = providerQA.completedCount + intakeQuality.completedCount
    let totalChecks = providerQA.totalCount + intakeQuality.totalCount
    let providerBlockers = comparison.providers.reduce(0) { $0 + $1.blockedCount }
    let handoffAttention = handoff.lines.filter { $0.tone == "attention" || $0.tone == "warning" }.count
    let releaseReadinessTasks = reviewTasks.filter {
      $0.linkedEntityType == .integration &&
        $0.linkedEntityID == "mailbox-release-readiness"
    }
    let openReleaseReadinessTaskCount = releaseReadinessTasks.filter { $0.status != .completed }.count
    let completedReleaseReadinessTaskCount = releaseReadinessTasks.filter { $0.status == .completed }.count
    let hasOpenReleaseReadinessTask = (spaceMailIMAPConnections.isEmpty && gmailMailboxConnections.isEmpty) || openReleaseReadinessTaskCount > 0
    let totalFetched = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFetchedCount }
    let totalImported = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let totalFiltered = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let totalUncertain = spaceMailIMAPConnections.reduce(0) { $0 + max($1.lastRefreshUncertainCount, $1.uncertainMessages.count) }
      + gmailMailboxConnections.reduce(0) { $0 + max($1.lastRefreshUncertainCount ?? 0, $1.uncertainMessages?.count ?? 0) }
    let linkedOrderCount = intakeEmails.filter { $0.linkedOrderID != nil }.count

    let verdict: String
    let detail: String
    let tone: String
    if providerQA.tone == "success" && intakeQuality.tone == "success" && providerBlockers == 0 && handoffAttention == 0 && !hasOpenReleaseReadinessTask {
      verdict = "Mailbox release snapshot: release task needed"
      detail = "Create and keep open a mailbox release readiness review task before treating mailbox intake as release-ready."
      tone = "attention"
    } else if providerQA.tone == "success" && intakeQuality.tone == "success" && providerBlockers == 0 && handoffAttention == 0 {
      verdict = "Mailbox release snapshot: ready for supervised testing"
      detail = "Provider boundaries, intake quality, and handoff status are complete enough for a focused hands-on mailbox test."
      tone = "success"
    } else if completedChecks >= max(totalChecks - 3, 1) && providerBlockers == 0 {
      verdict = "Mailbox release snapshot: usable with review"
      detail = "\(completedChecks) of \(totalChecks) provider and intake checks are complete. Clear handoff or parser review items before relying on results."
      tone = "attention"
    } else {
      verdict = "Mailbox release snapshot: not ready yet"
      detail = "\(completedChecks) of \(totalChecks) provider and intake checks are complete. Finish setup, refresh, and intake quality checks first."
      tone = "warning"
    }

    let providerLines = comparison.providers.map { provider in
      "- \(provider.providerName): \(provider.statusTitle); \(provider.fetchedCount) fetched, \(provider.importedCount) imported, \(provider.uncertainCount) uncertain, \(provider.blockedCount) blockers."
    }
    let handoffLines = handoff.lines.map { "- \($0.title): \($0.detail)" }
    let reportLines = [
      "ParcelOps mailbox release readiness snapshot",
      "Generated: \(generatedDate)",
      "",
      "Verdict: \(verdict)",
      "Detail: \(detail)",
      "",
      "Recommended provider path: \(comparison.recommendedProvider)",
      "Provider QA: \(providerQA.completedCount)/\(providerQA.totalCount) - \(providerQA.verdict)",
      "Intake quality: \(intakeQuality.completedCount)/\(intakeQuality.totalCount) - \(intakeQuality.verdict)",
      "Handoff: \(handoff.title) - \(handoff.detail)",
      "",
      "Provider status:",
      providerLines.joined(separator: "\n"),
      "",
      "Mailbox counts:",
      "Fetched: \(totalFetched)",
      "Imported: \(totalImported)",
      "Filtered non-order: \(totalFiltered)",
      "Uncertain: \(totalUncertain)",
      "Parser diagnostics: \(intakeParserDiagnostics.count)",
      "Inbox rows linked to orders: \(linkedOrderCount)",
      "Open mailbox release readiness tasks: \(openReleaseReadinessTaskCount)",
      "Completed mailbox release readiness tasks: \(completedReleaseReadinessTaskCount)",
      "Release task gate: \(hasOpenReleaseReadinessTask ? "open task present" : "open task needed")",
      "",
      "Current handoff lines:",
      handoffLines.joined(separator: "\n"),
      "",
      "Release boundaries:",
      "- Mailbox refreshes are explicit, manual, and read-only.",
      "- No background sync, notifications, outbound email sending, Shopify, carrier APIs, OCR, scanners, calendars, or file pickers are active.",
      "- Passwords, tokens, auth strings, and full message bodies should not be stored in ParcelOps JSON or Audit.",
      "- Mixed-mailbox filtering is local only and should keep non-order mail out of primary Inbox.",
      "",
      "Recommended release-candidate test:",
      "1. Run the active provider manual refresh.",
      "2. Confirm the refresh summary, provider QA, and intake quality cards.",
      "3. Import or dismiss uncertain messages.",
      "4. Create or link one order from confirmed Inbox intake.",
      "5. Confirm Dashboard, Workbench, Tasks, and Audit show the handoff."
    ]

    return SpaceMailReleaseSnapshot(
      verdict: verdict,
      detail: detail,
      generatedDate: generatedDate,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Checks", value: "\(completedChecks)/\(totalChecks)", tone: tone),
        SpaceMailReleaseSnapshotMetric(title: "Providers", value: "\(mailboxProviderSetupCount)", tone: providerBlockers == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Fetched", value: "\(totalFetched)", tone: totalFetched > 0 ? "neutral" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(totalImported)", tone: totalImported > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(totalFiltered)", tone: totalFiltered > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Handoff", value: "\(handoffAttention)", tone: handoffAttention == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Release task", value: "\(openReleaseReadinessTaskCount)", tone: spaceMailIMAPConnections.isEmpty && gmailMailboxConnections.isEmpty ? "neutral" : hasOpenReleaseReadinessTask ? "success" : "attention")
      ],
      reportText: reportLines.joined(separator: "\n")
    )
  }

  var mailboxReleaseBlockerSummary: MailboxReleaseBlockerSummary {
    let providerQA = mailboxProviderQACheckSummary
    let intakeQuality = mailboxIntakeQualitySummary
    let comparison = mailboxProviderComparisonSummary
    let handoff = mailboxOperationsHandoffSummary
    let gmailBlockers = gmailReleaseBlockerSummary.blockers.filter { $0.tone == "warning" || $0.tone == "attention" }
    var blockers: [MailboxReleaseBlockerItem] = []

    for check in providerQA.checks where !check.isComplete {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Provider QA",
          title: check.title,
          detail: check.evidence,
          nextAction: check.detail,
          tone: check.tone == "success" ? "neutral" : check.tone,
          symbol: check.tone == "warning" ? "exclamationmark.triangle.fill" : "wrench.and.screwdriver.fill"
        )
      )
    }

    for check in intakeQuality.checks where !check.isComplete {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Intake quality",
          title: check.title,
          detail: check.evidence,
          nextAction: check.detail,
          tone: check.tone == "success" ? "neutral" : check.tone,
          symbol: check.tone == "warning" ? "exclamationmark.triangle.fill" : "doc.text.magnifyingglass"
        )
      )
    }

    for item in comparison.actionItems.prefix(4) {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: item.providerName,
          title: item.title,
          detail: item.detail,
          nextAction: "Complete this provider action before treating mailbox intake as release-ready.",
          tone: item.tone,
          symbol: item.symbol
        )
      )
    }

    for line in handoff.lines where line.tone == "warning" || line.tone == "attention" {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Operator handoff",
          title: line.title,
          detail: line.detail,
          nextAction: "Clear this handoff item or create a follow-up task from the release snapshot.",
          tone: line.tone,
          symbol: line.symbol
        )
      )
    }

    for blocker in gmailBlockers {
      blockers.append(
        MailboxReleaseBlockerItem(
          source: "Gmail: \(blocker.source)",
          title: blocker.title,
          detail: blocker.detail,
          nextAction: blocker.nextAction,
          tone: blocker.tone,
          symbol: blocker.symbol
        )
      )
    }

    let warningCount = blockers.filter { $0.tone == "warning" }.count
    let attentionCount = blockers.filter { $0.tone == "attention" }.count
    let uniqueBlockers = Array(
      Dictionary(grouping: blockers, by: { "\($0.source)-\($0.title)-\($0.detail)" })
        .compactMap { $0.value.first }
        .sorted { lhs, rhs in
          let lhsRank = lhs.tone == "warning" ? 0 : lhs.tone == "attention" ? 1 : 2
          let rhsRank = rhs.tone == "warning" ? 0 : rhs.tone == "attention" ? 1 : 2
          if lhsRank != rhsRank { return lhsRank < rhsRank }
          return lhs.source < rhs.source
        }
    )

    let title: String
    let detail: String
    let tone: String
    if warningCount > 0 {
      title = "Mailbox release has blocking items"
      detail = "\(warningCount) high-priority blocker\(warningCount == 1 ? "" : "s") should be resolved before release-candidate testing."
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Mailbox release needs operator review"
      detail = "\(attentionCount) review item\(attentionCount == 1 ? "" : "s") should be handled or tracked as follow-up before relying on mailbox results."
      tone = "attention"
    } else {
      title = "Mailbox release blockers are clear"
      detail = "Provider setup, intake quality, and handoff checks do not currently show release blockers."
      tone = "success"
    }

    return MailboxReleaseBlockerSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Review", value: "\(attentionCount)", tone: attentionCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Provider QA", value: "\(providerQA.completedCount)/\(providerQA.totalCount)", tone: providerQA.tone),
        SpaceMailReleaseSnapshotMetric(title: "Intake QA", value: "\(intakeQuality.completedCount)/\(intakeQuality.totalCount)", tone: intakeQuality.tone),
        SpaceMailReleaseSnapshotMetric(title: "Gmail", value: "\(gmailBlockers.count)", tone: gmailBlockers.contains { $0.tone == "warning" } ? "warning" : gmailBlockers.isEmpty ? "success" : "attention")
      ],
      blockers: Array(uniqueBlockers.prefix(8))
    )
  }

  var mailboxRunTimelineSummary: MailboxRunTimelineSummary {
    let spaceMailEntries = spaceMailIMAPConnections.flatMap { connection in
      connection.refreshHistory.prefix(5).map { entry in
        MailboxRunTimelineEntry(
          id: "spacemail-\(entry.id.uuidString)",
          provider: "SpaceMail",
          timestamp: entry.timestamp,
          title: connection.displayName,
          detail: "\(entry.fetchedCount) fetched, \(entry.importedCount) imported, \(entry.duplicateCount) duplicates, \(entry.filteredNonOrderCount) filtered, \(entry.uncertainCount) uncertain.",
          outcome: entry.status,
          tone: entry.importedCount > 0 || entry.uncertainCount > 0 ? "attention" : (entry.status.localizedCaseInsensitiveContains("success") || entry.filteredNonOrderCount > 0 || entry.duplicateCount > 0 ? "success" : "warning"),
          symbol: "server.rack"
        )
      }
    }

    let gmailEvents = auditEvents.filter { event in
      event.entityType == .gmailMailboxConnection
        && (
          event.summary.localizedCaseInsensitiveContains("Gmail refresh")
            || event.summary.localizedCaseInsensitiveContains("Gmail mailbox fetch")
            || event.afterDetail?.localizedCaseInsensitiveContains("Gmail refresh") == true
        )
    }
    let gmailEntries = gmailEvents.prefix(8).map { event in
      let detail = event.afterDetail ?? ""
      let tone: String
      if event.summary.localizedCaseInsensitiveContains("failed")
        || event.summary.localizedCaseInsensitiveContains("blocked")
        || detail.localizedCaseInsensitiveContains("Status: Auth required")
        || detail.localizedCaseInsensitiveContains("Status: API rejected") {
        tone = "warning"
      } else if detail.localizedCaseInsensitiveContains("Imported: 0")
        && detail.localizedCaseInsensitiveContains("Filtered non-order:") {
        tone = "success"
      } else if detail.localizedCaseInsensitiveContains("Imported:")
        || detail.localizedCaseInsensitiveContains("Uncertain:") {
        tone = "attention"
      } else {
        tone = "neutral"
      }
      return MailboxRunTimelineEntry(
        id: "gmail-\(event.id.uuidString)",
        provider: "Gmail",
        timestamp: event.timestamp,
        title: event.entityLabel,
        detail: event.summary,
        outcome: event.action.rawValue,
        tone: tone,
        symbol: "envelope.badge.shield.half.filled"
      )
    }

    let entries = Array((spaceMailEntries + gmailEntries).sorted { $0.timestamp > $1.timestamp }.prefix(8))
    let importedCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshImportedCount }
    let filteredCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
      + gmailMailboxConnections.reduce(0) { $0 + $1.lastRefreshFilteredNonOrderCount }
    let uncertainCount = spaceMailIMAPConnections.reduce(0) { $0 + max($1.lastRefreshUncertainCount, $1.uncertainMessages.count) }
      + gmailMailboxConnections.reduce(0) { $0 + max($1.lastRefreshUncertainCount ?? 0, $1.uncertainMessages?.count ?? 0) }
    let warningCount = entries.filter { $0.tone == "warning" }.count
    let attentionCount = entries.filter { $0.tone == "attention" }.count

    let title: String
    let detail: String
    let tone: String
    if entries.isEmpty {
      title = "Mailbox run timeline is empty"
      detail = "Run a manual mailbox refresh to build handoff history."
      tone = "attention"
    } else if warningCount > 0 {
      title = "Mailbox run timeline has failed or blocked runs"
      detail = "\(warningCount) recent run\(warningCount == 1 ? "" : "s") need setup or auth review before relying on mailbox intake."
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Mailbox run timeline has operator work"
      detail = "\(attentionCount) recent run\(attentionCount == 1 ? "" : "s") produced imported or uncertain work for Inbox review."
      tone = "attention"
    } else {
      title = "Mailbox run timeline is stable"
      detail = "Recent refreshes show no unresolved imported or uncertain mailbox work."
      tone = "success"
    }

    return MailboxRunTimelineSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Runs", value: "\(entries.count)", tone: entries.isEmpty ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Review", value: "\(attentionCount)", tone: attentionCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Imported", value: "\(importedCount)", tone: importedCount > 0 ? "attention" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Filtered", value: "\(filteredCount)", tone: filteredCount > 0 ? "success" : "neutral"),
        SpaceMailReleaseSnapshotMetric(title: "Uncertain", value: "\(uncertainCount)", tone: uncertainCount > 0 ? "attention" : "success")
      ],
      entries: entries
    )
  }

  var mailboxReleaseTestPlanSummary: MailboxReleaseTestPlanSummary {
    let providerQA = mailboxProviderQACheckSummary
    let intakeQA = mailboxIntakeQualitySummary
    let blockers = mailboxReleaseBlockerSummary
    let timeline = mailboxRunTimelineSummary
    let handoff = mailboxOperationsHandoffSummary

    let providerReady = providerQA.tone == "success" || providerQA.completedCount >= max(providerQA.totalCount - 1, 1)
    let hasRunEvidence = !timeline.entries.isEmpty
    let hasCleanRun = timeline.entries.contains { $0.tone == "success" || $0.tone == "attention" }
    let hasImportedOrUncertain = mailboxRunTimelineSummary.metrics.contains { metric in
      (metric.title == "Imported" || metric.title == "Uncertain") && Int(metric.value) ?? 0 > 0
    }
    let hasInboxReview = !reviewIntakeEmails.isEmpty || intakeEmails.contains { $0.reviewState == .reviewed || $0.reviewState == .ignored }
    let hasOrderHandoff = orders.contains { $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import" || $0.isInboxCreatedLocalOrder }
      || intakeEmails.contains { $0.linkedOrderID != nil }
    let hasAuditTrail = auditEvents.contains { event in
      [.spaceMailIMAPConnection, .gmailMailboxConnection, .intakeEmail, .order, .reviewTask].contains(event.entityType)
    }
    let hasNoReleaseBlockers = blockers.blockers.filter { $0.tone == "warning" }.isEmpty
    let intakeReady = intakeQA.tone == "success" || intakeQA.completedCount >= max(intakeQA.totalCount - 2, 1)

    let steps = [
      MailboxReleaseTestPlanStep(
        title: "1. Provider setup",
        detail: "Confirm at least one mailbox provider has setup, credential/sign-in evidence, and read-only boundaries.",
        evidence: "\(providerQA.completedCount) of \(providerQA.totalCount) provider QA checks complete.",
        nextAction: providerReady ? "Provider setup evidence is sufficient for a supervised test." : "Finish the highest-priority provider QA item.",
        isComplete: providerReady,
        tone: providerReady ? "success" : "warning",
        symbol: "server.rack"
      ),
      MailboxReleaseTestPlanStep(
        title: "2. Manual refresh run",
        detail: "Run or review one explicit read-only mailbox refresh.",
        evidence: hasRunEvidence ? "\(timeline.entries.count) recent mailbox run\(timeline.entries.count == 1 ? "" : "s") available." : "No mailbox run timeline entry exists yet.",
        nextAction: hasCleanRun ? "Use the latest run to test Inbox triage." : "Run one manual provider refresh; keep mock refresh separate from real refresh.",
        isComplete: hasRunEvidence && hasCleanRun,
        tone: hasRunEvidence && hasCleanRun ? "success" : "attention",
        symbol: "clock.arrow.circlepath"
      ),
      MailboxReleaseTestPlanStep(
        title: "3. Intake quality",
        detail: "Check imported, duplicate, filtered, uncertain, and parser outcomes before creating operational work.",
        evidence: "\(intakeQA.completedCount) of \(intakeQA.totalCount) intake QA checks complete.",
        nextAction: intakeReady ? "Review any visible parser or uncertain items, then continue." : "Use Mailbox Monitor to review parser diagnostics and uncertain messages.",
        isComplete: intakeReady,
        tone: intakeReady ? "success" : "attention",
        symbol: "doc.text.magnifyingglass"
      ),
      MailboxReleaseTestPlanStep(
        title: "4. Inbox triage",
        detail: "Confirm one imported or reviewable mailbox message can be reviewed, ignored, linked, or converted locally.",
        evidence: hasImportedOrUncertain ? "Latest run has imported or uncertain review work." : "\(reviewIntakeEmails.count) Inbox row\(reviewIntakeEmails.count == 1 ? "" : "s") currently need review.",
        nextAction: hasInboxReview ? "Open Inbox or Mailbox Monitor and complete one local triage decision." : "Send or use a known test order email, refresh, then triage the row.",
        isComplete: hasInboxReview,
        tone: hasInboxReview ? "success" : "attention",
        symbol: "tray.full.fill"
      ),
      MailboxReleaseTestPlanStep(
        title: "5. Order handoff",
        detail: "Create or link one local order from confirmed intake and verify it appears in Orders, Dashboard, Workbench, and Tasks context.",
        evidence: hasOrderHandoff ? "Inbox/order source trail exists." : "No Inbox-created or linked order evidence yet.",
        nextAction: hasOrderHandoff ? "Open Orders and confirm the source trail." : "Use Inbox Create order or Link order on a confirmed intake row.",
        isComplete: hasOrderHandoff,
        tone: hasOrderHandoff ? "success" : "attention",
        symbol: "shippingbox.fill"
      ),
      MailboxReleaseTestPlanStep(
        title: "6. Release blockers",
        detail: "Confirm the release blocker queue has no high-priority warnings.",
        evidence: "\(blockers.blockers.filter { $0.tone == "warning" }.count) warning blocker\(blockers.blockers.filter { $0.tone == "warning" }.count == 1 ? "" : "s") and \(blockers.blockers.filter { $0.tone == "attention" }.count) review item\(blockers.blockers.filter { $0.tone == "attention" }.count == 1 ? "" : "s").",
        nextAction: hasNoReleaseBlockers ? "Track remaining review items as follow-up if needed." : "Resolve the warning blockers before release-candidate testing.",
        isComplete: hasNoReleaseBlockers,
        tone: hasNoReleaseBlockers ? "success" : "warning",
        symbol: "exclamationmark.octagon.fill"
      ),
      MailboxReleaseTestPlanStep(
        title: "7. Audit and persistence",
        detail: "Confirm local actions are visible in Audit and persist after reopening the app.",
        evidence: hasAuditTrail ? "\(auditEvents.count) audit event\(auditEvents.count == 1 ? "" : "s") available." : "No mailbox/intake/order audit trail evidence yet.",
        nextAction: hasAuditTrail ? "Quit and reopen the app, then confirm the same local records remain." : "Complete one triage or release follow-up action to generate audit evidence.",
        isComplete: hasAuditTrail,
        tone: hasAuditTrail ? "success" : "attention",
        symbol: "list.clipboard.fill"
      )
    ]

    let completedCount = steps.filter(\.isComplete).count
    let warningCount = steps.filter { !$0.isComplete && $0.tone == "warning" }.count
    let title: String
    let detail: String
    let tone: String
    if completedCount == steps.count {
      title = "Mailbox release test plan is ready"
      detail = "All mailbox release test steps have local evidence. Run the hands-on pass and record any real operator issues."
      tone = "success"
    } else if warningCount > 0 {
      title = "Mailbox release test plan has blockers"
      detail = "\(completedCount) of \(steps.count) steps have evidence. Resolve warning steps before treating mailbox intake as release-ready."
      tone = "warning"
    } else {
      title = "Mailbox release test plan is in progress"
      detail = "\(completedCount) of \(steps.count) steps have evidence. Complete the remaining local checks during the next hands-on pass."
      tone = "attention"
    }

    return MailboxReleaseTestPlanSummary(
      title: title,
      detail: detail,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Steps", value: "\(completedCount)/\(steps.count)", tone: tone),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(warningCount)", tone: warningCount == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Runs", value: "\(timeline.entries.count)", tone: timeline.entries.isEmpty ? "attention" : "success"),
        SpaceMailReleaseSnapshotMetric(title: "Handoff", value: handoff.tone == "success" || handoff.tone == "neutral" ? "Ready" : "Review", tone: handoff.tone),
        SpaceMailReleaseSnapshotMetric(title: "Audit", value: "\(auditEvents.count)", tone: auditEvents.isEmpty ? "attention" : "success")
      ],
      steps: steps
    )
  }

  var mailboxOperatorDecisionSummary: MailboxOperatorDecisionSummary {
    let blockers = mailboxReleaseBlockerSummary
    let timeline = mailboxRunTimelineSummary
    let testPlan = mailboxReleaseTestPlanSummary
    let providerQA = mailboxProviderQACheckSummary
    let intakeQA = mailboxIntakeQualitySummary
    let warningBlockers = blockers.blockers.filter { $0.tone == "warning" }.count
    let reviewBlockers = blockers.blockers.filter { $0.tone == "attention" }.count
    let hasProviderSetup = !spaceMailIMAPConnections.isEmpty || !gmailMailboxConnections.isEmpty || !microsoft365MailboxConnections.isEmpty
    let hasRefreshEvidence = !timeline.entries.isEmpty
    let openInboxCount = reviewIntakeEmails.count
    let uncertainCount = spaceMailIMAPConnections.reduce(0) { $0 + max($1.uncertainMessages.count, $1.lastRefreshUncertainCount) }
      + gmailMailboxConnections.reduce(0) { $0 + max($1.uncertainMessages?.count ?? 0, $1.lastRefreshUncertainCount ?? 0) }
    let parserIssueCount = intakeParserDiagnostics.count
    let linkedOrderCount = intakeEmails.filter { $0.linkedOrderID != nil }.count
    let inboxCreatedOrderCount = inboxCreatedOrders.count
    let openTaskCount = reviewTasksNeedingAttention.count + handoffNotesNeedingAttention.count
    let latestRunHasAction = timeline.entries.contains { $0.tone == "attention" }

    let decisions = [
      MailboxOperatorDecisionItem(
        title: "Fix setup blockers first",
        detail: "\(warningBlockers) warning blocker\(warningBlockers == 1 ? "" : "s") currently prevent a clean mailbox release pass.",
        action: "Open the blocker queue and resolve warning items before refreshing again.",
        isActive: warningBlockers > 0,
        tone: warningBlockers > 0 ? "warning" : "success",
        symbol: "exclamationmark.triangle.fill"
      ),
      MailboxOperatorDecisionItem(
        title: "Run a manual mailbox refresh",
        detail: hasRefreshEvidence ? "A refresh timeline exists; run again only when checking for new mail." : "No manual mailbox run is recorded yet.",
        action: "Use the active provider's explicit manual refresh button. Keep mock refresh separate.",
        isActive: hasProviderSetup && !hasRefreshEvidence && warningBlockers == 0,
        tone: hasProviderSetup && !hasRefreshEvidence && warningBlockers == 0 ? "attention" : "neutral",
        symbol: "clock.arrow.circlepath"
      ),
      MailboxOperatorDecisionItem(
        title: "Review imported Inbox work",
        detail: "\(openInboxCount) Inbox intake row\(openInboxCount == 1 ? "" : "s") need review; latest run action flag: \(latestRunHasAction ? "yes" : "no").",
        action: "Open Inbox or Mailbox Monitor, then review, ignore, link, or create orders from confirmed rows.",
        isActive: openInboxCount > 0 || latestRunHasAction,
        tone: openInboxCount > 0 || latestRunHasAction ? "attention" : "success",
        symbol: "tray.full.fill"
      ),
      MailboxOperatorDecisionItem(
        title: "Review uncertain or parser items",
        detail: "\(uncertainCount) uncertain preview\(uncertainCount == 1 ? "" : "s") and \(parserIssueCount) parser diagnostic\(parserIssueCount == 1 ? "" : "s") are visible.",
        action: "Import true order messages, dismiss non-order messages, and reprocess parser rows where needed.",
        isActive: uncertainCount + parserIssueCount > 0,
        tone: uncertainCount + parserIssueCount > 0 ? "attention" : "success",
        symbol: "doc.text.magnifyingglass"
      ),
      MailboxOperatorDecisionItem(
        title: "Create or verify order handoff",
        detail: "\(linkedOrderCount) linked intake row\(linkedOrderCount == 1 ? "" : "s"); \(inboxCreatedOrderCount) Inbox-created order\(inboxCreatedOrderCount == 1 ? "" : "s").",
        action: "Use Create order or Link order, then confirm Orders and order detail show the source trail.",
        isActive: linkedOrderCount == 0 && inboxCreatedOrderCount == 0 && openInboxCount > 0,
        tone: linkedOrderCount == 0 && inboxCreatedOrderCount == 0 ? "attention" : "success",
        symbol: "shippingbox.fill"
      ),
      MailboxOperatorDecisionItem(
        title: "Record release follow-up",
        detail: "\(reviewBlockers) review item\(reviewBlockers == 1 ? "" : "s"); \(openTaskCount) task or handoff follow-up\(openTaskCount == 1 ? "" : "s") currently open.",
        action: "Create a mailbox release follow-up task from the snapshot if anything remains for the next session.",
        isActive: reviewBlockers > 0 && openTaskCount == 0,
        tone: reviewBlockers > 0 && openTaskCount == 0 ? "attention" : "neutral",
        symbol: "checklist"
      )
    ]

    let activeDecisions = decisions.filter(\.isActive)
    let primaryAction: String
    let title: String
    let detail: String
    let tone: String
    if let firstWarning = activeDecisions.first(where: { $0.tone == "warning" }) {
      primaryAction = firstWarning.action
      title = "Mailbox decision: stop and fix blockers"
      detail = firstWarning.detail
      tone = "warning"
    } else if let firstActive = activeDecisions.first {
      primaryAction = firstActive.action
      title = "Mailbox decision: \(firstActive.title.lowercased())"
      detail = firstActive.detail
      tone = firstActive.tone == "success" ? "attention" : firstActive.tone
    } else if testPlan.tone == "success" {
      primaryAction = "Run the hands-on release pass, then tag or document the local MVP state."
      title = "Mailbox decision: ready for release-candidate pass"
      detail = "Provider setup, intake quality, run timeline, handoff, and blockers do not currently require action."
      tone = "success"
    } else {
      primaryAction = "Review the release test plan and complete the next incomplete step."
      title = "Mailbox decision: continue readiness checks"
      detail = testPlan.detail
      tone = testPlan.tone
    }

    return MailboxOperatorDecisionSummary(
      title: title,
      detail: detail,
      primaryAction: primaryAction,
      tone: tone,
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Provider QA", value: "\(providerQA.completedCount)/\(providerQA.totalCount)", tone: providerQA.tone),
        SpaceMailReleaseSnapshotMetric(title: "Intake QA", value: "\(intakeQA.completedCount)/\(intakeQA.totalCount)", tone: intakeQA.tone),
        SpaceMailReleaseSnapshotMetric(title: "Blockers", value: "\(warningBlockers)", tone: warningBlockers == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Inbox", value: "\(openInboxCount)", tone: openInboxCount == 0 ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Orders", value: "\(linkedOrderCount + inboxCreatedOrderCount)", tone: linkedOrderCount + inboxCreatedOrderCount > 0 ? "success" : "attention")
      ],
      decisions: decisions
    )
  }

  var mailboxProviderSetupChecklistSummary: MailboxProviderSetupChecklistSummary {
    func hasUsefulText(_ value: String) -> Bool {
      !value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        && value != "Never"
        && value.localizedCaseInsensitiveCompare("unknown") != .orderedSame
    }

    func credentialLooksReady(_ value: String) -> Bool {
      value.localizedCaseInsensitiveContains("available")
        || value.localizedCaseInsensitiveContains("ready")
        || value.localizedCaseInsensitiveContains("keychain")
        || value.localizedCaseInsensitiveContains("managed")
    }

    let spaceMail = spaceMailIMAPConnections.first
    let gmail = gmailMailboxConnections.first
    let microsoft365 = microsoft365MailboxConnections.first
    let gmailReadiness = gmail.map(gmailOAuthReadinessSummary(for:))
    let gmailAuth = gmail.map(gmailAuthSessionState(for:))
    let microsoft365Readiness = microsoft365.map(microsoft365OAuthReadinessSummary(for:))
    let microsoft365Auth = microsoft365.map(microsoft365AuthSessionState(for:))

    let spaceMailChecks = [
      MailboxProviderSetupChecklistItem(
        title: "Setup record",
        detail: spaceMail == nil ? "Add a SpaceMail IMAP placeholder before testing real refresh." : "\(spaceMail?.displayName ?? "SpaceMail") is saved locally.",
        isComplete: spaceMail != nil,
        tone: spaceMail == nil ? "warning" : "success",
        symbol: "server.rack"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Host, port, security, folder",
        detail: spaceMail == nil ? "Needs host, port 993, SSL/TLS, and INBOX or selected folder." : "\(spaceMail?.imapHost ?? ""):\(spaceMail?.imapPort ?? "") • \(spaceMail?.securityMode ?? "") • \(spaceMail?.folderName ?? "")",
        isComplete: spaceMail.map { hasUsefulText($0.imapHost) && hasUsefulText($0.imapPort) && hasUsefulText($0.securityMode) && hasUsefulText($0.folderName) } ?? false,
        tone: spaceMail.map { hasUsefulText($0.imapHost) && hasUsefulText($0.imapPort) && hasUsefulText($0.securityMode) && hasUsefulText($0.folderName) } == true ? "success" : "attention",
        symbol: "checklist.checked"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Keychain credential",
        detail: spaceMail?.credentialStorageStatus ?? "Password reference is not configured.",
        isComplete: spaceMail.map { credentialLooksReady($0.credentialStorageStatus) } ?? false,
        tone: spaceMail.map { credentialLooksReady($0.credentialStorageStatus) } == true ? "success" : "warning",
        symbol: "key.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Mailbox mode",
        detail: spaceMail?.mailboxMode.rawValue ?? "Choose dedicated or mixed mailbox filtering.",
        isComplete: spaceMail != nil,
        tone: spaceMail == nil ? "attention" : "success",
        symbol: "line.3.horizontal.decrease.circle"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Manual refresh evidence",
        detail: spaceMail == nil ? "No SpaceMail refresh has run." : "Last refresh: \(spaceMail?.lastManualRefreshDate ?? "Never"). \(spaceMail?.lastRefreshSummary ?? "")",
        isComplete: spaceMail.map { $0.lastManualRefreshDate != "Never" } ?? false,
        tone: spaceMail.map { $0.lastManualRefreshDate != "Never" } == true ? "success" : "attention",
        symbol: "arrow.clockwise.circle.fill"
      )
    ]

    let gmailChecks = [
      MailboxProviderSetupChecklistItem(
        title: "Setup record",
        detail: gmail == nil ? "Add Gmail only for Gmail-hosted mailboxes." : "\(gmail?.displayName ?? "Gmail") is saved locally.",
        isComplete: gmail != nil,
        tone: gmail == nil ? "neutral" : "success",
        symbol: "envelope.badge.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "OAuth placeholders",
        detail: gmailReadiness?.missingFields.isEmpty == true ? "Google Cloud OAuth setup is complete enough for sign-in testing." : (gmailReadiness?.missingFields.prefix(3).joined(separator: ", ") ?? "OAuth client, callback scheme, scopes, and consent notes are not configured."),
        isComplete: gmailReadiness?.isReady == true,
        tone: gmailReadiness?.isReady == true ? "success" : (gmail == nil ? "neutral" : "warning"),
        symbol: "person.badge.key.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Auth session",
        detail: gmailAuth == nil ? "No Gmail auth state yet." : "Status: \(gmailAuth?.status.rawValue ?? "Unknown").",
        isComplete: gmailAuth?.status == .connected,
        tone: gmailAuth?.status == .connected ? "success" : (gmail == nil ? "neutral" : "attention"),
        symbol: "person.crop.circle.badge.checkmark"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Read-only scopes",
        detail: gmail?.requestedScopesSummary ?? "Plan gmail.readonly before real Gmail refresh.",
        isComplete: gmail?.requestedScopesSummary.localizedCaseInsensitiveContains("gmail.readonly") == true
          || gmail?.requestedScopesSummary.localizedCaseInsensitiveContains("gmail.metadata") == true,
        tone: (gmail?.requestedScopesSummary.localizedCaseInsensitiveContains("gmail.readonly") == true
          || gmail?.requestedScopesSummary.localizedCaseInsensitiveContains("gmail.metadata") == true) ? "success" : (gmail == nil ? "neutral" : "attention"),
        symbol: "lock.doc.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Manual refresh evidence",
        detail: gmail == nil ? "No Gmail refresh has run." : "Last refresh: \(gmail?.lastManualRefreshDate ?? "Never"). \(gmail?.lastRefreshSummary ?? "")",
        isComplete: gmail.map { $0.lastManualRefreshDate != "Never" } ?? false,
        tone: gmail.map { $0.lastManualRefreshDate != "Never" } == true ? "success" : (gmail == nil ? "neutral" : "attention"),
        symbol: "arrow.clockwise.circle.fill"
      )
    ]

    let microsoft365Checks = [
      MailboxProviderSetupChecklistItem(
        title: "Setup record",
        detail: microsoft365 == nil ? "Add Outlook / Microsoft 365 only for Microsoft-hosted mailboxes." : "\(microsoft365?.displayName ?? "Microsoft 365") is saved locally.",
        isComplete: microsoft365 != nil,
        tone: microsoft365 == nil ? "neutral" : "success",
        symbol: "mail.stack.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "OAuth placeholders",
        detail: microsoft365Readiness?.missingFields.isEmpty == true ? "Microsoft Entra OAuth setup is complete enough for sign-in testing." : (microsoft365Readiness?.missingFields.prefix(3).joined(separator: ", ") ?? "Tenant ID, client ID, redirect URI, scopes, and consent notes are not configured."),
        isComplete: microsoft365Readiness?.isReady == true,
        tone: microsoft365Readiness?.isReady == true ? "success" : (microsoft365 == nil ? "neutral" : "warning"),
        symbol: "person.badge.key.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Auth session",
        detail: microsoft365Auth == nil ? "No Microsoft 365 auth state yet." : "Status: \(microsoft365Auth?.status.rawValue ?? "Unknown").",
        isComplete: microsoft365Auth?.status == .connected,
        tone: microsoft365Auth?.status == .connected ? "success" : (microsoft365 == nil ? "neutral" : "attention"),
        symbol: "person.crop.circle.badge.checkmark"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Read-only scopes",
        detail: microsoft365?.requestedScopesSummary ?? "Plan User.Read and Mail.Read before real Outlook refresh.",
        isComplete: microsoft365?.requestedScopesSummary.localizedCaseInsensitiveContains("Mail.Read") == true,
        tone: microsoft365?.requestedScopesSummary.localizedCaseInsensitiveContains("Mail.Read") == true ? "success" : (microsoft365 == nil ? "neutral" : "attention"),
        symbol: "lock.doc.fill"
      ),
      MailboxProviderSetupChecklistItem(
        title: "Manual refresh evidence",
        detail: microsoft365 == nil ? "No Outlook refresh has run." : "Last refresh: \(microsoft365?.lastManualRefreshDate ?? "Never"). \(microsoft365?.connectionStatus ?? "")",
        isComplete: microsoft365.map { $0.lastManualRefreshDate != "Never" } ?? false,
        tone: microsoft365.map { $0.lastManualRefreshDate != "Never" } == true ? "success" : (microsoft365 == nil ? "neutral" : "attention"),
        symbol: "arrow.clockwise.circle.fill"
      )
    ]

    func providerTone(for checks: [MailboxProviderSetupChecklistItem], optional: Bool = false) -> String {
      let incompleteRequired = checks.filter { !$0.isComplete && $0.tone != "neutral" }.count
      if optional && checks.allSatisfy({ $0.tone == "neutral" || !$0.isComplete }) {
        return "neutral"
      }
      if checks.contains(where: { !$0.isComplete && $0.tone == "warning" }) {
        return "warning"
      }
      return incompleteRequired == 0 ? "success" : "attention"
    }

    let spaceMailIsOptional = spaceMail == nil && (gmail != nil || microsoft365 != nil)
    let spaceMailTone = providerTone(for: spaceMailChecks, optional: spaceMailIsOptional)
    let gmailTone = providerTone(for: gmailChecks, optional: gmail == nil)
    let microsoft365Tone = providerTone(for: microsoft365Checks, optional: microsoft365 == nil)

    struct ProviderDecisionCandidate {
      var name: String
      var tone: String
      var hasSetup: Bool
      var hasRefresh: Bool
      var nextAction: String
      var blockers: [String]
    }

    func blockerTitles(from checks: [MailboxProviderSetupChecklistItem]) -> [String] {
      checks
        .filter { !$0.isComplete && $0.tone != "neutral" }
        .map(\.title)
    }

    let providerCandidates = [
      ProviderDecisionCandidate(
        name: "SpaceMail IMAP",
        tone: spaceMailTone,
        hasSetup: spaceMail != nil,
        hasRefresh: spaceMail.map { $0.lastManualRefreshDate != "Never" } ?? false,
        nextAction: spaceMailIsOptional ? "Leave SpaceMail aside unless this mailbox is hosted through IMAP." : (spaceMailTone == "success" ? "Use SpaceMail for the next manual read-only refresh." : "Finish SpaceMail host/folder and Keychain credential setup before relying on refresh."),
        blockers: blockerTitles(from: spaceMailChecks)
      ),
      ProviderDecisionCandidate(
        name: "Gmail",
        tone: gmailTone,
        hasSetup: gmail != nil,
        hasRefresh: gmail.map { $0.lastManualRefreshDate != "Never" } ?? false,
        nextAction: gmail == nil ? "Add Gmail only when the mailbox is Gmail-hosted." : (gmailTone == "success" ? "Use Gmail for the next hosted-mailbox readiness test." : "Finish Google OAuth placeholders and sign-in readiness before real Gmail refresh."),
        blockers: blockerTitles(from: gmailChecks)
      ),
      ProviderDecisionCandidate(
        name: "Outlook",
        tone: microsoft365Tone,
        hasSetup: microsoft365 != nil,
        hasRefresh: microsoft365.map { $0.lastManualRefreshDate != "Never" } ?? false,
        nextAction: microsoft365 == nil ? "Add Outlook only when the mailbox is Microsoft-hosted." : (microsoft365Tone == "success" ? "Use Outlook for the next Microsoft Graph readiness test." : "Finish Entra/OAuth setup and sign-in before real Graph refresh."),
        blockers: blockerTitles(from: microsoft365Checks)
      )
    ]

    let configuredCandidates = providerCandidates.filter(\.hasSetup)
    let usableCandidates = configuredCandidates.filter { $0.tone == "success" }
    let refreshedCandidates = configuredCandidates.filter(\.hasRefresh)
    let primaryProviderTitle: String
    let primaryProviderDetail: String
    let primaryProviderNextAction: String
    let topBlockers: [String]
    if let refreshedUsable = usableCandidates.first(where: { $0.hasRefresh }) {
      primaryProviderTitle = "\(refreshedUsable.name) is the current proven path"
      primaryProviderDetail = "It has setup, credential/sign-in, and manual refresh evidence. Keep other providers as optional unless a mailbox changes host."
      primaryProviderNextAction = refreshedUsable.nextAction
      topBlockers = configuredCandidates
        .filter { $0.name != refreshedUsable.name }
        .flatMap { candidate in candidate.blockers.prefix(2).map { "\(candidate.name): \($0)" } }
    } else if let usable = usableCandidates.first {
      primaryProviderTitle = "\(usable.name) is the closest ready path"
      primaryProviderDetail = "Setup looks complete, but run a manual read-only refresh to collect current intake evidence."
      primaryProviderNextAction = usable.nextAction
      topBlockers = configuredCandidates
        .filter { $0.name != usable.name }
        .flatMap { candidate in candidate.blockers.prefix(2).map { "\(candidate.name): \($0)" } }
    } else if let refreshed = refreshedCandidates.first {
      primaryProviderTitle = "\(refreshed.name) has refresh evidence but still needs review"
      primaryProviderDetail = "A refresh has run, but setup checks still show blockers. Treat the latest results as diagnostic until the blockers are cleared."
      primaryProviderNextAction = refreshed.nextAction
      topBlockers = refreshed.blockers.prefix(4).map { "\(refreshed.name): \($0)" }
    } else if let configured = configuredCandidates.first {
      primaryProviderTitle = "\(configured.name) is configured but not proven"
      primaryProviderDetail = "Complete the listed setup checks, then run one explicit manual read-only refresh before treating it as the active intake path."
      primaryProviderNextAction = configured.nextAction
      topBlockers = configured.blockers.prefix(4).map { "\(configured.name): \($0)" }
    } else {
      primaryProviderTitle = "No mailbox provider is ready yet"
      primaryProviderDetail = "Add one provider setup record first. For the current project, SpaceMail IMAP is the practical path when using the caught@droctopus.net mailbox."
      primaryProviderNextAction = "Set up SpaceMail IMAP, save/check the Keychain credential, then run one manual read-only refresh."
      topBlockers = ["No provider setup record", "No credential or sign-in evidence", "No manual refresh evidence"]
    }

    let providers = [
      MailboxProviderSetupChecklistProvider(
        providerName: "SpaceMail IMAP",
        status: spaceMailIsOptional ? "Optional, not configured" : (spaceMailTone == "success" ? "Ready for manual read-only refresh" : "Setup needs attention"),
        detail: "Use for SpaceMail or generic IMAP mailboxes. Passwords stay in Keychain, not JSON.",
        nextAction: spaceMailIsOptional ? "Leave SpaceMail unconfigured unless an IMAP mailbox is needed." : (spaceMailTone == "success" ? "Run real SpaceMail refresh when checking new mail." : "Confirm setup fields and Keychain credential before refreshing."),
        tone: spaceMailTone,
        symbol: "server.rack",
        checks: spaceMailChecks
      ),
      MailboxProviderSetupChecklistProvider(
        providerName: "Gmail",
        status: gmail == nil ? "Optional, not configured" : (gmailTone == "success" ? "Ready for Gmail sign-in/refresh checks" : "Gmail setup needs attention"),
        detail: "Use only for Gmail-hosted mailboxes. OAuth/token values are not stored in JSON.",
        nextAction: gmail == nil ? "Leave Gmail unconfigured unless a Gmail mailbox is needed." : "Complete OAuth/client setup before real Gmail refresh testing.",
        tone: gmailTone,
        symbol: "g.circle.fill",
        checks: gmailChecks
      ),
      MailboxProviderSetupChecklistProvider(
        providerName: "Outlook",
        status: microsoft365 == nil ? "Optional, not configured" : (microsoft365Tone == "success" ? "Ready for Microsoft Graph refresh checks" : "Outlook setup needs attention"),
        detail: "Use only for Outlook / Microsoft 365 mailboxes hosted by Microsoft. MSAL manages its token cache; token values are not stored in JSON.",
        nextAction: microsoft365 == nil ? "Leave Outlook unconfigured unless a Microsoft 365 mailbox is needed." : "Complete Entra/OAuth setup and sign in before real Graph refresh testing.",
        tone: microsoft365Tone,
        symbol: "mail.stack.fill",
        checks: microsoft365Checks
      )
    ]

    var requiredChecks: [MailboxProviderSetupChecklistItem] = []
    if !(spaceMail == nil && (gmail != nil || microsoft365 != nil)) {
      requiredChecks.append(contentsOf: spaceMailChecks)
    }
    if gmail != nil {
      requiredChecks.append(contentsOf: gmailChecks)
    }
    if microsoft365 != nil {
      requiredChecks.append(contentsOf: microsoft365Checks)
    }
    let completedChecks = requiredChecks.filter(\.isComplete).count
    let totalChecks = requiredChecks.count
    let requiredWarnings = requiredChecks.filter { !$0.isComplete && $0.tone == "warning" }.count
    let refreshEvidence = spaceMailIMAPConnections.contains { $0.lastManualRefreshDate != "Never" }
      || gmailMailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
      || microsoft365MailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
    let summaryTone = requiredWarnings > 0 ? "warning" : (refreshEvidence ? "success" : "attention")

    return MailboxProviderSetupChecklistSummary(
      title: summaryTone == "success" ? "Provider setup checklist is usable" : "Provider setup checklist needs review",
      detail: "Compare SpaceMail, Gmail, and Outlook prerequisites before running manual mailbox refreshes. This checklist reads local setup state only.",
      tone: summaryTone,
      primaryProviderTitle: primaryProviderTitle,
      primaryProviderDetail: primaryProviderDetail,
      primaryProviderNextAction: primaryProviderNextAction,
      topBlockers: Array(topBlockers.prefix(5)),
      metrics: [
        SpaceMailReleaseSnapshotMetric(title: "Configured", value: "\(mailboxProviderSetupCount)", tone: hasMailboxProviderSetup ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Checks", value: "\(completedChecks)/\(totalChecks)", tone: completedChecks == totalChecks ? "success" : "attention"),
        SpaceMailReleaseSnapshotMetric(title: "Warnings", value: "\(requiredWarnings)", tone: requiredWarnings == 0 ? "success" : "warning"),
        SpaceMailReleaseSnapshotMetric(title: "Refresh evidence", value: refreshEvidence ? "Yes" : "No", tone: refreshEvidence ? "success" : "attention")
      ],
      providers: providers
    )
  }

  var localDataHygieneSummary: LocalDataHygieneSummary {
    func isPlaceholder(_ value: String) -> Bool {
      let normalized = value.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
      let compact = normalized.replacingOccurrences(of: " ", with: "")
      return normalized.isEmpty
        || normalized == "pending"
        || normalized == "unknown"
        || normalized == "no subject"
        || normalized == "unknown sender"
        || normalized == "unknown date"
        || normalized == "unassigned"
        || compact.contains("needsreview")
        || compact.contains("unknownsender")
        || compact.contains("unknowndate")
    }

    func preview(_ value: String, limit: Int = 72) -> String {
      let cleaned = value
        .replacingOccurrences(of: "\n", with: " ")
        .replacingOccurrences(of: "\t", with: " ")
        .trimmingCharacters(in: .whitespacesAndNewlines)
      guard cleaned.count > limit else { return cleaned.isEmpty ? "Untitled" : cleaned }
      return String(cleaned.prefix(limit - 1)) + "..."
    }

    let intakeIDs = Set(intakeEmails.map(\.id))
    let orderIDs = Set(orders.map(\.id))
    let duplicateIngestCount = mailboxIngestRecords.filter { $0.status == .duplicateSkipped }.count
    let orphanIngestCount = mailboxIngestRecords.filter { record in
      guard let intakeEmailID = record.intakeEmailID else { return false }
      return !intakeIDs.contains(intakeEmailID)
    }.count
    let orphanLinkedIntakeCount = intakeEmails.filter { email in
      guard let linkedOrderID = email.linkedOrderID else { return false }
      return !orderIDs.contains(linkedOrderID)
    }.count
    let placeholderIntakeCount = intakeEmails.filter { email in
      isPlaceholder(email.subject)
        || isPlaceholder(email.sender)
        || isPlaceholder(email.detectedOrderNumber)
        || isPlaceholder(email.detectedTrackingNumber)
        || email.rawBodyPreview.localizedCaseInsensitiveContains("Content-Type:")
        || email.rawBodyPreview.localizedCaseInsensitiveContains("Return-Path:")
    }.count
    let ignoredIntakeCount = intakeEmails.filter { $0.reviewState == .ignored }.count
    let reviewedUnlinkedIntakeCount = intakeEmails.filter { $0.reviewState == .reviewed && $0.linkedOrderID == nil }.count
    let pendingUncertainCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.uncertainMessages.count }
    let pendingFilteredReviewCount = spaceMailIMAPConnections.reduce(0) { $0 + $1.filteredMessages.count }
    let parserDiagnosticCount = intakeParserDiagnostics.count
    let inboxCreatedOrderCount = orders.filter { $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import" }.count
    let openPartialOrderTasks = reviewTasks.filter { $0.isPartialInboxOrderFollowUp && $0.status != .completed }.count
    let activeNoiseSignals = placeholderIntakeCount
      + orphanIngestCount
      + orphanLinkedIntakeCount
      + parserDiagnosticCount
      + pendingUncertainCount
      + openPartialOrderTasks

    let verdict: String
    let detail: String
    let nextAction: String
    let tone: String
    if activeNoiseSignals == 0 && reviewIntakeEmails.isEmpty {
      verdict = "Local data looks tidy enough for routine testing"
      detail = "No obvious intake, ingest, parser, or partial-order hygiene signals are active."
      nextAction = "Continue normal Inbox-to-Orders testing"
      tone = "success"
    } else if activeNoiseSignals <= 5 {
      verdict = "Local data has a small review load"
      detail = "\(activeNoiseSignals) hygiene signal\(activeNoiseSignals == 1 ? "" : "s") are visible. They can usually be handled from Inbox, Mailbox Monitor, or Tasks."
      nextAction = "Review flagged intake rows and partial order tasks"
      tone = "attention"
    } else {
      verdict = "Local data has accumulated testing noise"
      detail = "\(activeNoiseSignals) hygiene signals are visible, mostly from mailbox testing, parser diagnostics, duplicate ingest, or partial order handoff."
      nextAction = "Use Inbox, Mailbox Monitor, Tasks, and Audit to resolve or ignore records intentionally"
      tone = "warning"
    }

    var examples: [String] = []
    examples.append(contentsOf: intakeEmails.filter {
      isPlaceholder($0.subject) || isPlaceholder($0.sender) || isPlaceholder($0.detectedOrderNumber) || isPlaceholder($0.detectedTrackingNumber)
    }.prefix(3).map { "Intake needs cleanup: \(preview($0.subject))" })
    examples.append(contentsOf: spaceMailIMAPConnections.flatMap(\.uncertainMessages).prefix(2).map { "Uncertain SpaceMail: \(preview($0.subject))" })
    examples.append(contentsOf: intakeParserDiagnostics.prefix(2).map { "Parser diagnostic: \(preview($0.title))" })
    examples.append(contentsOf: reviewTasks.filter { $0.isPartialInboxOrderFollowUp && $0.status != .completed }.prefix(2).map { "Partial order task: \(preview($0.title))" })

    return LocalDataHygieneSummary(
      verdict: verdict,
      detail: detail,
      nextAction: nextAction,
      tone: tone,
      signalCount: activeNoiseSignals,
      metrics: [
        LocalDataHygieneMetric(title: "Intake placeholders", value: "\(placeholderIntakeCount)", detail: "Rows with missing sender, subject, order, tracking, or raw header-like preview text.", tone: placeholderIntakeCount == 0 ? "success" : "attention"),
        LocalDataHygieneMetric(title: "Needs review", value: "\(reviewIntakeEmails.count)", detail: "Forwarded intake emails still waiting for operator review.", tone: reviewIntakeEmails.isEmpty ? "success" : "attention"),
        LocalDataHygieneMetric(title: "Ignored intake", value: "\(ignoredIntakeCount)", detail: "Rows already ignored locally; useful as test noise evidence, not active Inbox work.", tone: ignoredIntakeCount == 0 ? "success" : "neutral"),
        LocalDataHygieneMetric(title: "Reviewed unlinked", value: "\(reviewedUnlinkedIntakeCount)", detail: "Reviewed intake rows that were not linked to an order.", tone: reviewedUnlinkedIntakeCount == 0 ? "success" : "neutral"),
        LocalDataHygieneMetric(title: "Duplicate ingest", value: "\(duplicateIngestCount)", detail: "Duplicate provider message IDs skipped by the ingest layer.", tone: duplicateIngestCount == 0 ? "success" : "neutral"),
        LocalDataHygieneMetric(title: "Orphan ingest links", value: "\(orphanIngestCount)", detail: "Ingest records pointing at intake IDs no longer present locally.", tone: orphanIngestCount == 0 ? "success" : "warning"),
        LocalDataHygieneMetric(title: "Orphan order links", value: "\(orphanLinkedIntakeCount)", detail: "Intake rows linked to order IDs no longer present locally.", tone: orphanLinkedIntakeCount == 0 ? "success" : "warning"),
        LocalDataHygieneMetric(title: "Parser diagnostics", value: "\(parserDiagnosticCount)", detail: "Local parser checks still visible for review.", tone: parserDiagnosticCount == 0 ? "success" : "attention"),
        LocalDataHygieneMetric(title: "Uncertain SpaceMail", value: "\(pendingUncertainCount)", detail: "Ambiguous previews kept out of Inbox until imported or dismissed.", tone: pendingUncertainCount == 0 ? "success" : "attention"),
        LocalDataHygieneMetric(title: "Filtered review", value: "\(pendingFilteredReviewCount)", detail: "Filtered mixed-mailbox examples available for spot review.", tone: pendingFilteredReviewCount == 0 ? "success" : "neutral"),
        LocalDataHygieneMetric(title: "Inbox orders", value: "\(inboxCreatedOrderCount)", detail: "Orders created or linked from Inbox/import handoff.", tone: inboxCreatedOrderCount == 0 ? "neutral" : "success"),
        LocalDataHygieneMetric(title: "Partial order tasks", value: "\(openPartialOrderTasks)", detail: "Open verification tasks for incomplete Inbox-created orders.", tone: openPartialOrderTasks == 0 ? "success" : "attention")
      ],
      examples: Array(examples.prefix(6)),
      boundaries: [
        "Read-only summary: no records are deleted, merged, or rewritten.",
        "Duplicate tracking metadata remains intact.",
        "No mailbox refresh, Keychain read, network call, or mailbox mutation runs from this card.",
        "Use existing Inbox, Mailbox Monitor, Tasks, and Audit actions to resolve records deliberately."
      ]
    )
  }

  var spaceMailMVPReadinessSummary: SpaceMailMVPReadinessSummary {
    let hasConnection = !spaceMailIMAPConnections.isEmpty
    let configuredConnections = spaceMailIMAPConnections.filter { connection in
      !connection.emailAddressUsername.isPlaceholderValidationValue
        && !connection.imapHost.isPlaceholderValidationValue
        && !connection.imapPort.isPlaceholderValidationValue
        && !connection.folderName.isPlaceholderValidationValue
    }
    let credentialReady = spaceMailIMAPConnections.contains {
      $0.credentialStorageStatus == SpaceMailCredentialStoreStatus.passwordReferenceAvailable.rawValue
    }
    let hasRealRefresh = spaceMailIMAPConnections.contains {
      $0.lastManualRefreshDate != "Never" && $0.connectionStatus.localizedCaseInsensitiveContains("real imap")
    }
    let mixedFilteringReady = spaceMailIMAPConnections.contains {
      $0.mailboxMode == .mixedFiltered && ($0.lastRefreshFilteredNonOrderCount > 0 || !$0.filteredMessages.isEmpty || !$0.lastRefreshReasonBreakdown.isEmpty)
    }
    let parserQueueClear = intakeParserDiagnostics.isEmpty
    let inboxOrderHandoffReady = orders.contains {
      $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import"
    }

    let items = [
      SpaceMailMVPReadinessItem(
        title: "SpaceMail configured",
        detail: hasConnection
          ? "\(configuredConnections.count) configured connection\(configuredConnections.count == 1 ? "" : "s") with host, folder, and mailbox address."
          : "Add a SpaceMail setup before testing real intake.",
        isComplete: hasConnection && !configuredConnections.isEmpty,
        tone: hasConnection && !configuredConnections.isEmpty ? "success" : "warning"
      ),
      SpaceMailMVPReadinessItem(
        title: "Credential ready",
        detail: credentialReady ? "A Keychain password reference is available for manual refresh." : "Set or check the SpaceMail Keychain credential.",
        isComplete: credentialReady,
        tone: credentialReady ? "success" : "warning"
      ),
      SpaceMailMVPReadinessItem(
        title: "Read-only refresh tested",
        detail: hasRealRefresh ? "At least one real manual IMAP refresh has completed or reported a real IMAP result." : "Run real SpaceMail refresh once credentials are ready.",
        isComplete: hasRealRefresh,
        tone: hasRealRefresh ? "success" : "attention"
      ),
      SpaceMailMVPReadinessItem(
        title: "Mixed mailbox filtering visible",
        detail: mixedFilteringReady ? "Latest refresh results include filtering/reason evidence for mixed mailbox review." : "Run refresh or classifier tests until filtered/uncertain/imported outcomes are visible.",
        isComplete: mixedFilteringReady,
        tone: mixedFilteringReady ? "success" : "attention"
      ),
      SpaceMailMVPReadinessItem(
        title: "Parser queue controlled",
        detail: parserQueueClear ? "No parser diagnostics currently need attention." : "\(intakeParserDiagnostics.count) parser check\(intakeParserDiagnostics.count == 1 ? "" : "s") still need review.",
        isComplete: parserQueueClear,
        tone: parserQueueClear ? "success" : "attention"
      ),
      SpaceMailMVPReadinessItem(
        title: "Inbox-to-order handoff tested",
        detail: inboxOrderHandoffReady ? "At least one order exists from Inbox/import handoff." : "Create or link one order from a real intake row before calling the workflow tested.",
        isComplete: inboxOrderHandoffReady,
        tone: inboxOrderHandoffReady ? "success" : "attention"
      )
    ]

    let completedCount = items.filter(\.isComplete).count
    let tone: String
    let verdict: String
    let detail: String
    let nextAction: String

    if completedCount == items.count {
      tone = "success"
      verdict = "SpaceMail MVP ready for hands-on testing"
      detail = "Real read-only intake, filtering, parser review, and order handoff have enough local evidence for supervised use."
      nextAction = "Run a short hands-on test: refresh, review Inbox, create/link an order, then confirm Audit."
    } else if completedCount >= 4 {
      tone = "attention"
      verdict = "SpaceMail MVP nearly ready"
      detail = "\(completedCount) of \(items.count) readiness checks are complete."
      nextAction = items.first { !$0.isComplete }?.detail ?? "Review remaining checks."
    } else {
      tone = "warning"
      verdict = "SpaceMail MVP needs setup checks"
      detail = "\(completedCount) of \(items.count) readiness checks are complete."
      nextAction = items.first { !$0.isComplete }?.detail ?? "Complete SpaceMail setup first."
    }

    return SpaceMailMVPReadinessSummary(
      verdict: verdict,
      detail: detail,
      nextAction: nextAction,
      tone: tone,
      completedCount: completedCount,
      totalCount: items.count,
      items: items
    )
  }

  var liveMailboxMVPReadinessSummary: SpaceMailMVPReadinessSummary {
    let hasSpaceMailSetup = !spaceMailIMAPConnections.isEmpty
    let hasGmailSetup = !gmailMailboxConnections.isEmpty
    let hasMicrosoft365Setup = !microsoft365MailboxConnections.isEmpty
    let providerCount = (hasSpaceMailSetup ? 1 : 0) + (hasGmailSetup ? 1 : 0) + (hasMicrosoft365Setup ? 1 : 0)
    let hasMailboxSetup = providerCount > 0
    let hasSpaceMailCredential = spaceMailIMAPConnections.contains {
      $0.credentialStorageStatus == SpaceMailCredentialStoreStatus.passwordReferenceAvailable.rawValue
        || $0.credentialStorageStatus.localizedCaseInsensitiveContains("available")
        || $0.credentialStorageStatus.localizedCaseInsensitiveContains("ready")
    }
    let hasGmailAuth = gmailMailboxConnections.contains { gmailAuthSessionState(for: $0).status == .connected }
    let hasMicrosoft365Auth = microsoft365MailboxConnections.contains { microsoft365AuthSessionState(for: $0).status == .connected }
    let hasCredentialOrAuth = hasSpaceMailCredential || hasGmailAuth || hasMicrosoft365Auth
    let hasRealRefresh = spaceMailIMAPConnections.contains { $0.lastManualRefreshDate != "Never" }
      || gmailMailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
      || microsoft365MailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
    let mixedFilteringReady = spaceMailIMAPConnections.contains {
      $0.mailboxMode == .mixedFiltered && ($0.lastRefreshFilteredNonOrderCount > 0 || !$0.filteredMessages.isEmpty || !$0.uncertainMessages.isEmpty || !$0.lastRefreshReasonBreakdown.isEmpty)
    } || gmailMailboxConnections.contains {
      $0.mailboxMode == .mixedFiltered && ($0.lastRefreshFilteredNonOrderCount > 0 || ($0.filteredMessages?.isEmpty == false) || ($0.uncertainMessages?.isEmpty == false))
    }
    let parserQueueClear = intakeParserDiagnostics.isEmpty
    let inboxOrderHandoffReady = orders.contains {
      $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import" || $0.isInboxCreatedLocalOrder
    }
    let providerLabel: String
    let configuredProviderNames = [
      hasSpaceMailSetup ? "SpaceMail" : nil,
      hasGmailSetup ? "Gmail" : nil,
      hasMicrosoft365Setup ? "Outlook" : nil
    ].compactMap { $0 }
    if !configuredProviderNames.isEmpty {
      providerLabel = configuredProviderNames.joined(separator: ", ")
    } else {
      providerLabel = "No live mailbox provider"
    }

    let items = [
      SpaceMailMVPReadinessItem(
        title: "Mailbox provider configured",
        detail: hasMailboxSetup
          ? "\(providerLabel) setup exists for manual read-only intake."
          : "Add SpaceMail for IMAP mailboxes, Gmail for Google-hosted mailboxes, or Outlook for Microsoft-hosted mailboxes before testing real intake.",
        isComplete: hasMailboxSetup,
        tone: hasMailboxSetup ? "success" : "warning"
      ),
      SpaceMailMVPReadinessItem(
        title: "Credential or sign-in ready",
        detail: hasCredentialOrAuth
          ? "SpaceMail Keychain credential, Gmail Google sign-in, or Outlook Microsoft sign-in evidence is available."
          : "Set/check the SpaceMail Keychain credential, complete Gmail Google sign-in, or complete Outlook Microsoft sign-in.",
        isComplete: hasCredentialOrAuth,
        tone: hasCredentialOrAuth ? "success" : "warning"
      ),
      SpaceMailMVPReadinessItem(
        title: "Read-only refresh tested",
        detail: hasRealRefresh
          ? "At least one manual mailbox refresh has produced local result evidence."
          : "Run one explicit manual read-only refresh after setup and credential/sign-in are ready.",
        isComplete: hasRealRefresh,
        tone: hasRealRefresh ? "success" : "attention"
      ),
      SpaceMailMVPReadinessItem(
        title: "Mixed mailbox filtering visible",
        detail: mixedFilteringReady
          ? "Latest refresh results include filtered, uncertain, or reason evidence for mixed-mailbox review."
          : "Run refresh or classifier tests until imported, filtered, or uncertain outcomes are visible.",
        isComplete: mixedFilteringReady,
        tone: mixedFilteringReady ? "success" : "attention"
      ),
      SpaceMailMVPReadinessItem(
        title: "Parser queue controlled",
        detail: parserQueueClear ? "No parser diagnostics currently need attention." : "\(intakeParserDiagnostics.count) parser check\(intakeParserDiagnostics.count == 1 ? "" : "s") still need review.",
        isComplete: parserQueueClear,
        tone: parserQueueClear ? "success" : "attention"
      ),
      SpaceMailMVPReadinessItem(
        title: "Inbox-to-order handoff tested",
        detail: inboxOrderHandoffReady ? "At least one order exists from Inbox/import handoff." : "Create or link one order from confirmed intake before calling the workflow tested.",
        isComplete: inboxOrderHandoffReady,
        tone: inboxOrderHandoffReady ? "success" : "attention"
      )
    ]

    let completedCount = items.filter(\.isComplete).count
    let tone: String
    let verdict: String
    let detail: String
    let nextAction: String

    if completedCount == items.count {
      tone = "success"
      verdict = "Live mailbox MVP ready for hands-on testing"
      detail = "\(providerLabel) read-only intake, filtering, parser review, and order handoff have enough local evidence for supervised use."
      nextAction = "Run a short hands-on test: refresh, review Inbox, create/link an order, then confirm Audit."
    } else if completedCount >= 4 {
      tone = "attention"
      verdict = "Live mailbox MVP nearly ready"
      detail = "\(completedCount) of \(items.count) readiness checks are complete across mailbox intake."
      nextAction = items.first { !$0.isComplete }?.detail ?? "Review remaining checks."
    } else {
      tone = "warning"
      verdict = "Live mailbox MVP needs setup checks"
      detail = "\(completedCount) of \(items.count) readiness checks are complete across mailbox intake."
      nextAction = items.first { !$0.isComplete }?.detail ?? "Complete mailbox setup first."
    }

    return SpaceMailMVPReadinessSummary(
      verdict: verdict,
      detail: detail,
      nextAction: nextAction,
      tone: tone,
      completedCount: completedCount,
      totalCount: items.count,
      items: items
    )
  }

  var liveMailboxQACheckSummary: SpaceMailQACheckSummary {
    let hasSpaceMailSetup = !spaceMailIMAPConnections.isEmpty
    let hasGmailSetup = !gmailMailboxConnections.isEmpty
    let hasMicrosoft365Setup = !microsoft365MailboxConnections.isEmpty
    let providerLabel: String
    let configuredProviderNames = [
      hasSpaceMailSetup ? "SpaceMail" : nil,
      hasGmailSetup ? "Gmail" : nil,
      hasMicrosoft365Setup ? "Outlook" : nil
    ].compactMap { $0 }
    if !configuredProviderNames.isEmpty {
      providerLabel = configuredProviderNames.joined(separator: ", ")
    } else {
      providerLabel = "No live mailbox provider"
    }

    let hasSpaceMailCredentialEvidence = auditEvents.contains { event in
      event.entityType == .spaceMailIMAPConnection
        && (event.summary.localizedCaseInsensitiveContains("credential check succeeded")
          || event.summary.localizedCaseInsensitiveContains("credential saved"))
    }
    let hasGmailAuthEvidence = gmailMailboxConnections.contains { gmailAuthSessionState(for: $0).status == .connected }
      || auditEvents.contains { event in
        event.entityType == .gmailMailboxConnection
          && (event.summary.localizedCaseInsensitiveContains("real gmail sign-in succeeded")
            || event.summary.localizedCaseInsensitiveContains("mock gmail auth succeeded"))
      }
    let hasMicrosoft365AuthEvidence = microsoft365MailboxConnections.contains { microsoft365AuthSessionState(for: $0).status == .connected }
      || auditEvents.contains { event in
        event.entityType == .microsoft365MailboxConnection
          && (event.summary.localizedCaseInsensitiveContains("real microsoft 365 sign-in succeeded")
            || event.summary.localizedCaseInsensitiveContains("mock auth succeeded"))
      }
    let hasCredentialOrAuthEvidence = hasSpaceMailCredentialEvidence || hasGmailAuthEvidence || hasMicrosoft365AuthEvidence

    let successfulSpaceMailRefresh = auditEvents.contains { event in
      event.entityType == .spaceMailIMAPConnection
        && event.summary.localizedCaseInsensitiveContains("real spacemail imap refresh")
        && (event.summary.localizedCaseInsensitiveContains("completed")
          || (event.afterDetail ?? "").localizedCaseInsensitiveContains("Fetch result: Fetch success"))
    }
    let successfulGmailRefresh = auditEvents.contains { event in
      event.entityType == .gmailMailboxConnection
        && event.summary.localizedCaseInsensitiveContains("gmail refresh")
        && (event.summary.localizedCaseInsensitiveContains("completed")
          || (event.afterDetail ?? "").localizedCaseInsensitiveContains("Fetch result: Fetch success"))
    } || gmailMailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
    let successfulMicrosoft365Refresh = auditEvents.contains { event in
      event.entityType == .microsoft365MailboxConnection
        && (event.summary.localizedCaseInsensitiveContains("graph")
          || event.summary.localizedCaseInsensitiveContains("microsoft 365"))
        && (event.summary.localizedCaseInsensitiveContains("completed")
          || (event.afterDetail ?? "").localizedCaseInsensitiveContains("Graph result")
          || (event.afterDetail ?? "").localizedCaseInsensitiveContains("Fetch result"))
    } || microsoft365MailboxConnections.contains { $0.lastManualRefreshDate != "Never" }
    let hasRefreshEvidence = successfulSpaceMailRefresh || successfulGmailRefresh || successfulMicrosoft365Refresh

    let spaceMailFilteringEvidence = spaceMailIMAPConnections.contains {
      $0.mailboxMode == .mixedFiltered
        && ($0.lastRefreshFilteredNonOrderCount > 0 || !$0.lastRefreshReasonBreakdown.isEmpty || !$0.filteredMessages.isEmpty || !$0.uncertainMessages.isEmpty)
    }
    let gmailFilteringEvidence = gmailMailboxConnections.contains {
      $0.mailboxMode == .mixedFiltered
        && ($0.lastRefreshFilteredNonOrderCount > 0 || ($0.filteredMessages?.isEmpty == false) || ($0.uncertainMessages?.isEmpty == false) || ($0.lastRefreshFilteredExamples?.isEmpty == false) || ($0.lastRefreshUncertainExamples?.isEmpty == false))
    }
    let hasFilteringEvidence = spaceMailFilteringEvidence || gmailFilteringEvidence

    let parserEvidence = !intakeParserDiagnostics.isEmpty || intakeEmails.contains { email in
      !email.detectedOrderNumber.isPlaceholderValidationValue || !email.detectedTrackingNumber.isPlaceholderValidationValue
    }
    let inboxOrderHandoffEvidence = orders.contains {
      $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import" || $0.isInboxCreatedLocalOrder
    }
    let liveMailboxAuditEvidence = auditEvents.contains { event in
      [.spaceMailIMAPConnection, .gmailMailboxConnection, .microsoft365MailboxConnection, .intakeEmail, .order].contains(event.entityType)
        || event.summary.localizedCaseInsensitiveContains("SpaceMail")
        || event.summary.localizedCaseInsensitiveContains("Gmail")
        || event.summary.localizedCaseInsensitiveContains("Microsoft 365")
        || event.summary.localizedCaseInsensitiveContains("Outlook")
    }

    let checks = [
      SpaceMailQACheck(
        title: "Provider setup evidence",
        detail: "At least one live mailbox provider is configured for manual intake testing.",
        evidence: hasSpaceMailSetup || hasGmailSetup || hasMicrosoft365Setup ? "\(providerLabel) setup exists." : "No active mailbox provider setup exists yet.",
        isComplete: hasSpaceMailSetup || hasGmailSetup || hasMicrosoft365Setup,
        tone: hasSpaceMailSetup || hasGmailSetup || hasMicrosoft365Setup ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Credential or sign-in evidence",
        detail: "SpaceMail has Keychain credential evidence, Gmail has sign-in evidence, or Outlook has Microsoft sign-in evidence.",
        evidence: hasCredentialOrAuthEvidence ? "Credential/sign-in evidence exists without storing secrets in JSON." : "No SpaceMail credential check/save, Gmail sign-in, or Microsoft sign-in evidence yet.",
        isComplete: hasCredentialOrAuthEvidence,
        tone: hasCredentialOrAuthEvidence ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Read-only refresh evidence",
        detail: "A manual mailbox refresh completed or produced a clear safe result.",
        evidence: hasRefreshEvidence ? "Manual read-only refresh evidence exists." : "Run one real or mock manual refresh to collect evidence.",
        isComplete: hasRefreshEvidence,
        tone: hasRefreshEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Mixed-mailbox decision evidence",
        detail: "Filtering, uncertain, duplicate, or reason evidence exists for mixed-use mailbox review.",
        evidence: hasFilteringEvidence ? "Mixed-mailbox decision evidence is visible for operator review." : "Run refresh/classifier checks until filtered or uncertain decisions are visible.",
        isComplete: hasFilteringEvidence,
        tone: hasFilteringEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Parser evidence",
        detail: "Imported intake has parser output or diagnostics for order/tracking review.",
        evidence: parserEvidence ? "\(intakeParserDiagnostics.count) parser checks and \(intakeEmails.count) intake emails are available." : "No parser or extracted order/tracking evidence yet.",
        isComplete: parserEvidence,
        tone: parserEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Inbox-to-order handoff evidence",
        detail: "At least one order has been created or linked from Inbox/import work.",
        evidence: inboxOrderHandoffEvidence ? "Inbox/import-created order evidence exists." : "Create or link one order from Inbox before RC testing.",
        isComplete: inboxOrderHandoffEvidence,
        tone: inboxOrderHandoffEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Audit trail evidence",
        detail: "Audit contains mailbox, intake, or order events for traceability.",
        evidence: liveMailboxAuditEvidence ? "\(auditEvents.count) audit events available." : "No live mailbox/intake/order audit evidence yet.",
        isComplete: liveMailboxAuditEvidence,
        tone: liveMailboxAuditEvidence ? "success" : "warning"
      )
    ]

    let completedCount = checks.filter(\.isComplete).count
    let tone: String
    let verdict: String
    if completedCount == checks.count {
      tone = "success"
      verdict = "Live mailbox QA evidence complete"
    } else if completedCount >= 5 {
      tone = "attention"
      verdict = "Live mailbox QA evidence mostly ready"
    } else {
      tone = "warning"
      verdict = "Live mailbox QA evidence incomplete"
    }

    return SpaceMailQACheckSummary(
      verdict: verdict,
      detail: "\(completedCount) of \(checks.count) live mailbox QA checks are complete across active providers.",
      completedCount: completedCount,
      totalCount: checks.count,
      tone: tone,
      checks: checks
    )
  }

  var spaceMailQACheckSummary: SpaceMailQACheckSummary {
    let hasCredentialEvidence = auditEvents.contains { event in
      event.entityType == .spaceMailIMAPConnection
        && (event.summary.localizedCaseInsensitiveContains("credential check succeeded")
          || event.summary.localizedCaseInsensitiveContains("credential saved"))
    }
    let realRefreshEvents = auditEvents.filter { event in
      event.entityType == .spaceMailIMAPConnection
        && event.summary.localizedCaseInsensitiveContains("real spacemail imap refresh")
    }
    let successfulRefreshEvents = realRefreshEvents.filter {
      $0.summary.localizedCaseInsensitiveContains("completed")
        || ($0.afterDetail ?? "").localizedCaseInsensitiveContains("Fetch result: Fetch success")
    }
    let filteringEvidence = spaceMailIMAPConnections.contains {
      $0.lastRefreshFilteredNonOrderCount > 0 || !$0.lastRefreshReasonBreakdown.isEmpty
    }
    let parserEvidence = !intakeParserDiagnostics.isEmpty || intakeEmails.contains { email in
      !email.detectedOrderNumber.isPlaceholderValidationValue || !email.detectedTrackingNumber.isPlaceholderValidationValue
    }
    let orderHandoffEvidence = orders.contains {
      $0.source == .forwardedMailbox || $0.checkedMailbox == "manual-import"
    }
    let auditTrailEvidence = auditEvents.contains { event in
      event.entityType == .intakeEmail || event.entityType == .order || event.entityType == .spaceMailIMAPConnection
    }

    let checks = [
      SpaceMailQACheck(
        title: "Credential evidence",
        detail: "Keychain password/app-password status has been checked or saved locally.",
        evidence: hasCredentialEvidence ? "Found SpaceMail credential audit evidence." : "No successful credential check/save evidence yet.",
        isComplete: hasCredentialEvidence,
        tone: hasCredentialEvidence ? "success" : "warning"
      ),
      SpaceMailQACheck(
        title: "Read-only refresh evidence",
        detail: "A real manual SpaceMail IMAP refresh completed or returned a clear result.",
        evidence: successfulRefreshEvents.first?.summary ?? "No completed real refresh evidence yet.",
        isComplete: !successfulRefreshEvents.isEmpty,
        tone: successfulRefreshEvents.isEmpty ? "attention" : "success"
      ),
      SpaceMailQACheck(
        title: "Mixed-mailbox filter evidence",
        detail: "The latest SpaceMail state shows filtered/reasoned mixed-mailbox decisions.",
        evidence: filteringEvidence ? "Filtered count or reason breakdown exists." : "Run a real refresh or classifier suite to collect filter evidence.",
        isComplete: filteringEvidence,
        tone: filteringEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Parser evidence",
        detail: "Inbox has parser diagnostics or extracted order/tracking fields to review.",
        evidence: parserEvidence ? "\(intakeParserDiagnostics.count) parser checks, \(intakeEmails.count) intake emails." : "No parser evidence yet.",
        isComplete: parserEvidence,
        tone: parserEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Order handoff evidence",
        detail: "At least one order has been created or linked from intake/import work.",
        evidence: orderHandoffEvidence ? "Inbox/import-created order evidence exists." : "Create or link one order from Inbox before RC testing.",
        isComplete: orderHandoffEvidence,
        tone: orderHandoffEvidence ? "success" : "attention"
      ),
      SpaceMailQACheck(
        title: "Audit trail evidence",
        detail: "Audit contains SpaceMail, intake, or order events for traceability.",
        evidence: auditTrailEvidence ? "\(auditEvents.count) audit events available." : "No intake/order audit evidence yet.",
        isComplete: auditTrailEvidence,
        tone: auditTrailEvidence ? "success" : "warning"
      )
    ]

    let completedCount = checks.filter(\.isComplete).count
    let tone: String
    let verdict: String
    if completedCount == checks.count {
      tone = "success"
      verdict = "SpaceMail RC evidence complete"
    } else if completedCount >= 4 {
      tone = "attention"
      verdict = "SpaceMail RC evidence mostly ready"
    } else {
      tone = "warning"
      verdict = "SpaceMail RC evidence incomplete"
    }

    return SpaceMailQACheckSummary(
      verdict: verdict,
      detail: "\(completedCount) of \(checks.count) QA evidence checks are complete.",
      completedCount: completedCount,
      totalCount: checks.count,
      tone: tone,
      checks: checks
    )
  }

  func spaceMailIntakeHealthSummary(for connection: SpaceMailIMAPConnection) -> SpaceMailIntakeHealthSummary {
    let mailboxID = connection.id
    let ingestRecords = mailboxIngestRecords.filter { $0.sourceMailboxID == mailboxID }
    let duplicateRefreshCounts = duplicateRefreshCounts(for: ingestRecords)
    let linkedIntakeIDs = Set(ingestRecords.compactMap(\.intakeEmailID))
    let linkedIntakeCount = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }.count
    let parserIssueCount = intakeParserDiagnostics.filter { linkedIntakeIDs.contains($0.intakeEmailID) }.count
    let reasonLabels = connection.lastRefreshReasonBreakdown
      .prefix(4)
      .map { "\($0.decision): \($0.reason) x\($0.count)" }

    let status = connection.connectionStatus
    let verdict: String
    let detail: String
    let nextAction: String
    let tone: String

    if status.localizedCaseInsensitiveContains("missing") || status.localizedCaseInsensitiveContains("failed") {
      verdict = "Setup needs attention"
      detail = "The latest SpaceMail state did not reach a clean read-only refresh."
      nextAction = "Check host, folder, SSL/TLS, and Keychain credential status, then run real SpaceMail refresh."
      tone = "warning"
    } else if connection.lastRefreshFetchedCount == 0 && connection.lastManualRefreshDate == "Never" {
      verdict = "Ready for first refresh"
      detail = "SpaceMail setup exists, but no real refresh has been recorded yet."
      nextAction = "Set/check the Keychain credential, then run a manual real refresh."
      tone = "neutral"
    } else if connection.lastRefreshUncertainCount > 0 || !connection.uncertainMessages.isEmpty {
      verdict = "Uncertain messages need review"
      detail = "Some mixed-mailbox messages looked order-related but not strong enough for automatic Inbox import."
      nextAction = "Review uncertain previews, import true order mail, or dismiss/filter non-order mail locally."
      tone = "attention"
    } else if parserIssueCount > 0 {
      verdict = "Parser review needed"
      detail = "Imported intake exists, but local parsing still needs a person to confirm order or tracking fields."
      nextAction = "Open the parser review queue, reprocess if needed, or create a follow-up task."
      tone = "attention"
    } else if connection.lastRefreshImportedCount > 0 {
      verdict = "Order intake captured"
      detail = "The latest refresh imported likely order-related messages into Inbox without mailbox mutation."
      nextAction = "Review the imported Inbox rows and create or link orders where appropriate."
      tone = "success"
    } else if connection.lastRefreshFilteredNonOrderCount > 0 && connection.lastRefreshDuplicateCount == 0 {
      verdict = "Filter working"
      detail = "The mixed mailbox filter kept fetched non-order messages out of Inbox."
      nextAction = "No action needed unless filtered examples look order-related."
      tone = "success"
    } else if connection.lastRefreshDuplicateCount > 0 {
      verdict = "No new order mail"
      detail = "The latest refresh found messages ParcelOps had already captured or reviewed."
      nextAction = "Wait for new mail or review filtered/parsed examples if something looks wrong."
      tone = "neutral"
    } else {
      verdict = "Monitor mailbox"
      detail = "SpaceMail is configured, but the latest refresh did not produce actionable intake."
      nextAction = "Run a manual refresh after forwarding a known order update."
      tone = "neutral"
    }

    return SpaceMailIntakeHealthSummary(
      connectionID: connection.id,
      displayName: connection.displayName,
      verdict: verdict,
      detail: detail,
      nextAction: nextAction,
      tone: tone,
      fetchedCount: connection.lastRefreshFetchedCount,
      importedCount: connection.lastRefreshImportedCount,
      duplicateCount: connection.lastRefreshDuplicateCount,
      duplicateRefreshedCount: duplicateRefreshCounts.updated,
      duplicateNoChangeCount: duplicateRefreshCounts.noChange,
      filteredCount: connection.lastRefreshFilteredNonOrderCount,
      uncertainCount: connection.lastRefreshUncertainCount,
      parserIssueCount: parserIssueCount,
      linkedIntakeCount: linkedIntakeCount,
      pendingFilteredReviewCount: connection.filteredMessages.count,
      pendingUncertainReviewCount: connection.uncertainMessages.count,
      lastRefreshDate: connection.lastManualRefreshDate,
      topReasonLabels: reasonLabels
    )
  }

  func gmailIntakeHealthSummary(for connection: GmailMailboxConnection) -> GmailIntakeHealthSummary {
    let mailboxID = connection.id
    let ingestRecords = mailboxIngestRecords.filter { $0.sourceMailboxID == mailboxID }
    let duplicateRefreshCounts = duplicateRefreshCounts(for: ingestRecords)
    let linkedIntakeIDs = Set(ingestRecords.compactMap(\.intakeEmailID))
    let linkedIntakeCount = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }.count
    let status = connection.connectionStatus
    let readiness = gmailOAuthReadinessSummary(for: connection)
    let authState = gmailAuthSessionState(for: connection)
    let uncertainCount = connection.lastRefreshUncertainCount ?? 0
    let pendingUncertainCount = connection.uncertainMessages?.count ?? 0

    let verdict: String
    let detail: String
    let nextAction: String
    let tone: String

    if !readiness.isReady {
      verdict = "Gmail setup blocked"
      detail = "\(readiness.statusText). \(readiness.compiledClientIDStatus). \(readiness.compiledCallbackSchemeStatus)."
      nextAction = "Open Mailbox Monitor or Settings, fix the Gmail setup blockers, then run Check readiness before sign-in."
      tone = "warning"
    } else if authState.status != .connected && connection.lastRefreshFetchedCount == 0 {
      verdict = "Gmail sign-in needed"
      detail = "Gmail setup and compiled callback checks are ready, but the mailbox is not signed in for the read-only refresh path."
      nextAction = "Run Test real Google sign-in, then run manual read-only Gmail refresh."
      tone = "attention"
    } else if status.localizedCaseInsensitiveContains("Auth required") ||
      status.localizedCaseInsensitiveContains("Consent required") ||
      status.localizedCaseInsensitiveContains("API rejected") ||
      status.localizedCaseInsensitiveContains("Network failed") ||
      status.localizedCaseInsensitiveContains("not configured") {
      verdict = "Gmail setup needs attention"
      detail = "The latest Gmail state did not reach a clean read-only refresh even though setup readiness checks passed."
      nextAction = "Check Google consent, sign in again, then run manual read-only Gmail refresh."
      tone = "warning"
    } else if connection.lastRefreshFetchedCount == 0 && connection.lastManualRefreshDate == "Never" {
      verdict = "Ready for Gmail setup"
      detail = "Gmail setup exists, but no readiness check or refresh has been recorded yet."
      nextAction = "Save setup, run Test real Google sign-in, then use manual read-only Gmail refresh."
      tone = "neutral"
    } else if pendingUncertainCount > 0 || uncertainCount > 0 {
      verdict = "Gmail uncertain mail needs review"
      detail = "Some mixed Gmail messages looked order-related but not strong enough for automatic Inbox import."
      nextAction = "Review uncertain Gmail previews in Mailbox Monitor, import true order mail, or dismiss non-order mail locally."
      tone = "attention"
    } else if connection.lastRefreshImportedCount > 0 {
      verdict = "Gmail order intake captured"
      detail = "The latest Gmail refresh imported likely order-related messages into Inbox without mailbox mutation."
      nextAction = "Review imported Inbox rows and create or link orders where appropriate."
      tone = "success"
    } else if connection.lastRefreshFilteredNonOrderCount > 0 && connection.lastRefreshDuplicateCount == 0 {
      verdict = "Gmail filter working"
      detail = "The mixed mailbox filter kept fetched non-order Gmail messages out of Inbox."
      nextAction = "No action needed unless filtered examples look order-related."
      tone = "success"
    } else if connection.lastRefreshDuplicateCount > 0 {
      verdict = "No new Gmail order mail"
      detail = "The latest Gmail refresh found messages ParcelOps had already captured or reviewed. Duplicate-safe handling can refresh existing Inbox rows from newly parsed previews where fields change."
      nextAction = "Wait for new mail, review refreshed Inbox rows, or check filtered/uncertain examples if something looks wrong."
      tone = "neutral"
    } else if status.localizedCaseInsensitiveContains("Ready") || status.localizedCaseInsensitiveContains("sign-in") {
      verdict = "Gmail ready for manual refresh"
      detail = "Gmail setup has readiness or sign-in evidence, but no actionable intake is pending."
      nextAction = "Run manual read-only Gmail refresh when you want to check the mailbox."
      tone = "neutral"
    } else {
      verdict = "Monitor Gmail mailbox"
      detail = "Gmail is configured, but the latest state did not produce actionable intake."
      nextAction = "Run a readiness check or manual refresh after confirming Google setup."
      tone = "neutral"
    }

    return GmailIntakeHealthSummary(
      connectionID: connection.id,
      displayName: connection.displayName,
      verdict: verdict,
      detail: detail,
      nextAction: nextAction,
      tone: tone,
      fetchedCount: connection.lastRefreshFetchedCount,
      importedCount: connection.lastRefreshImportedCount,
      duplicateCount: connection.lastRefreshDuplicateCount,
      duplicateRefreshedCount: duplicateRefreshCounts.updated,
      duplicateNoChangeCount: duplicateRefreshCounts.noChange,
      filteredCount: connection.lastRefreshFilteredNonOrderCount,
      uncertainCount: uncertainCount,
      linkedIntakeCount: linkedIntakeCount,
      pendingUncertainReviewCount: pendingUncertainCount,
      lastRefreshDate: connection.lastManualRefreshDate,
      lastRefreshSummary: connection.lastRefreshSummary
    )
  }

  func microsoft365IntakeHealthSummary(for connection: Microsoft365MailboxConnection) -> Microsoft365IntakeHealthSummary {
    let mailboxID = connection.id
    let ingestRecords = mailboxIngestRecords.filter { $0.sourceMailboxID == mailboxID }
    let duplicateRefreshCounts = duplicateRefreshCounts(for: ingestRecords)
    let linkedIntakeIDs = Set(ingestRecords.compactMap(\.intakeEmailID))
    let linkedIntakeCount = intakeEmails.filter { linkedIntakeIDs.contains($0.id) }.count
    let importedCount = max(connection.lastRefreshImportedCount, ingestRecords.filter { $0.status == .imported }.count)
    let duplicateCount = max(connection.lastRefreshDuplicateCount, ingestRecords.filter {
      $0.status == .duplicateSkipped || $0.status == .duplicateRefreshed || $0.status == .duplicateNoChange
    }.count)
    let readiness = microsoft365OAuthReadinessSummary(for: connection)
    let authState = microsoft365AuthSessionState(for: connection)
    let status = connection.connectionStatus
    let hasManualRefreshEvidence = connection.lastManualRefreshDate != "Never"
    let fetchedCount = max(connection.lastRefreshFetchedCount, ingestRecords.count, hasManualRefreshEvidence ? 1 : 0)
    let pendingFilteredReviewCount = connection.filteredMessages.count
    let pendingUncertainReviewCount = connection.uncertainMessages.count
    let filteredCount = max(connection.lastRefreshFilteredNonOrderCount, pendingFilteredReviewCount)
    let uncertainCount = max(connection.lastRefreshUncertainCount, pendingUncertainReviewCount)
    let hasProblem = authState.status == .authFailed
      || authState.status == .consentRequired
      || authState.status == .tokenExpired
      || status.localizedCaseInsensitiveContains("auth required")
      || status.localizedCaseInsensitiveContains("failed")
      || status.localizedCaseInsensitiveContains("rejected")
      || status.localizedCaseInsensitiveContains("401")
    let blockedCount = hasProblem ? 1 : 0

    let verdict: String
    let detail: String
    let nextAction: String
    let tone: String

    if hasProblem {
      verdict = "Outlook diagnostics need review"
      detail = "The latest Microsoft 365 state has auth, consent, token, or Graph-read diagnostics to review."
      nextAction = "Open Mailbox Monitor or Audit, confirm sign-in and Graph consent, then retry manual read-only Graph refresh."
      tone = "warning"
    } else if !readiness.isReady {
      verdict = "Outlook setup incomplete"
      detail = "\(readiness.statusText). Use Outlook / Microsoft 365 only when this is the active Microsoft-hosted mailbox."
      nextAction = "Complete tenant, client, redirect, and scope placeholders before real sign-in."
      tone = "neutral"
    } else if authState.status != .connected && fetchedCount == 0 {
      verdict = "Outlook sign-in needed"
      detail = "Outlook / Microsoft 365 setup has readiness values, but no signed-in account or refresh evidence is available."
      nextAction = "Run Test real Microsoft sign-in only when this mailbox is Microsoft-hosted."
      tone = "attention"
    } else if importedCount > 0 {
      verdict = "Outlook order intake captured"
      detail = "Microsoft 365 imported messages through the same provider-neutral Inbox intake path."
      nextAction = "Review Outlook-origin Inbox rows and create or link orders where appropriate."
      tone = "success"
    } else if duplicateRefreshCounts.updated > 0 {
      verdict = "Outlook duplicate refresh updated intake"
      detail = "Duplicate-safe Outlook refresh updated existing Inbox rows without creating duplicates."
      nextAction = "Review refreshed Outlook-origin Inbox rows if any fields changed."
      tone = "neutral"
    } else if uncertainCount > 0 {
      verdict = "Outlook uncertain mail needs review"
      detail = "Some mixed Microsoft 365 messages looked order-related but were not strong enough for automatic Inbox import."
      nextAction = "Review the latest Microsoft 365 refresh examples in Mailbox Monitor or Audit before changing filter mode."
      tone = "attention"
    } else if filteredCount > 0 && importedCount == 0 && duplicateCount == 0 {
      verdict = "Outlook mixed filter working"
      detail = "The mixed mailbox filter kept fetched non-order Microsoft 365 messages out of Inbox."
      nextAction = "No action needed unless filtered examples look order-related."
      tone = "success"
    } else if duplicateCount > 0 {
      verdict = "No new Outlook order mail"
      detail = "Microsoft 365 refresh evidence found messages already captured by ParcelOps."
      nextAction = "Run manual Graph refresh again only when new Outlook mail is expected."
      tone = "neutral"
    } else if fetchedCount > 0 {
      verdict = "Outlook refresh evidence recorded"
      detail = "Outlook / Microsoft 365 has manual Graph refresh evidence, but no actionable Inbox intake is pending."
      nextAction = "Use Outlook refresh only when this is the active mailbox provider."
      tone = "neutral"
    } else {
      verdict = "Ready for Outlook refresh"
      detail = "Outlook / Microsoft 365 setup exists, but no refresh evidence is active yet."
      nextAction = "Run explicit read-only Graph refresh only for a Microsoft-hosted mailbox."
      tone = "neutral"
    }

    return Microsoft365IntakeHealthSummary(
      connectionID: connection.id,
      displayName: connection.displayName,
      verdict: verdict,
      detail: detail,
      nextAction: nextAction,
      tone: tone,
      fetchedCount: fetchedCount,
      importedCount: importedCount,
      duplicateCount: duplicateCount,
      duplicateRefreshedCount: duplicateRefreshCounts.updated,
      duplicateNoChangeCount: duplicateRefreshCounts.noChange,
      filteredCount: filteredCount,
      uncertainCount: uncertainCount,
      blockedCount: blockedCount,
      linkedIntakeCount: linkedIntakeCount,
      pendingFilteredReviewCount: pendingFilteredReviewCount,
      pendingUncertainReviewCount: pendingUncertainReviewCount,
      lastRefreshDate: connection.lastManualRefreshDate,
      lastRefreshSummary: connection.lastRefreshSummary
    )
  }

  private func duplicateRefreshCounts(for ingestRecords: [MailboxIngestRecord]) -> (updated: Int, noChange: Int) {
    (
      updated: ingestRecords.filter { $0.status == .duplicateRefreshed }.count,
      noChange: ingestRecords.filter { $0.status == .duplicateNoChange }.count
    )
  }

  func gmailLabelReadinessSummary(for connection: GmailMailboxConnection) -> GmailLabelReadinessSummary {
    let labels = connection.monitoredLabelNames
      .split(separator: ",")
      .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
      .filter { !$0.isEmpty }
    let primaryLabel = labels.first ?? "INBOX"
    let normalizedPrimary = primaryLabel.uppercased()
    let systemLabelAliases: [String: String] = [
      "INBOX": "INBOX",
      "UNREAD": "UNREAD",
      "IMPORTANT": "IMPORTANT",
      "STARRED": "STARRED",
      "SENT": "SENT",
      "DRAFT": "DRAFT",
      "TRASH": "TRASH",
      "SPAM": "SPAM",
      "CATEGORY_PERSONAL": "CATEGORY_PERSONAL",
      "CATEGORY_SOCIAL": "CATEGORY_SOCIAL",
      "CATEGORY_PROMOTIONS": "CATEGORY_PROMOTIONS",
      "CATEGORY_UPDATES": "CATEGORY_UPDATES",
      "CATEGORY_FORUMS": "CATEGORY_FORUMS",
      "PROMOTIONS": "CATEGORY_PROMOTIONS",
      "UPDATES": "CATEGORY_UPDATES",
      "SOCIAL": "CATEGORY_SOCIAL",
      "FORUMS": "CATEGORY_FORUMS",
      "PERSONAL": "CATEGORY_PERSONAL"
    ]
    let refreshMode = systemLabelAliases[normalizedPrimary].map { "System label \($0)" } ?? "Custom label search"

    if labels.isEmpty {
      return GmailLabelReadinessSummary(
        status: "Label missing",
        primaryLabel: "INBOX",
        labelCount: 0,
        refreshMode: "Default would be INBOX",
        detail: "Real Gmail refresh needs a monitored label. Use INBOX for the whole mailbox or a Gmail label such as Order Updates for a focused feed.",
        nextAction: "Edit setup and add the exact Gmail label to check.",
        tone: "warning"
      )
    }

    if labels.count > 1 {
      return GmailLabelReadinessSummary(
        status: "Primary label selected",
        primaryLabel: primaryLabel,
        labelCount: labels.count,
        refreshMode: refreshMode,
        detail: "Real Gmail refresh currently reads one label per manual run. It will use '\(primaryLabel)' first; the other configured labels are setup notes only.",
        nextAction: "Put the label you want fetched first, or run separate setup records for separate labels.",
        tone: "attention"
      )
    }

    return GmailLabelReadinessSummary(
      status: "Label ready",
      primaryLabel: primaryLabel,
      labelCount: labels.count,
      refreshMode: refreshMode,
      detail: "Real Gmail refresh will use '\(primaryLabel)' for the read-only message list request.",
      nextAction: "Run real refresh after Google sign-in and Gmail read-only consent are ready.",
      tone: "success"
    )
  }

  func spaceMailAssignedFollowUpSummaries(for connection: SpaceMailIMAPConnection) -> [String] {
    let connectionID = connection.id.uuidString
    let taskSummaries = reviewTasks
      .filter { task in
        (task.status != .completed || task.reviewState != .accepted)
          && (task.linkedEntityID == connectionID
            || task.title.localizedCaseInsensitiveContains("spacemail")
            || task.summary.localizedCaseInsensitiveContains("spacemail"))
      }
      .map { task in
        "Task: \(task.title) · \(task.status.rawValue) · \(task.assignee)"
      }

    let handoffSummaries = handoffNotes
      .filter { note in
        (note.status != .completed || note.reviewState != .accepted)
          && (note.linkedEntityID == connectionID
            || note.title.localizedCaseInsensitiveContains("spacemail")
            || note.summary.localizedCaseInsensitiveContains("spacemail")
            || note.notes.localizedCaseInsensitiveContains("spacemail"))
      }
      .map { note in
        "Handoff: \(note.title) · \(note.status.rawValue) · \(note.assignee)"
      }

    return Array((handoffSummaries + taskSummaries).prefix(6))
  }

