    wishlistBatchBriefNeeded ? "Batch comparison packet needed" : "Batch comparison packet drafted"
  }

  var wishlistBatchBriefWorkbenchDetail: String {
    if wishlistBatchBriefNeeded {
      return "\(agentReadyWishlistResearchRequestCount) agent-ready Wishlist research brief\(agentReadyWishlistResearchRequestCount == 1 ? "" : "s") can be combined into one local packet before future comparison work."
    }
    return "Latest batch draft is ready for review in Drafts/Tasks. It remains local and does not run an external agent or retailer search."
  }

  var wishlistBatchBriefWorkbenchTone: String {
    wishlistBatchBriefNeeded ? "warning" : "success"
  }

  var wishlistWorkbenchMetricSummaries: [(String, String, String)] {
    let readiness = wishlistAgentReadinessSummary
    return [
      ("Follow-up", "\(wishlistWorkbenchFollowUpCount)", "attention"),
      ("Agent verdict", readiness.tone.capitalized, readiness.tone),
      ("Blocked", "\(wishlistWorkbenchBlockedCount)", wishlistWorkbenchBlockedCount > 0 ? "critical" : "success"),
      ("Release ready", "\(wishlistReleaseReadyItemCount)", wishlistReleaseReadyItemCount == 0 ? "muted" : "success"),
      ("Release blocked", "\(wishlistReleaseBlockedItemCount)", wishlistReleaseBlockedItemCount == 0 ? "success" : "warning"),
      ("Readiness", "\(wishlistReadinessBlockedItemCount)", wishlistReadinessBlockedItemCount == 0 ? "success" : "warning"),
      ("Critical checks", "\(wishlistReadinessCriticalItemCount)", wishlistReadinessCriticalItemCount == 0 ? "success" : "critical"),
      ("Order watch", "\(wishlistReleaseOrderWatchItemCount)", wishlistReleaseOrderWatchItemCount == 0 ? "muted" : "handoff"),
      ("Handoff sanity", "\(wishlistHandoffSanityBlockedItemCount)", wishlistHandoffSanityBlockedItemCount == 0 ? "success" : "warning"),
      ("Dispatch setup", "\(wishlistLinkedOrderDispatchGapItemCount)", wishlistLinkedOrderDispatchGapItemCount == 0 ? "success" : "dispatch"),
      ("Closure trail", "\(readiness.operationsClosureGapCount)", readiness.operationsClosureGapCount == 0 ? "success" : "warning"),
      ("Purchase packets", "\(wishlistPurchasePacketNeededItemCount)", wishlistPurchasePacketNeededItemCount == 0 ? "success" : "packet"),
      ("Packet drafts", "\(wishlistPurchasePacketDraftCount)", wishlistPurchasePacketDraftCount == 0 ? "muted" : "dispatch"),
      ("Brief gaps", "\(wishlistResearchAttentionRequestCount)", wishlistResearchAttentionRequestCount == 0 ? "success" : "warning"),
      ("Batch brief", "\(wishlistBatchResearchDraftCount)", wishlistBatchBriefWorkbenchTone),
      ("Evidence", "\(wishlistWorkbenchEvidenceIssueCount)", wishlistWorkbenchEvidenceIssueCount > 0 ? "warning" : "success"),
      ("Decision", "\(wishlistWorkbenchDecisionIssueCount)", wishlistWorkbenchDecisionIssueCount > 0 ? "decisionMuted" : "success"),
      ("Handoff gaps", "\(wishlistWorkbenchHandoffGapItemCount)", wishlistWorkbenchHandoffGapItemCount > 0 ? "attention" : "success")
    ]
  }

  var activeWishlistOrderWatchRecords: [WishlistOrderWatchRecord] {
    wishlistOrderWatchRecords.filter(isActiveWishlistOrderWatchRecord)
  }

  var activeWishlistOrderWatchRecordCount: Int {
    activeWishlistOrderWatchRecords.count
  }

  var wishlistOrderWatchRecordCount: Int {
    wishlistOrderWatchRecords.count
  }

  var openWishlistOrderWatchRecords: [WishlistOrderWatchRecord] {
    activeWishlistOrderWatchRecords.filter {
      !$0.watchStatus.localizedCaseInsensitiveContains("closed")
        && !$0.watchStatus.localizedCaseInsensitiveContains("matched")
    }
  }

  var openWishlistOrderWatchRecordCount: Int {
    openWishlistOrderWatchRecords.count
  }

  var activeWishlistFollowUpCount: Int {
    stagedWishlistCaptureCandidateCount
      + activeWishlistResearchRequestCount
      + activeWishlistOrderWatchRecordCount
  }

  var activeWishlistEvidenceCount: Int {
    activeWishlistItems.count
      + activeWishlistFollowUpCount
      + wishlistLinkedOrders.count
  }

  func wishlistSellerEvidenceGapCount(for item: WishlistItem) -> Int {
    (item.comparisonOptions ?? []).reduce(0) { total, option in
      total + option.operatorSellerEvidenceGaps.count
    }
  }

  func wishlistSellerEvidenceGaps(for item: WishlistItem) -> [String] {
    Array(Set((item.comparisonOptions ?? []).flatMap(\.operatorSellerEvidenceGaps))).sorted()
  }

  func wishlistNeedsPurchaseDecision(_ item: WishlistItem) -> Bool {
    let options = item.comparisonOptions ?? []
    guard !options.isEmpty else { return false }
    let checks = item.purchaseChecks ?? []
    let checksClear = !checks.isEmpty && !checks.contains { $0.status != "Passed" }
    return checksClear && item.purchaseDecision == nil
  }

  func wishlistPurchasePacketDraft(for item: WishlistItem) -> DraftMessage? {
    draftMessages.first {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == item.id.uuidString
        && $0.subject.localizedCaseInsensitiveContains("wishlist purchase packet")
    }
  }

  func wishlistNeedsPurchasePacket(_ item: WishlistItem) -> Bool {
    !(item.comparisonOptions ?? []).isEmpty && wishlistPurchasePacketDraft(for: item) == nil
  }

  func wishlistPacketTaskBadge(for item: WishlistItem) -> String {
    if wishlistNeedsPurchasePacket(item) { return "Packet" }
    if !wishlistHandoffSanityGaps(for: item).isEmpty { return "Sanity gaps" }
    if !wishlistHandoffPackGaps(for: item).isEmpty { return "Handoff gaps" }
    if !wishlistLinkedOrderDispatchGaps(for: item).isEmpty { return "Dispatch setup" }
    if wishlistNeedsPurchaseDecision(item) { return "Decision" }
    if wishlistSellerEvidenceGapCount(for: item) > 0 { return "Evidence" }
    if item.purchaseHandoff?.linkedOrderID != nil { return "Linked order" }
    if item.purchaseHandoff != nil { return "Order watch" }
    if item.purchaseDecision?.reviewState == .accepted { return "Handoff" }
    if item.operatorPurchaseBlockers.isEmpty { return "Ready" }
    return "Wishlist"
  }

  func wishlistPacketTaskTone(for item: WishlistItem) -> String {
    if wishlistNeedsPurchasePacket(item) { return "packet" }
    if !wishlistHandoffSanityGaps(for: item).isEmpty { return "warning" }
    if !wishlistHandoffPackGaps(for: item).isEmpty { return "warning" }
    if !wishlistLinkedOrderDispatchGaps(for: item).isEmpty { return "dispatch" }
    if wishlistNeedsPurchaseDecision(item) { return "decision" }
    if wishlistSellerEvidenceGapCount(for: item) > 0 { return "warning" }
    if item.purchaseHandoff?.linkedOrderID != nil { return "success" }
    if item.purchaseHandoff != nil { return "warning" }
    if item.purchaseDecision?.reviewState == .accepted { return "decision" }
    if item.operatorPurchaseBlockers.isEmpty { return "success" }
    return "warning"
  }

  func wishlistPacketTaskDetail(for item: WishlistItem) -> String {
    if wishlistNeedsPurchasePacket(item) {
      let optionCount = (item.comparisonOptions ?? []).count
      let seller = item.purchaseDecision?.selectedSellerName
        ?? item.preferredOptionID.flatMap { preferredID in
          item.comparisonOptions?.first { $0.id == preferredID }?.sellerName
        }
        ?? item.comparisonOptions?.first?.sellerName
        ?? item.storefront
      return "\(optionCount) seller option\(optionCount == 1 ? "" : "s") recorded. Create the local purchase packet before manual buying. Current seller: \(seller)."
    }
    let sanityGaps = wishlistHandoffSanityGaps(for: item)
    if !sanityGaps.isEmpty {
      return "Resolve handoff sanity before assigning purchase follow-up: \(sanityGaps.prefix(4).joined(separator: ", "))"
    }
    let handoffGaps = wishlistHandoffPackGaps(for: item)
    if !handoffGaps.isEmpty {
      return "Complete handoff pack: \(handoffGaps.prefix(4).joined(separator: ", "))"
    }
    let dispatchGaps = wishlistLinkedOrderDispatchGaps(for: item)
    if !dispatchGaps.isEmpty {
      return "Linked order exists. Stage dispatch setup before closing the purchase handoff: \(dispatchGaps.prefix(3).joined(separator: ", "))."
    }
    if wishlistNeedsPurchaseDecision(item) {
      return "Ready for a local purchase decision before handoff."
    }
    let evidenceGaps = wishlistSellerEvidenceGaps(for: item)
    if !evidenceGaps.isEmpty {
      return "Seller evidence to check: \(evidenceGaps.prefix(4).joined(separator: ", "))"
    }
    let seller = item.purchaseHandoff?.sellerName
      ?? item.purchaseDecision?.selectedSellerName
      ?? item.preferredOptionID.flatMap { preferredID in
        item.comparisonOptions?.first { $0.id == preferredID }?.sellerName
      }
      ?? item.storefront
    let total = item.purchaseDecision?.totalAUDSummary
      ?? item.preferredOptionID.flatMap { preferredID in
        item.comparisonOptions?.first { $0.id == preferredID }?.estimatedAUDTotal
      }
      ?? item.estimatedCost
    return "\(seller) • \(total) • \(item.operatorPurchaseNextAction)"
  }

  func wishlistTaskContextDetail(for item: WishlistItem) -> String {
    let evidenceGaps = wishlistSellerEvidenceGaps(for: item)
    if !evidenceGaps.isEmpty {
      return "\(item.status) • Seller evidence: \(evidenceGaps.prefix(3).joined(separator: ", "))"
    }
    if wishlistNeedsPurchaseDecision(item) {
      return "\(item.status) • Draft the local purchase decision before handoff."
    }
    let sanityGaps = wishlistHandoffSanityGaps(for: item)
    if !sanityGaps.isEmpty {
      return "\(item.status) • Handoff sanity: \(sanityGaps.prefix(3).joined(separator: ", "))"
    }
    let handoffGaps = wishlistHandoffPackGaps(for: item)
    if !handoffGaps.isEmpty {
      return "\(item.status) • Handoff pack: \(handoffGaps.prefix(3).joined(separator: ", "))"
    }
    let dispatchGaps = wishlistLinkedOrderDispatchGaps(for: item)
    if !dispatchGaps.isEmpty {
      return "\(item.status) • Dispatch setup: \(dispatchGaps.prefix(3).joined(separator: ", "))"
    }
    return "\(item.status) • \(item.operatorPurchaseNextAction)"
  }

  func wishlistTaskContextBadge(for item: WishlistItem) -> String {
    if !wishlistSellerEvidenceGaps(for: item).isEmpty { return "Evidence" }
    if wishlistNeedsPurchaseDecision(item) { return "Decision" }
    if !wishlistHandoffSanityGaps(for: item).isEmpty { return "Sanity gaps" }
    if !wishlistHandoffPackGaps(for: item).isEmpty { return "Handoff pack" }
    if !wishlistLinkedOrderDispatchGaps(for: item).isEmpty { return "Dispatch setup" }
    if item.purchaseHandoff != nil { return "Order watch" }
    return "Wishlist"
  }

  func wishlistTaskContextTone(for item: WishlistItem) -> String {
    if item.status.localizedCaseInsensitiveContains("blocked") { return "critical" }
    if !wishlistSellerEvidenceGaps(for: item).isEmpty { return "warning" }
    if wishlistNeedsPurchaseDecision(item) { return "decision" }
    if !wishlistHandoffSanityGaps(for: item).isEmpty { return "warning" }
    if !wishlistHandoffPackGaps(for: item).isEmpty { return "warning" }
    if !wishlistLinkedOrderDispatchGaps(for: item).isEmpty { return "dispatch" }
    if item.purchaseHandoff != nil { return "handoff" }
    return item.operatorPurchaseBlockers.isEmpty ? "success" : "attention"
  }

  var wishlistPurchasePacketDrafts: [DraftMessage] {
    draftMessages.filter {
      $0.linkedEntityType == .wishlistItem
        && $0.subject.localizedCaseInsensitiveContains("wishlist purchase packet")
    }
  }

  var wishlistPurchasePacketDraftCount: Int {
    wishlistPurchasePacketDrafts.count
  }

  var wishlistPurchasePacketNeededItems: [WishlistItem] {
    activeWishlistItems.filter(wishlistNeedsPurchasePacket)
  }

  var wishlistPurchasePacketNeededItemCount: Int {
    wishlistPurchasePacketNeededItems.count
  }

  var wishlistTaskContextItems: [WishlistItem] {
    activeWishlistItems.filter { item in
      item.status.localizedCaseInsensitiveContains("purchase blocked")
        || item.status.localizedCaseInsensitiveContains("handoff")
        || item.status.localizedCaseInsensitiveContains("awaiting order")
        || item.status.localizedCaseInsensitiveContains("confirmation")
        || (item.purchaseReadiness ?? "").localizedCaseInsensitiveContains("blocker")
        || (item.purchaseReadiness ?? "").localizedCaseInsensitiveContains("review")
        || wishlistSellerEvidenceGapCount(for: item) > 0
        || wishlistNeedsPurchaseDecision(item)
        || wishlistNeedsPurchasePacket(item)
        || !wishlistHandoffPackGaps(for: item).isEmpty
        || !wishlistHandoffSanityGaps(for: item).isEmpty
        || !wishlistLinkedOrderDispatchGaps(for: item).isEmpty
        || (item.purchaseHandoff != nil && item.purchaseHandoff?.linkedOrderID == nil)
    }
  }

  var wishlistTaskContextItemCount: Int {
    wishlistTaskContextItems.count
  }

  var wishlistUniqueAttentionItems: [WishlistItem] {
    var seen = Set<UUID>()
    let candidates = wishlistTaskContextItems
      + wishlistReadinessBlockedItems
      + wishlistHandoffSanityBlockedItems
      + wishlistLinkedOrderDispatchGapItems
      + wishlistPurchasePacketNeededItems
      + wishlistPurchasedNeedsOrderLinkItems

    return candidates.filter { item in
      if seen.contains(item.id) { return false }
      seen.insert(item.id)
      return true
    }
  }

  var wishlistUniqueAttentionItemCount: Int {
    wishlistUniqueAttentionItems.count
  }

  var wishlistWorkbenchFollowUpCount: Int {
    wishlistUniqueAttentionItemCount
      + wishlistResearchAttentionRequestCount
      + (wishlistBatchBriefNeeded ? 1 : 0)
  }

  var wishlistWorkbenchBlockedCount: Int {
    wishlistTaskContextItems.filter { $0.status.localizedCaseInsensitiveContains("blocked") }.count
  }

  var wishlistWorkbenchEvidenceIssueCount: Int {
    wishlistTaskContextItems.filter { wishlistSellerEvidenceGapCount(for: $0) > 0 }.count
  }

  var wishlistWorkbenchDecisionIssueCount: Int {
    wishlistTaskContextItems.filter {
      wishlistNeedsPurchaseDecision($0) || $0.purchaseDecision?.reviewState == .needsReview
    }.count
  }

  var wishlistWorkbenchHandoffGapItemCount: Int {
    wishlistTaskContextItems.filter { !wishlistHandoffPackGaps(for: $0).isEmpty }.count
  }

  var wishlistEvidenceGapCount: Int {
    wishlistTaskContextItems.reduce(0) { total, item in
      total + wishlistSellerEvidenceGapCount(for: item)
    }
  }

  var wishlistDecisionGapCount: Int {
    wishlistTaskContextItems.filter(wishlistNeedsPurchaseDecision).count
  }

  var wishlistHandoffGapCount: Int {
    wishlistTaskContextItems.reduce(0) { total, item in
      total + wishlistHandoffPackGaps(for: item).count
    }
  }

  var wishlistHandoffSanityGapCount: Int {
    wishlistTaskContextItems.reduce(0) { total, item in
      total + wishlistHandoffSanityGaps(for: item).count
    }
  }

  var wishlistLinkedOrderDispatchGapCount: Int {
    wishlistLinkedOrderDispatchGapItems.reduce(0) { total, item in
      total + wishlistLinkedOrderDispatchGaps(for: item).count
    }
  }

  func wishlistHandoffSanityIssueCount(for order: TrackedOrder) -> Int {
    activeWishlistItemsLinked(to: order).filter {
      !wishlistHandoffSanityGaps(for: $0).isEmpty
    }.count
  }

  var wishlistAgentReadinessIssueCount: Int {
    let summary = wishlistAgentReadinessSummary
    return summary.scopeGapCount
      + summary.sellerOptionGapCount
      + summary.trustReviewCount
      + summary.purchaseHandoffGapCount
      + summary.orderWatchGapCount
      + summary.operationsClosureGapCount
  }

  var wishlistDailyAttentionCount: Int {
    wishlistUniqueAttentionItemCount
      + wishlistResearchAttentionRequestCount
      + (wishlistBatchBriefNeeded ? 1 : 0)
  }

  var activeWishlistReviewTasks: [ReviewTask] {
    reviewTasks.filter {
      isActiveWishlistTask($0) && ($0.status != .completed || $0.reviewState != .accepted)
    }
  }

  var activeWishlistReviewTaskCount: Int {
    activeWishlistReviewTasks.count
  }

  var activeWishlistHandoffNotes: [HandoffNote] {
    handoffNotes.filter {
      isActiveWishlistHandoff($0) && ($0.status != .completed || $0.reviewState != .accepted)
    }
  }

  var activeWishlistHandoffNoteCount: Int {
    activeWishlistHandoffNotes.count
  }

  var activeWishlistDraftMessages: [DraftMessage] {
    draftMessages.filter {
      $0.linkedEntityType == .wishlistItem
        && isActiveWishlistDraft($0)
        && ($0.reviewState != .accepted || $0.status != .sentLocally || $0.linkedEntityID == "wishlist-research-batch")
    }
  }

  var activeWishlistDraftMessageCount: Int {
    activeWishlistDraftMessages.count
  }

  var wishlistTaskActionCount: Int {
    activeWishlistReviewTaskCount
      + activeWishlistHandoffNoteCount
      + activeWishlistDraftMessageCount
      + wishlistPurchasePacketNeededItemCount
      + wishlistNeedsHandoffItemCount
      + wishlistAwaitingOrderItemCount
      + wishlistLinkedOrderDispatchGapItemCount
  }

  var wishlistDashboardAttentionItems: [WishlistItem] {
    activeWishlistItems.filter { item in
      item.status.localizedCaseInsensitiveContains("purchase blocked")
        || item.status.localizedCaseInsensitiveContains("handoff")
        || item.status.localizedCaseInsensitiveContains("awaiting order")
        || item.status.localizedCaseInsensitiveContains("confirmation")
        || (item.purchaseReadiness ?? "").localizedCaseInsensitiveContains("blocker")
        || (item.purchaseReadiness ?? "").localizedCaseInsensitiveContains("review")
        || wishlistSellerEvidenceGapCount(for: item) > 0
        || wishlistNeedsPurchaseDecision(item)
        || !wishlistHandoffPackGaps(for: item).isEmpty
        || (item.purchaseHandoff != nil && item.purchaseHandoff?.linkedOrderID == nil)
    }
  }

  var wishlistDashboardAttentionItemCount: Int {
    wishlistDashboardAttentionItems.count
  }

  var wishlistReadyPurchaseItems: [WishlistItem] {
    activeWishlistItems.filter { item in
      item.status.localizedCaseInsensitiveContains("ready to purchase")
        || (item.purchaseReadiness ?? "").localizedCaseInsensitiveContains("ready for purchase")
    }
  }

  var wishlistReadyPurchaseItemCount: Int {
    wishlistReadyPurchaseItems.count
  }

  var wishlistAttentionBlockerSummary: String {
    if wishlistBatchBriefNeeded {
      return "batch research brief needed (\(agentReadyWishlistResearchRequestCount))"
    }
    if wishlistPurchasePacketNeededItemCount > 0 {
      return "purchase packet needed (\(wishlistPurchasePacketNeededItemCount))"
    }
    if wishlistReadinessBlockedItemCount > 0 {
      let criticalPrefix = wishlistReadinessCriticalItemCount == 0 ? "" : "\(wishlistReadinessCriticalItemCount) critical, "
      return "\(criticalPrefix)\(wishlistReadinessBlockedItemCount) readiness-blocked"
    }
    if wishlistPurchasedNeedsOrderLinkItemCount > 0 {
      return "purchased needs order link (\(wishlistPurchasedNeedsOrderLinkItemCount))"
    }
    if wishlistLinkedOrderDispatchGapItemCount > 0 {
      let manifestGaps = wishlistLinkedOrderDispatchGapItems.filter { suggestedShipmentManifestRecords(for: $0).isEmpty }.count
      let checklistGaps = wishlistLinkedOrderDispatchGapItems.filter { suggestedDispatchReadinessChecklists(for: $0).isEmpty }.count
      return "linked order dispatch setup: manifest \(manifestGaps), readiness \(checklistGaps)"
    }
    if wishlistHandoffSanityBlockedItemCount > 0 {
      let grouped = Dictionary(grouping: wishlistHandoffSanityBlockedItems.flatMap { wishlistHandoffSanityGaps(for: $0) }, by: { $0 })
        .map { (label: $0.key, count: $0.value.count) }
        .sorted {
          if $0.count == $1.count { return $0.label < $1.label }
          return $0.count > $1.count
        }
        .prefix(2)
        .map { "\($0.label) (\($0.count))" }
        .joined(separator: ", ")
      return grouped.isEmpty ? "handoff sanity check" : "handoff sanity: \(grouped)"
    }
    let blockers = wishlistDashboardAttentionItems.flatMap { item -> [String] in
      var labels = item.operatorPurchaseBlockers
      if wishlistSellerEvidenceGapCount(for: item) > 0 {
        labels.append("seller evidence")
      }
      if wishlistNeedsPurchaseDecision(item) {
        labels.append("purchase decision")
      }
      labels.append(contentsOf: wishlistHandoffPackGaps(for: item).map { "handoff \($0)" })
      return labels
    }
    if wishlistResearchAttentionRequestCount > 0 {
      let gaps = wishlistResearchAttentionRequests.flatMap(\.agentBriefGaps)
      let grouped = Dictionary(grouping: gaps, by: { $0 })
        .map { (label: $0.key, count: $0.value.count) }
        .sorted {
          if $0.count == $1.count { return $0.label < $1.label }
          return $0.count > $1.count
        }
        .prefix(2)
        .map { "\($0.label) (\($0.count))" }
        .joined(separator: ", ")
      return grouped.isEmpty ? "review agent research briefs" : "research scope: \(grouped)"
    }
    guard !blockers.isEmpty else {
      if wishlistReleaseReadyItemCount > 0 { return "ready handoff (\(wishlistReleaseReadyItemCount))" }
      return "review purchase release, handoff, or order confirmation"
    }
    let grouped = Dictionary(grouping: blockers, by: { $0 })
      .map { (label: $0.key, count: $0.value.count) }
      .sorted {
        if $0.count == $1.count { return $0.label < $1.label }
        return $0.count > $1.count
      }
      .prefix(3)
      .map { "\($0.label) (\($0.count))" }
      .joined(separator: ", ")
    return grouped.isEmpty ? "review purchase release, handoff, or order confirmation" : grouped
  }

  var wishlistDashboardNextAction: String {
    if wishlistDashboardAttentionItemCount == 0 && wishlistResearchAttentionRequestCount == 0 {
      if wishlistBatchBriefNeeded { return "Create batch research brief" }
      if wishlistPurchasePacketNeededItemCount > 0 { return "Create Wishlist purchase packet" }
      if wishlistPurchasedNeedsOrderLinkItemCount > 0 { return "Link purchased Wishlist orders" }
      if wishlistLinkedOrderDispatchGapItemCount > 0 { return "Stage Wishlist dispatch setup" }
      if wishlistHandoffSanityBlockedItemCount > 0 { return "Complete purchase handoff sanity checks" }
      if wishlistReleaseReadyItemCount > 0 { return "Review ready purchase handoffs" }
      return wishlistReadyPurchaseItemCount == 0 ? "No wishlist purchase follow-up" : "Review ready-to-buy items"
    }
    return "Clear: \(wishlistAttentionBlockerSummary)"
  }

  var wishlistDashboardAttentionInsight: String? {
    if wishlistBatchBriefNeeded {
      return "\(agentReadyWishlistResearchRequestCount) Wishlist research brief\(agentReadyWishlistResearchRequestCount == 1 ? "" : "s") are agent-ready and need one local batch packet before external comparison work."
    }
    if wishlistPurchasePacketNeededItemCount > 0 {
      return "\(wishlistPurchasePacketNeededItemCount) Wishlist item\(wishlistPurchasePacketNeededItemCount == 1 ? "" : "s") with seller options need a local purchase packet draft before any manual buying."
    }
    if wishlistReadinessBlockedItemCount > 0 {
      return "\(wishlistReadinessBlockedItemCount) Wishlist purchase readiness check\(wishlistReadinessBlockedItemCount == 1 ? "" : "s") need review before a buy decision."
    }
    if wishlistPurchasedNeedsOrderLinkItemCount > 0 {
      return "\(wishlistPurchasedNeedsOrderLinkItemCount) purchased Wishlist item\(wishlistPurchasedNeedsOrderLinkItemCount == 1 ? "" : "s") need an order link so delivery tracking can continue."
    }
    if wishlistLinkedOrderDispatchGapItemCount > 0 {
      return "\(wishlistLinkedOrderDispatchGapItemCount) linked Wishlist order\(wishlistLinkedOrderDispatchGapItemCount == 1 ? "" : "s") need local manifest or dispatch readiness setup before outbound handoff is treated as ready."
    }
    if wishlistHandoffSanityBlockedItemCount > 0 {
      return "\(wishlistHandoffSanityBlockedItemCount) Wishlist purchase handoff\(wishlistHandoffSanityBlockedItemCount == 1 ? "" : "s") need account, cost, receiving, or order-watch context."
    }
    if wishlistDashboardAttentionItemCount > 0 {
      return "\(wishlistDashboardAttentionItemCount) wishlist item\(wishlistDashboardAttentionItemCount == 1 ? "" : "s") need follow-up: \(wishlistAttentionBlockerSummary)."
    }
    return nil
  }

  var wishlistDashboardCardDetail: String {
    let readiness = wishlistAgentReadinessSummary
    if wishlistDailyAttentionCount == 0 {
      if wishlistBatchBriefNeeded {
        return "\(agentReadyWishlistResearchRequestCount) agent-ready research brief\(agentReadyWishlistResearchRequestCount == 1 ? "" : "s") need one batch packet. Agent verdict: \(readiness.verdict)."
      }
      return "\(readiness.verdict). Purchase packets: \(wishlistPurchasePacketDraftCount) drafted. Release checklist: \(wishlistReleaseReadyItemCount) ready handoff, \(wishlistReleaseBlockedItemCount) blocked, \(wishlistReleaseOrderWatchItemCount) watching for order confirmation."
    }
    return "Top blockers: \(wishlistAttentionBlockerSummary). Readiness checks: \(wishlistReadinessBlockedItemCount), purchase packets: \(wishlistPurchasePacketNeededItemCount), order links: \(wishlistPurchasedNeedsOrderLinkItemCount), dispatch setup: \(wishlistLinkedOrderDispatchGapItemCount), closure trail: \(readiness.operationsClosureGapCount)."
  }

  var wishlistOrderWatchItems: [WishlistItem] {
    activeWishlistItems
      .filter { item in
        item.purchaseHandoff != nil
          && item.purchaseHandoff?.linkedOrderID == nil
      }
      .sorted { first, second in
        let firstMatches = suggestedWishlistOrderConfirmations(for: first).count
        let secondMatches = suggestedWishlistOrderConfirmations(for: second).count
        if firstMatches == secondMatches {
          return first.itemName.localizedCaseInsensitiveCompare(second.itemName) == .orderedAscending
        }
        return firstMatches > secondMatches
      }
  }

  var wishlistOrderWatchMatchCount: Int {
    wishlistOrderWatchItems.reduce(0) { partial, item in
      partial + suggestedWishlistOrderConfirmations(for: item).count
    }
  }

  var wishlistPurchaseReadinessItems: [WishlistItem] {
    activeWishlistItems
      .filter { item in
        !item.operatorPurchaseBlockers.isEmpty
          || (item.purchaseDecision?.reviewState == .accepted && item.purchaseHandoff == nil)
          || (item.purchaseHandoff != nil && item.purchaseHandoff?.linkedOrderID == nil)
      }
      .sorted { first, second in
        let firstPriority = wishlistPurchaseReadinessPriority(for: first)
        let secondPriority = wishlistPurchaseReadinessPriority(for: second)
        if firstPriority == secondPriority {
          return first.itemName.localizedCaseInsensitiveCompare(second.itemName) == .orderedAscending
        }
        return firstPriority < secondPriority
      }
  }

  var wishlistPurchaseDecisionGapCount: Int {
    wishlistPurchaseReadinessItems.filter {
      $0.purchaseDecision == nil || $0.purchaseDecision?.reviewState != .accepted
    }.count
  }

  var wishlistPurchaseHandoffGapCount: Int {
    wishlistPurchaseReadinessItems.filter {
      $0.purchaseDecision?.reviewState == .accepted && $0.purchaseHandoff == nil
    }.count
  }

  func wishlistPurchaseReadinessPriority(for item: WishlistItem) -> Int {
    if item.comparisonOptions?.isEmpty != false { return 10 }
    if item.preferredOptionID == nil { return 20 }
    if item.purchaseChecks?.isEmpty != false { return 30 }
    if item.purchaseChecks?.contains(where: { $0.status != "Passed" }) == true { return 35 }
    if item.purchaseDecision == nil { return 40 }
    if item.purchaseDecision?.reviewState != .accepted { return 50 }
    if item.purchaseHandoff == nil { return 60 }
    if item.purchaseHandoff?.linkedOrderID == nil { return 70 }
    return 90
  }

  func wishlistPurchaseReadinessStage(for item: WishlistItem) -> String {
    switch wishlistPurchaseReadinessPriority(for: item) {
    case 10: return "Needs comparison"
    case 20: return "Choose seller"
    case 30: return "Run checks"
    case 35: return "Clear checks"
    case 40: return "Draft decision"
    case 50: return "Review decision"
    case 60: return "Prepare handoff"
    case 70: return "Watch order"
    default: return "Linked"
    }
  }

  func wishlistPurchaseReadinessTone(for item: WishlistItem) -> String {
    switch wishlistPurchaseReadinessPriority(for: item) {
    case 10: return "setup"
    case 20, 30: return "warning"
    case 35: return "critical"
    case 40, 50, 60: return "decision"
    case 70: return "handoff"
    default: return "success"
    }
  }

  func runWishlistPurchaseReadinessAction(for item: WishlistItem) {
    switch wishlistPurchaseReadinessPriority(for: item) {
    case 10:
      createWishlistComparisonPlan(item)
      createWishlistResearchRequest(from: item)
    case 20:
      evaluateWishlistComparisonOptions(item)
    case 30, 35:
      runWishlistPurchaseReadinessCheck(item)
    case 40:
      createWishlistPurchaseDecision(item)
    case 50:
      markWishlistPurchaseDecisionReviewed(item)
    case 60:
      prepareWishlistPurchaseHandoff(item)
    case 70:
      markWishlistOrderConfirmationSeen(item)
    default:
      break
    }
  }

