  }

  private func intakeParserRegressionResult(
    id: String,
    sampleName: String,
    message: FetchedMailboxMessage,
    parsed: ForwardedEmailIntake,
    expectedOrderNumber: String?,
    expectedTrackingNumber: String?,
    expectedMerchant: String?,
    expectedDestination: String?
  ) -> IntakeParserRegressionResult {
    var failures: [String] = []
    if let expectedOrderNumber {
      if parsed.detectedOrderNumber.normalizedValidationKey != expectedOrderNumber.normalizedValidationKey {
        failures.append("order expected \(expectedOrderNumber), got \(parsed.detectedOrderNumber)")
      }
    } else if !parsed.detectedOrderNumber.isPlaceholderValidationValue {
      failures.append("order should stay empty, got \(parsed.detectedOrderNumber)")
    }

    if let expectedTrackingNumber {
      if parsed.detectedTrackingNumber.normalizedValidationKey != expectedTrackingNumber.normalizedValidationKey {
        failures.append("tracking expected \(expectedTrackingNumber), got \(parsed.detectedTrackingNumber)")
      }
    } else if !parsed.detectedTrackingNumber.isPlaceholderValidationValue {
      failures.append("tracking should stay empty, got \(parsed.detectedTrackingNumber)")
    }

    if let expectedMerchant,
       parsed.detectedMerchant.normalizedValidationKey != expectedMerchant.normalizedValidationKey {
      failures.append("merchant expected \(expectedMerchant), got \(parsed.detectedMerchant)")
    }

    if let expectedDestination,
       !parsed.detectedDestinationAddress.localizedCaseInsensitiveContains(expectedDestination) {
      failures.append("destination expected \(expectedDestination), got \(parsed.detectedDestinationAddress)")
    }

    let status = failures.isEmpty ? "Passed" : "Needs review"
    let expectations = [
      expectedOrderNumber.map { "order \($0)" } ?? "no order expected",
      expectedTrackingNumber.map { "tracking \($0)" } ?? "no tracking expected",
      expectedDestination.map { "destination \($0)" } ?? nil
    ].compactMap(\.self).joined(separator: ", ")

    return IntakeParserRegressionResult(
      id: id,
      sampleName: sampleName,
      subjectPreview: safeAuditPreview(message.subject, limit: 120),
      expectedOrderNumber: expectedOrderNumber,
      detectedOrderNumber: parsed.detectedOrderNumber,
      expectedTrackingNumber: expectedTrackingNumber,
      detectedTrackingNumber: parsed.detectedTrackingNumber,
      expectedMerchant: expectedMerchant,
      detectedMerchant: parsed.detectedMerchant,
      expectedDestination: expectedDestination,
      detectedDestination: parsed.detectedDestinationAddress,
      status: status,
      detail: failures.isEmpty ? "Expected \(expectations)." : failures.joined(separator: "; ")
    )
  }

  private func detectedDestinationAddress(in text: String) -> String {
    if let range = text.range(of: #"(?i)\bto\s+([^.\n]+)"#, options: .regularExpression) {
      let value = text[range]
        .replacingOccurrences(of: #"(?i)^\s*to\s+"#, with: "", options: .regularExpression)
        .trimmingCharacters(in: .whitespacesAndNewlines)
      if !value.isEmpty { return value }
    }
    return "Destination needs review"
  }

  private func matchedOrderID(for orderNumber: String) -> UUID? {
    orders.first { $0.orderNumber.caseInsensitiveCompare(orderNumber) == .orderedSame }?.id
  }

  private func firstMatch(in text: String, pattern: String) -> String? {
    guard let regex = try? NSRegularExpression(pattern: pattern) else { return nil }
    let range = NSRange(text.startIndex..<text.endIndex, in: text)
    guard let match = regex.firstMatch(in: text, range: range) else { return nil }
    let captureRange = match.numberOfRanges > 1 ? match.range(at: 1) : match.range(at: 0)
    guard let swiftRange = Range(captureRange, in: text) else { return nil }
    return String(text[swiftRange]).trimmingCharacters(in: .whitespacesAndNewlines)
  }

  private func firstGenericOrderMatch(in text: String, pattern: String) -> String? {
    guard let regex = try? NSRegularExpression(pattern: pattern) else { return nil }
    let range = NSRange(text.startIndex..<text.endIndex, in: text)
    let matches = regex.matches(in: text, range: range)
    for match in matches {
      guard let matchRange = Range(match.range(at: 0), in: text) else { continue }
      let prefixStart = text.index(matchRange.lowerBound, offsetBy: -min(32, text.distance(from: text.startIndex, to: matchRange.lowerBound)), limitedBy: text.startIndex) ?? text.startIndex
      let prefix = String(text[prefixStart..<matchRange.lowerBound]).lowercased()
      if prefix.range(of: #"(tracking|shipment|parcel|consignment|waybill|awb)\s+(update|number|no\.?|id|ref)?\s*$"#, options: .regularExpression) != nil {
        continue
      }
      return String(text[matchRange]).trimmingCharacters(in: .whitespacesAndNewlines)
    }
    return nil
  }

  private func cleanDetectedIdentifier(_ value: String) -> String? {
    var cleaned = value
      .replacingOccurrences(of: #"\s+"#, with: "", options: .regularExpression)
      .trimmingCharacters(in: CharacterSet(charactersIn: " \t\r\n.,;:()[]{}<>\"'"))
    let boilerplateMarkers = ["SENTSECURELY", "SENTFROM", "FROM", "HTTPS", "HTTP", "VIEW", "CLICK"]
    for marker in boilerplateMarkers {
      if let range = cleaned.range(of: marker, options: [.caseInsensitive]),
         cleaned.distance(from: cleaned.startIndex, to: range.lowerBound) >= 5 {
        cleaned = String(cleaned[..<range.lowerBound])
      }
    }
    guard cleaned.count >= 3 else { return nil }
    return cleaned
  }

  private func isLikelyOrderIdentifier(_ value: String) -> Bool {
    let normalized = value.normalizedValidationKey.uppercased()
    guard normalized.count >= 4, normalized.count <= 32 else { return false }
    guard normalized.rangeOfCharacter(from: .decimalDigits) != nil else { return false }
    let blocked = ["ORDER", "ORDERS", "NUMBER", "CONFIRMATION", "RECEIPT", "INVOICE", "TRACKING", "SHIPMENT", "SHIPPING", "SHIPPED", "UPDATE", "DETAIL", "DETAILS", "INCLUDED", "NOTIFICATION", "ACCOUNT", "DELIVERY", "PURCHASE", "SPACEMAIL"]
    return !blocked.contains(normalized)
      && !blocked.contains { normalized.contains($0) }
  }

  private func isLikelyTrackingIdentifier(_ value: String) -> Bool {
    let normalized = value.normalizedValidationKey.uppercased()
    guard normalized.count >= 5, normalized.count <= 34 else { return false }
    guard normalized.rangeOfCharacter(from: .decimalDigits) != nil else { return false }
    let blocked = ["TRACKING", "SHIPMENT", "CONSIGNMENT", "NUMBER", "ORDER", "SHIPPING", "SHIPPED", "UPDATE", "DETAIL", "DETAILS", "INCLUDED", "NOTIFICATION", "ACCOUNT", "DELIVERY", "PURCHASE", "SPACEMAIL"]
    return !blocked.contains(normalized)
      && !blocked.contains { normalized.contains($0) }
  }

  private func safeAuditPreview(_ value: String, limit: Int) -> String {
    let cleaned = value
      .replacingOccurrences(of: #"\s+"#, with: " ", options: .regularExpression)
      .trimmingCharacters(in: .whitespacesAndNewlines)
    return cleaned.isEmpty ? "empty" : String(cleaned.prefix(limit))
  }

  private func mailboxIngestAuditDetail(for record: MailboxIngestRecord) -> String {
    "Provider message ID: \(record.providerMessageID)\nSource mailbox ID: \(record.sourceMailboxID.uuidString)\nStatus: \(record.status.rawValue)\nCaptured: \(record.capturedDate)\n\(record.summary)"
  }

