  func createHandoffNoteFromMailboxProviderHandoffPacket() {
    let packet = mailboxProviderHandoffPacketSummary
    let notePriority: TaskPriority
    switch packet.tone {
    case "warning":
      notePriority = .high
    case "attention":
      notePriority = .normal
    default:
