    persistReturnClaims()
    logAudit(action: .edited, entityType: .returnClaim, entityID: claim.id.uuidString, entityLabel: claim.title, summary: "Return or claim details updated.", beforeDetail: beforeDetail, afterDetail: claim.auditDetail)
  }

