      action: .created,
      entityType: .handoffNote,
      entityID: note.id.uuidString,
      entityLabel: note.title,
      summary: "Gmail shift handoff note created locally.",
      afterDetail: "\(detail)\nNo Google sign-in, token request, Gmail API call, mailbox fetch, external service call, or mailbox mutation occurred."
    )
  }

  func createGmailShiftReviewTask() {
    let summary = gmailShiftHandoffSummary
    let taskID = "gmail-shift-handoff"
    let priority = gmailHandoffPriority(for: summary.tone)
    let topBlocker = gmailReleaseBlockerSummary.blockers.first { $0.tone == "warning" || $0.tone == "attention" }
    let blockerDetail = topBlocker.map { "Top release blocker: \($0.title). \($0.detail) Next action: \($0.nextAction)" } ?? "Top release blocker: none promoted."
    let taskSummary = "\(summary.title): \(summary.detail) \(summary.lastRefreshText)\n\(gmailShiftHandoffDetail(summary))\n\(blockerDetail)"

    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .integration
        && $0.linkedEntityID == taskID
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = "Follow up Gmail shift handoff"
      reviewTasks[existingIndex].summary = taskSummary
      reviewTasks[existingIndex].priority = priority
      reviewTasks[existingIndex].dueDate = priority == .high ? "Today" : priority == .normal ? "Tomorrow" : "This week"
      reviewTasks[existingIndex].assignee = "Mailbox team"
      reviewTasks[existingIndex].reviewState = .needsReview
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Existing Gmail shift review task refreshed.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\n\(blockerDetail)\nRefreshed from local Gmail shift summary. No duplicate task was created. No Google sign-in, token request, Gmail API call, mailbox fetch, external service call, or mailbox mutation occurred."
      )
      return
    }

    let task = ReviewTask(
      title: "Follow up Gmail shift handoff",
      summary: taskSummary,
      linkedEntityType: .integration,
      linkedEntityID: taskID,
      priority: priority,
      dueDate: priority == .high ? "Today" : priority == .normal ? "Tomorrow" : "This week",
      assignee: "Mailbox team",
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: .needsReview
    )

    addReviewTask(task, summary: "Review task created from Gmail shift handoff.")
    logAudit(
      action: .created,
      entityType: .gmailMailboxConnection,
      entityID: taskID,
      entityLabel: "Gmail shift handoff",
      summary: "Gmail shift summary review task created locally.",
      afterDetail: "\(gmailShiftHandoffDetail(summary))\n\(blockerDetail)\nNo Google sign-in, token request, Gmail API call, mailbox fetch, external service call, or mailbox mutation occurred."
    )
  }

  func createGmailShiftDraftMessage() {
    let summary = gmailShiftHandoffSummary
    let draftID = "gmail-shift-handoff"
    createMailboxShiftDraftMessage(
      linkedEntityID: draftID,
      providerName: "Gmail",
      subject: "Gmail shift handoff - \(summary.title)",
      body: "\(gmailShiftHandoffDetail(summary))\nNo Google sign-in, token request, Gmail API call, mailbox fetch, external service call, or mailbox mutation occurred."
    )
  }

  private func gmailHandoffPriority(for tone: String) -> TaskPriority {
    switch tone {
    case "warning":
      return .high
    case "attention":
      return .normal
    case "success":
      return .low
    default:
      return .normal
    }
  }

  private func gmailShiftHandoffDetail(_ summary: GmailShiftHandoffSummary) -> String {
    let metrics = summary.keyCounts.map { "\($0.title): \($0.value)" }.joined(separator: ", ")
    let lines = summary.handoffLines.map { "- \($0.title): \($0.detail)" }.joined(separator: "\n")
    return """
    Handoff status: \(summary.title)
    Handoff detail: \(summary.detail)
    Latest refresh note: \(summary.lastRefreshText)
    Counts: \(metrics)
    Handoff checks:
    \(lines)
    Boundary: Gmail remains explicit, manual, and read-only. This follow-up does not run Google sign-in, request tokens, call Gmail, fetch mailbox messages, import messages, or mutate mailbox messages.
    """
  }

  private func gmailLatestRefreshTaskNextAction(for connection: GmailMailboxConnection, hasFailure: Bool, uncertainCount: Int, filteredCount: Int) -> String {
    if hasFailure {
      return "Open Mailbox Monitor, inspect the Gmail troubleshooting runbook, then retry sign-in or readiness only after setup is corrected"
    }
    if connection.lastRefreshImportedCount > 0 {
      return "Open Inbox and create or link orders from imported Gmail intake"
    }
    if uncertainCount > 0 {
      return "Review uncertain Gmail previews in Mailbox Monitor and import true order mail"
    }
    if filteredCount > 0 {
      return "Check filtered examples only if expected order mail is missing; otherwise no Inbox action is needed"
    }
    if connection.lastRefreshDuplicateCount > 0 {
      return "Confirm duplicates did not create extra Inbox rows"
    }
    return "Run refresh again only when new Gmail order mail is expected"
  }

  func gmailAuthSessionState(for connection: GmailMailboxConnection) -> GmailAuthSessionState {
    gmailAuthSessionStates[connection.id] ?? GmailAuthSessionState(
      connectionID: connection.id,
      status: .notConnected,
      signedInAccount: "Not signed in",
      lastAuthAttemptDate: "Never",
      lastSuccessfulAuthDate: "Never",
      tokenStoreStatus: "Token storage not configured",
      tokenStoreDetail: "ParcelOps custom Gmail token storage is not implemented. GoogleSignIn may manage its own SDK cache after real sign-in, but ParcelOps does not create, read, write, delete, store, or log Google access tokens or refresh tokens.",
      detailText: "Gmail is not connected for this setup record. Mock auth can test UI states. Real Google sign-in and manual read-only Gmail refresh are available only after the compiled app client ID and callback scheme match the saved Gmail setup."
    )
  }

  func connectGmailAuthMock(_ connection: GmailMailboxConnection) {
    let previousState = gmailAuthSessionState(for: connection)
    let startedState = GmailAuthSessionState(
      connectionID: connection.id,
      status: .connecting,
      signedInAccount: "Not signed in",
      lastAuthAttemptDate: Self.auditTimestamp(),
      lastSuccessfulAuthDate: previousState.lastSuccessfulAuthDate,
      tokenStoreStatus: previousState.tokenStoreStatus,
      tokenStoreDetail: previousState.tokenStoreDetail,
      detailText: "Mock Gmail auth started locally. No Google sign-in opened and no token request was made."
    )
    gmailAuthSessionStates[connection.id] = startedState
    logAudit(
      action: .evaluated,
      entityType: .gmailMailboxConnection,
      entityID: connection.id.uuidString,
      entityLabel: connection.displayName,
      summary: "Mock Gmail auth started.",
      afterDetail: gmailAuthSessionAuditDetail(startedState)
    )

    Task {
      let result = await gmailAuthClient.connect(connection: connection)
      await MainActor.run {
        applyGmailAuthResult(result, to: connection)
      }
    }
  }

  func testRealGmailSignIn(_ connection: GmailMailboxConnection) {
    let attemptID = UUID()
    activeGmailAuthAttempts[connection.id] = attemptID
    let previousState = gmailAuthSessionState(for: connection)
    let timestamp = Self.auditTimestamp()
    let startedState = GmailAuthSessionState(
      connectionID: connection.id,
      status: .connecting,
      signedInAccount: "Not signed in",
      lastAuthAttemptDate: timestamp,
      lastSuccessfulAuthDate: previousState.lastSuccessfulAuthDate,
      tokenStoreStatus: previousState.tokenStoreStatus,
      tokenStoreDetail: previousState.tokenStoreDetail,
      detailText: "Real Gmail sign-in test started. A browser sign-in may open, but ParcelOps will not store token values in JSON and will not fetch Gmail messages. Attempt ID: \(attemptID.uuidString)."
    )
    gmailAuthSessionStates[connection.id] = startedState
    logAudit(
      action: .evaluated,
      entityType: .gmailMailboxConnection,
      entityID: connection.id.uuidString,
      entityLabel: connection.displayName,
      summary: "Real Gmail sign-in test started.",
      afterDetail: gmailAuthSessionAuditDetail(startedState)
    )

    Task {
      let result = await realGmailAuthClient.connect(connection: connection)
      await MainActor.run {
        applyRealGmailAuthResult(result, to: connection, attemptID: attemptID)
      }
    }

    Task {
      try? await Task.sleep(for: .seconds(120))
      await MainActor.run {
        completeTimedOutGmailAuthAttempt(connectionID: connection.id, attemptID: attemptID)
      }
    }
  }

  private func applyRealGmailAuthResult(_ result: GmailAuthResult, to connection: GmailMailboxConnection, attemptID: UUID? = nil) {
    activeGmailAuthAttempts[connection.id] = nil
    let timestamp = Self.auditTimestamp()
    let previousState = gmailAuthSessionState(for: connection)
    let tokenStatus = connection.credentialStorageStatus.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
      ? "Token storage not configured"
      : connection.credentialStorageStatus
    let state = GmailAuthSessionState(
      connectionID: connection.id,
      status: result.status,
      signedInAccount: result.signedInAccount,
      lastAuthAttemptDate: timestamp,
      lastSuccessfulAuthDate: previousState.lastSuccessfulAuthDate,
      tokenStoreStatus: tokenStatus,
      tokenStoreDetail: result.status == .connected
        ? "GoogleSignIn completed sign-in and may manage its own token cache. ParcelOps did not write token values to JSON, custom Keychain storage, or audit logs."
        : "Real Gmail sign-in did not produce a connected session in ParcelOps. No Google token values were stored in JSON, custom Keychain storage, or audit logs.",
      detailText: attemptID.map { "\(result.detailText) Attempt ID: \($0.uuidString)." } ?? result.detailText
    )
    gmailAuthSessionStates[connection.id] = state
    updateGmailMailboxConnection(connection) { draft in
      draft.connectionStatus = "Real Gmail sign-in: \(result.status.rawValue)"
      draft.credentialStorageStatus = result.status == .connected ? "GoogleSignIn token cache managed by SDK" : draft.credentialStorageStatus
      draft.oauthReadinessStatus = result.status == .connected ? "Real Gmail sign-in completed" : result.status.rawValue
    }
    logAudit(
      action: .evaluated,
      entityType: .gmailMailboxConnection,
      entityID: connection.id.uuidString,
      entityLabel: connection.displayName,
      summary: result.status == .connected ? "Real Gmail sign-in succeeded." : "Real Gmail sign-in did not connect.",
      afterDetail: gmailAuthSessionAuditDetail(state)
    )
  }

  private func completeTimedOutGmailAuthAttempt(connectionID: UUID, attemptID: UUID) {
    guard activeGmailAuthAttempts[connectionID] == attemptID,
          let connection = gmailMailboxConnections.first(where: { $0.id == connectionID }) else { return }

    let previousState = gmailAuthSessionState(for: connection)
    guard previousState.status == .connecting else {
      activeGmailAuthAttempts[connectionID] = nil
      return
    }

    activeGmailAuthAttempts[connectionID] = nil
    let state = GmailAuthSessionState(
      connectionID: connectionID,
      status: .notConnected,
      signedInAccount: previousState.signedInAccount,
      lastAuthAttemptDate: previousState.lastAuthAttemptDate,
      lastSuccessfulAuthDate: previousState.lastSuccessfulAuthDate,
      tokenStoreStatus: previousState.tokenStoreStatus,
      tokenStoreDetail: previousState.tokenStoreDetail,
      detailText: "Timeout: ParcelOps did not receive a final GoogleSignIn completion after the browser sign-in window returned or stalled. Try Test real Google sign-in again from an active ParcelOps window. If this repeats, check the compiled Google callback URL scheme, Google Cloud OAuth client type, consent screen, Xcode signing, and GoogleSignIn callback routing. No Google access token, refresh token, ID token, auth code, client secret, password, raw callback URL, or Gmail message was stored in ParcelOps JSON or audit logs. No Gmail API mailbox call was made. Attempt ID: \(attemptID.uuidString)."
    )
    gmailAuthSessionStates[connectionID] = state
    updateGmailMailboxConnection(connection) { draft in
      draft.connectionStatus = "Real Gmail sign-in timed out"
      draft.oauthReadinessStatus = "Real Gmail sign-in timed out"
    }
    logAudit(
      action: .evaluated,
      entityType: .gmailMailboxConnection,
      entityID: connectionID.uuidString,
      entityLabel: connection.displayName,
      summary: "Real Gmail sign-in timed out before completion.",
      afterDetail: gmailAuthSessionAuditDetail(state)
    )
  }

