  func stageWishlistCaptureFromPastedLink(
    pastedText: String,
    itemName: String,
    sellerHint: String,
    priceHint: String,
    notes: String
  ) {
    let cleanText = pastedText.trimmingCharacters(in: .whitespacesAndNewlines)
    let cleanItemName = itemName.trimmingCharacters(in: .whitespacesAndNewlines)
    let cleanSellerHint = sellerHint.trimmingCharacters(in: .whitespacesAndNewlines)
    let cleanPriceHint = priceHint.trimmingCharacters(in: .whitespacesAndNewlines)
    let cleanNotes = notes.trimmingCharacters(in: .whitespacesAndNewlines)
    let detectedURL = Self.normalizedProductURLString(Self.firstURLString(in: cleanText))
    let labeledItemName = Self.labeledValue(in: cleanText, labels: ["item", "item name", "product", "product name", "title", "name"])
    let labeledSeller = Self.labeledValue(in: cleanText, labels: ["seller", "retailer", "store", "storefront", "merchant", "brand"])
    let labeledPrice = Self.labeledValue(in: cleanText, labels: ["price", "visible price", "budget", "cost", "listed price", "sale price"])
    let labeledNotes = Self.labeledValue(in: cleanText, labels: ["notes", "note", "model", "size", "shipping", "postage", "why"])
    let storefront = cleanSellerHint.isEmpty
      ? labeledSeller ?? Self.storefrontHint(from: detectedURL)
      : cleanSellerHint
    let detectedPrice = cleanPriceHint.isEmpty ? labeledPrice ?? "Price needs review" : cleanPriceHint
    let inferredTitle = cleanItemName.isEmpty
      ? labeledItemName ?? Self.titleHint(from: detectedURL, fallback: cleanText)
      : cleanItemName
    let summaryParts = [
      cleanItemName.isEmpty ? labeledItemName.map { "Item: \($0)" } : "Item: \(cleanItemName)",
      detectedURL.isPlaceholderValidationValue ? nil : "URL pasted for later review",
      detectedPrice.isPlaceholderValidationValue ? nil : "Price clue: \(detectedPrice)",
      labeledNotes,
      cleanNotes.isEmpty ? nil : cleanNotes
    ].compactMap { $0 }
    let summary = summaryParts.isEmpty
      ? "Pasted product link staged for Wishlist review. Confirm item, seller, price, postage, seller trust, and purchase intent before promotion."
      : summaryParts.joined(separator: ". ")

    let capture = WishlistCaptureCandidate(
      source: .shareSheet,
      pageTitle: inferredTitle,
      pageURL: detectedURL,
      detectedStorefront: storefront,
      detectedPrice: detectedPrice,
      productSummary: summary,
      captureStatus: "Pasted link staged",
      reviewState: .needsReview,
      capturedDate: Self.auditTimestamp(),
      notes: "Local pasted-link capture only. ParcelOps did not open the page, scrape the website, compare live prices, convert currency, rate the seller, log into accounts, buy, pay, or contact external services."
    )
    wishlistCaptureCandidates.insert(capture, at: 0)
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: capture.id.uuidString,
      entityLabel: capture.pageTitle,
      summary: "Wishlist pasted product link staged locally.",
      afterDetail: "\(capture.auditDetail)\nParsed hints: URL \(detectedURL.isPlaceholderValidationValue ? "missing" : "present"), seller \(storefront.isPlaceholderValidationValue ? "needs review" : "hinted"), price \(detectedPrice.isPlaceholderValidationValue ? "needs review" : "hinted"), item \(inferredTitle.isPlaceholderValidationValue ? "needs review" : "hinted"). Tracking parameters were stripped when possible. No browser extension, web lookup, scraping, account login, checkout, purchase, payment, currency conversion, seller trust lookup, mailbox fetch, or external service occurred."
    )
  }

  private static func firstURLString(in text: String) -> String {
    guard
      let detector = try? NSDataDetector(types: NSTextCheckingResult.CheckingType.link.rawValue),
      let match = detector.firstMatch(in: text, options: [], range: NSRange(text.startIndex..., in: text)),
      let range = Range(match.range, in: text)
    else {
      return "Product URL needs review"
    }
    var url = String(text[range]).trimmingCharacters(in: .whitespacesAndNewlines)
    while let last = url.last, [".", ",", ")", "]"].contains(String(last)) {
      url.removeLast()
    }
    return url
  }

  private static func normalizedProductURLString(_ urlString: String) -> String {
    let urlWithScheme = Self.URLStringWithScheme(urlString)
    guard
      !urlWithScheme.isPlaceholderValidationValue,
      var components = URLComponents(string: urlWithScheme)
    else {
      return urlString
    }

    let removablePrefixes = ["utm_", "fbclid", "gclid", "mc_", "igshid"]
    let removableNames: Set<String> = [
      "ref",
      "ref_",
      "referrer",
      "campaign",
      "source",
      "medium",
      "yclid",
      "msclkid",
      "spm",
      "tag"
    ]
    components.queryItems = components.queryItems?.filter { item in
      let name = item.name.lowercased()
      if removableNames.contains(name) { return false }
      return !removablePrefixes.contains { name.hasPrefix($0) }
    }
    if components.queryItems?.isEmpty == true {
      components.queryItems = nil
    }
    components.fragment = nil
    return components.string ?? urlWithScheme
  }

  private static func URLStringWithScheme(_ urlString: String) -> String {
    let cleaned = urlString.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !cleaned.isEmpty, !cleaned.isPlaceholderValidationValue else { return urlString }
    if cleaned.localizedCaseInsensitiveContains("://") { return cleaned }
    if cleaned.contains(".") && !cleaned.contains(" ") {
      return "https://\(cleaned)"
    }
    return cleaned
  }

  private static func storefrontHint(from urlString: String) -> String {
    guard
      !urlString.isPlaceholderValidationValue,
      let url = URL(string: urlString),
      let host = url.host
    else {
      return "Storefront needs review"
    }
    let trimmedHost = host
      .replacingOccurrences(of: "www.", with: "")
      .split(separator: ".")
      .first
      .map(String.init) ?? host
    let spaced = trimmedHost
      .replacingOccurrences(of: "-", with: " ")
      .replacingOccurrences(of: "_", with: " ")
    return spaced
      .split(separator: " ")
      .map { $0.prefix(1).uppercased() + $0.dropFirst() }
      .joined(separator: " ")
  }

  private static func titleHint(from urlString: String, fallback: String) -> String {
    guard
      !urlString.isPlaceholderValidationValue,
      let url = URL(string: urlString)
    else {
      let cleanFallback = fallback.trimmingCharacters(in: .whitespacesAndNewlines)
      return cleanFallback.isEmpty ? "Pasted Wishlist product" : String(cleanFallback.prefix(80))
    }
    let pathPieces = url.path
      .split(separator: "/")
      .map(String.init)
      .filter { piece in
        let lower = piece.lowercased()
        return !piece.isEmpty
          && lower != "products"
          && lower != "product"
          && lower != "item"
          && lower != "items"
          && lower != "p"
          && lower != "dp"
          && lower != "collections"
          && !lower.allSatisfy(\.isNumber)
      }
    guard let bestPiece = pathPieces.last else {
      return storefrontHint(from: urlString)
    }
    let decoded = bestPiece.removingPercentEncoding ?? bestPiece
    let cleaned = decoded
      .replacingOccurrences(of: "-", with: " ")
      .replacingOccurrences(of: "_", with: " ")
      .replacingOccurrences(of: "+", with: " ")
      .trimmingCharacters(in: .whitespacesAndNewlines)
    return cleaned.isEmpty ? storefrontHint(from: urlString) : String(cleaned.prefix(80))
  }

  private static func labeledValue(in text: String, labels: [String]) -> String? {
    let lowerLabels = labels.map { $0.lowercased() }
    for rawLine in text.components(separatedBy: .newlines) {
      let line = rawLine.trimmingCharacters(in: .whitespacesAndNewlines)
      let lowerLine = line.lowercased()
      for label in lowerLabels {
        for separator in [":", "-", "–", "—"] {
          let prefix = "\(label)\(separator)"
          if lowerLine.hasPrefix(prefix) {
            let index = line.index(line.startIndex, offsetBy: prefix.count)
            let value = line[index...].trimmingCharacters(in: .whitespacesAndNewlines)
            if !value.isEmpty { return String(value.prefix(140)) }
          }
        }
      }
    }
    return nil
  }

  private static func clippedComparisonText(_ text: String) -> String {
    let cleaned = text
      .components(separatedBy: .newlines)
      .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
      .filter { !$0.isEmpty }
      .joined(separator: " ")
    return String(cleaned.prefix(600))
  }

  private static func nonBlank(_ text: String) -> String? {
    let clean = text.trimmingCharacters(in: .whitespacesAndNewlines)
    return clean.isEmpty ? nil : clean
  }

  private static func pastedComparisonBlocks(from text: String) -> [String] {
    let normalized = text
      .replacingOccurrences(of: "\r\n", with: "\n")
      .replacingOccurrences(of: "\r", with: "\n")
    let separatorNormalized = normalized
      .components(separatedBy: .newlines)
      .map { line -> String in
        let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed == "---" || trimmed == "===" ? "" : line
      }
      .joined(separator: "\n")
    let blocks = separatorNormalized
      .components(separatedBy: "\n\n")
      .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
      .filter { !$0.isEmpty }
    return blocks.isEmpty ? [text.trimmingCharacters(in: .whitespacesAndNewlines)].filter { !$0.isEmpty } : Array(blocks.prefix(8))
  }

  private static func currencyHint(from listedPrice: String, urlString: String) -> String {
    let lowerPrice = listedPrice.localizedLowercase
    let lowerURL = urlString.localizedLowercase
    if lowerPrice.contains("aud") || lowerURL.contains(".com.au") || lowerURL.hasSuffix(".au") { return "AUD" }
    if lowerPrice.contains("usd") || lowerPrice.contains("us$") { return "USD" }
    if lowerPrice.contains("gbp") || lowerPrice.contains("£") { return "GBP" }
    if lowerPrice.contains("eur") || lowerPrice.contains("€") { return "EUR" }
    if lowerPrice.contains("jpy") || lowerPrice.contains("¥") { return "JPY" }
    if listedPrice.contains("$") { return "Currency needs review" }
    return "Currency needs review"
  }

  private static func sellerRegionHint(from urlString: String, currency: String) -> String {
    let lowerURL = urlString.localizedLowercase
    let lowerHost = URL(string: urlString)?.host?.localizedLowercase ?? lowerURL
    let lowerCurrency = currency.localizedLowercase
    if lowerHost.hasSuffix(".com.au") || lowerHost.hasSuffix(".au") || lowerCurrency.contains("aud") { return "Australia" }
    if lowerHost.hasSuffix(".co.nz") || lowerHost.hasSuffix(".nz") { return "New Zealand" }
    if lowerHost.hasSuffix(".co.uk") || lowerHost.hasSuffix(".uk") || lowerCurrency.contains("gbp") { return "United Kingdom" }
    if lowerHost.hasSuffix(".de") { return "Germany" }
    if lowerHost.hasSuffix(".fr") { return "France" }
    if lowerHost.hasSuffix(".it") { return "Italy" }
    if lowerHost.hasSuffix(".es") { return "Spain" }
    if lowerHost.hasSuffix(".nl") { return "Netherlands" }
    if lowerHost.hasSuffix(".eu") || lowerCurrency.contains("eur") { return "Europe" }
    if lowerHost.hasSuffix(".jp") || lowerCurrency.contains("jpy") { return "Japan" }
    if lowerHost.hasSuffix(".sg") { return "Singapore" }
    if lowerHost.hasSuffix(".hk") { return "Hong Kong" }
    if lowerHost.hasSuffix(".cn") { return "China" }
    if lowerHost.hasSuffix(".kr") { return "South Korea" }
    return "Region needs review"
  }

  private static func wishlistSellerOptionReviewAssessment(
    seller: String,
    productURL: String,
    listedPrice: String,
    audTotal: String,
    postageCost: String,
    postageTime: String,
    trust: String
  ) -> (risk: String, recommendation: String, gaps: [String]) {
    var gaps: [String] = []
    let trustLower = trust.localizedLowercase
    let riskyTrustWords = ["unknown", "needs review", "low trust", "new seller", "marketplace", "unverified", "scam", "complaint"]
    let trustNeedsReview = trust.isPlaceholderValidationValue || riskyTrustWords.contains { trustLower.contains($0) }

    if seller.isPlaceholderValidationValue { gaps.append("seller") }
    if productURL.isPlaceholderValidationValue || !productURL.localizedCaseInsensitiveContains("http") { gaps.append("product link") }
    if listedPrice.isPlaceholderValidationValue || listedPrice.localizedCaseInsensitiveContains("needs review") { gaps.append("listed price") }
    if audTotal.isPlaceholderValidationValue || audTotal.localizedCaseInsensitiveContains("needs review") { gaps.append("AUD landed total") }
    if postageCost.isPlaceholderValidationValue || postageCost.localizedCaseInsensitiveContains("needs review") { gaps.append("postage cost") }
    if postageTime.isPlaceholderValidationValue || postageTime.localizedCaseInsensitiveContains("needs review") { gaps.append("delivery time") }
    if trustNeedsReview { gaps.append("seller trust") }

    if trustLower.contains("scam") || trustLower.contains("low trust") || trustLower.contains("complaint") {
      return ("High", "Do not buy until seller trust is checked", gaps)
    }
    if gaps.count >= 4 {
      return ("High", "Needs evidence before purchase review: \(gaps.prefix(4).joined(separator: ", "))", gaps)
    }
    if gaps.isEmpty {
      return ("Medium", "Ready for operator verification", gaps)
    }
    return ("Needs review", "Needs evidence before purchase review: \(gaps.joined(separator: ", "))", gaps)
  }

  private static func wishlistComparisonOptionFromPastedResult(
    pastedText: String,
    sellerHint: String,
    productURLHint: String,
    listedPriceHint: String,
    currencyHint: String,
    audTotalHint: String,
    postageCostHint: String,
    postageTimeHint: String,
    trustHint: String,
    notes: String
  ) -> WishlistComparisonOption {
    let cleanText = pastedText.trimmingCharacters(in: .whitespacesAndNewlines)
    let cleanNotes = notes.trimmingCharacters(in: .whitespacesAndNewlines)
    let rawURL = Self.nonBlank(productURLHint)
      ?? Self.labeledValue(in: cleanText, labels: ["url", "product url", "product link", "link"])
      ?? Self.firstURLString(in: cleanText)
    let detectedURL = Self.normalizedProductURLString(rawURL)
    let seller = Self.nonBlank(sellerHint)
      ?? Self.labeledValue(in: cleanText, labels: ["seller", "retailer", "store", "merchant"])
      ?? Self.storefrontHint(from: detectedURL)
    let listedPrice = Self.nonBlank(listedPriceHint)
      ?? Self.labeledValue(in: cleanText, labels: ["listed price", "price", "listed"])
      ?? "Listed price needs review"
    let currency = Self.nonBlank(currencyHint)
      ?? Self.labeledValue(in: cleanText, labels: ["currency"])
      ?? Self.currencyHint(from: listedPrice, urlString: detectedURL)
    let audTotal = Self.nonBlank(audTotalHint)
      ?? Self.labeledValue(in: cleanText, labels: ["aud total", "total aud", "estimated aud", "landed", "landed cost", "total"])
      ?? (currency.localizedCaseInsensitiveContains("AUD") ? listedPrice : "AUD total needs review")
    let postageCost = Self.nonBlank(postageCostHint)
      ?? Self.labeledValue(in: cleanText, labels: ["postage cost", "shipping cost", "postage", "shipping"])
      ?? "Postage cost needs review"
    let postageTime = Self.nonBlank(postageTimeHint)
      ?? Self.labeledValue(in: cleanText, labels: ["postage time", "delivery time", "delivery", "eta"])
      ?? "Postage time needs review"
    let trust = Self.nonBlank(trustHint)
      ?? Self.labeledValue(in: cleanText, labels: ["trust rating", "seller trust", "trust"])
      ?? "Seller trust needs review"
    let summary = Self.clippedComparisonText(cleanText)
    let trustNotes = [
      trust,
      cleanNotes.isEmpty ? nil : cleanNotes,
      summary.isEmpty ? nil : "Pasted summary: \(summary)"
    ]
      .compactMap { $0 }
      .joined(separator: " ")
    let cleanSeller = seller.isPlaceholderValidationValue ? "Seller needs review" : seller
    let cleanProductURL = detectedURL.isPlaceholderValidationValue ? "Product URL needs review" : detectedURL
    let region = Self.sellerRegionHint(from: cleanProductURL, currency: currency)
    let assessment = Self.wishlistSellerOptionReviewAssessment(
      seller: cleanSeller,
      productURL: cleanProductURL,
      listedPrice: listedPrice,
      audTotal: audTotal,
      postageCost: postageCost,
      postageTime: postageTime,
      trust: trust
    )

    return WishlistComparisonOption(
      sellerName: cleanSeller,
      productURL: cleanProductURL,
      listedPrice: listedPrice,
      currency: currency,
      estimatedAUDTotal: audTotal,
      postageCost: postageCost,
      postageTime: postageTime,
      sellerRegion: region,
      trustRating: trust,
      trustNotes: trustNotes.isEmpty ? "Seller trust, returns, warranty, and delivery reliability need review." : trustNotes,
      recommendation: assessment.recommendation,
      lastChecked: Self.auditTimestamp(),
      localScore: nil,
      riskLevel: assessment.risk,
      decisionReason: "Created from a pasted comparison research result. Review gaps: \(assessment.gaps.isEmpty ? "none detected in pasted fields" : assessment.gaps.joined(separator: ", ")). Operator must verify live price, stock, AUD total, postage, seller trust, returns, warranty, account fit, and payment readiness before purchase."
    )
  }

  func promoteWishlistCaptureToItem(_ capture: WishlistCaptureCandidate) {
    guard wishlistCaptureCandidates.contains(where: { $0.id == capture.id }) else { return }
    wishlistCaptureCandidates.removeAll { $0.id == capture.id }
    let stagedOption = wishlistComparisonOptionFromCapture(capture)
    let item = WishlistItem(
      itemName: capture.pageTitle.isPlaceholderValidationValue ? capture.productSummary : capture.pageTitle,
      storefront: capture.detectedStorefront,
      storefrontURL: capture.pageURL.isPlaceholderValidationValue ? "https://example.com" : capture.pageURL,
      estimatedCost: capture.detectedPrice,
      owner: "Current user",
      pool: "Wishlist review",
      source: capture.source,
      status: "Needs review",
      capturedDetail: "\(capture.productSummary) \(capture.notes)",
      comparisonStatus: stagedOption == nil ? "Not compared" : "Capture seller option staged",
      comparisonNotes: stagedOption == nil
        ? "Promoted from local capture staging. Create a comparison plan before purchase."
        : "Promoted from local capture staging with an initial seller option created from captured page metadata. Confirm AUD total, postage, seller trust, returns, warranty, and live availability before purchase review.",
      purchaseReadiness: stagedOption == nil ? "Needs comparison" : "Needs seller evidence review",
      preferredOptionID: nil,
      comparisonOptions: stagedOption.map { [$0] } ?? []
    )
    wishlistItems.insert(item, at: 0)
    persistWishlist()
    logAudit(
      action: .linked,
      entityType: .wishlistItem,
      entityID: item.id.uuidString,
      entityLabel: item.itemName,
      summary: "Wishlist capture candidate promoted to item.",
      beforeDetail: capture.auditDetail,
      afterDetail: "\(item.auditDetail)\nInitial seller option from capture: \(stagedOption == nil ? "none" : "created for \(stagedOption?.sellerName ?? "captured seller")"). Captured seller/price/link clues stay local and must be reviewed before purchase.\nPromoted from capture candidate \(capture.id.uuidString). No browser extension sync, web lookup, account login, purchase, payment, or retailer action occurred."
    )
  }

  private func wishlistComparisonOptionFromCapture(_ capture: WishlistCaptureCandidate) -> WishlistComparisonOption? {
    let seller = capture.detectedStorefront.trimmingCharacters(in: .whitespacesAndNewlines)
    let url = capture.pageURL.trimmingCharacters(in: .whitespacesAndNewlines)
    let price = capture.detectedPrice.trimmingCharacters(in: .whitespacesAndNewlines)
    let summary = capture.productSummary.trimmingCharacters(in: .whitespacesAndNewlines)

    let hasSeller = !seller.isEmpty
      && !seller.isPlaceholderValidationValue
      && !seller.localizedCaseInsensitiveContains("needs review")
      && !seller.localizedCaseInsensitiveContains("pending")
    let hasURL = !url.isEmpty
      && !url.isPlaceholderValidationValue
      && url.localizedCaseInsensitiveContains("http")
      && !url.localizedCaseInsensitiveContains("example.com")
    let hasPrice = !price.isEmpty
      && !price.isPlaceholderValidationValue
      && !price.localizedCaseInsensitiveContains("needs review")
      && !price.localizedCaseInsensitiveContains("pending")

    guard hasSeller || hasURL || hasPrice else { return nil }

    let listedPrice = hasPrice ? price : "Listed price needs review"
    let estimatedAUD: String
    if hasPrice && price.localizedCaseInsensitiveContains("aud") {
      estimatedAUD = price
    } else {
      estimatedAUD = "AUD total needs review"
    }

    return WishlistComparisonOption(
      sellerName: hasSeller ? seller : "Captured seller needs review",
      productURL: hasURL ? url : "Product URL needs review",
      listedPrice: listedPrice,
      currency: hasPrice && price.localizedCaseInsensitiveContains("aud") ? "AUD" : "Currency needs review",
      estimatedAUDTotal: estimatedAUD,
      postageCost: "Postage cost needs review",
      postageTime: "Postage time needs review",
      sellerRegion: "Seller region needs review",
      trustRating: "Seller trust needs review",
      trustNotes: summary.isEmpty ? "Captured from Wishlist staging. Confirm seller reputation, returns, warranty, contact details, and delivery reliability before purchase." : "Captured from Wishlist staging: \(summary)",
      recommendation: "Review captured option",
      lastChecked: "Captured locally",
      localScore: nil,
      riskLevel: "Needs review",
      decisionReason: "Created from local capture metadata only. Confirm live price, AUD total, postage, trust, returns, warranty, and availability before selecting as preferred."
    )
  }

  func dismissWishlistCapture(_ capture: WishlistCaptureCandidate) {
    guard let index = wishlistCaptureCandidates.firstIndex(where: { $0.id == capture.id }) else { return }
    let dismissed = wishlistCaptureCandidates.remove(at: index)
    persistWishlist()
    logAudit(
      action: .removed,
      entityType: .wishlistItem,
      entityID: dismissed.id.uuidString,
      entityLabel: dismissed.pageTitle,
      summary: "Wishlist capture candidate dismissed locally.",
      beforeDetail: dismissed.auditDetail,
      afterDetail: "Candidate removed from local staging only. No wishlist item was created, no external service was contacted, and no browser data was changed."
    )
  }

  func updateWishlistCaptureCandidate(_ capture: WishlistCaptureCandidate) {
    guard let index = wishlistCaptureCandidates.firstIndex(where: { $0.id == capture.id }) else { return }
    let beforeDetail = wishlistCaptureCandidates[index].auditDetail
    wishlistCaptureCandidates[index] = capture
    persistWishlist()
    logAudit(
      action: .edited,
      entityType: .wishlistItem,
      entityID: capture.id.uuidString,
      entityLabel: capture.pageTitle,
      summary: "Wishlist capture candidate updated locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(capture.auditDetail)\nCapture candidate edit only. No browser extension sync, page scraping, account login, checkout, purchase, payment, or external service action occurred."
    )
  }

  func convertWishlistToOrder(_ item: WishlistItem) {
    let beforeDetail = item.auditDetail
    if
      let wishlistIndex = wishlistItems.firstIndex(where: { $0.id == item.id }),
      let linkedOrderID = wishlistItems[wishlistIndex].purchaseHandoff?.linkedOrderID,
      let existingOrder = orders.first(where: { $0.id == linkedOrderID })
    {
      wishlistItems[wishlistIndex].status = "Linked to order draft"
      wishlistItems[wishlistIndex].purchaseReadiness = "Existing local order draft linked from Wishlist"
      wishlistItems[wishlistIndex].purchaseHandoff?.purchaseStatus = "Linked to existing local order draft"
      wishlistItems[wishlistIndex].purchaseHandoff?.orderWatchStatus = "Linked to local order draft \(existingOrder.orderNumber)."
      wishlistItems[wishlistIndex].purchaseHandoff?.updatedAt = "Now"
      persistWishlist()
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Existing Wishlist-linked order draft reused locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(wishlistItems[wishlistIndex].auditDetail)\nExisting order: \(existingOrder.orderNumber) \(existingOrder.id.uuidString). No duplicate order draft was created. No purchase API, payment, supplier, carrier, Shopify, browser automation, checkout, or mailbox action occurred."
      )
      return
    }

    let order = TrackedOrder(
      orderNumber: "WISH-\(1000 + orders.count + 1)",
      store: item.storefront,
      recipientEmail: "wishlist@parcelops.example",
      checkedMailbox: "tracking-intake@parcelops.example",
      customer: item.owner,
      fulfillment: .delivery,
      carrier: "Pending",
      trackingNumber: "Pending",
      destination: "Pending",
      eta: "Pending",
      source: .manual,
      status: .intake,
      reviewState: .needsReview,
      latestStatus: "Converted from wishlist and awaiting purchase confirmation",
      timeline: [TimelineEvent(title: "Wishlist conversion", detail: item.itemName, time: "Now", symbol: "star.square.fill")],
      contactHistory: [ContactHistoryEvent(time: "Now", source: .manual, contactPoint: "Wishlist", summary: "Wishlist item converted to order draft.", evidence: item.capturedDetail, reviewState: .needsReview)]
    )
    orders.insert(order, at: 0)

    if let wishlistIndex = wishlistItems.firstIndex(where: { $0.id == item.id }) {
      var handoff = wishlistItems[wishlistIndex].purchaseHandoff
        ?? WishlistPurchaseHandoff(
          sellerName: item.storefront,
          accountLabel: "\(item.owner) account to confirm",
          purchaseStatus: "Converted to local order draft",
          expectedOrderSignals: "\(item.storefront) | \(item.itemName)",
          orderWatchStatus: "Local order draft created from Wishlist.",
          linkedOrderID: nil,
          notes: "Wishlist item converted into a local order draft. No purchase, payment, checkout, retailer login, or mailbox action occurred.",
          updatedAt: "Now"
        )
      handoff.purchaseStatus = "Converted to local order draft"
      handoff.orderWatchStatus = "Linked to local order draft \(order.orderNumber)."
      handoff.linkedOrderID = order.id
      handoff.updatedAt = "Now"
      wishlistItems[wishlistIndex].purchaseHandoff = handoff
      wishlistItems[wishlistIndex].status = "Linked to order draft"
      wishlistItems[wishlistIndex].purchaseReadiness = "Local order draft created from Wishlist"
    }

    persistOrders()
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .order,
      entityID: order.id.uuidString,
      entityLabel: order.orderNumber,
      summary: "Order draft created from wishlist item.",
      afterDetail: "\(order.auditDetail)\nWishlist source: \(item.auditDetail)\nNo purchase API, payment, supplier, carrier, Shopify, or mailbox action occurred."
    )
    logAudit(
      action: .linked,
      entityType: .wishlistItem,
      entityID: item.id.uuidString,
      entityLabel: item.itemName,
      summary: "Wishlist item converted into local order draft \(order.orderNumber).",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems.first { $0.id == item.id }?.auditDetail ?? item.auditDetail)\nCreated order: \(order.orderNumber) \(order.id.uuidString). Downstream Wishlist receiving, inventory, custody, label, verification, manifest, and dispatch readiness records can now inherit this local order context."
    )
  }

  func linkWishlistItemToOrder(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let matchedOrder = bestWishlistOrderMatch(for: wishlistItems[index])

    var handoff = wishlistItems[index].purchaseHandoff
      ?? WishlistPurchaseHandoff(
        sellerName: wishlistItems[index].storefront,
        accountLabel: "\(wishlistItems[index].owner) account to confirm",
        purchaseStatus: "Order link review needed",
        expectedOrderSignals: "\(wishlistItems[index].storefront) | \(wishlistItems[index].itemName)",
        orderWatchStatus: "Manual link action used.",
        linkedOrderID: nil,
        notes: "Manual link action only. Confirm the matched order before closing Wishlist follow-up.",
        updatedAt: "Now"
      )
    handoff.purchaseStatus = matchedOrder == nil ? "Order link needs manual selection" : "Linked to existing local order"
    handoff.orderWatchStatus = matchedOrder == nil
      ? "No confident local order match was found. Use Inbox or Orders to create/link the confirmation."
      : "Linked to local order \(matchedOrder?.orderNumber ?? "")."
    handoff.linkedOrderID = matchedOrder?.id
    handoff.updatedAt = "Now"
    wishlistItems[index].purchaseHandoff = handoff
    wishlistItems[index].status = matchedOrder == nil ? "Order link needs review" : "Linked to existing order"
    wishlistItems[index].purchaseReadiness = matchedOrder == nil ? "Choose or create local order before downstream handoff" : "Existing local order linked"
    persistWishlist()
    logAudit(
      action: .linked,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: matchedOrder == nil ? "Wishlist order link needs manual review." : "Wishlist item linked to existing order \(matchedOrder?.orderNumber ?? "").",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nMatched order: \(matchedOrder?.orderNumber ?? "none"). No mailbox fetch, retailer login, browser automation, checkout, payment, or external service occurred."
    )
  }

  private func bestWishlistOrderMatch(for item: WishlistItem) -> TrackedOrder? {
    let handoff = item.purchaseHandoff
    let itemName = item.itemName.localizedLowercase
    let seller = (handoff?.sellerName ?? item.storefront).localizedLowercase
    let expectedSignals = (handoff?.expectedOrderSignals ?? "")
      .components(separatedBy: CharacterSet(charactersIn: "|,"))
      .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).localizedLowercase }
      .filter { $0.count >= 4 && !$0.isPlaceholderValidationValue }

    return orders
      .map { order -> (TrackedOrder, Int) in
        let searchable = [
          order.orderNumber,
          order.store,
          order.customer,
          order.trackingNumber,
          order.destination,
          order.latestStatus,
          order.timeline.map(\.detail).joined(separator: " "),
          order.contactHistory.map(\.evidence).joined(separator: " ")
        ]
          .joined(separator: " ")
          .localizedLowercase
        var score = 0
        if !seller.isEmpty && searchable.contains(seller) { score += 4 }
        if !itemName.isEmpty && searchable.contains(itemName) { score += 4 }
        let matchedSignals = expectedSignals.filter { searchable.contains($0) }
        if !matchedSignals.isEmpty { score += min(6, matchedSignals.count * 2) }
        if !order.trackingNumber.isPlaceholderValidationValue
          && handoff?.expectedOrderSignals.localizedCaseInsensitiveContains(order.trackingNumber) == true {
          score += 4
        }
        if order.latestStatus.localizedCaseInsensitiveContains("confirmation")
          || order.latestStatus.localizedCaseInsensitiveContains("purchased")
          || order.latestStatus.localizedCaseInsensitiveContains("wishlist") {
          score += 2
        }
        if order.source == .manual && order.orderNumber.localizedCaseInsensitiveContains("WISH") { score += 2 }
        if order.reviewState == .needsReview { score += 1 }
        return (order, score)
      }
      .filter { $0.1 >= 4 }
      .sorted { $0.1 > $1.1 }
      .first?
      .0
  }

  func createWishlistComparisonPlan(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let optionID = UUID()
    let sellerName = wishlistItems[index].storefront.isPlaceholderValidationValue ? "Primary seller placeholder" : wishlistItems[index].storefront
    wishlistItems[index].comparisonStatus = "Needs agent research"
    wishlistItems[index].comparisonNotes = "Compare Australian and overseas sellers, convert totals to AUD, include postage cost/time, and assess seller trust before purchase. This is a local planning record only; no web research or agent run has started."
    wishlistItems[index].purchaseReadiness = "Waiting for comparison"
    wishlistItems[index].preferredOptionID = optionID
    wishlistItems[index].comparisonOptions = [
      WishlistComparisonOption(
        id: optionID,
        sellerName: sellerName,
        productURL: wishlistItems[index].storefrontURL,
        listedPrice: wishlistItems[index].estimatedCost,
        currency: "AUD or source currency",
        estimatedAUDTotal: "Pending AUD total",
        postageCost: "Pending postage",
        postageTime: "Pending delivery estimate",
        sellerRegion: "Unknown",
        trustRating: "Needs review",
        trustNotes: "Verify seller reputation, returns, warranty, delivery history, and recent independent reviews before recommending.",
        recommendation: "Baseline option",
        lastChecked: "Not checked"
      ),
      WishlistComparisonOption(
        sellerName: "Overseas retailer placeholder",
        productURL: "https://example.com/research-required",
        listedPrice: "Pending",
        currency: "Foreign currency",
        estimatedAUDTotal: "Pending FX and postage",
        postageCost: "Pending international postage",
        postageTime: "Pending",
        sellerRegion: "Overseas",
        trustRating: "Unknown",
        trustNotes: "Use only after seller trust, delivery reliability, and total landed cost are confirmed.",
        recommendation: "Research candidate",
        lastChecked: "Not checked"
      )
    ]
    persistWishlist()
    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist comparison plan created locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nComparison plan only. No browsing, web scraping, currency lookup, seller trust lookup, browser extension sync, purchase API, payment, or external agent run occurred."
    )
  }

  func createWishlistResearchRequest(from item: WishlistItem) {
    guard isActiveWishlistItem(item) else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Closed Wishlist research request skipped locally.",
        afterDetail: "The Wishlist item is closed or removed from active work, so no research request was created or refreshed. Reopen the item first if it needs new comparison work. No external research, browser automation, account login, checkout, purchase, or payment action occurred."
      )
      return
    }

    if let existingIndex = wishlistResearchRequests.firstIndex(where: { $0.wishlistItemID == item.id }) {
      let beforeDetail = wishlistResearchRequests[existingIndex].auditDetail
      wishlistResearchRequests[existingIndex].requestStatus = "Scope refreshed"
      wishlistResearchRequests[existingIndex].lastReviewedDate = "Now"
      wishlistResearchRequests[existingIndex].reviewState = .needsReview
      wishlistResearchRequests[existingIndex].notes = "Scope refreshed from current wishlist item. No live research or external agent run occurred."
      persistWishlist()
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Wishlist research request refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(wishlistResearchRequests[existingIndex].auditDetail)\nNo web search, retailer scraping, currency lookup, seller trust lookup, browser automation, account login, purchase, or payment action occurred."
      )
      return
    }

    let request = WishlistResearchRequest(
      wishlistItemID: item.id,
      itemName: item.itemName,
      sourceURL: item.storefrontURL,
      regionScope: "Compare Australian sellers first, then overseas sellers only if landed AUD cost, postage time, returns, and seller trust are acceptable.",
      sellerCriteria: "Find direct product pages from reputable retailers. Record product URL, listed price, currency, estimated AUD landed total, postage cost/time, seller region, returns/warranty notes, and trust evidence.",
      maxBudgetAUD: item.estimatedCost.localizedCaseInsensitiveContains("aud") ? item.estimatedCost : "Confirm AUD budget",
      postageRequirements: "Include postage cost and delivery estimate. Flag slow or uncertain delivery before purchase.",
      trustRequirements: "Reject low-trust sellers even when cheaper. Prefer established stores with clear contact, returns, warranty, and delivery evidence.",
      requestStatus: "Ready for future agent",
      createdDate: "Now",
      lastReviewedDate: "Not reviewed",
      reviewState: .needsReview,
      notes: "Local research brief only. ParcelOps has not searched the web, contacted sellers, opened browser pages, logged in, purchased, or stored payment details."
    )
    wishlistResearchRequests.insert(request, at: 0)
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: item.id.uuidString,
      entityLabel: item.itemName,
      summary: "Wishlist comparison research request staged locally.",
      afterDetail: "\(request.auditDetail)\nSource item: \(item.auditDetail)\nNo external research, network call, browser automation, account login, checkout, purchase, or payment action occurred."
    )
  }

  func createMissingWishlistResearchRequests() {
    let candidates = wishlistItems.filter { item in
      isActiveWishlistItem(item)
        && !wishlistResearchRequests.contains { $0.wishlistItemID == item.id }
        && (item.comparisonOptions ?? []).isEmpty
    }
    guard !candidates.isEmpty else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: "wishlist-research-batch",
        entityLabel: "Wishlist research runway",
        summary: "Wishlist missing research brief batch checked with no work needed.",
        afterDetail: "Every active Wishlist item already has a research brief or seller options. Closed Wishlist items remain historical and were not reactivated. No web search, browser automation, retailer access, account login, checkout, purchase, payment, or external agent run occurred."
      )
      return
    }

    for item in candidates {
      createWishlistComparisonPlan(item)
      let refreshedItem = wishlistItems.first { $0.id == item.id } ?? item
      createWishlistResearchRequest(from: refreshedItem)
    }

    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: "wishlist-research-batch",
      entityLabel: "Wishlist research runway",
      summary: "Missing Wishlist research briefs staged locally.",
      afterDetail: """
      Created or refreshed \(candidates.count) local Wishlist research brief\(candidates.count == 1 ? "" : "s").
      Each brief remains local and prepares future comparison work only.
      No web search, browser automation, retailer access, account login, checkout, purchase, payment, mailbox fetch, or external agent run occurred.
      """
    )
  }

  func markWishlistResearchRequestReviewed(_ request: WishlistResearchRequest) {
    guard let index = wishlistResearchRequests.firstIndex(where: { $0.id == request.id }) else { return }
    let beforeDetail = wishlistResearchRequests[index].auditDetail
    wishlistResearchRequests[index].requestStatus = wishlistResearchRequests[index].agentBriefGaps.filter { $0 != "operator review" }.isEmpty
      ? "Agent-ready for future comparison"
      : "Reviewed with scope gaps"
    wishlistResearchRequests[index].lastReviewedDate = "Now"
    wishlistResearchRequests[index].reviewState = .accepted
    persistWishlist()
    logAudit(
      action: .reviewed,
      entityType: .wishlistItem,
      entityID: wishlistResearchRequests[index].wishlistItemID?.uuidString ?? wishlistResearchRequests[index].id.uuidString,
      entityLabel: wishlistResearchRequests[index].itemName,
      summary: "Wishlist research request reviewed locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistResearchRequests[index].auditDetail)\nReview only. No external agent, retailer search, currency lookup, browser automation, purchase, or payment action occurred."
    )
  }

  func blockWishlistResearchRequest(_ request: WishlistResearchRequest) {
    guard let index = wishlistResearchRequests.firstIndex(where: { $0.id == request.id }) else { return }
    let beforeDetail = wishlistResearchRequests[index].auditDetail
    wishlistResearchRequests[index].requestStatus = "Blocked pending scope"
