  func createWishlistResearchBriefDraft(_ request: WishlistResearchRequest) {
    let linkedID = request.wishlistItemID?.uuidString ?? request.id.uuidString
    let linkedItem = request.wishlistItemID.flatMap { id in wishlistItems.first { $0.id == id } }
    let optionSummary = (linkedItem?.comparisonOptions ?? [])
      .prefix(6)
      .map { option in
        "- \(option.sellerName): \(option.listedPrice) \(option.currency), estimated total \(option.estimatedAUDTotal), postage \(option.postageCost) / \(option.postageTime), trust \(option.trustRating), URL \(option.productURL)"
      }
      .joined(separator: "\n")
    let existingContext = optionSummary.isEmpty ? "- No seller options are recorded yet." : optionSummary
    let body = """
    Wishlist comparison research brief.

    Agent packet status:
    \(request.agentBriefStatus)

    Agent packet next action:
    \(request.agentBriefNextAction)

    Item:
    \(request.itemName)

    Source URL:
    \(request.sourceURL)

    Budget:
    \(request.maxBudgetAUD)

    Region scope:
    \(request.regionScope)

    Seller criteria:
    \(request.sellerCriteria)

    Postage requirements:
    \(request.postageRequirements)

    Seller trust requirements:
    \(request.trustRequirements)

    Existing local seller options:
    \(existingContext)

    Agent instruction packet:
    \(request.agentInstructionPacket)

    Required output:
    - Compare Australian retailers first, then overseas retailers only where landed AUD cost, postage time, returns, warranty, and seller trust are acceptable.
    - Record product link, seller name, listed price/currency, estimated AUD landed total, postage cost, postage ETA, seller region, returns/warranty notes, and trust evidence.
    - Flag any seller with unclear delivery, poor trust signals, missing returns/warranty, or suspicious pricing.
    - Recommend the safest practical option, not only the cheapest option.

    Boundaries:
    Do not buy anything, enter payment details, log in to retailer accounts, store credentials, mutate mailboxes, book carriers, or run background monitoring from this brief.
    """
    let draft = DraftMessage(
      linkedEntityType: .wishlistItem,
      linkedEntityID: linkedID,
      templateID: nil,
      recipient: "Wishlist review",
      subject: "Wishlist research brief: \(request.itemName)",
      body: body,
      channel: .email,
      createdDate: Self.auditTimestamp(),
      status: .draft,
      reviewState: .needsReview
    )
    draftMessages.insert(draft, at: 0)
    persistDraftMessages()
    logAudit(
      action: .created,
      entityType: .draftMessage,
      entityID: draft.id.uuidString,
      entityLabel: draft.subject,
      summary: "Wishlist research brief draft created locally.",
      afterDetail: "\(draft.auditDetail)\nResearch request: \(request.auditDetail)\nNo web search, external agent, retailer access, login, checkout, payment, mailbox mutation, or background monitoring occurred."
    )
  }

  func createWishlistComparisonBriefDraft(from item: WishlistItem) {
    guard isActiveWishlistItem(item) else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Closed Wishlist brief draft skipped locally.",
        afterDetail: "The Wishlist item is closed or removed from active work, so no research brief draft was created. Reopen the item first if it needs comparison work. No web search, browser automation, retailer access, account login, purchase, payment, or external agent run occurred."
      )
      return
    }

    if let existingDraft = draftMessages.first(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == item.id.uuidString
        && $0.subject.localizedCaseInsensitiveContains("wishlist research brief")
    }) {
      reopenDraftMessage(existingDraft)
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Existing Wishlist research brief draft reused locally.",
        afterDetail: "An existing research brief draft was reopened instead of creating a duplicate. Draft: \(existingDraft.subject). No web search, browser automation, retailer access, account login, checkout, purchase, payment, mailbox mutation, or background monitoring occurred."
      )
      return
    }

    var currentItem = wishlistItems.first { $0.id == item.id } ?? item
    if (currentItem.comparisonOptions ?? []).isEmpty {
      createWishlistComparisonPlan(currentItem)
      currentItem = wishlistItems.first { $0.id == item.id } ?? currentItem
    }

    createWishlistResearchRequest(from: currentItem)

    guard let request = wishlistResearchRequests.first(where: { $0.wishlistItemID == item.id }) else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Wishlist research brief draft could not be created locally.",
        afterDetail: "No matching local research request was available after staging. No web search, browser automation, retailer access, account login, checkout, purchase, payment, mailbox mutation, or background monitoring occurred."
      )
      return
    }

    createWishlistResearchBriefDraft(request)
  }

  func createWishlistBatchResearchBriefDraft() {
    let requests = wishlistResearchRequests.filter(isActiveWishlistResearchRequest)
    let readyRequests = requests.filter(\.isAgentBriefReady)
    let scopedRequests = readyRequests.isEmpty ? requests.filter { !$0.requestStatus.localizedCaseInsensitiveContains("blocked") } : readyRequests
    let includedRequests = Array(scopedRequests.prefix(12))
    guard !includedRequests.isEmpty else { return }

    let requestPackets = includedRequests.enumerated().map { index, request in
      let linkedItem = request.wishlistItemID.flatMap { id in wishlistItems.first { $0.id == id } }
      let sellerOptions = (linkedItem?.comparisonOptions ?? [])
        .prefix(5)
        .map { option in
          "- \(option.sellerName): \(option.listedPrice) \(option.currency), estimated AUD \(option.estimatedAUDTotal), postage \(option.postageCost) / \(option.postageTime), region \(option.sellerRegion), trust \(option.trustRating), URL \(option.productURL)"
        }
        .joined(separator: "\n")
      let sellerContext = sellerOptions.isEmpty ? "- No local seller options recorded yet." : sellerOptions
      let gaps = request.agentBriefGaps.isEmpty ? "None" : request.agentBriefGaps.joined(separator: ", ")

      return """
      \(index + 1). \(request.itemName)
      Status: \(request.agentBriefStatus)
      Scope gaps: \(gaps)
      Source URL: \(request.sourceURL)
      Budget: \(request.maxBudgetAUD)
      Region scope: \(request.regionScope)
      Seller criteria: \(request.sellerCriteria)
      Postage requirements: \(request.postageRequirements)
      Trust requirements: \(request.trustRequirements)
      Existing local seller options:
      \(sellerContext)
      Agent instruction:
      \(request.agentInstructionPacket)
      """
    }.joined(separator: "\n\n---\n\n")

    let body = """
    Wishlist batch comparison research brief.

    Packet purpose:
    Prepare a future comparison-agent handoff for Wishlist items. Compare Australian and overseas retailers, convert or estimate landed totals in AUD, include postage cost and delivery time, and reject unsafe sellers even when they are cheaper.

    Included requests:
    \(includedRequests.count) of \(requests.count)

    Ready requests:
    \(readyRequests.count)

    Required output for each item:
    - Product URL and seller name
    - Listed price and source currency
    - Estimated AUD landed total, including postage where possible
    - Postage cost and delivery estimate
    - Seller region
    - Returns/warranty notes
    - Trust evidence and delivery reliability notes
    - Recommended seller, with reason
    - Explicit blockers where a seller should not be used

    Operator priorities:
    - Prefer Australian retailers first when price, stock, postage, returns, and trust are reasonable.
    - Use overseas sellers only when landed AUD cost, delivery reliability, and seller trust are acceptable.
    - Do not recommend unknown or suspicious sellers only because they are cheap.
    - Keep each recommendation traceable to a product URL and seller evidence.

    Requests:
    \(requestPackets)

    Boundaries:
    Do not buy anything, enter payment details, log in to retailer accounts, store credentials, mutate mailboxes, book carriers, run background monitoring, or contact sellers from this draft. This is a local research brief only.
    """

    let subject = "Wishlist batch research brief (\(includedRequests.count) item\(includedRequests.count == 1 ? "" : "s"))"
    let auditDetail = """
    Included requests: \(includedRequests.count)
    Ready requests available: \(readyRequests.count)
    Scope-gap requests included: \(includedRequests.filter { !$0.isAgentBriefReady }.count)
    Output contract: product URL, seller, listed price/currency, AUD landed total, postage cost/time, seller region, returns/warranty, trust evidence, recommendation, and explicit no-buy blockers.
    Draft only. No web search, external agent, retailer access, currency lookup, postage quote, seller trust lookup, browser automation, login, checkout, payment, mailbox mutation, or background monitoring occurred.
    """

    if let existingIndex = draftMessages.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == "wishlist-research-batch"
        && $0.status != .sentLocally
    }) {
      let beforeDetail = draftMessages[existingIndex].auditDetail
      draftMessages[existingIndex].recipient = "Wishlist review"
      draftMessages[existingIndex].subject = subject
      draftMessages[existingIndex].body = body
      draftMessages[existingIndex].channel = .email
      draftMessages[existingIndex].reviewState = .needsReview
      if draftMessages[existingIndex].status == .ready {
        draftMessages[existingIndex].status = .reopened
      }
      persistDraftMessages()
      logAudit(
        action: .edited,
        entityType: .draftMessage,
        entityID: draftMessages[existingIndex].id.uuidString,
        entityLabel: draftMessages[existingIndex].subject,
        summary: "Existing Wishlist batch research brief draft refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(draftMessages[existingIndex].auditDetail)\n\(auditDetail)\nNo duplicate Wishlist batch draft was created."
      )
      return
    }

    let draft = DraftMessage(
      linkedEntityType: .wishlistItem,
      linkedEntityID: "wishlist-research-batch",
      templateID: nil,
      recipient: "Wishlist review",
      subject: subject,
      body: body,
      channel: .email,
      createdDate: Self.auditTimestamp(),
      status: .draft,
      reviewState: .needsReview
    )
    draftMessages.insert(draft, at: 0)
    persistDraftMessages()
    logAudit(
      action: .created,
      entityType: .draftMessage,
      entityID: draft.id.uuidString,
      entityLabel: draft.subject,
      summary: "Wishlist batch research brief draft created locally.",
      afterDetail: auditDetail
    )
  }

  func removeWishlistResearchRequest(_ request: WishlistResearchRequest) {
    guard let index = wishlistResearchRequests.firstIndex(where: { $0.id == request.id }) else { return }
    let removed = wishlistResearchRequests.remove(at: index)
    persistWishlist()
    logAudit(
      action: .removed,
      entityType: .wishlistItem,
      entityID: removed.wishlistItemID?.uuidString ?? removed.id.uuidString,
      entityLabel: removed.itemName,
      summary: "Wishlist research request removed locally.",
      beforeDetail: removed.auditDetail,
      afterDetail: "Research request removed only. Wishlist item data, orders, mailboxes, retailers, accounts, and browser state were not changed."
    )
  }

  func markWishlistPreferredOption(_ item: WishlistItem, option: WishlistComparisonOption) {
