  func addWishlistSellerOptionsFromPastedComparisonBatch(
    _ item: WishlistItem,
    pastedText: String,
    sellerHint: String,
    productURLHint: String,
    listedPriceHint: String,
    currencyHint: String,
    audTotalHint: String,
    postageCostHint: String,
    postageTimeHint: String,
    trustHint: String,
    notes: String
  ) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let blocks = Self.pastedComparisonBlocks(from: pastedText)
    guard !blocks.isEmpty else { return }
    if blocks.count == 1 {
      addWishlistSellerOptionFromPastedComparison(
        item,
        pastedText: pastedText,
        sellerHint: sellerHint,
        productURLHint: productURLHint,
        listedPriceHint: listedPriceHint,
        currencyHint: currencyHint,
        audTotalHint: audTotalHint,
        postageCostHint: postageCostHint,
        postageTimeHint: postageTimeHint,
        trustHint: trustHint,
        notes: notes
      )
      return
    }

    let beforeDetail = wishlistItems[index].auditDetail
    let newOptions = blocks.map { block in
      Self.wishlistComparisonOptionFromPastedResult(
        pastedText: block,
        sellerHint: sellerHint,
        productURLHint: productURLHint,
        listedPriceHint: listedPriceHint,
        currencyHint: currencyHint,
        audTotalHint: audTotalHint,
        postageCostHint: postageCostHint,
        postageTimeHint: postageTimeHint,
        trustHint: trustHint,
        notes: notes
      )
    }
    var options = wishlistItems[index].comparisonOptions ?? []
    options.append(contentsOf: newOptions)
    wishlistItems[index].comparisonOptions = options
    wishlistItems[index].comparisonStatus = "Pasted comparison batch"
    wishlistItems[index].purchaseReadiness = "Waiting for pasted seller batch review"
    wishlistItems[index].comparisonNotes = "A pasted comparison batch created \(newOptions.count) local seller options. Verify live price, stock, AUD landed cost, postage, delivery time, seller trust, returns, warranty, account readiness, and payment readiness outside ParcelOps."
    if wishlistItems[index].preferredOptionID == nil {
      wishlistItems[index].preferredOptionID = newOptions.first?.id
    }
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist pasted comparison batch added locally.",
      beforeDetail: beforeDetail,
      afterDetail: """
      \(wishlistItems[index].auditDetail)
      Seller options added: \(newOptions.count)
      Sellers: \(newOptions.map(\.sellerName).joined(separator: ", "))
      Highest risk: \(newOptions.map { $0.riskLevel ?? "Needs review" }.contains("High") ? "High" : "Needs review")
      Review gaps: \(newOptions.map { $0.decisionReason ?? "Needs operator review." }.joined(separator: " | "))
      Blocks parsed: \(blocks.count)
      Maximum blocks imported per paste: 8
      Manual paste-back only. No live retailer search, website scraping, browser automation, currency API, postage quote, seller trust service, account login, checkout, purchase, payment, mailbox mutation, or external service occurred.
      """
    )
  }

  func duplicateWishlistSellerOption(_ item: WishlistItem, option: WishlistComparisonOption) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    var options = wishlistItems[index].comparisonOptions ?? []
    var duplicated = option
    duplicated.id = UUID()
    duplicated.sellerName = "\(option.sellerName) copy"
    duplicated.recommendation = "Manual review"
    duplicated.lastChecked = "Copied locally"
    duplicated.localScore = nil
    duplicated.riskLevel = "Needs review"
    duplicated.decisionReason = "Copied from an existing seller option for manual adjustment."
    options.append(duplicated)
    wishlistItems[index].comparisonOptions = options
    wishlistItems[index].comparisonStatus = "Manual seller options"
    wishlistItems[index].purchaseReadiness = "Waiting for seller option review"
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist seller option duplicated locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nDuplicated seller option: \(duplicated.sellerName). Manual copy only. No retailer, browser, currency, postage, trust, purchase, or payment action occurred."
    )
  }

  func updateWishlistSellerOption(_ item: WishlistItem, option: WishlistComparisonOption) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    var options = wishlistItems[index].comparisonOptions ?? []
    guard let optionIndex = options.firstIndex(where: { $0.id == option.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let beforeOption = options[optionIndex]
    var updated = option
    updated.sellerName = updated.sellerName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? beforeOption.sellerName : updated.sellerName
    updated.productURL = updated.productURL.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? beforeOption.productURL : updated.productURL
    updated.listedPrice = updated.listedPrice.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Pending" : updated.listedPrice
    updated.currency = updated.currency.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "AUD" : updated.currency
    updated.estimatedAUDTotal = updated.estimatedAUDTotal.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Pending AUD total" : updated.estimatedAUDTotal
    updated.postageCost = updated.postageCost.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Pending postage" : updated.postageCost
    updated.postageTime = updated.postageTime.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Pending delivery estimate" : updated.postageTime
    updated.sellerRegion = updated.sellerRegion.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Unknown" : updated.sellerRegion
    updated.trustRating = updated.trustRating.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Needs review" : updated.trustRating
    updated.trustNotes = updated.trustNotes.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Trust evidence still needs review." : updated.trustNotes
    updated.recommendation = updated.recommendation.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "Manual review" : updated.recommendation
    updated.lastChecked = "Edited locally"
    updated.localScore = nil
    updated.riskLevel = "Needs review"
    updated.decisionReason = "Seller option edited manually. Re-run local scoring after confirming live price, AUD total, postage, delivery time, trust, returns, and account fit."
    options[optionIndex] = updated
    wishlistItems[index].comparisonOptions = options
    wishlistItems[index].comparisonStatus = "Seller option edited"
    wishlistItems[index].purchaseReadiness = "Waiting for seller option scoring"
    persistWishlist()
    logAudit(
      action: .edited,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist seller option edited locally.",
      beforeDetail: "\(beforeDetail)\nBefore seller option: \(beforeOption.sellerName); total: \(beforeOption.estimatedAUDTotal); postage: \(beforeOption.postageCost), \(beforeOption.postageTime); trust: \(beforeOption.trustRating).",
      afterDetail: "\(wishlistItems[index].auditDetail)\nUpdated seller option: \(updated.sellerName); total: \(updated.estimatedAUDTotal); postage: \(updated.postageCost), \(updated.postageTime); trust: \(updated.trustRating). No retailer page, browser automation, currency API, postage API, trust lookup, account, checkout, purchase, or payment action occurred."
    )
  }

  func removeWishlistSellerOption(_ item: WishlistItem, option: WishlistComparisonOption) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    var options = wishlistItems[index].comparisonOptions ?? []
    guard let optionIndex = options.firstIndex(where: { $0.id == option.id }) else { return }
    let removed = options.remove(at: optionIndex)
    wishlistItems[index].comparisonOptions = options
    if wishlistItems[index].preferredOptionID == removed.id {
      wishlistItems[index].preferredOptionID = options.first?.id
    }
    wishlistItems[index].comparisonStatus = options.isEmpty ? "Comparison needed" : "Manual seller options"
    wishlistItems[index].purchaseReadiness = options.isEmpty ? "Waiting for seller options" : "Waiting for seller option review"
    persistWishlist()
    logAudit(
      action: .removed,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist seller option removed locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nRemoved seller option: \(removed.sellerName). Wishlist item, orders, accounts, retailer pages, and purchase state were not changed outside ParcelOps."
    )
  }

  func evaluateWishlistComparisonOptions(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    var options = wishlistItems[index].comparisonOptions ?? []

    guard !options.isEmpty else {
      wishlistItems[index].comparisonStatus = "Comparison needed"
      wishlistItems[index].comparisonNotes = "No seller options are available to score. Add or generate comparison options before purchase review."
      wishlistItems[index].purchaseReadiness = "Waiting for seller options"
      persistWishlist()
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: wishlistItems[index].id.uuidString,
        entityLabel: wishlistItems[index].itemName,
        summary: "Wishlist comparison scoring found no seller options.",
        beforeDetail: beforeDetail,
        afterDetail: "\(wishlistItems[index].auditDetail)\nNo live retailer, currency, postage, trust, or browser lookup occurred."
      )
      return
    }

    options = options.map { option in
      var evaluated = option
      let result = localWishlistOptionEvaluation(for: option)
      evaluated.localScore = result.score
      evaluated.riskLevel = result.risk
      evaluated.decisionReason = result.reasons.joined(separator: "; ")
      evaluated.recommendation = result.recommendation
      evaluated.lastChecked = "Scored locally"
      return evaluated
    }

    let sortedOptions = options.sorted { first, second in
      if (first.localScore ?? 0) == (second.localScore ?? 0) {
        return first.sellerName.localizedCaseInsensitiveCompare(second.sellerName) == .orderedAscending
      }
      return (first.localScore ?? 0) > (second.localScore ?? 0)
    }
    let best = sortedOptions.first
    let hasBlockedTrust = options.contains { option in
      (option.riskLevel ?? "").localizedCaseInsensitiveContains("high")
        || option.trustRating.localizedCaseInsensitiveContains("unknown")
        || option.trustRating.localizedCaseInsensitiveContains("review")
    }
    wishlistItems[index].comparisonOptions = options
    wishlistItems[index].preferredOptionID = best?.id
    wishlistItems[index].comparisonStatus = "Options scored locally"
    wishlistItems[index].purchaseReadiness = hasBlockedTrust
      ? "Trust/postage review required before purchase"
      : "Ready for purchase review"
    wishlistItems[index].comparisonNotes = [
      best.map { "Best local candidate: \($0.sellerName) with score \($0.localScore ?? 0)." },
      "Local scoring only; verify live price, AUD conversion, postage, delivery ETA, seller trust, warranty, and returns before buying."
    ].compactMap(\.self).joined(separator: " ")
    persistWishlist()
    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist seller options scored locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nScoring basis: \(options.map { "\($0.sellerName)=\($0.localScore ?? 0) \($0.riskLevel ?? "Unscored")" }.joined(separator: "; ")). No live retailer, currency, postage, seller trust, browser, account, purchase, or payment action occurred."
    )
  }

  func markWishlistReadyForPurchase(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    wishlistItems[index].status = "Ready to purchase"
    wishlistItems[index].purchaseReadiness = "Ready to purchase after manual account/payment confirmation"
    persistWishlist()
    logAudit(
      action: .reviewed,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist item marked ready for purchase locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nReady means local operator readiness only. ParcelOps did not buy the item, open an account, save payment credentials, monitor checkout, or contact any retailer."
    )
  }

  var wishlistAgentReadinessSummary: WishlistAgentReadinessSummary {
    let activeItems = wishlistItems.filter(isActiveWishlistItem)
    let researchRequests = wishlistResearchRequests.filter(isActiveWishlistResearchRequest)
    let readyBriefs = researchRequests.filter(\.isAgentBriefReady)
    let scopeGapRequests = researchRequests.filter { !$0.isAgentBriefReady && !$0.requestStatus.localizedCaseInsensitiveContains("blocked") }
    let sellerOptions = activeItems.flatMap { $0.comparisonOptions ?? [] }
    let sellerOptionGaps = sellerOptions.reduce(0) { total, option in
      total + option.operatorSellerEvidenceGaps.count
    }
    let trustReviewCount = sellerOptions.filter { option in
      option.trustRating.localizedCaseInsensitiveContains("unknown")
        || option.trustRating.localizedCaseInsensitiveContains("review")
        || option.trustRating.localizedCaseInsensitiveContains("low")
        || (option.riskLevel ?? "").localizedCaseInsensitiveContains("high")
    }.count + wishlistSellerTrustRecords.filter {
      isActiveWishlistSellerTrustRecord($0) && $0.reviewState != .accepted
    }.count
    let itemsWithoutComparison = activeItems.filter { ($0.comparisonOptions ?? []).isEmpty }.count
    let purchaseHandoffGaps = activeItems.reduce(0) { total, item in
      total + item.operatorPurchaseBlockers.filter { blocker in
        blocker.localizedCaseInsensitiveContains("purchase")
          || blocker.localizedCaseInsensitiveContains("handoff")
          || blocker.localizedCaseInsensitiveContains("decision")
      }.count
    }
    let orderWatchGaps = activeItems.filter { item in
      item.purchaseHandoff != nil && item.purchaseHandoff?.linkedOrderID == nil
    }.count + wishlistOrderWatchRecords.filter {
      isActiveWishlistOrderWatchRecord($0)
        && $0.linkedOrderID == nil
        && $0.reviewState != .accepted
    }.count
    let linkedOrderItems = activeItems.filter { $0.purchaseHandoff?.linkedOrderID != nil }
    let operationsClosureGapItems = linkedOrderItems.filter { !wishlistOperationsClosureGaps(for: $0).isEmpty }
    let operationsClosureGapPreview = operationsClosureGapItems
      .prefix(3)
      .map { item in
        "\(item.itemName): \(wishlistOperationsClosureGaps(for: item).prefix(4).joined(separator: ", "))"
      }
      .joined(separator: "; ")
    let readyPurchaseLinks = wishlistPurchaseLinkRecords.filter {
      isActiveWishlistPurchaseLinkRecord($0)
        && $0.selectedForPurchase
        && $0.reviewState == .accepted
        && !$0.productURL.isPlaceholderValidationValue
        && !$0.estimatedAUDTotal.isPlaceholderValidationValue
    }.count
    let readyApprovals = wishlistPurchaseApprovalRecords.filter {
      isActiveWishlistPurchaseApprovalRecord($0)
        && $0.reviewState == .accepted
        && ($0.approvalStatus.localizedCaseInsensitiveContains("approved")
          || $0.approvalStatus.localizedCaseInsensitiveContains("accepted"))
    }.count

    let items: [WishlistAgentReadinessItem] = [
      WishlistAgentReadinessItem(
        title: "Research brief scope",
        status: readyBriefs.isEmpty ? "No ready briefs" : "\(readyBriefs.count) ready",
        detail: scopeGapRequests.isEmpty ? "Ready briefs include item, source, AUD budget, region, postage, trust, and no-purchase boundaries." : "\(scopeGapRequests.count) brief\(scopeGapRequests.count == 1 ? "" : "s") need scope cleanup before future agent handoff.",
        tone: scopeGapRequests.isEmpty && !readyBriefs.isEmpty ? "success" : "attention",
        nextAction: scopeGapRequests.isEmpty ? "Create a batch brief when you want to hand off research." : "Open Wishlist research requests and fill missing scope fields."
      ),
      WishlistAgentReadinessItem(
        title: "Seller comparison evidence",
        status: sellerOptions.isEmpty ? "No options" : "\(sellerOptions.count) options",
        detail: sellerOptionGaps == 0 && !sellerOptions.isEmpty ? "Seller options have local product link, AUD total, postage, trust, and recommendation fields." : "\(sellerOptionGaps) seller option evidence gap\(sellerOptionGaps == 1 ? "" : "s") remain across \(max(sellerOptions.count, itemsWithoutComparison)) item\(max(sellerOptions.count, itemsWithoutComparison) == 1 ? "" : "s").",
        tone: sellerOptionGaps == 0 && !sellerOptions.isEmpty ? "success" : "warning",
        nextAction: sellerOptionGaps == 0 ? "Review the best option before purchase approval." : "Clean product links, AUD totals, postage, and recommendation notes."
      ),
      WishlistAgentReadinessItem(
        title: "Seller trust gate",
        status: trustReviewCount == 0 ? "Clear locally" : "\(trustReviewCount) review",
        detail: trustReviewCount == 0 ? "No current seller option or trust record is flagged as low, unknown, high risk, or unreviewed." : "Price should not beat trust. Review low/unknown/high-risk sellers before purchase handoff.",
        tone: trustReviewCount == 0 ? "success" : "warning",
        nextAction: trustReviewCount == 0 ? "Keep trust evidence with the selected purchase link." : "Open seller trust panels and record evidence or block the seller."
      ),
      WishlistAgentReadinessItem(
        title: "Purchase approval and links",
        status: "\(readyPurchaseLinks) links / \(readyApprovals) approvals",
        detail: readyPurchaseLinks > 0 && readyApprovals > 0 ? "At least one purchase route has an accepted link and approval record." : "Accepted purchase links and approvals are still local prerequisites before buying outside ParcelOps.",
        tone: readyPurchaseLinks > 0 && readyApprovals > 0 ? "success" : "attention",
        nextAction: "Confirm the selected product link, account context, approved limit, payment method summary, and no-checkout boundary."
      ),
      WishlistAgentReadinessItem(
        title: "Post-purchase order watch",
        status: orderWatchGaps == 0 ? "No open watch gaps" : "\(orderWatchGaps) open",
        detail: orderWatchGaps == 0 ? "No current Wishlist handoff is waiting for local order confirmation linking." : "After buying externally, the order confirmation still needs to be found in Inbox/Orders and linked locally.",
        tone: orderWatchGaps == 0 ? "success" : "attention",
        nextAction: orderWatchGaps == 0 ? "Keep monitoring manually only when purchases occur." : "Use order-watch records and Inbox linked-order shortcuts after mailbox refresh."
      ),
      WishlistAgentReadinessItem(
        title: "Operations closure trail",
        status: linkedOrderItems.isEmpty ? "No linked orders" : (operationsClosureGapItems.isEmpty ? "Closure trail clear" : "\(operationsClosureGapItems.count) gap\(operationsClosureGapItems.count == 1 ? "" : "s")"),
        detail: linkedOrderItems.isEmpty
          ? "No Wishlist purchase handoff is linked to a local order yet."
          : operationsClosureGapItems.isEmpty
            ? "Linked Wishlist orders have receiving, inventory, storage, custody, label, manual check, manifest, dispatch, and open-task closure checks clear."
            : "Linked Wishlist orders still need local operations evidence before closing. \(operationsClosureGapPreview)",
        tone: linkedOrderItems.isEmpty ? "neutral" : (operationsClosureGapItems.isEmpty ? "success" : "attention"),
        nextAction: linkedOrderItems.isEmpty
          ? "Link an order after an external purchase confirmation arrives."
          : operationsClosureGapItems.isEmpty
            ? "Close the Wishlist item locally only after final operator review."
            : "Stage or review receiving, inventory, storage, custody, label, manual check, manifest, dispatch, and open tasks before closure."
      )
    ]

    let warningCount = items.filter { $0.tone == "warning" }.count
    let attentionCount = items.filter { $0.tone == "attention" }.count
    let title: String
    let verdict: String
    let detail: String
    let tone: String
    if activeItems.isEmpty {
      title = "Wishlist agent path not started"
      verdict = "Add Wishlist items before agent readiness matters"
      detail = "No active Wishlist items exist. Manual capture is the first step."
      tone = "neutral"
    } else if warningCount > 0 {
      title = "Wishlist agent path has blockers"
      verdict = "\(warningCount) blocker area\(warningCount == 1 ? "" : "s") before live research or purchase handoff"
      detail = "Do not treat Wishlist as purchase-ready until seller comparison and trust evidence are complete."
      tone = "warning"
    } else if attentionCount > 0 {
      title = "Wishlist agent path needs operator review"
      verdict = "\(attentionCount) area\(attentionCount == 1 ? "" : "s") need review before release"
      detail = "The workflow is usable locally, but agent/live research remains a manual-review boundary."
      tone = "attention"
    } else {
      title = "Wishlist agent path is locally prepared"
      verdict = "Local records are ready for controlled manual research"
      detail = "This does not mean live web research, currency conversion, seller trust lookup, checkout, purchase, or order monitoring is active."
      tone = "success"
    }

    return WishlistAgentReadinessSummary(
      title: title,
      verdict: verdict,
      detail: detail,
      tone: tone,
      readyBriefCount: readyBriefs.count,
      scopeGapCount: scopeGapRequests.reduce(0) { $0 + $1.agentBriefGaps.count },
      sellerOptionGapCount: sellerOptionGaps,
      trustReviewCount: trustReviewCount,
      purchaseHandoffGapCount: purchaseHandoffGaps,
      orderWatchGapCount: orderWatchGaps,
      operationsClosureGapCount: operationsClosureGapItems.count,
      items: items
    )
  }

  func createWishlistAgentReadinessReviewTask() {
    let summary = wishlistAgentReadinessSummary
    let openItems = summary.items.filter { $0.tone != "success" }
    let taskTitle = summary.tone == "success"
      ? "Confirm Wishlist agent readiness"
      : "Review Wishlist agent readiness blockers"
    let taskPriority: TaskPriority = summary.tone == "warning" ? .high : summary.tone == "attention" ? .normal : .low
    let openSummary = openItems.isEmpty
      ? "No current readiness gaps are flagged. Confirm the local no-purchase boundary before any future agent or manual research handoff."
      : openItems
        .map { "\($0.title): \($0.status). Next: \($0.nextAction)" }
        .joined(separator: " | ")
    let taskSummary = [
      summary.verdict,
      summary.detail,
      "Open readiness areas: \(openSummary)",
      "Boundary: this is a local planning task only. It does not browse websites, compare live prices, convert currencies, rate sellers, open accounts, buy items, pay, or monitor orders."
    ].joined(separator: " ")

    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == "wishlist-agent-readiness"
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = taskTitle
      reviewTasks[existingIndex].summary = taskSummary
      reviewTasks[existingIndex].priority = taskPriority
      reviewTasks[existingIndex].dueDate = taskPriority == .high ? "Today" : "Tomorrow"
      reviewTasks[existingIndex].assignee = "Wishlist operations"
      reviewTasks[existingIndex].reviewState = .needsReview
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Wishlist agent readiness review task refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nRefreshed from the current Wishlist agent readiness verdict. No duplicate task was created and no external research, browsing, purchase, payment, account, retailer, mailbox, or background monitoring action occurred."
      )
      return
    }

    let task = ReviewTask(
      title: taskTitle,
      summary: taskSummary,
      linkedEntityType: .wishlistItem,
      linkedEntityID: "wishlist-agent-readiness",
      priority: taskPriority,
      dueDate: taskPriority == .high ? "Today" : "Tomorrow",
      assignee: "Wishlist operations",
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: .needsReview
    )
    addReviewTask(
      task,
      summary: "Review task created from Wishlist agent readiness verdict."
    )
  }

  func recordWishlistAgentReadinessSnapshot() {
    let summary = wishlistAgentReadinessSummary
    let readinessLines = summary.items.map { item in
      "\(item.title): \(item.status) - \(item.detail) Next: \(item.nextAction)"
    }
    let afterLines = [
      "Title: \(summary.title)",
      "Verdict: \(summary.verdict)",
      "Detail: \(summary.detail)",
      "Tone: \(summary.tone)",
      "Ready briefs: \(summary.readyBriefCount)",
      "Scope gaps: \(summary.scopeGapCount)",
      "Seller option gaps: \(summary.sellerOptionGapCount)",
      "Trust review count: \(summary.trustReviewCount)",
      "Purchase handoff gaps: \(summary.purchaseHandoffGapCount)",
      "Order watch gaps: \(summary.orderWatchGapCount)",
      "Readiness items:"
    ] + readinessLines + [
      "Boundary: snapshot only. No web search, browser automation, retailer comparison, currency conversion, postage quote, trust lookup, account login, checkout, purchase, payment, mailbox fetch, order monitoring, or external agent run occurred."
    ]

    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: "wishlist-agent-readiness",
      entityLabel: "Wishlist agent readiness",
      summary: summary.tone == "success"
        ? "Wishlist agent readiness snapshot recorded with no active blockers."
        : "Wishlist agent readiness snapshot recorded for operator review.",
      afterDetail: afterLines.joined(separator: "\n")
    )
  }

  func runWishlistPurchaseReadinessCheck(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let checkedItem = wishlistItems[index]
    let options = checkedItem.comparisonOptions ?? []
    let preferredOption = selectedWishlistSellerOption(for: checkedItem)
    var checks: [WishlistPurchaseCheck] = []
    let preferredEvidenceGaps = preferredOption?.operatorSellerEvidenceGaps ?? []

    checks.append(wishlistCheck(
      title: "Item and source",
      passed: !checkedItem.itemName.isPlaceholderValidationValue && !checkedItem.storefrontURL.isPlaceholderValidationValue,
      failDetail: "Confirm the exact item name and source URL before purchase.",
      passDetail: "Item name and source URL are present."
    ))
    checks.append(wishlistCheck(
      title: "Seller comparison",
      passed: !options.isEmpty,
      failDetail: "Add or generate seller options before choosing where to buy.",
      passDetail: "\(options.count) seller option\(options.count == 1 ? "" : "s") available for review."
    ))
    checks.append(wishlistCheck(
      title: "Selected seller",
      passed: preferredOption != nil,
      failDetail: "Select or score a seller option before marking ready to buy.",
      passDetail: preferredOption.map { checkedItem.preferredOptionID == $0.id ? "Preferred seller is \($0.sellerName)." : "Best scored seller fallback is \($0.sellerName)." } ?? "Seller selected."
    ))

    if let preferredOption {
      let score = preferredOption.localScore ?? 0
      let hasHighRisk = (preferredOption.riskLevel ?? "").localizedCaseInsensitiveContains("high")
        || preferredOption.trustRating.localizedCaseInsensitiveContains("unknown")
        || preferredOption.trustRating.localizedCaseInsensitiveContains("review")
        || preferredOption.trustRating.localizedCaseInsensitiveContains("low")
        || preferredOption.trustNotes.localizedCaseInsensitiveContains("scam")
        || preferredOption.trustNotes.localizedCaseInsensitiveContains("complaint")
      checks.append(wishlistCheck(
        title: "Direct product link",
        passed: !preferredOption.productURL.isPlaceholderValidationValue
          && preferredOption.productURL.localizedCaseInsensitiveContains("http")
          && !preferredOption.productURL.localizedCaseInsensitiveContains("example.com"),
        failDetail: "Confirm a direct product URL for \(preferredOption.sellerName), not a placeholder or generic storefront, before purchase review.",
        passDetail: "Direct product link is recorded for \(preferredOption.sellerName)."
      ))
      checks.append(wishlistCheck(
        title: "Seller trust",
        passed: !hasHighRisk && score >= 55,
        failDetail: "Seller trust or score needs review before purchase. Current score: \(preferredOption.localScore.map(String.init) ?? "not scored"); trust: \(preferredOption.trustRating).",
        passDetail: "Preferred seller trust looks acceptable locally. Score: \(preferredOption.localScore.map(String.init) ?? "not scored")."
      ))
      checks.append(wishlistCheck(
        title: "Postage and delivery",
        passed: !preferredEvidenceGaps.contains("postage cost")
          && !preferredEvidenceGaps.contains("postage time")
          && !preferredOption.postageCost.localizedCaseInsensitiveContains("pending")
          && !preferredOption.postageCost.localizedCaseInsensitiveContains("needs review")
          && !preferredOption.postageTime.localizedCaseInsensitiveContains("pending")
          && !preferredOption.postageTime.localizedCaseInsensitiveContains("needs review"),
        failDetail: "Postage cost and delivery time must be confirmed before purchase.",
        passDetail: "Postage \(preferredOption.postageCost), delivery \(preferredOption.postageTime)."
      ))
      checks.append(wishlistCheck(
        title: "AUD landed cost",
        passed: !preferredEvidenceGaps.contains("AUD total")
          && preferredOption.estimatedAUDTotal.localizedCaseInsensitiveContains("aud")
          && !preferredOption.estimatedAUDTotal.localizedCaseInsensitiveContains("pending")
          && !preferredOption.estimatedAUDTotal.localizedCaseInsensitiveContains("needs review"),
        failDetail: "Confirm total landed AUD cost including item price, currency conversion, postage, and likely fees.",
        passDetail: "AUD total is recorded as \(preferredOption.estimatedAUDTotal)."
      ))
      checks.append(wishlistCheck(
        title: "Returns and warranty",
        passed: !preferredEvidenceGaps.contains("returns/warranty"),
        failDetail: "Record returns and warranty evidence for \(preferredOption.sellerName) before purchase review.",
        passDetail: "Returns or warranty evidence is recorded for \(preferredOption.sellerName)."
      ))
      let saferAlternative = options.first { option in
        option.id != preferredOption.id
          && option.operatorSellerEvidenceGaps.isEmpty
          && option.operatorSellerMatrixScore > preferredOption.operatorSellerMatrixScore
      }
      checks.append(wishlistCheck(
        title: "Seller choice rationale",
        passed: saferAlternative == nil,
        failDetail: "A stronger local seller option may exist: \(saferAlternative?.sellerName ?? "review alternatives"). Confirm why \(preferredOption.sellerName) is preferred before purchase.",
        passDetail: "No stronger complete-evidence seller option is currently ranked above \(preferredOption.sellerName)."
      ))
    } else {
      checks.append(WishlistPurchaseCheck(title: "Direct product link", status: "Blocked", detail: "Select or score a seller before checking the product URL.", severity: "High"))
      checks.append(WishlistPurchaseCheck(title: "Seller trust", status: "Blocked", detail: "Select or score a seller before assessing trust.", severity: "High"))
      checks.append(WishlistPurchaseCheck(title: "Postage and delivery", status: "Blocked", detail: "Select or score a seller before checking postage and delivery time.", severity: "High"))
      checks.append(WishlistPurchaseCheck(title: "AUD landed cost", status: "Blocked", detail: "Select or score a seller before checking landed cost.", severity: "High"))
      checks.append(WishlistPurchaseCheck(title: "Returns and warranty", status: "Blocked", detail: "Select or score a seller before checking returns and warranty.", severity: "High"))
      checks.append(WishlistPurchaseCheck(title: "Seller choice rationale", status: "Blocked", detail: "Select or score a seller before documenting why that seller is preferred.", severity: "High"))
    }

    checks.append(wishlistCheck(
      title: "Owner and account",
      passed: !checkedItem.owner.isPlaceholderValidationValue
        && !checkedItem.owner.localizedCaseInsensitiveContains("needs review")
        && !checkedItem.owner.localizedCaseInsensitiveContains("to confirm"),
      failDetail: "Confirm who owns the purchase and which account should be used before buying.",
      passDetail: "Owner is \(checkedItem.owner). Account choice still requires manual confirmation outside ParcelOps."
    ))

    let blockerCount = checks.filter { $0.status == "Blocked" || $0.severity == "High" }.count
    let warningCount = checks.filter { $0.status == "Review" || $0.severity == "Medium" }.count
    wishlistItems[index].purchaseChecks = checks
    wishlistItems[index].purchaseReadiness = blockerCount > 0
      ? "\(blockerCount) blockers before purchase"
      : warningCount > 0
        ? "\(warningCount) checks need review before purchase"
        : "Ready for purchase review"
    wishlistItems[index].status = blockerCount > 0 ? "Purchase blocked" : "Ready to purchase"
    wishlistItems[index].comparisonNotes = [
      wishlistItems[index].comparisonNotes,
      preferredOption.map { "Readiness checked against \($0.sellerName). Evidence gaps: \(preferredEvidenceGaps.isEmpty ? "none" : preferredEvidenceGaps.joined(separator: ", "))." },
      "Ready means local operator review only; ParcelOps still does not open retailer pages, log in, check out, buy, pay, or monitor the external order."
    ].compactMap { $0 }.joined(separator: " ")
    persistWishlist()
    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist purchase readiness checked locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nReadiness result: \(blockerCount) blocker\(blockerCount == 1 ? "" : "s"), \(warningCount) warning\(warningCount == 1 ? "" : "s"). Checks: \(checks.map { "\($0.title)=\($0.status)" }.joined(separator: "; ")). No live retailer, currency, postage, seller trust, account, checkout, purchase, payment, browser automation, or mailbox action occurred."
    )
  }

  func runWishlistPurchaseReadinessChecksForDecisionQueue() {
    let candidates = wishlistItems.filter { item in
      let options = item.comparisonOptions ?? []
      let checks = item.purchaseChecks ?? []
      return isActiveWishlistItem(item)
        && !options.isEmpty
        && selectedWishlistSellerOption(for: item) != nil
        && !options.contains { !$0.operatorSellerEvidenceGaps.isEmpty }
        && (checks.isEmpty || checks.contains { $0.status != "Passed" })
    }
    guard !candidates.isEmpty else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: "wishlist-purchase-readiness-batch",
        entityLabel: "Wishlist purchase readiness",
        summary: "Wishlist purchase readiness batch checked with no work needed.",
        afterDetail: "No Wishlist purchase decision queue items currently need local readiness checks. No retailer, browser, account, checkout, payment, mailbox, or external service action occurred."
      )
      return
    }

    for item in candidates {
      runWishlistPurchaseReadinessCheck(item)
    }

    let refreshed = candidates.compactMap { candidate in
      wishlistItems.first { $0.id == candidate.id }
    }
    let blockerCount = refreshed.reduce(0) { total, item in
      total + (item.purchaseChecks ?? []).filter { $0.status == "Blocked" || $0.severity == "High" }.count
    }
    let readyCount = refreshed.filter { item in
      let checks = item.purchaseChecks ?? []
      return !checks.isEmpty && checks.allSatisfy { $0.status == "Passed" }
    }.count

    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: "wishlist-purchase-readiness-batch",
      entityLabel: "Wishlist purchase readiness",
      summary: "Wishlist purchase readiness checks ran in batch locally.",
      afterDetail: """
      Checked \(candidates.count) Wishlist purchase decision queue item\(candidates.count == 1 ? "" : "s").
      Ready after check: \(readyCount).
      Remaining blocker count: \(blockerCount).
      Local readiness only. No live retailer, currency, postage, seller trust, account, checkout, purchase, payment, browser automation, mailbox, or external service action occurred.
      """
    )
  }

  func createWishlistPurchaseDecision(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let current = wishlistItems[index]
    let options = current.comparisonOptions ?? []
    let selectedOption = selectedWishlistSellerOption(for: current)
    let existingChecks = current.purchaseChecks ?? []
    let openChecks = existingChecks.filter { $0.status != "Passed" }
    let selectedGaps = selectedOption?.operatorSellerEvidenceGaps ?? []
    let rejectedOptions = options
      .filter { $0.id != selectedOption?.id }
      .map { "\($0.sellerName): \($0.estimatedAUDTotal), trust \($0.trustRating), score \($0.localScore ?? $0.operatorSellerMatrixScore), gaps \($0.operatorSellerEvidenceGaps.isEmpty ? "none" : $0.operatorSellerEvidenceGaps.joined(separator: ", "))" }
      .joined(separator: " | ")
    let decisionStatus: String
    if selectedOption == nil {
      decisionStatus = "Blocked pending seller option"
    } else if !openChecks.isEmpty || !selectedGaps.isEmpty {
      decisionStatus = "Draft decision with unresolved checks"
    } else {
      decisionStatus = "Draft decision"
    }
    wishlistItems[index].purchaseDecision = WishlistPurchaseDecision(
      selectedOptionID: selectedOption?.id,
      selectedSellerName: selectedOption?.sellerName ?? current.storefront,
      decisionStatus: decisionStatus,
      totalAUDSummary: selectedOption?.estimatedAUDTotal ?? "No seller option selected",
      postageSummary: selectedOption.map { "\($0.postageCost), \($0.postageTime)" } ?? "No postage option selected",
      trustSummary: selectedOption.map { "\($0.trustRating): \($0.trustNotes). Risk \(($0.riskLevel ?? $0.operatorSellerMatrixRisk)); score \($0.localScore ?? $0.operatorSellerMatrixScore)." } ?? "Seller trust not assessed",
      rejectedOptionsSummary: rejectedOptions.isEmpty ? "No rejected seller options recorded." : rejectedOptions,
      decisionNotes: selectedOption == nil
        ? "Add, edit, and score seller options before deciding where to buy."
        : [
          "Draft only.",
          selectedGaps.isEmpty ? "Selected seller evidence gaps: none recorded locally." : "Selected seller evidence gaps: \(selectedGaps.joined(separator: ", ")).",
          openChecks.isEmpty ? "Readiness checks have no open local failures." : "Open readiness checks: \(openChecks.map { "\($0.title)=\($0.status)" }.joined(separator: "; ")).",
          "Confirm live price, stock, AUD total, postage, returns, warranty, seller trust, account, and payment readiness outside ParcelOps before buying."
        ].joined(separator: " "),
      decidedBy: current.owner,
      decidedDate: "Now",
      reviewState: .needsReview
    )
    wishlistItems[index].status = selectedOption == nil || !selectedGaps.isEmpty || !openChecks.isEmpty ? "Purchase decision needs review" : "Purchase decision drafted"
    wishlistItems[index].purchaseReadiness = selectedOption == nil
      ? "Seller option required before decision"
      : (!selectedGaps.isEmpty || !openChecks.isEmpty ? "Decision has unresolved evidence before purchase" : "Decision needs review before purchase")
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist purchase decision drafted locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nDecision status: \(decisionStatus). Selected gaps: \(selectedGaps.isEmpty ? "none" : selectedGaps.joined(separator: ", ")). Open readiness checks: \(openChecks.isEmpty ? "none" : openChecks.map { "\($0.title)=\($0.status)" }.joined(separator: "; ")). Purchase decision is a local review record only. No retailer page was opened, no account was accessed, no checkout or payment occurred, and no external seller verification ran."
    )
  }

  func markWishlistPurchaseDecisionReviewed(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }), var decision = wishlistItems[index].purchaseDecision else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    decision.decisionStatus = "Decision reviewed"
    decision.reviewState = .accepted
    decision.decidedDate = "Now"
    decision.decisionNotes = "Decision reviewed locally. Operator still must confirm live price, stock, postage, seller trust, account, payment, delivery address, returns, and warranty outside ParcelOps before buying."
    wishlistItems[index].purchaseDecision = decision
    wishlistItems[index].status = "Purchase decision reviewed"
    wishlistItems[index].purchaseReadiness = "Ready for manual purchase handoff"
    persistWishlist()
    logAudit(
      action: .reviewed,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist purchase decision reviewed locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nReview only. ParcelOps did not buy the item, store payment details, open a retailer account, or monitor external checkout state."
    )
  }

