      "Seller: \(decision?.selectedSellerName ?? "No seller selected").",
      "AUD total: \(decision?.totalAUDSummary ?? "Not recorded").",
      "Postage: \(decision?.postageSummary ?? "Not recorded").",
      "Trust: \(decision?.trustSummary ?? "Not recorded").",
      "Alternates: \(decision?.rejectedOptionsSummary ?? "No alternates recorded").",
      "Confirm live price, stock, delivery time, returns, warranty, account, delivery address, and payment readiness outside ParcelOps before buying."
    ].joined(separator: " ")

    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == item.id.uuidString
        && $0.title.localizedCaseInsensitiveContains("purchase decision")
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = taskTitle
      reviewTasks[existingIndex].summary = taskSummary
      reviewTasks[existingIndex].priority = decision?.reviewState == .accepted ? .normal : .high
      reviewTasks[existingIndex].dueDate = "Today"
      reviewTasks[existingIndex].assignee = item.owner
      reviewTasks[existingIndex].reviewState = .needsReview
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Wishlist purchase decision review task refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nRefreshed from Wishlist purchase decision. No duplicate task was created and no external purchase, payment, account, retailer, browser, or mailbox action occurred."
      )
      return
    }

    let task = ReviewTask(
      title: taskTitle,
      summary: taskSummary,
      linkedEntityType: .wishlistItem,
      linkedEntityID: item.id.uuidString,
      priority: decision?.reviewState == .accepted ? .normal : .high,
      dueDate: "Today",
      assignee: item.owner,
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: .needsReview
    )
    addReviewTask(
      task,
      summary: "Review task created from Wishlist purchase decision."
    )
  }

  func createWishlistPurchasePacketDraft(_ item: WishlistItem) {
    guard isActiveWishlistItem(item) else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Closed Wishlist purchase packet skipped locally.",
        afterDetail: "The Wishlist item is closed or removed from active work, so no purchase packet draft was created. Reopen it before preparing a purchase packet. No retailer page, browser automation, account login, checkout, payment, purchase, mailbox mutation, or external service action occurred."
      )
      return
    }

    if let existingDraft = draftMessages.first(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == item.id.uuidString
        && $0.subject.localizedCaseInsensitiveContains("wishlist purchase packet")
    }) {
      reopenDraftMessage(existingDraft)
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: item.id.uuidString,
        entityLabel: item.itemName,
        summary: "Existing Wishlist purchase packet draft reused locally.",
        afterDetail: "Existing draft reopened instead of creating a duplicate: \(existingDraft.subject). No retailer page, browser automation, account login, checkout, payment, purchase, mailbox mutation, or external service action occurred."
      )
      return
    }

    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    if (wishlistItems[index].comparisonOptions ?? []).isEmpty {
      createWishlistComparisonPlan(wishlistItems[index])
    }
    evaluateWishlistComparisonOptions(wishlistItems[index])

    let current = wishlistItems.first { $0.id == item.id } ?? item
    if current.purchaseDecision == nil {
      createWishlistPurchaseDecision(current)
    }
    let refreshed = wishlistItems.first { $0.id == item.id } ?? current
    let options = (refreshed.comparisonOptions ?? []).sorted {
      let firstScore = $0.localScore ?? $0.operatorSellerMatrixScore
      let secondScore = $1.localScore ?? $1.operatorSellerMatrixScore
      if firstScore == secondScore {
        return $0.sellerName.localizedCaseInsensitiveCompare($1.sellerName) == .orderedAscending
      }
      return firstScore > secondScore
    }
    let selectedOption = selectedWishlistSellerOption(for: refreshed)
    let sellerQuotes = wishlistSellerQuotes(for: refreshed)
    let trustRecords = wishlistSellerTrustRecords.filter { record in
      record.wishlistItemID == refreshed.id
        || record.itemName.localizedCaseInsensitiveContains(refreshed.itemName)
        || refreshed.itemName.localizedCaseInsensitiveContains(record.itemName)
    }
    let approvalRecords = wishlistPurchaseApprovalRecords(for: refreshed)
    let linkRecords = wishlistPurchaseLinkRecords(for: refreshed)
    let watchRecords = wishlistOrderWatchRecords(for: refreshed)

    let optionSummary = options.prefix(8).map { option in
      "- \(option.sellerName): \(option.listedPrice) \(option.currency), estimated \(option.estimatedAUDTotal), postage \(option.postageCost) / \(option.postageTime), region \(option.sellerRegion), trust \(option.trustRating), score \(option.localScore ?? option.operatorSellerMatrixScore), risk \(option.riskLevel ?? option.operatorSellerMatrixRisk), link \(option.productURL), note \(option.decisionReason ?? option.operatorSellerMatrixRecommendation)"
    }.joined(separator: "\n")
    let quoteSummary = sellerQuotes.prefix(6).map { quote in
      "- \(quote.sellerName): \(quote.listedPrice) \(quote.currency), estimated \(quote.estimatedAUDTotal), postage \(quote.postageCost) / \(quote.postageTime), trust \(quote.trustSummary), status \(quote.quoteStatus), URL \(quote.productURL)"
    }.joined(separator: "\n")
    let trustSummary = trustRecords.prefix(6).map { record in
      "- \(record.sellerName): \(record.checkType), result \(record.resultStatus), risk \(record.riskLevel), evidence \(record.evidenceSummary)"
    }.joined(separator: "\n")
    let approvalSummary = approvalRecords.prefix(4).map { record in
      "- \(record.approvalStatus): limit \(record.approvedAUDLimit), budget \(record.budgetCode), approver \(record.approver), payment \(record.paymentMethodSummary)"
    }.joined(separator: "\n")
    let linkSummary = linkRecords.prefix(5).map { record in
      "- \(record.sellerName): \(record.linkType), total \(record.estimatedAUDTotal), postage \(record.postageSummary), trust \(record.trustSummary), ready \(record.readinessStatus), selected \(record.selectedForPurchase ? "yes" : "no"), URL \(record.productURL)"
    }.joined(separator: "\n")
    let watchSummary = watchRecords.prefix(4).map { record in
      "- \(record.sellerName): account \(record.accountLabel), expected signals \(record.expectedOrderSignals), status \(record.watchStatus), matched \(record.matchedOrderSummary)"
    }.joined(separator: "\n")
    let checksSummary = (refreshed.purchaseChecks ?? []).map { check in
      "- \(check.title): \(check.status) (\(check.severity)) - \(check.detail)"
    }.joined(separator: "\n")

    let body = """
    Wishlist purchase packet.

    Item:
    \(refreshed.itemName)

    Owner / pool:
    \(refreshed.owner) / \(refreshed.pool)

    Current purchase readiness:
    \(refreshed.purchaseReadiness ?? "Not assessed")

    Selected seller:
    \(selectedOption?.sellerName ?? "No seller selected")

    Selected seller details:
    \(selectedOption.map { "Total \($0.estimatedAUDTotal); postage \($0.postageCost) / \($0.postageTime); trust \($0.trustRating); risk \($0.riskLevel ?? $0.operatorSellerMatrixRisk); URL \($0.productURL)" } ?? "No selected option is available.")

    Local seller shortlist:
    \(optionSummary.isEmpty ? "- No seller options recorded." : optionSummary)

    Captured seller quotes:
    \(quoteSummary.isEmpty ? "- No seller quote records captured." : quoteSummary)

    Trust evidence:
    \(trustSummary.isEmpty ? "- No seller trust records captured." : trustSummary)

    Readiness checks:
    \(checksSummary.isEmpty ? "- No readiness checks recorded." : checksSummary)

    Local purchase decision:
    \(refreshed.purchaseDecision?.decisionStatus ?? "No purchase decision recorded")
    Seller: \(refreshed.purchaseDecision?.selectedSellerName ?? "Not selected")
    AUD total: \(refreshed.purchaseDecision?.totalAUDSummary ?? "Not recorded")
    Postage: \(refreshed.purchaseDecision?.postageSummary ?? "Not recorded")
    Trust: \(refreshed.purchaseDecision?.trustSummary ?? "Not recorded")
    Alternatives: \(refreshed.purchaseDecision?.rejectedOptionsSummary ?? "No alternatives recorded")

    Approvals:
    \(approvalSummary.isEmpty ? "- No approval records captured." : approvalSummary)

    Purchase links:
    \(linkSummary.isEmpty ? "- No purchase link records captured." : linkSummary)

    Order watch after external purchase:
    \(watchSummary.isEmpty ? "- No order-watch records captured." : watchSummary)

    Manual purchase checklist:
    - Confirm live price, stock, final landed AUD total, postage cost, delivery ETA, returns, warranty, seller identity, and seller trust outside ParcelOps.
    - Confirm the account and payment method outside ParcelOps.
    - If you purchase externally, watch Inbox/Orders for the confirmation and link it back to this Wishlist item.
    - Do not buy from any seller with unclear delivery, poor trust signals, missing returns/warranty, or suspicious pricing.

    Boundaries:
    This packet is local only. ParcelOps did not open retailer pages, compare live prices, convert currency, rate sellers externally, log into accounts, store payment details, check out, buy, pay, mutate mailboxes, or monitor orders in the background.
    """

    let draft = DraftMessage(
      linkedEntityType: .wishlistItem,
      linkedEntityID: refreshed.id.uuidString,
      templateID: nil,
      recipient: "Wishlist review",
      subject: "Wishlist purchase packet: \(refreshed.itemName)",
      body: body,
      channel: .email,
      createdDate: Self.auditTimestamp(),
      status: .draft,
      reviewState: .needsReview
    )
    draftMessages.insert(draft, at: 0)
    persistDraftMessages()
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .draftMessage,
      entityID: draft.id.uuidString,
      entityLabel: draft.subject,
      summary: "Wishlist purchase packet draft created locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(draft.auditDetail)\nSource item: \(refreshed.auditDetail)\nIncluded seller options: \(options.count); seller quotes: \(sellerQuotes.count); trust records: \(trustRecords.count); approval records: \(approvalRecords.count); purchase links: \(linkRecords.count); order-watch records: \(watchRecords.count). Draft only. No retailer, browser, account, checkout, payment, purchase, mailbox mutation, or external service action occurred."
    )
  }

  func createWishlistSellerEvidenceReviewTask(_ item: WishlistItem) {
    let options = item.comparisonOptions ?? []
    let preferred = selectedWishlistSellerOption(for: item)
    let missingBySeller = options.compactMap { option -> String? in
      let gaps = option.operatorSellerEvidenceGaps
      guard !gaps.isEmpty else { return nil }
      return "\(option.sellerName): \(gaps.joined(separator: ", "))"
    }
    let sellerSummaries = options.map { option in
      "- \(option.sellerName): total \(option.estimatedAUDTotal); postage \(option.postageCost) / \(option.postageTime); trust \(option.trustRating); score \(option.operatorSellerMatrixScore); gaps \(option.operatorSellerEvidenceGaps.isEmpty ? "none" : option.operatorSellerEvidenceGaps.joined(separator: ", "))."
    }
    let taskTitle = "Review Wishlist seller evidence: \(item.itemName)"
    let taskSummary: String
    if missingBySeller.isEmpty {
      taskSummary = """
      Seller evidence appears complete for \(item.itemName).

      Selected seller:
      \(preferred.map { "\($0.sellerName) - \($0.estimatedAUDTotal), postage \($0.postageCost) / \($0.postageTime), trust \($0.trustRating)." } ?? "No seller selected.")

      Local seller evidence:
      \(sellerSummaries.isEmpty ? "- No seller options recorded." : sellerSummaries.joined(separator: "\n"))

      Final manual checks before buying externally:
      - Reconfirm live product page, stock, exact model/variant, and price.
      - Reconfirm final AUD landed cost, currency conversion, postage cost, delivery ETA, returns, warranty, and seller identity.
      - Confirm the buying account, delivery address, and payment method outside ParcelOps.
      - Do not buy if delivery reliability, seller trust, returns/warranty, or total landed cost is unclear.

      Local boundary: no web search, retailer lookup, browser automation, account login, checkout, purchase, payment, mailbox mutation, or external verification action occurred.
      """
    } else {
      taskSummary = """
      Confirm missing seller evidence before purchase for \(item.itemName).

      Missing evidence:
      \(missingBySeller.map { "- \($0)" }.joined(separator: "\n"))

      Local seller evidence:
      \(sellerSummaries.isEmpty ? "- No seller options recorded." : sellerSummaries.joined(separator: "\n"))

      Evidence checklist:
      - Product link: direct product page, not a generic storefront.
      - AUD total: final landed AUD amount including item, GST/tax if known, postage, and fees.
      - Postage cost/time: shipping cost and realistic delivery window to Australia.
      - Seller trust: trust notes, recent reviews, returns, warranty, seller identity, and delivery reliability.
      - Account/payment readiness: which account will be used and whether purchase details are ready outside ParcelOps.

      Keep checks local until the user explicitly opens seller pages or decides to buy. No web search, retailer lookup, browser automation, account login, checkout, purchase, payment, mailbox mutation, or external verification action occurred.
      """
    }

    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == item.id.uuidString
        && $0.title.localizedCaseInsensitiveContains("seller evidence")
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = taskTitle
      reviewTasks[existingIndex].summary = taskSummary
      reviewTasks[existingIndex].priority = missingBySeller.isEmpty ? .normal : .high
      reviewTasks[existingIndex].dueDate = "Today"
      reviewTasks[existingIndex].assignee = item.owner
      reviewTasks[existingIndex].reviewState = missingBySeller.isEmpty ? .accepted : .needsReview
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Wishlist seller evidence task refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nRefreshed from Wishlist seller comparison evidence. No duplicate task was created and no web search, retailer lookup, browser automation, purchase, payment, account, mailbox, or external verification action occurred."
      )
      return
    }

    let task = ReviewTask(
      title: taskTitle,
      summary: taskSummary,
      linkedEntityType: .wishlistItem,
      linkedEntityID: item.id.uuidString,
      priority: missingBySeller.isEmpty ? .normal : .high,
      dueDate: "Today",
      assignee: item.owner,
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: missingBySeller.isEmpty ? .accepted : .needsReview
    )
    addReviewTask(
      task,
      summary: "Review task created from Wishlist seller evidence checklist."
    )
  }

  private func wishlistCheck(title: String, passed: Bool, failDetail: String, passDetail: String) -> WishlistPurchaseCheck {
    WishlistPurchaseCheck(
      title: title,
      status: passed ? "Passed" : "Review",
      detail: passed ? passDetail : failDetail,
      severity: passed ? "Low" : "Medium"
    )
  }

  private func wishlistBudgetCode(for item: WishlistItem) -> String {
    let pool = item.pool.trimmingCharacters(in: .whitespacesAndNewlines)
    return pool.isEmpty ? "Wishlist" : "Wishlist / \(pool)"
  }

  private func wishlistPurchaseAmountText(for item: WishlistItem) -> String {
    if let decisionTotal = item.purchaseDecision?.totalAUDSummary.trimmingCharacters(in: .whitespacesAndNewlines), !decisionTotal.isEmpty {
      return decisionTotal
    }
    if let preferredOption = selectedWishlistSellerOption(for: item) {
      let preferredTotal = preferredOption.estimatedAUDTotal.trimmingCharacters(in: .whitespacesAndNewlines)
      if !preferredTotal.isEmpty {
        return preferredTotal
      }
    }
    return item.estimatedCost.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "AUD total to confirm" : item.estimatedCost
  }

  func createWishlistPurchaseCostRecord(_ item: WishlistItem) {
    guard wishlistItems.contains(where: { $0.id == item.id }) else { return }
    if let existing = suggestedCostRecords(for: item).first {
      logAudit(
        action: .evaluated,
        entityType: .costRecord,
        entityID: existing.id.uuidString,
        entityLabel: existing.title,
        summary: "Existing Wishlist purchase cost placeholder reused locally.",
        afterDetail: "\(existing.auditDetail)\nWishlist item: \(item.itemName). No duplicate cost record was created. No purchase, payment, reimbursement, accounting, bank, retailer, or mailbox action occurred."
      )
      return
    }
    let selectedOption = selectedWishlistSellerOption(for: item)
    let seller = item.purchaseDecision?.selectedSellerName ?? item.purchaseHandoff?.sellerName ?? selectedOption?.sellerName ?? item.storefront
    let account = suggestedAccounts(for: item).first
    let amountText = wishlistPurchaseAmountText(for: item)
    let postage = item.purchaseDecision?.postageSummary ?? selectedOption.map { "\($0.postageCost), \($0.postageTime)" } ?? "Postage to confirm"
    let trust = item.purchaseDecision?.trustSummary ?? selectedOption?.trustRating ?? "Seller trust to confirm"
    let cost = CostRecord(
      title: "Wishlist purchase cost: \(item.itemName)",
      linkedEntityType: .wishlistItem,
      linkedEntityID: item.id.uuidString,
      orderID: item.purchaseHandoff?.linkedOrderID,
      shipmentGroupID: nil,
      packageContentID: nil,
      customerProfileID: nil,
      vendorProfileID: nil,
      accountID: account?.id,
      costCategory: .orderCost,
      amountText: amountText,
      currency: "AUD",
      taxGSTText: "GST/import duty to confirm",
      reimbursementStatus: .notSubmitted,
      approvalStatus: .draft,
      budgetCode: wishlistBudgetCode(for: item),
      costOwnerTeam: item.owner,
      evidenceAttachmentIDs: [],
      notes: "Local Wishlist purchase budget placeholder for \(seller). Postage: \(postage). Trust: \(trust). Account: \(account?.accountName ?? "to confirm"). No payment, checkout, retailer API, accounting system, or bank feed was used.",
      riskLevel: item.purchaseDecision?.reviewState == .accepted ? .medium : .high,
      createdDate: Self.auditTimestamp(),
      lastReviewedDate: "Never",
      reviewState: .needsReview
    )
    costRecords.insert(cost, at: 0)
    persistCostRecords()
    logAudit(
      action: .created,
      entityType: .costRecord,
      entityID: cost.id.uuidString,
      entityLabel: cost.title,
      summary: "Wishlist purchase cost placeholder created.",
      afterDetail: "\(cost.auditDetail)\nCreated from Wishlist item \(item.itemName). This is local budget tracking only; no purchase, payment, reimbursement, accounting, bank, or retailer action occurred."
    )
  }

