  func prepareWishlistPurchaseHandoff(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let current = wishlistItems[index]
    let preferredOption = selectedWishlistSellerOption(for: current)
    let sellerName = preferredOption?.sellerName ?? current.storefront
    wishlistItems[index].purchaseHandoff = WishlistPurchaseHandoff(
      sellerName: sellerName,
      accountLabel: "\(current.owner) account to confirm",
      purchaseStatus: "Ready for manual purchase decision",
      expectedOrderSignals: [sellerName, current.itemName, preferredOption?.productURL ?? current.storefrontURL]
        .filter { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty }
        .joined(separator: " | "),
      orderWatchStatus: "After purchase, watch Inbox and Orders for local confirmation email or order record.",
      linkedOrderID: nil,
      notes: "Manual handoff only. Confirm account, payment method, delivery address, returns, warranty, and final AUD total before buying outside ParcelOps.",
      updatedAt: "Now"
    )
    wishlistItems[index].status = "Purchase handoff ready"
    wishlistItems[index].purchaseReadiness = "Manual purchase handoff prepared"
    persistWishlist()
    addWishlistOrderWatchRecord(wishlistItems[index])
    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist purchase handoff prepared locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nHandoff only. No checkout, purchase, payment, account login, browser automation, mailbox monitoring, or retailer contact occurred."
    )
  }

  func createWishlistPurchaseHandoffReviewTask(_ item: WishlistItem) {
    let handoff = item.purchaseHandoff
    let decision = item.purchaseDecision
    let preferredOption = selectedWishlistSellerOption(for: item)
    let seller = handoff?.sellerName ?? decision?.selectedSellerName ?? preferredOption?.sellerName ?? item.storefront
    let account = handoff?.accountLabel ?? "\(item.owner) account to confirm"
    let expectedSignals = handoff?.expectedOrderSignals ?? [seller, item.itemName, preferredOption?.productURL ?? item.storefrontURL]
      .filter { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty }
      .joined(separator: " | ")
    let taskTitle = "Prepare Wishlist purchase handoff: \(item.itemName)"
    let taskSummary = [
      "Confirm the manual purchase handoff before buying outside ParcelOps.",
      "Seller: \(seller).",
      "Account: \(account).",
      "AUD total: \(decision?.totalAUDSummary ?? preferredOption?.estimatedAUDTotal ?? item.estimatedCost).",
      "Postage: \(decision?.postageSummary ?? preferredOption.map { "\($0.postageCost), \($0.postageTime)" } ?? "Not recorded").",
      "Trust: \(decision?.trustSummary ?? preferredOption?.trustRating ?? "Not recorded").",
      "Expected order signals: \(expectedSignals).",
      "Confirm live price, stock, delivery address, returns, warranty, payment method, and account access outside ParcelOps. No purchase should be marked complete until a confirmation is visible in Inbox, Mailbox Monitor, or Orders."
    ].joined(separator: " ")

    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == item.id.uuidString
        && $0.title.localizedCaseInsensitiveContains("purchase handoff")
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = taskTitle
      reviewTasks[existingIndex].summary = taskSummary
      reviewTasks[existingIndex].priority = handoff == nil || handoff?.linkedOrderID == nil ? .high : .normal
      reviewTasks[existingIndex].dueDate = "Today"
      reviewTasks[existingIndex].assignee = item.owner
      reviewTasks[existingIndex].reviewState = handoff == nil ? .needsReview : .accepted
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Wishlist purchase handoff task refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nRefreshed from Wishlist purchase handoff packet. No duplicate task was created and no checkout, purchase, payment, retailer, browser, account, or mailbox action occurred."
      )
      return
    }

    let task = ReviewTask(
      title: taskTitle,
      summary: taskSummary,
      linkedEntityType: .wishlistItem,
      linkedEntityID: item.id.uuidString,
      priority: handoff == nil || handoff?.linkedOrderID == nil ? .high : .normal,
      dueDate: "Today",
      assignee: item.owner,
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: handoff == nil ? .needsReview : .accepted
    )
    addReviewTask(
      task,
      summary: "Review task created from Wishlist purchase handoff."
    )
  }

  func recordWishlistPurchasedExternally(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    let expectedSignals = wishlistExpectedOrderConfirmationSignals(for: wishlistItems[index])
    var handoff = wishlistItems[index].purchaseHandoff
      ?? WishlistPurchaseHandoff(
        sellerName: wishlistItems[index].storefront,
        accountLabel: "\(wishlistItems[index].owner) account to confirm",
        purchaseStatus: "Ready for manual purchase decision",
        expectedOrderSignals: expectedSignals,
        orderWatchStatus: "Not watching yet",
        linkedOrderID: nil,
        notes: "Manual handoff created when purchase was recorded.",
        updatedAt: "Now"
      )
    if handoff.expectedOrderSignals.trimmingCharacters(in: .whitespacesAndNewlines).count < expectedSignals.count
      || handoff.expectedOrderSignals.isPlaceholderValidationValue {
      handoff.expectedOrderSignals = expectedSignals
    }
    handoff.purchaseStatus = "Purchased externally, awaiting order confirmation"
    handoff.orderWatchStatus = "Watch Inbox, Mailbox Monitor, and Orders for confirmation from \(handoff.sellerName). Expected signals: \(handoff.expectedOrderSignals)."
    handoff.notes = "Operator recorded that this was purchased outside ParcelOps. Use the expected signal packet to match the next imported order confirmation. No payment credentials, checkout session, or retailer account details were stored."
    handoff.updatedAt = "Now"
    wishlistItems[index].purchaseHandoff = handoff
    wishlistItems[index].status = "Awaiting order confirmation"
    wishlistItems[index].purchaseReadiness = "Purchased externally; watch for confirmation"
    persistWishlist()
    addWishlistOrderWatchRecord(wishlistItems[index])
    logAudit(
      action: .reviewed,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: "Wishlist item marked purchased externally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nExpected confirmation signals: \(handoff.expectedOrderSignals).\nManual record only. ParcelOps did not purchase the item, store payment details, log in to a retailer, send email, or monitor a mailbox in the background."
    )
  }

  private func wishlistExpectedOrderConfirmationSignals(for item: WishlistItem) -> String {
    let preferredOption = selectedWishlistSellerOption(for: item)
    let selectedPurchaseLink = wishlistPurchaseLinkRecords(for: item).first { $0.selectedForPurchase } ?? wishlistPurchaseLinkRecords(for: item).first
    let seller = item.purchaseHandoff?.sellerName
      ?? item.purchaseDecision?.selectedSellerName
      ?? selectedPurchaseLink?.sellerName
      ?? preferredOption?.sellerName
      ?? item.storefront
    let productURL = selectedPurchaseLink?.productURL ?? preferredOption?.productURL ?? item.storefrontURL
    let productHost = URL(string: productURL)?.host
      ?? productURL
        .replacingOccurrences(of: "https://", with: "")
        .replacingOccurrences(of: "http://", with: "")
        .split(separator: "/")
        .first
        .map(String.init)
    let cleanHost = productHost?
      .replacingOccurrences(of: "www.", with: "")
      .trimmingCharacters(in: .whitespacesAndNewlines)
    let rawSignals = [
      seller,
      item.itemName,
      item.storefront,
      item.purchaseDecision?.selectedSellerName,
      selectedPurchaseLink?.sellerName,
      preferredOption?.sellerName,
      cleanHost,
      selectedPurchaseLink?.accountContext,
      selectedPurchaseLink?.estimatedAUDTotal,
      preferredOption?.estimatedAUDTotal,
      item.purchaseDecision?.totalAUDSummary,
      "order confirmation",
      "order number",
      "order received",
      "receipt",
      "invoice",
      "dispatch",
      "shipped",
      "tracking",
      "your order"
    ]
      .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
      .filter { !$0.isEmpty && !$0.isPlaceholderValidationValue }
    var seen = Set<String>()
    let uniqueSignals = rawSignals.filter { signal in
      let key = signal.localizedLowercase
      guard !seen.contains(key) else { return false }
      seen.insert(key)
      return true
    }
    return uniqueSignals.prefix(10).joined(separator: " | ")
  }

  func markWishlistOrderConfirmationSeen(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    var handoff = wishlistItems[index].purchaseHandoff
      ?? WishlistPurchaseHandoff(
        sellerName: wishlistItems[index].storefront,
        accountLabel: "\(wishlistItems[index].owner) account to confirm",
        purchaseStatus: "Order confirmation review needed",
        expectedOrderSignals: "\(wishlistItems[index].storefront) | \(wishlistItems[index].itemName)",
        orderWatchStatus: "Order confirmation marked seen locally",
        linkedOrderID: nil,
        notes: "Manual confirmation marker created.",
        updatedAt: "Now"
      )
    let matchingOrder = orders.first { order in
      let refreshedItem = wishlistItems[index]
      let searchableOrder = [
        order.orderNumber,
        order.store,
        order.customer,
        order.trackingNumber,
        order.destination,
        order.latestStatus,
        order.timeline.map(\.detail).joined(separator: " "),
        order.contactHistory.map(\.evidence).joined(separator: " ")
      ].joined(separator: " ").localizedLowercase
      let signals = wishlistExpectedOrderConfirmationSignals(for: refreshedItem)
        .components(separatedBy: CharacterSet(charactersIn: "|,"))
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).localizedLowercase }
        .filter { $0.count >= 4 }
      let seller = handoff.sellerName.localizedLowercase
      let itemName = refreshedItem.itemName.localizedLowercase
      return (!seller.isEmpty && searchableOrder.contains(seller))
        || (!itemName.isEmpty && searchableOrder.contains(itemName))
        || signals.contains { searchableOrder.contains($0) }
    }
    handoff.purchaseStatus = matchingOrder == nil
      ? "Order confirmation seen; link order manually"
      : "Order confirmation linked locally"
    handoff.orderWatchStatus = matchingOrder == nil
      ? "Confirmation was seen, but no matching local order was linked automatically."
      : "Linked to local order \(matchingOrder?.orderNumber ?? "")."
    handoff.linkedOrderID = matchingOrder?.id
    handoff.updatedAt = "Now"
    wishlistItems[index].purchaseHandoff = handoff
    wishlistItems[index].status = matchingOrder == nil ? "Order confirmation needs linking" : "Order confirmation linked"
    wishlistItems[index].purchaseReadiness = "Order confirmation reviewed locally"
    persistWishlist()
    logAudit(
      action: .linked,
      entityType: .wishlistItem,
      entityID: wishlistItems[index].id.uuidString,
      entityLabel: wishlistItems[index].itemName,
      summary: matchingOrder == nil ? "Wishlist order confirmation marked seen locally." : "Wishlist order confirmation linked locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[index].auditDetail)\nLinked order: \(matchingOrder?.orderNumber ?? "none"). Expected signals: \(handoff.expectedOrderSignals). No mailbox was fetched, no retailer account was accessed, and no external monitoring ran."
    )
  }

  func suggestedWishlistOrderConfirmations(for item: WishlistItem) -> [ForwardedEmailIntake] {
    guard item.purchaseHandoff != nil else { return [] }
    return intakeEmails
      .filter { email in
        email.reviewState != .ignored && wishlistOrderConfirmationMatchDetail(item: item, email: email).score >= 4
      }
      .sorted { first, second in
        let firstScore = wishlistOrderConfirmationMatchDetail(item: item, email: first).score
        let secondScore = wishlistOrderConfirmationMatchDetail(item: item, email: second).score
        if firstScore == secondScore {
          return first.receivedDate > second.receivedDate
        }
        return firstScore > secondScore
      }
  }

  func confirmWishlistOrderFromIntake(_ item: WishlistItem, email: ForwardedEmailIntake) {
    guard let wishlistIndex = wishlistItems.firstIndex(where: { $0.id == item.id }),
          let emailIndex = intakeEmails.firstIndex(where: { $0.id == email.id }) else { return }
    let beforeDetail = wishlistItems[wishlistIndex].auditDetail
    let intakeBeforeDetail = intakeEmails[emailIndex].auditDetail
    let matchDetail = wishlistOrderConfirmationMatchDetail(item: wishlistItems[wishlistIndex], email: intakeEmails[emailIndex])

    var linkedOrderID = intakeEmails[emailIndex].linkedOrderID
    if linkedOrderID == nil {
      createOrder(from: intakeEmails[emailIndex])
      linkedOrderID = intakeEmails.first(where: { $0.id == email.id })?.linkedOrderID
    } else {
      intakeEmails[emailIndex].reviewState = .reviewed
      persistIntakeEmails()
    }

    var handoff = wishlistItems[wishlistIndex].purchaseHandoff
      ?? WishlistPurchaseHandoff(
        sellerName: wishlistItems[wishlistIndex].storefront,
        accountLabel: "\(wishlistItems[wishlistIndex].owner) account to confirm",
        purchaseStatus: "Order confirmation review needed",
        expectedOrderSignals: "\(wishlistItems[wishlistIndex].storefront) | \(wishlistItems[wishlistIndex].itemName)",
        orderWatchStatus: "Order confirmation matched from Inbox",
        linkedOrderID: nil,
        notes: "Manual confirmation marker created from Inbox.",
        updatedAt: "Now"
      )
    handoff.purchaseStatus = linkedOrderID == nil
      ? "Inbox confirmation used; order link needs review"
      : "Inbox confirmation linked locally"
    handoff.orderWatchStatus = "Inbox intake '\(intakeEmails.first(where: { $0.id == email.id })?.subject ?? email.subject)' was used as the local purchase confirmation."
    handoff.linkedOrderID = linkedOrderID
    handoff.updatedAt = "Now"
    handoff.notes = "Operator confirmed this Inbox intake row as the Wishlist purchase confirmation. No mailbox was fetched, no retailer account was accessed, and no payment or checkout data was stored."
    wishlistItems[wishlistIndex].purchaseHandoff = handoff
    wishlistItems[wishlistIndex].status = linkedOrderID == nil ? "Order confirmation needs linking" : "Order confirmation linked"
    wishlistItems[wishlistIndex].purchaseReadiness = "Order confirmation matched from Inbox"

    persistWishlist()
    logAudit(
      action: .linked,
      entityType: .wishlistItem,
      entityID: wishlistItems[wishlistIndex].id.uuidString,
      entityLabel: wishlistItems[wishlistIndex].itemName,
      summary: linkedOrderID == nil ? "Wishlist Inbox confirmation used locally." : "Wishlist Inbox confirmation linked to order locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistItems[wishlistIndex].auditDetail)\nMatch confidence: \(matchDetail.confidence) (\(matchDetail.score)). Reasons: \(matchDetail.reasons.joined(separator: ", ")).\nIntake before: \(intakeBeforeDetail)\nNo mailbox fetch, browser automation, retailer login, checkout, payment, notification, or external monitoring occurred."
    )
  }

  func wishlistItemsLinked(to order: TrackedOrder) -> [WishlistItem] {
    wishlistItems.filter { item in
      item.purchaseHandoff?.linkedOrderID == order.id
        || item.status.localizedCaseInsensitiveContains(order.orderNumber)
        || item.purchaseReadiness?.localizedCaseInsensitiveContains(order.orderNumber) == true
    }
  }

