  func wishlistOrderConfirmationMatchDetail(item: WishlistItem, email: ForwardedEmailIntake) -> (score: Int, confidence: String, reasons: [String]) {
    let handoff = item.purchaseHandoff
    let selectedOption = selectedWishlistSellerOption(for: item)
    let productURL = selectedOption?.productURL ?? item.storefrontURL
    let productHost = URL(string: productURL)?.host?
      .replacingOccurrences(of: "www.", with: "")
      .localizedLowercase
    let searchable = [
      email.sender,
      email.subject,
      email.rawBodyPreview,
      email.detectedMerchant,
      email.detectedOrderNumber,
      email.detectedTrackingNumber
    ]
      .joined(separator: " ")
      .localizedLowercase
    let itemName = item.itemName.localizedLowercase
    let seller = (handoff?.sellerName ?? item.storefront).localizedLowercase
    let signals = (handoff?.expectedOrderSignals ?? wishlistExpectedOrderConfirmationSignals(for: item))
      .components(separatedBy: CharacterSet(charactersIn: "|,"))
      .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).localizedLowercase }
      .filter { $0.count >= 4 && !$0.isPlaceholderValidationValue }
    let itemWords = itemName
      .components(separatedBy: CharacterSet.alphanumerics.inverted)
      .filter { $0.count >= 4 }

    var score = 0
    var reasons: [String] = []
    if !seller.isEmpty && searchable.contains(seller) {
      score += 4
      reasons.append("seller")
    }
    if !itemName.isEmpty && searchable.contains(itemName) {
      score += 5
      reasons.append("item name")
    }
    let matchedItemWords = itemWords.filter { searchable.contains($0) }
    if !matchedItemWords.isEmpty {
      score += min(4, matchedItemWords.count)
      reasons.append("item word")
    }
    let matchedSignals = signals.filter { searchable.contains($0) }
    if !matchedSignals.isEmpty {
      score += min(6, matchedSignals.count * 2)
      reasons.append("expected signal")
    }
    if let productHost, searchable.contains(productHost) {
      score += 3
      reasons.append("product host")
    }
    if !email.detectedOrderNumber.isPlaceholderValidationValue {
      score += 4
      reasons.append("order number")
    }
    if !email.detectedTrackingNumber.isPlaceholderValidationValue {
      score += 4
      reasons.append("tracking number")
    }
    if searchable.contains("order") {
      score += 1
      reasons.append("order wording")
    }
    if searchable.contains("confirmation") || searchable.contains("confirmed") {
      score += 2
      reasons.append("confirmation wording")
    }
    if searchable.contains("shipped") || searchable.contains("tracking") || searchable.contains("dispatch") || searchable.contains("delivery") {
      score += 2
      reasons.append("shipping wording")
    }
    if searchable.contains("invoice") || searchable.contains("receipt") {
      score += 1
      reasons.append("receipt wording")
    }
    if email.linkedOrderID != nil {
      score += 3
      reasons.append("linked order")
    }
    if email.reviewState == .reviewed {
      score += 1
      reasons.append("reviewed intake")
    }
    if searchable.contains("newsletter") || searchable.contains("unsubscribe") || searchable.contains("promotion") || searchable.contains("sale ends") {
      score -= 5
      reasons.append("marketing signal")
    }
    let confidence: String
    if score >= 10 {
      confidence = "High"
    } else if score >= 7 {
      confidence = "Medium"
    } else if score >= 4 {
      confidence = "Low"
    } else {
      confidence = "No match"
    }
    return (score, confidence, reasons.isEmpty ? ["no clear local signal"] : Array(reasons.prefix(6)))
  }

  private func localWishlistOptionEvaluation(for option: WishlistComparisonOption) -> (score: Int, risk: String, recommendation: String, reasons: [String]) {
    let searchable = [
      option.sellerName,
      option.productURL,
      option.listedPrice,
      option.currency,
      option.estimatedAUDTotal,
      option.postageCost,
      option.postageTime,
      option.sellerRegion,
      option.trustRating,
      option.trustNotes,
      option.recommendation
    ].joined(separator: " ").localizedLowercase

    var score = 50
    var reasons: [String] = []

    if searchable.contains("aud") {
      score += 12
      reasons.append("AUD total visible")
    } else if searchable.contains("pending aud") || searchable.contains("foreign") {
      score -= 8
      reasons.append("AUD conversion pending")
    }

    if option.postageCost.localizedCaseInsensitiveContains("pending") || option.postageTime.localizedCaseInsensitiveContains("pending") {
      score -= 14
      reasons.append("postage detail pending")
    } else {
      score += 10
      reasons.append("postage detail present")
    }

    if searchable.contains("australia") || searchable.contains(" au") || searchable.contains("local") {
      score += 12
      reasons.append("local seller signal")
    }
    if searchable.contains("overseas") || searchable.contains("international") || searchable.contains("global") {
      score -= 6
      reasons.append("overseas seller review")
    }

    if option.trustRating.localizedCaseInsensitiveContains("high") || option.trustRating.localizedCaseInsensitiveContains("trusted") {
      score += 22
      reasons.append("higher trust signal")
    } else if option.trustRating.localizedCaseInsensitiveContains("unknown") {
      score -= 24
      reasons.append("unknown seller trust")
    } else if option.trustRating.localizedCaseInsensitiveContains("review") {
      score -= 16
      reasons.append("trust review required")
    }

    if searchable.contains("returns") || searchable.contains("warranty") {
      score += 6
      reasons.append("returns/warranty noted")
    } else {
      score -= 4
      reasons.append("returns/warranty not confirmed")
    }

    let clampedScore = min(max(score, 0), 100)
    let risk: String
    let recommendation: String
    if clampedScore >= 78 {
      risk = "Lower risk"
      recommendation = "Best candidate"
    } else if clampedScore >= 55 {
      risk = "Review before purchase"
      recommendation = "Viable with checks"
    } else {
      risk = "High risk"
      recommendation = "Do not buy until reviewed"
    }
    return (clampedScore, risk, recommendation, reasons)
  }

  func wishlistPriceSnapshots(for item: WishlistItem) -> [WishlistPriceSnapshot] {
    wishlistPriceSnapshots
      .filter { snapshot in
        snapshot.wishlistItemID == item.id
          || snapshot.itemName.localizedCaseInsensitiveContains(item.itemName)
          || item.itemName.localizedCaseInsensitiveContains(snapshot.itemName)
      }
      .sorted { first, second in
        if first.reviewState == second.reviewState {
          return first.capturedDate > second.capturedDate
        }
        return first.reviewState == .needsReview
      }
  }

  func addWishlistPriceSnapshot(_ item: WishlistItem) {
    let preferredOption = selectedWishlistSellerOption(for: item)
    let timestamp = Self.auditTimestamp()
    let snapshot = WishlistPriceSnapshot(
      wishlistItemID: item.id,
      itemName: item.itemName,
      sellerName: preferredOption?.sellerName ?? item.storefront,
      productURL: preferredOption?.productURL ?? item.storefrontURL,
      observedPrice: preferredOption?.listedPrice ?? item.estimatedCost,
      currency: preferredOption?.currency ?? "AUD or source currency",
      estimatedAUDTotal: preferredOption?.estimatedAUDTotal ?? item.estimatedCost,
      postageCost: preferredOption?.postageCost ?? "Postage to confirm",
      postageTime: preferredOption?.postageTime ?? "Delivery time to confirm",
      availabilityStatus: "Manual availability check needed",
      trustSignal: preferredOption?.trustRating ?? "Trust evidence to confirm",
      snapshotSource: "Manual price/watch snapshot",
      capturedDate: timestamp,
      reviewState: .needsReview,
      notes: "Local manual price/watch snapshot only. No retailer page was fetched, no live price was checked, no browser automation ran, no account login occurred, and no purchase was made."
    )
    wishlistPriceSnapshots.insert(snapshot, at: 0)
    persistWishlist()
    logAudit(
      action: .created,
      entityType: .wishlistItem,
      entityID: item.id.uuidString,
      entityLabel: item.itemName,
      summary: "Wishlist price/watch snapshot added locally.",
      afterDetail: "\(snapshot.auditDetail)\nSource item: \(item.auditDetail)\nSnapshot is operator-entered/local only. No retailer lookup, currency conversion, postage lookup, trust lookup, browser extension sync, account login, checkout, purchase, or payment occurred."
    )
  }

  func markWishlistPriceSnapshotReviewed(_ snapshot: WishlistPriceSnapshot) {
    guard let index = wishlistPriceSnapshots.firstIndex(where: { $0.id == snapshot.id }) else { return }
    let beforeDetail = wishlistPriceSnapshots[index].auditDetail
    wishlistPriceSnapshots[index].reviewState = .accepted
    wishlistPriceSnapshots[index].notes = "\(wishlistPriceSnapshots[index].notes) Reviewed locally at \(Self.auditTimestamp())."
    persistWishlist()
    logAudit(
      action: .reviewed,
      entityType: .wishlistItem,
      entityID: wishlistPriceSnapshots[index].wishlistItemID?.uuidString ?? wishlistPriceSnapshots[index].id.uuidString,
      entityLabel: wishlistPriceSnapshots[index].itemName,
      summary: "Wishlist price/watch snapshot reviewed locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistPriceSnapshots[index].auditDetail)\nReview only. Live price, stock, postage, seller trust, account access, checkout, and payment still need confirmation outside ParcelOps before buying."
    )
  }

  func removeWishlistPriceSnapshot(_ snapshot: WishlistPriceSnapshot) {
    guard let index = wishlistPriceSnapshots.firstIndex(where: { $0.id == snapshot.id }) else { return }
    let removed = wishlistPriceSnapshots.remove(at: index)
    persistWishlist()
    logAudit(
      action: .removed,
      entityType: .wishlistItem,
      entityID: removed.wishlistItemID?.uuidString ?? removed.id.uuidString,
      entityLabel: removed.itemName,
      summary: "Wishlist price/watch snapshot removed locally.",
      beforeDetail: removed.auditDetail,
      afterDetail: "Snapshot removed from the local price/watch ledger only. No wishlist item, seller page, account, checkout, purchase, payment, mailbox, or external service was changed."
    )
  }

