      afterDetail: "\(record.auditDetail)\nSource item: \(item.auditDetail)\nNo mailbox polling, background job, retailer monitoring, browser automation, checkout, payment, or purchase occurred."
    )
  }

  private func wishlistOrderWatchRecordTemplate(for item: WishlistItem) -> WishlistOrderWatchRecord {
    let handoff = item.purchaseHandoff
    let selectedLink = wishlistPurchaseLinkRecords(for: item).first { $0.selectedForPurchase } ?? wishlistPurchaseLinkRecords(for: item).first
    let sellerName = handoff?.sellerName ?? selectedLink?.sellerName ?? item.purchaseDecision?.selectedSellerName ?? item.storefront
    let expectedSignals = wishlistExpectedOrderConfirmationSignals(for: item)
    let purchasedExternally = handoff?.purchaseStatus.localizedCaseInsensitiveContains("purchased") == true
    return WishlistOrderWatchRecord(
      wishlistItemID: item.id,
      linkedOrderID: handoff?.linkedOrderID,
      itemName: item.itemName,
      sellerName: sellerName,
      accountLabel: handoff?.accountLabel ?? selectedLink?.accountContext ?? "\(item.owner) account to confirm",
      expectedOrderSignals: expectedSignals,
      expectedMailboxOrSource: "Inbox triage after manual mailbox refresh",
      watchStatus: handoff?.linkedOrderID == nil
        ? (purchasedExternally ? "Awaiting order confirmation" : "Awaiting external purchase")
        : "Linked to local order",
      matchedOrderSummary: handoff?.linkedOrderID.flatMap { id in orders.first { $0.id == id }?.orderNumber } ?? "No linked order yet",
      nextCheckSummary: "After a human buys externally, refresh the relevant mailbox and link a captured confirmation that matches seller, item, host, order, receipt, invoice, dispatch, or tracking signals.",
      createdDate: Self.auditTimestamp(),
      lastCheckedDate: "Not checked",
      reviewState: .needsReview,
      notes: "Local watch rule only. Expected signals: \(expectedSignals). No background polling, retailer monitoring, mailbox mutation, order placement, or purchase automation occurs."
    )
  }

  func checkWishlistOrderWatchRecord(_ record: WishlistOrderWatchRecord) {
    guard let index = wishlistOrderWatchRecords.firstIndex(where: { $0.id == record.id }) else { return }
    let beforeDetail = wishlistOrderWatchRecords[index].auditDetail
    let watchedItem = wishlistItems.first { $0.id == wishlistOrderWatchRecords[index].wishlistItemID } ?? WishlistItem(
      itemName: wishlistOrderWatchRecords[index].itemName,
      storefront: wishlistOrderWatchRecords[index].sellerName,
      storefrontURL: "",
      estimatedCost: "",
      owner: "",
      pool: "Wishlist",
      source: .manual,
      status: "",
      capturedDetail: wishlistOrderWatchRecords[index].expectedOrderSignals
    )
    let matchedOrder = bestWishlistOrderMatch(for: watchedItem)
    let confirmationCandidates = matchedOrder == nil ? suggestedWishlistOrderConfirmations(for: watchedItem) : []
    let candidateSummary = confirmationCandidates.isEmpty
      ? "No Inbox confirmation candidates found."
      : "\(confirmationCandidates.count) Inbox confirmation candidate\(confirmationCandidates.count == 1 ? "" : "s") need review."
    wishlistOrderWatchRecords[index].linkedOrderID = matchedOrder?.id ?? wishlistOrderWatchRecords[index].linkedOrderID
    wishlistOrderWatchRecords[index].matchedOrderSummary = matchedOrder.map { "\($0.orderNumber) from \($0.store)" } ?? candidateSummary
    wishlistOrderWatchRecords[index].watchStatus = matchedOrder == nil
      ? (confirmationCandidates.isEmpty ? "No confirmation found yet" : "Inbox confirmation candidates need review")
      : "Matched local order"
    wishlistOrderWatchRecords[index].lastCheckedDate = Self.auditTimestamp()
    wishlistOrderWatchRecords[index].reviewState = matchedOrder == nil ? .needsReview : .accepted
    if let wishlistItemID = wishlistOrderWatchRecords[index].wishlistItemID,
       let itemIndex = wishlistItems.firstIndex(where: { $0.id == wishlistItemID }) {
      var handoff = wishlistItems[itemIndex].purchaseHandoff
      if handoff == nil {
        prepareWishlistPurchaseHandoff(wishlistItems[itemIndex])
        handoff = wishlistItems[itemIndex].purchaseHandoff
      }
      let existingLinkedOrderID = handoff?.linkedOrderID
      let watchStatus = wishlistOrderWatchRecords[index].watchStatus
      let updatedAt = Self.auditTimestamp()
      handoff?.linkedOrderID = matchedOrder?.id ?? existingLinkedOrderID
      handoff?.orderWatchStatus = watchStatus
      handoff?.updatedAt = updatedAt
      wishlistItems[itemIndex].purchaseHandoff = handoff
      wishlistItems[itemIndex].purchaseReadiness = matchedOrder == nil
        ? (confirmationCandidates.isEmpty ? "Order watch checked; refresh or review mailbox" : "Order confirmation candidate ready for review")
        : "Order watch matched local order"
    }
    persistWishlist()
    if matchedOrder == nil {
      refreshWishlistOrderWatchFollowUpTask(record: wishlistOrderWatchRecords[index], candidateMatches: confirmationCandidates)
    } else {
      completeWishlistOrderWatchFollowUpTaskIfNeeded(record: wishlistOrderWatchRecords[index], matchedOrder: matchedOrder)
    }
    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: wishlistOrderWatchRecords[index].wishlistItemID?.uuidString ?? wishlistOrderWatchRecords[index].id.uuidString,
      entityLabel: wishlistOrderWatchRecords[index].itemName,
      summary: matchedOrder == nil
        ? (confirmationCandidates.isEmpty ? "Wishlist order watch checked with no confirmation found." : "Wishlist order watch found Inbox confirmation candidates.")
        : "Wishlist order watch matched local order \(matchedOrder?.orderNumber ?? "").",
      beforeDetail: beforeDetail,
      afterDetail: "\(wishlistOrderWatchRecords[index].auditDetail)\nInbox candidates: \(confirmationCandidates.count). \(candidateSummary)\nLocal match check only. ParcelOps did not fetch mail, poll in the background, open retailer pages, mutate mailbox items, purchase, or pay."
    )
  }

  func checkOpenWishlistOrderWatchRecords() {
    func activeLinkedOrderWatchCount() -> Int {
      wishlistOrderWatchRecords.filter { isActiveWishlistOrderWatchRecord($0) && $0.linkedOrderID != nil }.count
    }

    func stillWaitingOrderWatchCount(candidateIDs: [UUID]) -> Int {
      wishlistOrderWatchRecords.filter { record in
        candidateIDs.contains(record.id)
          && record.linkedOrderID == nil
          && !record.watchStatus.localizedCaseInsensitiveContains("blocked")
      }.count
    }

    let candidateIDs = wishlistOrderWatchRecords
      .filter { record in
        isActiveWishlistOrderWatchRecord(record)
          && record.linkedOrderID == nil
          && !record.watchStatus.localizedCaseInsensitiveContains("blocked")
      }
      .map(\.id)
    let beforeLinked = activeLinkedOrderWatchCount()
    let beforeWaiting = candidateIDs.count
    guard !candidateIDs.isEmpty else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: "wishlist-order-watch-batch",
        entityLabel: "Wishlist order watch",
        summary: "Wishlist order watch batch check found no open records.",
        afterDetail: "Open watch rules checked: 0\nNo local order matching was needed. No mailbox fetch, background polling, retailer access, checkout, payment, purchase, or external service call occurred."
      )
      return
    }

    for recordID in candidateIDs {
      if let record = wishlistOrderWatchRecords.first(where: { $0.id == recordID }) {
        checkWishlistOrderWatchRecord(record)
      }
    }

    let afterLinked = activeLinkedOrderWatchCount()
    let stillWaiting = stillWaitingOrderWatchCount(candidateIDs: candidateIDs)
    let matched = max(afterLinked - beforeLinked, 0)
    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: "wishlist-order-watch-batch",
      entityLabel: "Wishlist order watch",
      summary: "Wishlist order watch batch checked locally.",
      afterDetail: "Open watch rules checked: \(beforeWaiting)\nMatched local orders: \(matched)\nStill waiting: \(stillWaiting)\nIndividual watch rules were checked against local orders only. No mailbox fetch, background polling, retailer access, checkout, payment, purchase, or external service call occurred."
    )
  }

  func checkWishlistOperationsClosureReadinessBatch() {
    let candidates = wishlistItems.filter { item in
      isActiveWishlistItem(item)
        && (item.purchaseHandoff?.linkedOrderID != nil
        || !suggestedReceivingInspections(for: item).isEmpty
        || !suggestedInventoryReceipts(for: item).isEmpty
        || !suggestedStorageLocations(for: item).isEmpty
        || !suggestedCustodyRecords(for: item).isEmpty
        || !suggestedLabelReferenceRecords(for: item).isEmpty
        || !suggestedScanSessionRecords(for: item).isEmpty
        || !suggestedShipmentManifestRecords(for: item).isEmpty
        || !suggestedDispatchReadinessChecklists(for: item).isEmpty)
    }
    guard !candidates.isEmpty else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: "wishlist-closure-readiness-batch",
        entityLabel: "Wishlist closure readiness",
        summary: "Wishlist closure readiness checked with no linked operations trail.",
        afterDetail: "No Wishlist items currently have linked order or downstream operations records to close. No order, receiving, inventory, dispatch, mailbox, retailer, payment, purchase, or external service action occurred."
      )
      return
    }

    let results = candidates.map { item -> (WishlistItem, [String]) in
      var gaps: [String] = []
      if item.purchaseHandoff?.linkedOrderID == nil { gaps.append("order link") }
      if suggestedReceivingInspections(for: item).isEmpty { gaps.append("receiving") }
      if suggestedInventoryReceipts(for: item).isEmpty { gaps.append("inventory") }
      if suggestedStorageLocations(for: item).isEmpty { gaps.append("storage") }
      if suggestedCustodyRecords(for: item).isEmpty { gaps.append("custody") }
      if suggestedLabelReferenceRecords(for: item).isEmpty { gaps.append("label") }
      if suggestedScanSessionRecords(for: item).isEmpty { gaps.append("manual check") }
      if suggestedShipmentManifestRecords(for: item).isEmpty { gaps.append("manifest") }
      if suggestedDispatchReadinessChecklists(for: item).isEmpty { gaps.append("dispatch") }
      let openTasks = reviewTasks.filter { task in
        task.linkedEntityType == .wishlistItem
          && task.linkedEntityID == item.id.uuidString
          && task.status != .completed
      }
      if !openTasks.isEmpty { gaps.append("open task") }
      return (item, gaps)
    }
    let blocked = results.filter { !$0.1.isEmpty }
    let ready = results.filter { $0.1.isEmpty }
    let groupedGapCounts = Dictionary(grouping: blocked.flatMap(\.1), by: { $0 })
      .mapValues(\.count)
      .sorted { first, second in
        if first.value == second.value {
          return first.key < second.key
        }
        return first.value > second.value
      }
    let topBlocked = blocked
      .prefix(5)
      .map { "\($0.0.itemName): \($0.1.prefix(4).joined(separator: ", "))" }

    if !blocked.isEmpty {
      let summary = "Review Wishlist operations closure readiness. \(blocked.count) item\(blocked.count == 1 ? "" : "s") still have local closure gaps: \(groupedGapCounts.prefix(6).map { "\($0.key) \($0.value)" }.joined(separator: "; ")). This task is local only and does not close orders, receive stock, book dispatch, mutate mailboxes, contact retailers, purchase, or pay."
      let priority: TaskPriority = blocked.count > 3 ? .high : .normal
      if let existingIndex = reviewTasks.firstIndex(where: {
        $0.linkedEntityType == .wishlistItem
          && $0.linkedEntityID == "wishlist-closure-readiness-batch"
          && $0.status != .completed
      }) {
        let beforeDetail = reviewTasks[existingIndex].auditDetail
        reviewTasks[existingIndex].title = "Follow up Wishlist closure readiness"
        reviewTasks[existingIndex].summary = summary
        reviewTasks[existingIndex].priority = priority
        reviewTasks[existingIndex].dueDate = priority == .urgent ? "Today" : "Tomorrow"
        reviewTasks[existingIndex].assignee = "Wishlist review"
        reviewTasks[existingIndex].reviewState = .needsReview
        persistReviewTasks()
        logAudit(
          action: .edited,
          entityType: .reviewTask,
          entityID: reviewTasks[existingIndex].id.uuidString,
          entityLabel: reviewTasks[existingIndex].title,
          summary: "Wishlist closure readiness follow-up task refreshed locally.",
          beforeDetail: beforeDetail,
          afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nExisting batch task was updated instead of duplicated. No order, receiving, inventory, dispatch, mailbox, retailer, payment, purchase, or external service action occurred."
        )
      } else {
        createReviewTask(
          linkedEntityType: .wishlistItem,
          linkedEntityID: "wishlist-closure-readiness-batch",
          label: "Wishlist closure readiness",
          summary: summary,
          priority: priority,
          assignee: "Wishlist review"
        )
      }
    }

    logAudit(
      action: .evaluated,
      entityType: .wishlistItem,
      entityID: "wishlist-closure-readiness-batch",
      entityLabel: "Wishlist closure readiness",
      summary: blocked.isEmpty ? "Wishlist closure readiness checked with no gaps." : "Wishlist closure readiness checked with gaps.",
      afterDetail: """
      Checked Wishlist operations trails: \(candidates.count)
      Ready to close locally: \(ready.count)
      With closure gaps: \(blocked.count)
      Gap counts: \(groupedGapCounts.isEmpty ? "none" : groupedGapCounts.map { "\($0.key): \($0.value)" }.joined(separator: ", "))
      Top gap examples: \(topBlocked.isEmpty ? "none" : topBlocked.joined(separator: " | "))
      \(blocked.isEmpty ? "No task was needed." : "One local review task was created for the closure gap summary.")
      Local closure readiness only. ParcelOps did not close orders externally, receive stock, update inventory systems, book dispatch, print labels, scan hardware, contact sellers, mutate mailboxes, purchase, or pay.
      """
    )
  }

  private func wishlistOperationsClosureGaps(for item: WishlistItem) -> [String] {
    var gaps: [String] = []
    if item.purchaseHandoff?.linkedOrderID == nil { gaps.append("order link") }
    if suggestedReceivingInspections(for: item).isEmpty { gaps.append("receiving") }
    if suggestedInventoryReceipts(for: item).isEmpty { gaps.append("inventory") }
    if suggestedStorageLocations(for: item).isEmpty { gaps.append("storage") }
    if suggestedCustodyRecords(for: item).isEmpty { gaps.append("custody") }
    if suggestedLabelReferenceRecords(for: item).isEmpty { gaps.append("label") }
    if suggestedScanSessionRecords(for: item).isEmpty { gaps.append("manual check") }
    if suggestedShipmentManifestRecords(for: item).isEmpty { gaps.append("manifest") }
    if suggestedDispatchReadinessChecklists(for: item).isEmpty { gaps.append("dispatch") }
    let hasOpenTasks = reviewTasks.contains { task in
      task.linkedEntityType == .wishlistItem
        && task.linkedEntityID == item.id.uuidString
        && task.status != .completed
    }
    if hasOpenTasks { gaps.append("open task") }
    return Array(Set(gaps)).sorted()
  }

  func closeWishlistItemLocally(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let current = wishlistItems[index]
    let gaps = wishlistOperationsClosureGaps(for: current)
    guard gaps.isEmpty else {
      createReviewTask(
        linkedEntityType: .wishlistItem,
        linkedEntityID: current.id.uuidString,
        label: "Close Wishlist item: \(current.itemName)",
        summary: "Wishlist item cannot be closed yet. Remaining local closure gaps: \(gaps.joined(separator: ", ")). This is a local task only and does not close external orders, receive stock, book dispatch, contact sellers, purchase, or pay.",
        priority: .normal,
        assignee: current.owner
      )
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: current.id.uuidString,
        entityLabel: current.itemName,
        summary: "Wishlist item closure blocked by local gaps.",
        afterDetail: "Closure gaps: \(gaps.joined(separator: ", ")). A local review task was created. No Wishlist item was closed, deleted, or moved. No order, receiving, inventory, dispatch, mailbox, seller, purchase, payment, or external service action occurred."
      )
      return
    }

    let beforeDetail = current.auditDetail
    var closed = current
    var handoff = closed.purchaseHandoff
    let previousHandoffNotes = handoff?.notes
    handoff?.purchaseStatus = "Closed locally after operations handoff"
    handoff?.orderWatchStatus = "Closed against local order and operations trail"
    handoff?.notes = [previousHandoffNotes, "Closed locally after order, receiving, inventory, storage, custody, label, manual check, manifest, dispatch, and open-task closure checks passed."]
      .compactMap { $0 }
      .joined(separator: " ")
    handoff?.updatedAt = Self.auditTimestamp()
    closed.purchaseHandoff = handoff
    closed.status = "Closed locally"
    closed.purchaseReadiness = "Wishlist operations closed locally"
    wishlistItems[index] = closed
    persistWishlist()
    logAudit(
      action: .completed,
      entityType: .wishlistItem,
      entityID: closed.id.uuidString,
      entityLabel: closed.itemName,
      summary: "Wishlist item closed locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(closed.auditDetail)\nClosure was local only. ParcelOps did not close external orders, receive stock, update inventory systems, book dispatch, print labels, scan hardware, contact sellers, mutate mailboxes, purchase, or pay."
    )
  }

  func closeReadyWishlistItemsLocally() {
    let candidates = wishlistItems.filter { item in
      isActiveWishlistItem(item)
        && (item.purchaseHandoff?.linkedOrderID != nil
          || !suggestedReceivingInspections(for: item).isEmpty
          || !suggestedInventoryReceipts(for: item).isEmpty
          || !suggestedStorageLocations(for: item).isEmpty
          || !suggestedCustodyRecords(for: item).isEmpty
          || !suggestedLabelReferenceRecords(for: item).isEmpty
          || !suggestedScanSessionRecords(for: item).isEmpty
          || !suggestedShipmentManifestRecords(for: item).isEmpty
          || !suggestedDispatchReadinessChecklists(for: item).isEmpty)
    }
    let ready = candidates.filter { wishlistOperationsClosureGaps(for: $0).isEmpty }
    guard !ready.isEmpty else {
      logAudit(
        action: .evaluated,
        entityType: .wishlistItem,
        entityID: "wishlist-close-ready-batch",
        entityLabel: "Wishlist close ready",
        summary: "Wishlist close-ready batch found no closable items.",
        afterDetail: "Items checked: \(candidates.count)\nNo Wishlist item passed all local closure checks. No item was closed, deleted, or moved. No order, receiving, inventory, dispatch, mailbox, seller, purchase, payment, or external service action occurred."
      )
      return
    }

    for item in ready {
      closeWishlistItemLocally(item)
    }

    logAudit(
      action: .completed,
      entityType: .wishlistItem,
      entityID: "wishlist-close-ready-batch",
      entityLabel: "Wishlist close ready",
      summary: "Wishlist close-ready batch completed locally.",
      afterDetail: "Items checked: \(candidates.count)\nItems closed locally: \(ready.count)\nClosed item examples: \(ready.prefix(6).map(\.itemName).joined(separator: ", "))\nClosure was local only. ParcelOps did not close external orders, receive stock, update inventory systems, book dispatch, print labels, scan hardware, contact sellers, mutate mailboxes, purchase, or pay."
    )
  }

  func reopenClosedWishlistItem(_ item: WishlistItem) {
    guard let index = wishlistItems.firstIndex(where: { $0.id == item.id }) else { return }
    let beforeDetail = wishlistItems[index].auditDetail
    var reopened = wishlistItems[index]
    var handoff = reopened.purchaseHandoff
    let hasLinkedOrder = handoff?.linkedOrderID != nil
    handoff?.purchaseStatus = "Reopened locally for follow-up"
    handoff?.orderWatchStatus = hasLinkedOrder ? "Reopened with linked local order" : "Reopened; order link needs review"
    handoff?.updatedAt = Self.auditTimestamp()
    reopened.purchaseHandoff = handoff
    reopened.status = hasLinkedOrder ? "Order confirmation linked" : "Order confirmation needs linking"
    reopened.purchaseReadiness = "Reopened locally after closure"
    wishlistItems[index] = reopened
    persistWishlist()
    logAudit(
      action: .reopened,
      entityType: .wishlistItem,
      entityID: reopened.id.uuidString,
      entityLabel: reopened.itemName,
      summary: "Closed Wishlist item reopened locally.",
      beforeDetail: beforeDetail,
      afterDetail: "\(reopened.auditDetail)\nReopen was local only. No external order, receiving, inventory, dispatch, mailbox, seller, purchase, payment, or background action occurred."
    )
  }

