      record: record,
      candidateMatches: item.map { suggestedWishlistOrderConfirmations(for: $0) } ?? []
    )
  }

  private func refreshWishlistOrderWatchFollowUpTask(record: WishlistOrderWatchRecord, candidateMatches: [ForwardedEmailIntake]) {
    let linkedEntityID = record.wishlistItemID?.uuidString ?? record.id.uuidString
    let hasCandidates = !candidateMatches.isEmpty
    let title = hasCandidates
      ? "Review Wishlist Inbox confirmation candidates: \(record.itemName)"
      : "Find Wishlist order confirmation: \(record.itemName)"
    let candidateLines = candidateMatches.prefix(3).map { email in
      let order = email.detectedOrderNumber.isPlaceholderValidationValue ? "order needs review" : email.detectedOrderNumber
      let tracking = email.detectedTrackingNumber.isPlaceholderValidationValue ? "tracking needs review" : email.detectedTrackingNumber
      return "- \(email.subject): \(order), \(tracking), received \(email.receivedDate)."
    }
    let nextAction = hasCandidates
      ? "Open Wishlist order watch, review the Inbox candidate rows, then use the correct confirmation to create or link the local order."
      : "Run a manual mailbox refresh if needed, then review Inbox, Mailbox Monitor, and Orders for seller, receipt, dispatch, order number, or tracking signals."
    let summary = [
      "Wishlist order confirmation follow-up for \(record.itemName).",
      "Seller: \(record.sellerName).",
      "Account: \(record.accountLabel).",
      "Expected signals: \(record.expectedOrderSignals).",
      "Source to check: \(record.expectedMailboxOrSource).",
      "Current watch status: \(record.watchStatus).",
      "Inbox candidates: \(candidateMatches.count).",
      candidateLines.isEmpty ? "Candidate preview: none found locally yet." : "Candidate preview:\n\(candidateLines.joined(separator: "\n"))",
      "Next action: \(nextAction)",
      "Boundary: this task is local follow-up only. ParcelOps did not fetch mail, poll in the background, open retailer pages, mutate mailbox items, purchase, pay, or access retailer accounts."
    ].joined(separator: "\n")

    if let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == linkedEntityID
        && ($0.title.localizedCaseInsensitiveContains("Wishlist order confirmation")
          || $0.title.localizedCaseInsensitiveContains("Wishlist Inbox confirmation")
          || $0.title.localizedCaseInsensitiveContains("Review order watch"))
        && $0.status != .completed
    }) {
      let beforeDetail = reviewTasks[existingIndex].auditDetail
      reviewTasks[existingIndex].title = title
      reviewTasks[existingIndex].summary = summary
      reviewTasks[existingIndex].priority = hasCandidates ? .urgent : .high
      reviewTasks[existingIndex].dueDate = "Today"
      reviewTasks[existingIndex].assignee = "Wishlist review"
      reviewTasks[existingIndex].reviewState = .needsReview
      persistReviewTasks()
      logAudit(
        action: .edited,
        entityType: .reviewTask,
        entityID: reviewTasks[existingIndex].id.uuidString,
        entityLabel: reviewTasks[existingIndex].title,
        summary: "Wishlist order confirmation follow-up task refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nInbox candidates: \(candidateMatches.count). No duplicate task was created. No mailbox fetch, background polling, retailer access, checkout, payment, purchase, or mailbox mutation occurred."
      )
      return
    }

    let task = ReviewTask(
      title: title,
      summary: summary,
      linkedEntityType: .wishlistItem,
      linkedEntityID: linkedEntityID,
      priority: hasCandidates ? .urgent : .high,
      dueDate: "Today",
      assignee: "Wishlist review",
      status: .open,
      createdDate: Self.auditTimestamp(),
      completedDate: nil,
      reviewState: .needsReview
    )
    addReviewTask(task, summary: "Wishlist order confirmation follow-up task created locally.")
  }

  private func completeWishlistOrderWatchFollowUpTaskIfNeeded(record: WishlistOrderWatchRecord, matchedOrder: TrackedOrder?) {
    guard let matchedOrder else { return }
    let linkedEntityID = record.wishlistItemID?.uuidString ?? record.id.uuidString
    guard let existingIndex = reviewTasks.firstIndex(where: {
      $0.linkedEntityType == .wishlistItem
        && $0.linkedEntityID == linkedEntityID
        && ($0.title.localizedCaseInsensitiveContains("Wishlist order confirmation")
          || $0.title.localizedCaseInsensitiveContains("Wishlist Inbox confirmation")
          || $0.title.localizedCaseInsensitiveContains("Review order watch"))
        && $0.status != .completed
    }) else { return }
    let beforeDetail = reviewTasks[existingIndex].auditDetail
    reviewTasks[existingIndex].status = .completed
    reviewTasks[existingIndex].completedDate = Self.auditTimestamp()
    reviewTasks[existingIndex].reviewState = .accepted
    reviewTasks[existingIndex].summary += "\nCompleted locally because the Wishlist order watch matched order \(matchedOrder.orderNumber) from \(matchedOrder.store)."
    persistReviewTasks()
    logAudit(
      action: .completed,
      entityType: .reviewTask,
      entityID: reviewTasks[existingIndex].id.uuidString,
      entityLabel: reviewTasks[existingIndex].title,
      summary: "Wishlist order confirmation follow-up task completed after local order match.",
      beforeDetail: beforeDetail,
      afterDetail: "\(reviewTasks[existingIndex].auditDetail)\nMatched order: \(matchedOrder.orderNumber). No mailbox fetch, background polling, retailer access, checkout, payment, purchase, or mailbox mutation occurred."
    )
  }

  func createReviewTask(from item: WishlistItem) {
    let optionCount = item.comparisonOptions?.count ?? 0
    let trustIssueCount = (item.comparisonOptions ?? []).filter {
      $0.trustRating.localizedCaseInsensitiveContains("unknown")
        || $0.trustRating.localizedCaseInsensitiveContains("review")
    }.count
    createReviewTask(
      linkedEntityType: .wishlistItem,
      linkedEntityID: item.id.uuidString,
      label: item.itemName,
      summary: "Compare wishlist item before purchase: \(item.itemName). \(optionCount) seller option\(optionCount == 1 ? "" : "s"); \(trustIssueCount) trust review signal\(trustIssueCount == 1 ? "" : "s"). Confirm AUD landed cost, postage, delivery time, returns, seller trust, and account/payment readiness before buying.",
      priority: trustIssueCount > 0 || optionCount == 0 ? .high : .normal,
      assignee: item.owner
    )
  }

  func createDraftMessage(from item: WishlistItem) {
    let options = item.comparisonOptions ?? []
    let preferredOption = selectedWishlistSellerOption(for: item)
    let decision = item.purchaseDecision
    let handoff = item.purchaseHandoff
    let checks = item.purchaseChecks ?? []
    let failedChecks = checks.filter { $0.status != "Passed" }
    let optionSummary = options
      .prefix(4)
      .map { option in
        let marker: String
        if option.id == item.preferredOptionID {
          marker = "Preferred - "
        } else if option.id == preferredOption?.id {
          marker = "Best scored fallback - "
        } else {
          marker = ""
        }
        let gaps = option.operatorSellerEvidenceGaps
        return "\(marker)\(option.sellerName): \(option.estimatedAUDTotal), postage \(option.postageCost), \(option.postageTime), trust \(option.trustRating), evidence \(gaps.isEmpty ? "complete" : "missing \(gaps.joined(separator: ", "))")"
      }
      .joined(separator: "\n")
    let packetBlockers = item.operatorPurchaseBlockers
    let orderLink = handoff?.linkedOrderID?.uuidString ?? "No local order linked yet"
    let subject = "Wishlist purchase review: \(item.itemName)"
    let body = """
      Please review this wishlist item before purchase.

      Item: \(item.itemName)
      Storefront: \(item.storefront)
      Source URL: \(item.storefrontURL)
      Estimated cost: \(item.estimatedCost)
      Comparison status: \(item.comparisonStatus ?? "Not compared")
      Purchase readiness: \(item.purchaseReadiness ?? "Not assessed")
      Preferred seller: \(preferredOption?.sellerName ?? decision?.selectedSellerName ?? "Not selected")
      AUD total: \(decision?.totalAUDSummary ?? preferredOption?.estimatedAUDTotal ?? item.estimatedCost)
      Postage: \(decision?.postageSummary ?? preferredOption.map { "\($0.postageCost), \($0.postageTime)" } ?? "Not reviewed")
      Trust: \(decision?.trustSummary ?? preferredOption?.trustRating ?? "Not reviewed")
      Decision: \(decision?.decisionStatus ?? "Not drafted")
      Handoff: \(handoff?.purchaseStatus ?? "Not prepared")
      Account: \(handoff?.accountLabel ?? "\(item.owner) account to confirm")
      Order watch: \(handoff?.orderWatchStatus ?? "Not watching yet")
      Linked order: \(orderLink)

      Seller options:
      \(optionSummary.isEmpty ? "No seller options have been compared yet." : optionSummary)

      Readiness checks:
      \(checks.isEmpty ? "No local readiness check has been run yet." : checks.map { "- \($0.title): \($0.status) - \($0.detail)" }.joined(separator: "\n"))

      Packet blockers:
      \(packetBlockers.isEmpty ? "No local packet blockers are currently detected." : packetBlockers.map { "- \($0)" }.joined(separator: "\n"))

      Failed or review checks:
      \(failedChecks.isEmpty ? "No failed/review checks recorded." : failedChecks.map { "- \($0.title): \($0.detail)" }.joined(separator: "\n"))

      Confirm live price, stock, total landed AUD cost, postage time, seller trust, returns/warranty, delivery address, account access, and payment method outside ParcelOps before buying. ParcelOps has not purchased anything, sent a message, accessed a retailer account, or stored payment details.
      """

    let auditDetail = """
      \(item.auditDetail)
      Draft only. No outbound email was sent, no retailer was contacted, no browser automation ran, and no purchase or payment action occurred.
      """

    if let draftIndex = draftMessages.firstIndex(where: {
      $0.linkedEntityID == item.id.uuidString
        && $0.linkedEntityType == .wishlistItem
        && $0.subject.localizedCaseInsensitiveContains("wishlist purchase review")
        && $0.status != .sentLocally
    }) {
      let beforeDetail = draftMessages[draftIndex].auditDetail
      draftMessages[draftIndex].recipient = item.owner
      draftMessages[draftIndex].subject = subject
      draftMessages[draftIndex].body = body
      draftMessages[draftIndex].channel = .email
      draftMessages[draftIndex].reviewState = .needsReview
      if draftMessages[draftIndex].status == .ready {
        draftMessages[draftIndex].status = .reopened
      }
      persistDraftMessages()
      logAudit(
        action: .edited,
        entityType: .draftMessage,
        entityID: draftMessages[draftIndex].id.uuidString,
        entityLabel: draftMessages[draftIndex].subject,
        summary: "Existing Wishlist purchase review draft refreshed locally.",
        beforeDetail: beforeDetail,
        afterDetail: "\(draftMessages[draftIndex].auditDetail)\n\(auditDetail)\nNo duplicate purchase review draft was created. Purchase packet and research drafts were left unchanged."
      )
      return
    }

    let draft = DraftMessage(
      linkedEntityType: .wishlistItem,
      linkedEntityID: item.id.uuidString,
      templateID: nil,
      recipient: item.owner,
      subject: subject,
      body: body,
      channel: .email,
      createdDate: Self.auditTimestamp(),
      status: .draft,
      reviewState: .needsReview
    )
    draftMessages.insert(draft, at: 0)
    persistDraftMessages()
    logAudit(
      action: .created,
      entityType: .draftMessage,
      entityID: draft.id.uuidString,
      entityLabel: draft.subject,
      summary: "Wishlist purchase review draft created locally.",
      afterDetail: auditDetail
    )
  }

