private extension ValidationSeverity {
  var sortRank: Int {
    switch self {
    case .critical: 4
    case .high: 3
    case .warning: 2
    case .info: 1
    }
  }

  var shipmentRiskLevel: ShipmentRiskLevel? {
    switch self {
    case .info: .low
    case .warning: .medium
    case .high: .high
    case .critical: .critical
    }
  }
}

private extension VendorRiskLevel {
  var shipmentRiskLevel: ShipmentRiskLevel {
    switch self {
    case .low: .low
    case .medium: .medium
    case .high: .high
    case .critical: .critical
    }
  }
}

private extension WorkbenchItem {
  var shipmentRiskLevel: ShipmentRiskLevel? {
    switch prioritySeverity {
    case "Low": .low
    case "Medium", "Normal": .medium
    case "High": .high
    case "Critical", "Urgent": .critical
    default: nil
    }
  }
}

